-- Poems batch 331
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('3ec7e50a-9e61-43f2-b0fc-27f85f61a207','呈外舅孫莘老二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','甓社湖中有明月，淮南草木借光輝。',32,'全唐诗/poet.song.56000.json','["甓社湖中有明月，淮南草木借光輝。", "故應剖蚌登王府，不若行沙弄夕霏。"]'),
('edf076ae-f86f-46c0-8069-793a58761995','以天壇靈壽杖送莘老','黄庭堅','宋','宋诗','song-poetry','','[]','王屋千霜老紫藤，扶公休沐對親朋。',32,'全唐诗/poet.song.56000.json','["王屋千霜老紫藤，扶公休沐對親朋。", "異時駟馬安車去，拄到天壇願力能。"]'),
('17b5567a-dd61-488c-bb33-0fd67d3d4471','戲答俞清老道人寒夜三首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','索索葉自雨，月寒遙夜闌。',48,'全唐诗/poet.song.56000.json','["索索葉自雨，月寒遙夜闌。", "馬嘶車鐸鳴，羣動不遑安。", "有人夢超俗，去髮脫儒冠。", "平明視清鏡，正爾良獨難。"]'),
('7fe64ce1-fa1b-4afa-a98d-b0222f21181a','戲答俞清老道人寒夜三首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','聞道一稊米，出身縛簪纓。',48,'全唐诗/poet.song.56000.json','["聞道一稊米，出身縛簪纓。", "懷我伐木友，寒衾夢丁丁。", "富貴但如此，百年半曲肱。", "早晚相隨去，松根有茯苓。"]'),
('72e1b0b3-96a5-413d-b904-43b7343e7c30','戲答俞清老道人寒夜三首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','牧羊金華山，早通玉帝籍。',48,'全唐诗/poet.song.56000.json','["牧羊金華山，早通玉帝籍。", "至今風低草，𧥄𧥄見白石。", "金華風煙下，亦有君履迹。", "何爲紅塵裏，頷鬚欲雪白。"]'),
('b66a2ea5-a50c-498f-a70d-5aace07458ef','祕書省冬夜宿直寄懷李德素','黄庭堅','宋','宋诗','song-poetry','','[]','曲肱驚夢寒，皎皎入牖下。',84,'全唐诗/poet.song.56000.json','["曲肱驚夢寒，皎皎入牖下。", "出門問何祥，岑寂省中夜。", "姮娥携青女，一笑粲萬瓦。", "懷我金玉人，幽獨秉大雅。", "古來絕朱絃，蓋爲知音者。", "同牀有不察，而況子在野。", "獨立占少微，長懷何由寫。"]'),
('b402226d-b48f-4b32-9985-00beb21c26f8','歲寒知松柏','黄庭堅','宋','宋诗','song-poetry','','[]','羣陰彫品物，松柏尚桓桓。',72,'全唐诗/poet.song.56000.json','["羣陰彫品物，松柏尚桓桓。", "老去惟心在，相依到歲寒。", "霜嚴御史府，雨立大夫官。", "犧象溝中斷，徽絃爨下殘。", "光陰一鳥過，翦伐萬牛難。", "春日輝桃李，蒼顔亦預觀。"]'),
('44f6bf9a-8f04-4f1a-a691-15e61402e59c','東觀讀未見書','黄庭堅','宋','宋诗','song-poetry','','[]','漢規羣玉府，東觀近宸居。',72,'全唐诗/poet.song.56000.json','["漢規羣玉府，東觀近宸居。", "詔許無雙士，來觀未見書。", "皇文開萬卷，家學陋三餘。", "竹帛森延閣，星辰繞直廬。", "諸生起孤賤，天子自吹噓。", "願以多聞力，論思補帝裾。"]'),
('441fba27-9750-4533-8b30-14fc69571627','被褐懷珠玉','黄庭堅','宋','宋诗','song-poetry','','[]','國士懷珠玉，通津不易扛。',72,'全唐诗/poet.song.56000.json','["國士懷珠玉，通津不易扛。", "櫝藏心有待，褐短義難降。", "寶唾歸青簡，晴虹貫夜窗。", "直言方按劍，豈是故迷邦。", "彈雀輕千仞，連城買一雙。", "安知藍縷底，明月弄寒江。"]'),
('440186ed-589d-4faf-a10e-c3775483fc06','款塞來享','黄庭堅','宋','宋诗','song-poetry','','[]','前朝夏州守，來款塞門西。',72,'全唐诗/poet.song.56000.json','["前朝夏州守，來款塞門西。", "聖主敷文德，降書付狄鞮。", "氈裘瞻日月，剺面带金犀。", "殿陛閒干羽，邊亭息鼓鼙。", "永輸量谷馬，不作觸藩羝。", "聲勢常相倚，今聞定五溪。"]'),
('83710e1c-aa46-461e-a2f9-8ba70f8c6f8c','憶邢惇夫','黄庭堅','宋','宋诗','song-poetry','','[]','詩到隨州更老成，江山爲助筆縱橫。',32,'全唐诗/poet.song.56000.json','["詩到隨州更老成，江山爲助筆縱橫。", "眼看白璧埋黄壤，何況人間父子情。"]'),
('df6d2e1b-bafe-4a9d-b043-2a25c5503ac1','次韵秦少章晁適道贈答詩','黄庭堅','宋','宋诗','song-poetry','','[]','二子論文地，陰風雪塞廬。',48,'全唐诗/poet.song.56000.json','["二子論文地，陰風雪塞廬。", "寧穿東郭履，不遺子公書。", "士固難推挽，時聞有詔除。", "負暄真得計，獻御恐成疏。"]'),
('51a6f262-df90-4ce6-bd0d-5baa53901c5b','次韵答秦少章乞酒','黄庭堅','宋','宋诗','song-poetry','','[]','朝事鞍馬早，吏曹文墨拘。',108,'全唐诗/poet.song.56000.json','["朝事鞍馬早，吏曹文墨拘。", "初無尺寸補，但于朋友疏。", "豈如簞瓢子，卧起一牀書。", "炙背道堯舜，雪屋相與娛。", "步出城東門，野鳥吟廢墟。", "頗知富貴事，勢窮心亦舒。", "詩來獻窮狀，水餠嚼冰蔬。", "斗酒得醉否，枵腹如瓠壺。", "亦可召西舍，侯嬴非博徒。"]'),
('f5baa047-0888-4d17-b0e0-148e50d15c28','頤軒詩六首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','金石不隨波，松竹知歲寒。',24,'全唐诗/poet.song.56000.json','["金石不隨波，松竹知歲寒。", "冥此芸芸境，迴向自心觀。"]'),
('32035801-c035-445d-8280-6af0c1900844','頤軒詩六首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','知足是靈龜，無厭乃朵頤。',24,'全唐诗/poet.song.56000.json','["知足是靈龜，無厭乃朵頤。", "虛心萬物表，寒暑自四時。"]'),
('c423db3b-23c6-4b9f-8adc-7f9b4397d9bf','頤軒詩六首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','無外一精明，六合同出自。',24,'全唐诗/poet.song.56000.json','["無外一精明，六合同出自。", "公能知本源，佛亦不相似。"]'),
('601a57a3-f89a-4c02-87fc-fecc6cfe4a00','頤軒詩六首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','辱莫辱多欲，樂莫樂無求。',24,'全唐诗/poet.song.56000.json','["辱莫辱多欲，樂莫樂無求。", "人生强學耳，萬古一東流。"]'),
('49924d7c-d502-4eee-8f46-a2e5602e2a39','頤軒詩六首  其五','黄庭堅','宋','宋诗','song-poetry','','[]','樞機要發遲，飲食戒味厚。',24,'全唐诗/poet.song.56000.json','["樞機要發遲，飲食戒味厚。", "漁人溺於波，君子溺於口。"]'),
('8b06f3e8-7b52-4b16-82a8-349dea85d801','頤軒詩六首  其六','黄庭堅','宋','宋诗','song-poetry','','[]','涇流不濁渭，種桃無李實。',24,'全唐诗/poet.song.56000.json','["涇流不濁渭，種桃無李實。", "養心去塵緣，光明生虛室。"]'),
('505bcb26-92bf-45c6-9367-54598a0dabea','寺齋睡起二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','小黠大癡螳捕蟬，有餘不足夔憐蚿。',32,'全唐诗/poet.song.56000.json','["小黠大癡螳捕蟬，有餘不足夔憐蚿。", "退食歸來北窗夢，一江風月桃李船。"]'),
('a8370eee-98de-4e24-a3b6-92ddaabe31d5','寺齋睡起二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','桃李無言一再風，黄鸝惟見綠葱葱。',32,'全唐诗/poet.song.56000.json','["桃李無言一再風，黄鸝惟見綠葱葱。", "人言九事八爲律，儻有江船吾欲東。"]'),
('09317c75-7b1a-4716-b4ba-eaa5f07c8dbf','記夢','黄庭堅','宋','宋诗','song-poetry','','[]','衆真絕妙擁靈君，曉然夢之非紛紜。',80,'全唐诗/poet.song.56000.json','["衆真絕妙擁靈君，曉然夢之非紛紜。", "窗中遠山是眉黛，席上榴花皆舞裙。", "借問琵琶得聞否，靈君色莊妓摇手。", "兩客爭棋爛斧柯，一兒壞局君不呵。", "杏梁歸燕語空多，奈此雲窗霧閣何。"]'),
('45d16141-05d2-40d5-9842-f2eac09a46ef','同元明過洪福寺戲題','黄庭堅','宋','宋诗','song-poetry','','[]','洪福僧園拂紺紗，舊題塵壁似昏鴉。',32,'全唐诗/poet.song.56000.json','["洪福僧園拂紺紗，舊題塵壁似昏鴉。", "春殘已是風和雨，更著遊人撼落花。"]'),
('56ad926c-46cb-48e7-bce2-6c8a2581524d','戲答晁深道乞消梅二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','青莎徑裏香未乾，黄鳥陰中實已團。',32,'全唐诗/poet.song.56000.json','["青莎徑裏香未乾，黄鳥陰中實已團。", "蒸豆作烏鹽作白，屬聞丹杏薦牙盤。"]'),
('56a4fad4-8d1c-4e48-8a37-af25eb587b45','戲答晁深道乞消梅二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','北客未嘗眉自顰，南人誇說齒生津。',32,'全唐诗/poet.song.56000.json','["北客未嘗眉自顰，南人誇說齒生津。", "磨錢和蜜誰能許，去蒂供鹽亦可人。"]'),
('617b24b1-96cb-428d-a62b-6db8a69d55cf','以梅餽晁深道戲贈二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','带葉連枝摘未殘，依依茶塢竹籬間。',32,'全唐诗/poet.song.56000.json','["带葉連枝摘未殘，依依茶塢竹籬間。", "相如病渴應須此，莫與文君蹙遠山。"]'),
('622c8626-9f33-4dc3-b019-1682df6eef68','以梅餽晁深道戲贈二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','渴夢吞江起解顔，詩成有味齒牙間。',32,'全唐诗/poet.song.56000.json','["渴夢吞江起解顔，詩成有味齒牙間。", "前身鄴下劉公幹，今日江南庾子山。"]'),
('34569511-b3c4-4348-b90a-db650af6f2bc','次韵孫子實題少章寄寂齋','黄庭堅','宋','宋诗','song-poetry','','[]','虛名誤壯夫，今古可笑閔。',120,'全唐诗/poet.song.56000.json','["虛名誤壯夫，今古可笑閔。", "尸裹萬里歸，書載五車稛。", "安知衡門下，身與天地準。", "秦晁兩美士，內行頗修謹。", "余欲造之深，抽琴去其軫。", "寄寂喧鬨間，此道有汲引。", "獄戶聞笞榜，市聲雜嘲辴。", "二生對曲肱，圭玉發石藴。", "大小窮鵬鷃，短長見椿槿。", "欲聞寂時聲，黄鍾在龍筍。"]'),
('9da4b1e3-e0fb-49c8-b15c-c9fa3e65b51c','次韵孫子實寄少游','黄庭堅','宋','宋诗','song-poetry','','[]','薛宣欲吏雲，季氏或招閔。',120,'全唐诗/poet.song.56000.json','["薛宣欲吏雲，季氏或招閔。", "此公胸中秋，萬物欲收稛。", "賣藥偶知名，草玄非近準。", "才難不易得，志大略細謹。", "士生要弘毅，天地爲蓋軫。", "驥來鹽車驂，井下短綆引。", "難甘呼爾食，聊寄粲然辴。", "誰能借前籌，還婦用束縕。", "吾聞調羹鼎，異味及枌堇。", "豈其供王羞，而弃會稽筍。"]'),
('5091c53e-08de-401b-a4c2-b21b10db1ef0','戲書秦少游壁','黄庭堅','宋','宋诗','song-poetry','','[]','丁令威，化作遼東白鶴歸，朱顔未改故人非。',92,'全唐诗/poet.song.56000.json','["丁令威，化作遼東白鶴歸，朱顔未改故人非。", "微服過宋風退飛，宋父擁篲待來歸，誰饋百牢鸜鵒妃。", "秦氏烏生八九子，鴉烏之兄畢逋尾。", "憶炊門牡烹伏雌，未肯增巢令汝棲。", "莫愁野雉疏家雞，但願主人印纍纍。"]'),
('19d734a2-fd66-42cd-ad72-e2ee91c8699f','贈秦少儀','黄庭堅','宋','宋诗','song-poetry','','[]','汝南許文休，馬磨自衣食。',132,'全唐诗/poet.song.56000.json','["汝南許文休，馬磨自衣食。", "但聞郡功曹，滿世名籍籍。", "渠命有顯晦，非人作通塞。", "秦氏多英俊，少游眉最白。", "頗聞鴻雁行，筆皆萬人敵。", "吾早知有覯，而不知有覿。", "少儀袖詩來，剖蚌珠的皪。", "乃能持一鏃，與我箭鋒直。", "自吾得此詩，三日卧向壁。", "挽士不能寸，推去輒數尺。", "才難不其然，有亦未易識。"]'),
('955577c7-2c32-47cd-b905-0a9a4c5a7e81','送少章從翰林蘇公餘杭','黄庭堅','宋','宋诗','song-poetry','','[]','東南淮海惟揚州，國士無雙秦少游。',96,'全唐诗/poet.song.56000.json','["東南淮海惟揚州，國士無雙秦少游。", "欲攀天關守九虎，但有筆力迴萬牛。", "文學縱橫乃如此，故應當家有季子。", "時來誰能力作難，鴻雁行飛入道山。", "斑衣兒啼真自樂，從師學道也不惡。", "但使新年勝故年，即如常在郎罷前。"]'),
('5a17c0bf-3248-44c9-8a7d-e6878ee4ba19','題浄因壁二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','暝倚蒲團挂鉢囊，半窗疏箔度微凉。',32,'全唐诗/poet.song.56000.json','["暝倚蒲團挂鉢囊，半窗疏箔度微凉。", "蕉心不展待時雨，葵葉爲誰傾太陽。"]'),
('8434bc2f-25b1-4ff3-96a6-3978e11d244c','題浄因壁二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','門外黄塵不見山，此中草木亦常閒。',32,'全唐诗/poet.song.56000.json','["門外黄塵不見山，此中草木亦常閒。", "履聲如度薄冰過，催粥華鯨吼夜闌。"]'),
('9171763f-f770-4ac7-b229-cbb4cb1cee3c','六月十七日晝寢','黄庭堅','宋','宋诗','song-poetry','','[]','紅塵席帽烏韡裏，想見滄洲白鳥雙。',32,'全唐诗/poet.song.56000.json','["紅塵席帽烏韡裏，想見滄洲白鳥雙。", "馬齕枯萁喧午枕，夢成風雨浪翻江。"]'),
('00d42f45-f230-47c1-bb09-1fc2deaa67a7','北窗','黄庭堅','宋','宋诗','song-poetry','','[]','生物趨功日夜流，園林才夏麥先秋。',32,'全唐诗/poet.song.56000.json','["生物趨功日夜流，園林才夏麥先秋。", "綠陰黄鳥北窗簟，付與來禽安石榴。"]'),
('9337ea27-baa2-4db7-902c-bbdd798fd0c4','趙子充示竹夫人詩蓋凉寢竹器憩臂休膝似非夫人之職予爲名曰青奴并以小詩取之二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','青奴元不解梳妝，合在禪齋夢蝶牀。',32,'全唐诗/poet.song.56000.json','["青奴元不解梳妝，合在禪齋夢蝶牀。", "公自有人同枕簟，肌膚冰雪助清凉。"]'),
('4ed070fc-84e2-4122-aa70-b95196b06567','趙子充示竹夫人詩蓋凉寢竹器憩臂休膝似非夫人之職予爲名曰青奴并以小詩取之二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','穠李四絃風拂席，昭華三弄月侵牀。',32,'全唐诗/poet.song.56000.json','["穠李四絃風拂席，昭華三弄月侵牀。", "我無紅袖堪娛夜，正要青奴一味凉。"]'),
('17cffc12-71e9-4086-ba72-ed096f4976a7','范蜀公挽詞二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','信道雖常爾，知人乃獨亨。',48,'全唐诗/poet.song.56000.json','["信道雖常爾，知人乃獨亨。", "書林身老大，諫紙字敧傾。", "鼇去三山動，人危五鼎烹。", "保全天子聖，几杖送餘生。"]'),
('d58f40f4-b80f-45a9-8335-9ffb5308865e','范蜀公挽詞二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','公在昭陵日，文章近赤墀。',48,'全唐诗/poet.song.56000.json','["公在昭陵日，文章近赤墀。", "空嗟伏生老，不侍邇英帷。", "去國幾三虎，聞韶待一夔。", "誰言蓋棺了，新樂鎖蛛絲。"]'),
('6431d1cb-24cf-4e94-a4d1-7dcac0413993','宗室公壽挽詞二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','昔在熙寧日，葭莩接貴游。',48,'全唐诗/poet.song.56000.json','["昔在熙寧日，葭莩接貴游。", "題詩奉先寺，橫笛寶津樓。", "天網恢中夏，賓筵禁列侯。", "但聞劉子政，頭白更清修。"]'),
('eb571ed8-915a-4bb0-86f2-fe2406b99455','宗室公壽挽詞二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','昧旦鳴珂路，春朝禁殿班。',48,'全唐诗/poet.song.56000.json','["昧旦鳴珂路，春朝禁殿班。", "方看分寶玉，何意作丘山。", "燕入風榮舞，花開日笑顔。", "空餘杜陵淚，一爲漢中潸。"]'),
('3d02fd5c-b4ce-4c81-8c80-7be69df786f4','出城送客過故人東平侯趙景珍墓','黄庭堅','宋','宋诗','song-poetry','','[]','朱顔苦留不肯住，白髮正爾欺得人。',64,'全唐诗/poet.song.56000.json','["朱顔苦留不肯住，白髮正爾欺得人。", "嬋娟去作誰家妾，意氣都成一聚塵。", "今日牛羊上丘壟，當時近前左右嗔。", "花開鳥啼荆棘裏，誰與平章作好春。"]'),
('e0333bf6-b360-43fe-921b-4455675a2093','黄潁州挽詞三首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','恭惟同自出，累世復通家。',48,'全唐诗/poet.song.56000.json','["恭惟同自出，累世復通家。", "惠沫霑枯涸，忠規補過差。", "胸中明玉石，仕路困風沙。", "尚有平生酒，秋原洒菊花。"]'),
('37921997-5d52-46cc-9b6f-1b3606193539','黄潁州挽詞三首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','臨民次公老，論事長輿通。',48,'全唐诗/poet.song.56000.json','["臨民次公老，論事長輿通。", "袖有投虛刃，時無斲鼻工。", "風流前輩近，名實後人公。", "不謂三日別，今成萬事空。"]'),
('7fce2035-672a-4b47-90fe-8f94bbfb7177','黄潁州挽詞三首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','公與汝陽守，人間孝友稀。',48,'全唐诗/poet.song.56000.json','["公與汝陽守，人間孝友稀。", "脊令鳴夜雨，常棣倚春暉。", "粉省雙飛入，泉臺相與歸。", "哀笳宛丘道，衰涕不勝揮。"]'),
('61a74bd9-f2a0-45db-b63f-3c8055fd4d5f','樂壽縣君呂氏挽詞二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','歸裝衣楚楚，家世印纍纍。',48,'全唐诗/poet.song.56000.json','["歸裝衣楚楚，家世印纍纍。", "來作箕帚婦，不忘蘋藻詩。", "居然成萬古，何啻謁三醫。", "騎省還秋直，霜侵鬢脚衰。"]'),
('15542fef-21ca-4058-b5ec-90220ab33df0','樂壽縣君呂氏挽詞二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','剪髻賓筵盛，齊眉婦禮閑。',48,'全唐诗/poet.song.56000.json','["剪髻賓筵盛，齊眉婦禮閑。", "謂宜俱白髮，忽去作青山。", "大夢驚蝴蝶，何時識佩環。", "哀歌行欲絕，丹旐雨斑斑。"]'),
('7f7414c7-160a-4a41-8f3d-e6a3d1cc9c10','叔父給事挽詞十首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','元祐宗臣考十科，公居八九未爲多。',32,'全唐诗/poet.song.56000.json','["元祐宗臣考十科，公居八九未爲多。", "功名身後無瑕點，孝友生知不琢磨。"]'),
('30784325-2a77-4c19-a571-52f3a9c70af4','叔父給事挽詞十首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','平生治獄有陰功，忠孝臨民父母同。',32,'全唐诗/poet.song.56000.json','["平生治獄有陰功，忠孝臨民父母同。", "贛上樵夫談卓令，宣城老吏識于公。"]'),
('31e2f23b-04eb-49bc-bac8-375227148f99','叔父給事挽詞十首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','三晉山河數十州，頻年水旱不能秋。',32,'全唐诗/poet.song.56000.json','["三晉山河數十州，頻年水旱不能秋。", "我公出把司農節，粟麥還于地上流。"]'),
('16a7776e-ffbd-45cf-9f07-4346a6ac552c','叔父給事挽詞十首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','更生苦訟石中書，宰掾非人欲引裾。',32,'全唐诗/poet.song.56000.json','["更生苦訟石中書，宰掾非人欲引裾。", "兩猾論兵幾敗國，同時御史更誰如。"]'),
('ef10b40d-c9ae-49f1-b75c-3d401c09d964','叔父給事挽詞十首  其五','黄庭堅','宋','宋诗','song-poetry','','[]','曾發公家鉅萬錢，溝中襁褓却生全。',32,'全唐诗/poet.song.56000.json','["曾發公家鉅萬錢，溝中襁褓却生全。", "三齊水後皆禾稼，不殺耕牛更可傳。"]'),
('76ece801-390a-4f86-9e77-af30df9ce33c','叔父給事挽詞十首  其六','黄庭堅','宋','宋诗','song-poetry','','[]','晉地無戎卧賊曹，民兵賜笏解弓刀。',32,'全唐诗/poet.song.56000.json','["晉地無戎卧賊曹，民兵賜笏解弓刀。", "六年講武儒冠在，不踏金門著戰袍。"]'),
('fccef65c-f2bd-4a64-8304-21cc76673755','叔父給事挽詞十首  其七','黄庭堅','宋','宋诗','song-poetry','','[]','軍容百萬轉風雷，獨料王師不戰摧。',32,'全唐诗/poet.song.56000.json','["軍容百萬轉風雷，獨料王師不戰摧。", "三篋飛書公對獄，元豐天子照姦回。"]'),
('49e44188-34c4-459a-9e58-659b5b1fa23c','叔父給事挽詞十首  其八','黄庭堅','宋','宋诗','song-poetry','','[]','隴上千山漢節回，掃除民蜮不爲災。',32,'全唐诗/poet.song.56000.json','["隴上千山漢節回，掃除民蜮不爲災。", "蜀茶總入諸蕃市，胡馬常從萬里來。"]'),
('de14a534-24fe-452b-84d3-fc94202f1eaa','叔父給事挽詞十首  其九','黄庭堅','宋','宋诗','song-poetry','','[]','廊廟從來不在邊，黄扉青瑣慶登賢。',32,'全唐诗/poet.song.56000.json','["廊廟從來不在邊，黄扉青瑣慶登賢。", "除書未試回天筆，何意佳城到馬前。"]'),
('a6117302-e80f-489c-9439-b82e45df66ff','叔父給事挽詞十首  其一○','黄庭堅','宋','宋诗','song-poetry','','[]','榮祿常思澤九宗，山摧梁壞牀成空。',32,'全唐诗/poet.song.56000.json','["榮祿常思澤九宗，山摧梁壞牀成空。", "百年遺恨誰昭洗，他日諸郎有父風。"]'),
('7ce7ed46-b9ab-45f8-b665-36d9efff88bf','寂住閣','黄庭堅','宋','宋诗','song-poetry','','[]','莊周夢爲胡蝶，胡蝶不知莊周。',28,'全唐诗/poet.song.56000.json','["莊周夢爲胡蝶，胡蝶不知莊周。", "當處出生隨意，急流水上不流。"]'),
('9fc747dd-e9a7-4906-89cd-f90658579a10','深明閣','黄庭堅','宋','宋诗','song-poetry','','[]','象踏恒河徹底，日行閻浮破冥。',28,'全唐诗/poet.song.56000.json','["象踏恒河徹底，日行閻浮破冥。", "若問深明宗旨，風花時度窗櫺。"]'),
('c1506a43-fe1a-499c-ad40-7ddbd4621bb0','竹枝詞二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','撐崖拄谷蝮蛇愁，入箐攀天猿掉頭。',32,'全唐诗/poet.song.56000.json','["撐崖拄谷蝮蛇愁，入箐攀天猿掉頭。", "鬼門關外莫言遠，五十三驛是皇州。"]'),
('eb37d747-04c6-43cc-8ed0-c5fe0025be31','竹枝詞二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','浮雲一百八盤縈，落日四十八渡明。',32,'全唐诗/poet.song.56000.json','["浮雲一百八盤縈，落日四十八渡明。", "鬼門關外莫言遠，四海一家皆弟兄。"]'),
('2f5bddd4-7027-47fa-959d-6412878238ab','夢李白誦竹枝詞三疊  其一','黄庭堅','宋','宋诗','song-poetry','','[]','一聲望帝花片飛，萬里明妃雪打圍。',32,'全唐诗/poet.song.56000.json','["一聲望帝花片飛，萬里明妃雪打圍。", "馬上胡兒那解聽，琵琶應道不如歸。"]'),
('c942870c-73eb-483f-ba03-7a07e7de80d2','夢李白誦竹枝詞三疊  其二','黄庭堅','宋','宋诗','song-poetry','','[]','竹竿坡面蛇倒退，摩圍山腰胡孫愁。',32,'全唐诗/poet.song.56000.json','["竹竿坡面蛇倒退，摩圍山腰胡孫愁。", "杜鵑無血可續淚，何日金雞赦九州。"]'),
('d386f578-7450-4dbe-8c1b-3bbcb75b04a3','夢李白誦竹枝詞三疊  其三','黄庭堅','宋','宋诗','song-poetry','','[]','命輕人鮓甕頭船，日瘦鬼門關外天。',32,'全唐诗/poet.song.56000.json','["命輕人鮓甕頭船，日瘦鬼門關外天。", "北人墮淚南人笑，青壁無梯聞杜鵑。"]'),
('64d60ec2-2309-458e-bad2-5f015c78d270','和答元明黔南贈別','黄庭堅','宋','宋诗','song-poetry','','["\u6292\u60c5", "\u8d60\u522b"]','萬里相看忘逆旅，三聲清淚落離觴。',64,'全唐诗/poet.song.56000.json','["萬里相看忘逆旅，三聲清淚落離觴。", "朝雲往日攀天夢，夜雨何時對榻凉。", "急雪脊令相並影，驚風鴻雁不成行。", "歸舟天際常回首，從此頻書慰斷腸。"]'),
('c9bf6bad-fcd4-477c-8e9c-cd4651a17baf','題蘇若蘭回文錦詩圖','黄庭堅','宋','宋诗','song-poetry','','[]','千詩織就回文錦，如此陽臺暮雨何。',32,'全唐诗/poet.song.56000.json','["千詩織就回文錦，如此陽臺暮雨何。", "亦有英靈蘇蕙手，只無悔過竇連波。"]'),
('6acdfa97-03b2-4a55-82e2-b8bc2d92a8cc','次韵楊明叔四首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','魚去游濠上，鴞來止坐隅。',48,'全唐诗/poet.song.56000.json','["魚去游濠上，鴞來止坐隅。", "吉凶終我在，憂樂與生俱。", "决定不是物，方名大丈夫。", "今觀由也果，老子欲乘桴。"]'),
('05101a22-52a4-4bb8-8fa7-b6b3693d8e44','次韵楊明叔四首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','道常無一物，學要反三隅。',48,'全唐诗/poet.song.56000.json','["道常無一物，學要反三隅。", "喜與嗔同本，嗔時喜自俱。", "心隨物作宰，人謂我非夫。", "利用兼精義，還成到岸桴。"]'),
('ac836a11-2733-406a-9ecf-5192324cdb7f','次韵楊明叔四首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','全德備萬物，大方無四隅。',48,'全唐诗/poet.song.56000.json','["全德備萬物，大方無四隅。", "身隨腐草化，名與太山俱。", "道學歸吾子，言詩起老夫。", "無爲蹈東海，留作濟川桴。"]'),
('00cf5a64-f460-4350-896d-9688e6b0fbdb','次韵楊明叔四首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','匹士能光國，三孱不滿隅。',48,'全唐诗/poet.song.56000.json','["匹士能光國，三孱不滿隅。", "竊觀今日事，君與古人俱。", "氣類鶑求友，精誠石望夫。", "雷門震驚手，待汝一援桴。"]'),
('3ec7c1f0-365c-4cd9-8f1a-200d52b56999','再次韵','黄庭堅','宋','宋诗','song-poetry','','[]','窮奇投有北，鴻鵠止丘隅。',48,'全唐诗/poet.song.56000.json','["窮奇投有北，鴻鵠止丘隅。", "我已魑魅禦，君方燕雀俱。", "道應無蒂芥，學要盡工夫。", "莫斬猿狙杙，明堂待棟桴。"]'),
('851acda5-8dc6-4e61-bcc5-57d1c2685b34','謫居黔南十首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','相望六千里，天地隔江山。',24,'全唐诗/poet.song.56000.json','["相望六千里，天地隔江山。", "十書九不到，何用一開顔。"]'),
('68f0476a-1eb9-4f94-b762-7a03755ad18f','謫居黔南十首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','霜降水反壑，風落木歸山。',24,'全唐诗/poet.song.56000.json','["霜降水反壑，風落木歸山。", "冉冉歲華晚，昆蟲皆閉關。"]'),
('4d7485ac-8265-4ffa-baa8-0fa0f1030747','謫居黔南十首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','冷淡病心情，暄和好時節。',24,'全唐诗/poet.song.56000.json','["冷淡病心情，暄和好時節。", "故園音信斷，遠郡親賓絕。"]'),
('8ebdffeb-b043-424c-8288-38f5fe782828','謫居黔南十首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','山郭燈火稀，峽天星漢少。',24,'全唐诗/poet.song.56000.json','["山郭燈火稀，峽天星漢少。", "年光東流水，生計南枝鳥。"]'),
('0eed3f8b-93d1-4c8c-917c-b2668cc6726a','謫居黔南十首  其五','黄庭堅','宋','宋诗','song-poetry','','[]','冥懷齊遠近，委順隨南北。',24,'全唐诗/poet.song.56000.json','["冥懷齊遠近，委順隨南北。", "歸去誠可憐，天涯住亦得。"]'),
('8e7423f7-5b21-4af7-bf9c-056878a05618','謫居黔南十首  其六','黄庭堅','宋','宋诗','song-poetry','','[]','老色日上面，歡悰日去心。',24,'全唐诗/poet.song.56000.json','["老色日上面，歡悰日去心。", "今既不如昔，後當不如今。"]'),
('9463bb2e-4197-4ed4-9933-93c4b8bdf9e1','謫居黔南十首  其七','黄庭堅','宋','宋诗','song-poetry','','[]','嘖嘖雀引雛，梢梢笋成竹。',24,'全唐诗/poet.song.56000.json','["嘖嘖雀引雛，梢梢笋成竹。", "時物感人情，憶我故鄉曲。"]'),
('7d0bd581-8483-43ed-bd1a-5fb04786ed52','謫居黔南十首  其八','黄庭堅','宋','宋诗','song-poetry','','[]','苦雨初入梅，瘴雲稍含毒。',24,'全唐诗/poet.song.56000.json','["苦雨初入梅，瘴雲稍含毒。", "泥秧水畦稻，灰種畬田粟。"]'),
('10e9c4ca-7fbe-4e03-b69c-a3897b635695','謫居黔南十首  其九','黄庭堅','宋','宋诗','song-poetry','','[]','輕紗一幅巾，小簟六尺牀。',24,'全唐诗/poet.song.56000.json','["輕紗一幅巾，小簟六尺牀。", "無客盡日靜，有風終夜凉。"]'),
('af65db61-ac09-430c-b030-5e46c4a7d05a','謫居黔南十首  其一○','黄庭堅','宋','宋诗','song-poetry','','[]','病人多夢醫，囚人多夢赦。',24,'全唐诗/poet.song.56000.json','["病人多夢醫，囚人多夢赦。", "如何春來夢，合眼在鄉社。"]'),
('646f357a-bfb3-44ac-b870-03f34f357a2c','贈黔南賈使君','黄庭堅','宋','宋诗','song-poetry','','[]','綠髮將軍領百蠻，橫戈得句一開顔。',64,'全唐诗/poet.song.56000.json','["綠髮將軍領百蠻，橫戈得句一開顔。", "少年圯下傳書客，老去崆峒問道山。", "春入鶑花空自笑，秋成梨棗爲誰攀。", "何時定作風光主，待得征西鼓吹還。"]'),
('e78310a6-c1c3-4ebc-abe1-885c2fc5e63a','次韵雨絲雲鶴二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','煙雲杳靄合中稀，霧雨空濛密更微。',64,'全唐诗/poet.song.56000.json','["煙雲杳靄合中稀，霧雨空濛密更微。", "園客繭絲抽萬緒，蛛蝥網面罩羣飛。", "風光錯綜天經緯，草木文章帝杼機。", "願染朝霞成五色，爲君王補坐朝衣。"]'),
('08d7d1d5-a45f-4ade-b312-45bb96abd6ea','次韵雨絲雲鶴二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','幾片雲如薛公鶴，精神態度不曾齊。',64,'全唐诗/poet.song.56000.json','["幾片雲如薛公鶴，精神態度不曾齊。", "安知隴鳥樊籠密，便覺南鵬羽翼低。", "風散又成千里去，夜寒應上九天栖。", "坐來改變如蒼狗，試欲揮毫意自迷。"]'),
('ac6bcaf1-dff1-460b-91d1-ff5cd8c94991','從斌老乞苦筍','黄庭堅','宋','宋诗','song-poetry','','[]','南園苦笋味勝肉，籜龍稱冤莫采錄。',32,'全唐诗/poet.song.56000.json','["南園苦笋味勝肉，籜龍稱冤莫采錄。", "煩君更致蒼玉束，明日風雨皆成竹。"]'),
('b6443384-1a8d-48bc-8668-b665d6485b04','次韵黄斌老所畫橫竹','黄庭堅','宋','宋诗','song-poetry','','["\u6292\u60c5", "\u8d5e\u7f8e"]','酒澆胸次不能平，吐出蒼竹歲崢嶸。',64,'全唐诗/poet.song.56000.json','["酒澆胸次不能平，吐出蒼竹歲崢嶸。", "卧龍偃蹇雷不驚，公與此君俱忘形。", "晴窗影落石泓處，松煤淺染飽霜兔。", "中安三石使屈蟠，亦恐形全便飛去。"]'),
('cd3792fe-dd0a-4078-ac1c-b75ee4eec15b','次韵謝黄斌老送墨竹十二韵','黄庭堅','宋','宋诗','song-poetry','','[]','古今作生竹，能者未十輩。',144,'全唐诗/poet.song.56000.json','["古今作生竹，能者未十輩。", "吳生勒枝葉，筌寀遠不逮。", "江南鐵鉤鎖，最許誠懸會。", "燕公灑墨成，落落與時背。", "譬如刳心松，中有歲寒在。", "湖州三百年，筆與前哲配。", "規模轉銀鉤，幽賞非俗愛。", "披圖風雨入，咫尺莽蒼外。", "吾宗學湖州，師逸功已倍。", "有來竹四幅，冬夏生變態。", "預知更入神，後出遂無對。", "吾詩被壓倒，物固不兩大。"]'),
('435c420e-b451-496c-a232-3ad239612904','用前韵謝子舟爲予作風雨竹','黄庭堅','宋','宋诗','song-poetry','','[]','子舟詩書客，畫手睨前輩。',144,'全唐诗/poet.song.56000.json','["子舟詩書客，畫手睨前輩。", "挹袂拍其肩，餘力左右逮。", "摩拂造化爐，經營鬼神會。", "光煤疊亂葉，世與作者背。", "看君回腕筆，猶喜漢儀在。", "歲寒十三本，與可可追配。", "小山蒼苔面，突兀謝憎愛。", "風斜兼雨重，意出筆墨外。", "吾聞絕一源，戰勝自十倍。", "榮枯轉時機，生死付交態。", "狙公倒七芧，勿用嗔喜對。", "此物當更工，請以小喻大。"]'),
('4eddf18b-c1f4-4e3c-9121-e8638abcfc99','再用前韵詠子舟所作竹','黄庭堅','宋','宋诗','song-poetry','','[]','森萷一山竹，壯士十三輩。',144,'全唐诗/poet.song.56000.json','["森萷一山竹，壯士十三輩。", "自干雲天去，草芥肯下逮。", "虛心聽造物，顛沛風雲會。", "榮枯偶同時，終不相棄背。", "誰云湖州沒，筆力今尚在。", "阿筌雖墨妙，好以桃李配。", "國工裁主意，冷淡恐不愛。", "子舟落心畫，榮觀不在外。", "耆年道機熟，增勝當倍倍。", "祖述今百家，小紙弄姿態。", "雖云出湖州，卷置懶開對。", "非公筆如椽，孰能爲之大。"]'),
('1973f1c7-55d8-4492-8084-69c75f39a3af','戲詠子舟畫兩竹兩鸜鵒','黄庭堅','宋','宋诗','song-poetry','','[]','風晴日暖摇雙竹，竹間相語兩鸜鵒。',64,'全唐诗/poet.song.56000.json','["風晴日暖摇雙竹，竹間相語兩鸜鵒。", "鸜鵒之肉不可餚，人生不材果爲福。", "子舟之筆利如錐，千變萬化皆天機。", "未知筆下鸜鵒語，何似夢中胡蝶飛。"]'),
('64ee0940-7570-41c8-8718-b1738a78c943','次韵答斌老病起獨游東園二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','萬事同一機，多慮乃禪病。',48,'全唐诗/poet.song.56000.json','["萬事同一機，多慮乃禪病。", "排悶有新詩，忘蹄出兔徑。", "蓮花生淤泥，可見嗔喜性。", "小立近幽香，心與晚色靜。"]'),
('e2c68152-d01c-494b-bcd9-18a617aeda26','次韵答斌老病起獨游東園二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','主人心安樂，花竹有和氣。',48,'全唐诗/poet.song.56000.json','["主人心安樂，花竹有和氣。", "時從物外賞，自益酒中味。", "斸枯蟻改穴，掃籜筍迸地。", "萬籟寂中生，乃知風雨至。"]'),
('7b7a9765-4035-4629-8d92-0ba1c3d75ef5','又和二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','西風鏖殘暑，如用霍去病。',48,'全唐诗/poet.song.56000.json','["西風鏖殘暑，如用霍去病。", "疏溝滿蓮塘，掃葉明竹逕。", "中有寂寞人，自知圓覺性。", "心猿方睡起，一笑六窗靜。"]'),
('134df8f3-0869-4e47-b588-873801f4569c','又和二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','外物攻伐人，鐘鼓作聲氣。',48,'全唐诗/poet.song.56000.json','["外物攻伐人，鐘鼓作聲氣。", "待渠弓箭盡，我自味無味。", "宴安衽席間，蛟鰐垂涎地。", "君子履微霜，即知堅冰至。"]'),
('8b619d4a-c814-416e-99d4-a1347ed17d10','又答斌老病愈遣悶二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','百痾從中來，悟罷本誰病。',48,'全唐诗/poet.song.56000.json','["百痾從中來，悟罷本誰病。", "西風將小雨，凉入居士徑。", "苦竹遶蓮塘，自悅魚鳥性。", "紅荷倚翠蓋，不點禪心靜。"]'),
('27dd6421-7550-4b29-a9e7-93470810ddfc','又答斌老病愈遣悶二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','風生高竹凉，雨送新荷氣。',48,'全唐诗/poet.song.56000.json','["風生高竹凉，雨送新荷氣。", "魚游悟世網，鳥語入禪味。", "一揮四百病，智刃有餘地。", "病來每厭客，今乃思客至。"]'),
('6b74761d-faa8-45e3-94f4-72a21c8c05a6','次韵黄斌老晚游池亭二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','路入東園無俗駕，忽逢佳士喜同遊。',64,'全唐诗/poet.song.56000.json','["路入東園無俗駕，忽逢佳士喜同遊。", "綠荷菡萏稍覺晚，黄菊拒霜殊未秋。", "客位正須懸榻下，主人自愛小塘幽。", "老夫多病蠻江上，頗憶平生馬少游。"]'),
('06e14f89-6082-41ec-9ea3-10c688de2700','次韵黄斌老晚游池亭二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','岑寂東園可散愁，膠膠擾擾夢神遊。',64,'全唐诗/poet.song.56000.json','["岑寂東園可散愁，膠膠擾擾夢神遊。", "萬竿苦竹旌旗卷，一部鳴蛙鼓吹休。", "雨後月前天欲冷，身閒心遠地常幽。", "杜門謝客恐生謗，且作人間鵬鷃游。"]'),
('7d18d885-b9e8-4cb8-9251-fe4f9942de6c','戲答史應之三首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','先生早擅屠龍學，袖有新硎不試刀。',32,'全唐诗/poet.song.56000.json','["先生早擅屠龍學，袖有新硎不試刀。", "歲晚亦無雞可割，庖蛙煎鱔薦松醪。"]'),
('1093ed0b-7b44-4611-bfba-81ec7a6d7a71','戲答史應之三首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','老萊有婦懷高義，不厭夫家苜蓿盤。',32,'全唐诗/poet.song.56000.json','["老萊有婦懷高義，不厭夫家苜蓿盤。", "收得千金不龜藥，短裙漂絖暮江寒。"]'),
('0c866b7c-89e2-4f2a-bf36-4b42c7e90f7f','戲答史應之三首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','甑有輕塵釜有魚，漢庭日日召嚴徐。',32,'全唐诗/poet.song.56000.json','["甑有輕塵釜有魚，漢庭日日召嚴徐。", "不嫌藜藿來同飯，更展芭蕉看學書。"]'),
('b2eb2acb-0f66-4624-9840-a44499042759','題也足軒','黄庭堅','宋','宋诗','song-poetry','','[]','道人手種兩三竹，使君忽來唾珠玉。',64,'全唐诗/poet.song.56000.json','["道人手種兩三竹，使君忽來唾珠玉。", "不須客賦千首詩，若是賞音一夔足。", "世人愛處但同流，一絲不掛似太俗。", "客來若問有何好，道人優曇遠山綠。"]'),
('a4ea9ffa-c3ce-49d8-9e75-469e61a5560d','寄題榮州祖元大師此君軒','黄庭堅','宋','宋诗','song-poetry','','[]','王師學琴三十年，響如清夜落澗泉。',160,'全唐诗/poet.song.56000.json','["王師學琴三十年，響如清夜落澗泉。", "滿堂洗盡箏琶耳，請師停手恐斷絃。", "神人傳書道人命，死生貴賤如看鏡。", "晚知直語觸憎嫌，深藏幽寺聽鐘磬。", "有酒如澠客滿門，不可一日無此君。", "當時手栽數寸碧，聲挾風雨今連雲。", "此君傾蓋如故舊，骨相奇怪清且秀。", "程嬰杵臼立孤難，伯夷叔齊采薇瘦。", "霜鐘堂上弄秋月，微風入絃此君悅。", "公家周彥筆如椽，此君語意當能傳。"]'),
('5976e794-c81f-4a63-ad65-7d89e6d22b6a','答李任道謝分豆粥','黄庭堅','宋','宋诗','song-poetry','','[]','豆粥能驅晚瘴寒，與公同味更同餐。',32,'全唐诗/poet.song.56000.json','["豆粥能驅晚瘴寒，與公同味更同餐。", "安知天上養賢鼎，且作山中煮菜看。"]'),
('73872109-bd09-4bb0-9e5a-e8d0dc659901','贈知命弟離戎州','黄庭堅','宋','宋诗','song-poetry','','[]','道人終歲學陶朱，西子同舟泛五湖。',32,'全唐诗/poet.song.56000.json','["道人終歲學陶朱，西子同舟泛五湖。", "船窗卧讀書萬卷，還有新詩來起予。"]'),
('d4621feb-d499-4969-8f4e-90457c5d7607','姪桘隨知命舟行','黄庭堅','宋','宋诗','song-poetry','','[]','莫去沙邊學釣魚，莫將百丈作轆轤。',32,'全唐诗/poet.song.56000.json','["莫去沙邊學釣魚，莫將百丈作轆轤。", "清江濯足窗下坐，燕子日長宜讀書。"]'),
('e8a21e4b-6a6a-4ac9-a488-a56435b40dc3','次韵奉答文少激推官紀贈二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','詩來清吹拂衣巾，句法詞鋒覺有神。',64,'全唐诗/poet.song.56000.json','["詩來清吹拂衣巾，句法詞鋒覺有神。", "今日相看青眼舊，他年肯作白頭新。", "文如霧豹容窺管，氣似靈犀可辟塵。", "慙愧相期在臺省，無心枯木豈能春。"]'),
('158c0670-1dc5-496b-9365-3c852d759e2d','次韵奉答文少激推官紀贈二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','文章藻鑑隨時去，人物權衡逐勢低。',64,'全唐诗/poet.song.56000.json','["文章藻鑑隨時去，人物權衡逐勢低。", "揚子墨池春草遍，武侯祠廟曉鶑啼。", "書帷寂寞知音少，幕府留連要路迷。", "顧我何人敢推輓，看君桃李合成蹊。"]'),
('3dc88ae2-2e7a-43c7-8428-9e2ae05694e6','次韵文少激祈雨有感','黄庭堅','宋','宋诗','song-poetry','','[]','窮儒憂樂與民同，何況朱輪職勸農。',64,'全唐诗/poet.song.56000.json','["窮儒憂樂與民同，何況朱輪職勸農。", "終日虀鹽供一飯，幾時膚寸冒千峰。", "未須丘垤占鳴鸛，只要朝廷起卧龍。", "從此滂沱徧枯槁，愛民天子似仁宗。"]'),
('ab65e343-fcc1-4a55-9d1a-5e734bf18cdd','次韵李任道晚飲鎖江亭','黄庭堅','宋','宋诗','song-poetry','','[]','西來雪浪如炰烹，兩涯一葦乃可橫。',64,'全唐诗/poet.song.56000.json','["西來雪浪如炰烹，兩涯一葦乃可橫。", "忽思鍾陵江十里，白蘋風起縠紋生。", "酒杯未覺浮蟻滑，茶鼎已作蒼蠅鳴。", "歸時共須落日盡，亦嫌持蓋僕屢更。"]'),
('01332856-ca7f-47d8-a29d-53f872dd9d6f','再次韵兼簡履中南玉三首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','李侯詩律嚴且清，諸生賡載筆縱橫。',64,'全唐诗/poet.song.56000.json','["李侯詩律嚴且清，諸生賡載筆縱橫。", "句中稍覺道戰勝，胸次不使俗塵生。", "山繞樓臺鐘鼓晚，江觸石磯碪杵鳴。", "鎖江主人能致酒，願渠久住莫終更。"]'),
('35eebc50-652d-4359-ad13-68bd5d0a6d83','再次韵兼簡履中南玉三首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','江津道人心源清，不繫虛舟盡日橫。',64,'全唐诗/poet.song.56000.json','["江津道人心源清，不繫虛舟盡日橫。", "道機禪觀轉萬物，文采風流被諸生。", "與世浮沈惟酒可，隨人憂樂以詩鳴。", "江頭一醉豈易得，事如浮雲多變更。"]'),
('09dfd9c8-8847-4906-b1f8-b7467b91ff4e','再次韵兼簡履中南玉三首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','鎖江亭上一樽酒，山自白雲江自橫。',64,'全唐诗/poet.song.56000.json','["鎖江亭上一樽酒，山自白雲江自橫。", "李侯短褐有長處，不與俗物同條生。", "經術貂蟬續狗尾，文章瓦釜作雷鳴。", "古來寒士但守節，夜夜抱關聽五更。"]'),
('bbbc5fe4-7fcb-430c-8fff-0fb6786a4cc0','次韵任道食荔支有感三首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','一錢不直程衛尉，萬事稱好司馬公。',32,'全唐诗/poet.song.56000.json','["一錢不直程衛尉，萬事稱好司馬公。", "白髮永無懷橘日，六年怊悵荔支紅。"]'),
('55c54147-cef2-4c07-9f76-294e821c5ce5','次韵任道食荔支有感三首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','今年荔子熟南風，莫愁留滯太史公。',32,'全唐诗/poet.song.56000.json','["今年荔子熟南風，莫愁留滯太史公。", "五月照江鴨頭綠，六月連山柘枝紅。"]'),
('50490348-1a09-4744-8dcf-66cbb3ec2e4d','次韵任道食荔支有感三首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','舞女荔支熟雖晚，臨江照影自惱公。',32,'全唐诗/poet.song.56000.json','["舞女荔支熟雖晚，臨江照影自惱公。", "天與蹙羅裝寶髻，更挼猩血染殷紅。"]'),
('bcaaebe8-b833-4e00-8232-b7cad3662f27','廖致平送綠荔支爲戎州第一王公權荔支綠酒亦爲戎州第一','黄庭堅','宋','宋诗','song-poetry','','[]','王公權家荔支綠，廖致平家綠荔支。',64,'全唐诗/poet.song.56000.json','["王公權家荔支綠，廖致平家綠荔支。", "試傾一杯重碧色，快剝千顆輕紅肌。", "撥醅蒲萄未足數，堆盤馬乳不同時。", "誰能同此勝絕味，唯有老杜東樓詩。"]'),
('d2106ecc-6bc1-4e9c-b4f1-6c65b3b4b0e9','謝楊履道送銀茄四首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','藜藿盤中生精神，珍蔬長蒂色勝銀。',32,'全唐诗/poet.song.56000.json','["藜藿盤中生精神，珍蔬長蒂色勝銀。", "朝來鹽醯飽滋味，已覺瓜瓠漫輪囷。"]'),
('66ed8449-efb2-4eca-92bd-268525e17a51','謝楊履道送銀茄四首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','君家水茄白銀色，殊勝埧裏紫彭亨。',32,'全唐诗/poet.song.56000.json','["君家水茄白銀色，殊勝埧裏紫彭亨。", "蜀人生疏不下箸，吾與北人俱眼明。"]'),
('761c54b7-2c65-4c44-8306-0a31acd95039','謝楊履道送銀茄四首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','白金作顆非椎成，中有萬粟嚼輕冰。',32,'全唐诗/poet.song.56000.json','["白金作顆非椎成，中有萬粟嚼輕冰。", "戎州夏畦少蔬供，感君來飯在家僧。"]'),
('86994858-4e5b-4bc1-8fb1-227240dd3977','謝楊履道送銀茄四首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','畦丁收盡垂露實，葉底猶藏十二三。',32,'全唐诗/poet.song.56000.json','["畦丁收盡垂露實，葉底猶藏十二三。", "待得銀包已成穀，更當乞種過江南。"]'),
('48b03195-e84d-454a-b5c2-fb7b8a7d1894','送石長卿太學秋補','黄庭堅','宋','宋诗','song-poetry','','[]','長卿家亦但四壁，文君窺之介如石。',64,'全唐诗/poet.song.56000.json','["長卿家亦但四壁，文君窺之介如石。", "胸中已無少年事，骨氣乃有老松格。", "漢文新覽天下圖，詔山采玉淵獻珠。", "再三可陳治安策，第一莫上登封書。"]'),
('be21ec0f-4c1c-4f23-90f4-c134d31ca97c','次韵少激甘露降太守居桃葉上','黄庭堅','宋','宋诗','song-poetry','','[]','金莖甘露薦齋房，潤及邊城草木香。',64,'全唐诗/poet.song.56000.json','["金莖甘露薦齋房，潤及邊城草木香。", "蕡實葉間天與味，成蹊枝上月翻光。", "羣心愛戴葵傾日，萬事驅除葉隕霜。", "玉燭時和君會否，舊臣重疊起南荒。"]'),
('91aa509c-c430-40c2-aca5-d5135f758d20','借景亭','黄庭堅','宋','宋诗','song-poetry','','[]','青神縣中得兩張，愛民財力惟恐傷。',64,'全唐诗/poet.song.56000.json','["青神縣中得兩張，愛民財力惟恐傷。", "二公身安民乃樂，勸葺城頭五月凉。", "竹鋪不涴吳綾襪，東西開軒蔭清樾。", "當官借景不傷民，恰似鑿池取明月。"]'),
('4c3e0663-708a-4753-8f27-797eb7e90f2e','戲贈家安國','黄庭堅','宋','宋诗','song-poetry','','[]','家侯口吃善著書，常願執戈王前驅。',64,'全唐诗/poet.song.56000.json','["家侯口吃善著書，常願執戈王前驅。", "朱紱蹉跎晚監郡，吟弄風月思天衢。", "二蘇平生親且舊，少年筆硯老杯酒。", "但使一氣轉洪鈞，此老矍鑠還冠軍。"]'),
('28ec4a96-0a73-491e-b7c8-2af08eedc9ab','次韵楊君全送酒','黄庭堅','宋','宋诗','song-poetry','','[]','扶衰却老世無方，惟有君家酒未嘗。',64,'全唐诗/poet.song.56000.json','["扶衰却老世無方，惟有君家酒未嘗。", "秋入園林花老眼，茗搜文字響枯腸。", "醡頭夜雨排簷滴，盃面春風繞鼻香。", "不待澄清遣分送，定知佳客對空觴。"]'),
('3d358ac2-eee4-4742-810e-9e805fa68cb3','次韵楊君全送春花','黄庭堅','宋','宋诗','song-poetry','','[]','化工能斡大鈞回，不得東君花不開。',32,'全唐诗/poet.song.56000.json','["化工能斡大鈞回，不得東君花不開。", "誰道纖纖綠窗手，磨刀剪綵喚春來。"]'),
('a2c23336-4c3e-4b53-8b68-f697df40e6d7','謝楊景山送酒器','黄庭堅','宋','宋诗','song-poetry','','[]','楊君喜我梨花盞，却念初無注酒魁。',32,'全唐诗/poet.song.56000.json','["楊君喜我梨花盞，却念初無注酒魁。", "矲矮金壺肯持送，挼莎殘菊更傳杯。"]'),
('9275cbef-97f1-4a83-b3a1-6c37fbdb9d58','史彥昇送春花','黄庭堅','宋','宋诗','song-poetry','','[]','千林摇落照秋空，忽散穠花在眼中。',32,'全唐诗/poet.song.56000.json','["千林摇落照秋空，忽散穠花在眼中。", "蝶繞蜂隨俱入座，君家女手化春風。"]'),
('f43fed47-ccfd-4870-9714-559e50d83ec0','題石恪畫嘗醋翁','黄庭堅','宋','宋诗','song-poetry','','[]','石媼忍酸喙三尺，石皤嘗味面百摺。',32,'全唐诗/poet.song.56000.json','["石媼忍酸喙三尺，石皤嘗味面百摺。", "誰知聳膊寒至骨，圖畫不減吳生筆。"]'),
('3db48f4a-1410-43b4-bf5c-15ae34768016','謝應之','黄庭堅','宋','宋诗','song-poetry','','[]','昨夜風雷震海隅，天心急擬活焦枯。',32,'全唐诗/poet.song.56000.json','["昨夜風雷震海隅，天心急擬活焦枯。", "去年席上蛟龍語，未委先生記得無。"]'),
('65415ed9-4c7a-463e-a436-acc78736e879','走筆謝王朴居士拄杖','黄庭堅','宋','宋诗','song-poetry','','[]','投我木瓜霜雪枝，六年流落放歸時。',32,'全唐诗/poet.song.56000.json','["投我木瓜霜雪枝，六年流落放歸時。", "千巖萬壑須重到，脚底危時幸見持。"]'),
('e67364cd-56db-4b2b-96c0-a67d4a0baca6','戲答王居士送文石','黄庭堅','宋','宋诗','song-poetry','','[]','南極一星天九秋，自埋光景落江流。',32,'全唐诗/poet.song.56000.json','["南極一星天九秋，自埋光景落江流。", "是公至樂山中物，乞與衰翁似暗投。"]'),
('dc59c0af-62c8-4b7b-8029-77aca82278d5','次韵楊明叔見餞十首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','平津善牧豕，佽飛能斬蛟。',48,'全唐诗/poet.song.56000.json','["平津善牧豕，佽飛能斬蛟。", "終藉一汲黯，淮南解兵交。", "楊子有直氣，未忍死草茅。", "引之入漢朝，誰爲續弦膠。"]'),
('5b3a1c67-2f19-4410-bc6a-613d8c4b3d56','次韵楊明叔見餞十首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','楊君清渭水，自流濁涇中。',48,'全唐诗/poet.song.56000.json','["楊君清渭水，自流濁涇中。", "今年貧到骨，豪氣似元龍。", "男兒生世間，筆端吐白虹。", "何事與秋螢，爭光蒲葦叢。"]'),
('4b8a0fa8-49fb-48a8-8530-08290103f88d','次韵楊明叔見餞十首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','事隨世滔滔，心欲自得得。',48,'全唐诗/poet.song.56000.json','["事隨世滔滔，心欲自得得。", "楊君爲己學，度越流輩百。", "坐捫故衣蝨，垢襪春汗黑。", "睥睨紈袴兒，可飲三斗墨。"]'),
('8be43845-ad50-423a-a59a-1291bb88aa21','次韵楊明叔見餞十首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','清靜草玄學，西京有子雲。',48,'全唐诗/poet.song.56000.json','["清靜草玄學，西京有子雲。", "太尉死宗社，大鳥泣其墳。", "寂寞向千載，風流被仍昆。", "富貴何足道，聖處要策勳。"]'),
('3e8296e0-e37a-434c-bac8-7b95fe5cc8a2','次韵楊明叔見餞十首  其五','黄庭堅','宋','宋诗','song-poetry','','[]','桑輿金石交，既別十日雨。',48,'全唐诗/poet.song.56000.json','["桑輿金石交，既別十日雨。", "子輿裹飯來，一笑相告語。", "楊子困簞瓢，諸公不能舉。", "儻可從我歸，沙頭駐鳴艣。"]'),
('e4ac6938-78be-4a15-afd8-ad19edb04d8c','次韵楊明叔見餞十首  其六','黄庭堅','宋','宋诗','song-poetry','','[]','山圍少天日，狐鬼能作妖。',48,'全唐诗/poet.song.56000.json','["山圍少天日，狐鬼能作妖。", "睒閃載一車，獵人用鳴梟。", "小智窘流俗，蹇淺不能超。", "安得萬里沙，晴天看射鵰。"]'),
('c84183a9-d694-4522-95af-997d47e041fc','次韵楊明叔見餞十首  其七','黄庭堅','宋','宋诗','song-poetry','','[]','元之如砥柱，大年若霜鶚。',48,'全唐诗/poet.song.56000.json','["元之如砥柱，大年若霜鶚。", "王楊立本朝，與世作郛郭。", "觀公有膽氣，自可繼前作。", "丈夫存遠大，胸次要落落。"]'),
('413de090-bfbf-4b32-b70f-c6f109ba2958','次韵楊明叔見餞十首  其八','黄庭堅','宋','宋诗','song-poetry','','[]','虛心觀萬物，險易極變態。',48,'全唐诗/poet.song.56000.json','["虛心觀萬物，險易極變態。", "皮毛剝落盡，惟有真實在。", "侍中乃珥貂，御史則冠豸。", "照影或可羞，短蓑釣寒瀨。"]'),
('58ec9cd4-734d-4e43-8a71-2adf78446115','次韵楊明叔見餞十首  其九','黄庭堅','宋','宋诗','song-poetry','','[]','松柏生澗壑，坐閱草木秋。',48,'全唐诗/poet.song.56000.json','["松柏生澗壑，坐閱草木秋。", "金石在波中，仰看萬物流。", "抗髒自抗髒，伊優自伊優。", "但觀百歲後，傳者非公侯。"]'),
('6a252bd9-c81b-4071-9c15-dc4afdc13a5c','次韵楊明叔見餞十首  其一○','黄庭堅','宋','宋诗','song-poetry','','[]','老作同安守，蹇足信所便。',48,'全唐诗/poet.song.56000.json','["老作同安守，蹇足信所便。", "胸中無水鏡，敢當吏部銓。", "恨此虛名在，未脫世糾纏。", "夢作白鷗去，江南水如天。"]'),
('776cd3be-eac2-4327-8ea2-4846cb644e86','次韵石七三六言七首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','從來不似一物，妄欲貫穿九流。',28,'全唐诗/poet.song.56000.json','["從來不似一物，妄欲貫穿九流。", "骨硬非黄閤相，眼青見白蘋洲。"]'),
('2b7b0084-0d5e-4cd0-ab42-d015624c196e','次韵石七三六言七首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','生涯一九節筇，老境五十六翁。',28,'全唐诗/poet.song.56000.json','["生涯一九節筇，老境五十六翁。", "不堪上補黼黻，但可歸教兒童。"]'),
('666542f5-6d21-4924-b667-6f3f0b449ad9','次韵石七三六言七首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','萬里草荒先壟，六年蟲蠹羣經。',28,'全唐诗/poet.song.56000.json','["萬里草荒先壟，六年蟲蠹羣經。", "老喜寬恩放去，心似驚波不停。"]'),
('924274bb-6ae1-4e36-aa14-3cf447c91263','次韵石七三六言七首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','爲君試講古學，此事可牋天公。',28,'全唐诗/poet.song.56000.json','["爲君試講古學，此事可牋天公。", "君看花梢朝露，何如松上霜風。"]'),
('85238925-5aaa-4196-b765-30fefc5fb83f','次韵石七三六言七首  其五','黄庭堅','宋','宋诗','song-poetry','','[]','幽州已投斧柯，崇山更用憂何。',28,'全唐诗/poet.song.56000.json','["幽州已投斧柯，崇山更用憂何。", "且喜龔鄒冠豸，又聞張董上坡。"]'),
('237ea866-88d2-4580-bdd5-f743585927af','次韵石七三六言七首  其六','黄庭堅','宋','宋诗','song-poetry','','[]','看著莊周枯槁，化爲胡蝶翾輕。',28,'全唐诗/poet.song.56000.json','["看著莊周枯槁，化爲胡蝶翾輕。", "人見穿花入柳，誰知有體無情。"]'),
('4ad9fd92-f506-4523-b89d-f5e828a5181c','次韵石七三六言七首  其七','黄庭堅','宋','宋诗','song-poetry','','[]','欲行水遶山圍，但聞鯤化鵬飛。',28,'全唐诗/poet.song.56000.json','["欲行水遶山圍，但聞鯤化鵬飛。", "女憂鬢髮盡白，兄歎江船未歸。"]'),
('416f5ab3-d3bd-4723-b174-e1ec5b914b4a','萬州太守高仲本宿約遊岑公洞而夜雨連明戲作二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','肩輿欲到岑公洞，正怯衝泥傍險行。',32,'全唐诗/poet.song.56000.json','["肩輿欲到岑公洞，正怯衝泥傍險行。", "定是岑公閟清境，春江一夜雨連明。"]'),
('9af00b9d-a438-4434-8c96-4b2be4fb338f','萬州太守高仲本宿約遊岑公洞而夜雨連明戲作二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','蓬窗高卧雨如繩，恰似糟牀壓酒聲。',32,'全唐诗/poet.song.56000.json','["蓬窗高卧雨如繩，恰似糟牀壓酒聲。", "今日岑公不能飲，吾儕聞健且頻傾。"]'),
('d5fd3dce-cb18-4c55-b5bf-cac098daf819','萬州下巖二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','空巖靜發鐘磬響，古木倒掛藤蘿昏。',32,'全唐诗/poet.song.56000.json','["空巖靜發鐘磬響，古木倒掛藤蘿昏。", "莫道蒼崖鎖靈骨，時應持鉢到諸村。"]'),
('d79e981c-a92c-4214-90d9-742c725bffd3','萬州下巖二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','寺古松楠老，巖虛塔廟開。',48,'全唐诗/poet.song.56000.json','["寺古松楠老，巖虛塔廟開。", "僧緣蠶麥去，官數荔支來。", "石室無心骨，金鋪稱意苔。", "若爲劉道者，拽得鼻頭迴。"]'),
('d40e126d-0b0c-4518-8a28-fad5729429c2','又戲題下巖','黄庭堅','宋','宋诗','song-poetry','','[]','往往携家來託宿，裙襦參錯佛衣巾。',32,'全唐诗/poet.song.56000.json','["往往携家來託宿，裙襦參錯佛衣巾。", "未嫌滿院油頭臭，蹋破苔錢最惱人。"]'),
('9cfedb97-7867-4038-888f-16c9bb4d6c7e','戲題巫山縣用杜子美韵','黄庭堅','宋','宋诗','song-poetry','','[]','巴俗深留客，吳儂但憶歸。',48,'全唐诗/poet.song.56000.json','["巴俗深留客，吳儂但憶歸。", "直知難共語，不是故相違。", "東縣聞銅臭，江陵換袷衣。", "丁寧巫峽雨，慎莫暗朝暉。"]'),
('59cc5e19-a345-4feb-b69e-22caaa9ab8b8','和王觀復洪駒父謁陳無己長句','黄庭堅','宋','宋诗','song-poetry','','[]','陳君今古焉不學，清渭無心映涇濁。',128,'全唐诗/poet.song.56000.json','["陳君今古焉不學，清渭無心映涇濁。", "漢官舊儀重九鼎，集賢學士見一角。", "王侯文采似於菟，洪甥人間汗血駒。", "相將問道城南隅，無屋正借船官居。", "有書萬卷繞四壁，樵蘇不爨談至夕。", "主人自是文章伯，鄰里頗怪有此客。", "食貧各仕天一方，佳人可思不可忘。", "河從天來砥柱立，愛莫助之涕淋浪。"]'),
('d43308bc-b7fa-46cc-a4ba-9514aa27dd3f','以古銅壺送王觀復','黄庭堅','宋','宋诗','song-poetry','','[]','隨俗易汩沒，從公常糾紛。',72,'全唐诗/poet.song.56000.json','["隨俗易汩沒，從公常糾紛。", "我觀王隆化，入蕕不改薰。", "未見蛇起陸，已看豹成文。", "愛君古人風，古壺投贈君。", "酌酒時在傍，可用弭楚氛。", "問君何以報，直諒與多聞。"]'),
('4f875c6c-5c54-4b49-99a5-a12782e17e5d','病起荆江亭即事十首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','翰墨場中老伏波，菩提坊裏病維摩。',32,'全唐诗/poet.song.56000.json','["翰墨場中老伏波，菩提坊裏病維摩。", "近人積水無鷗鷺，時有歸牛浮鼻過。"]'),
('15f0776e-74ae-4708-90e5-1afd29ce1210','病起荆江亭即事十首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','維摩老子五十七，大聖天子初元年。',32,'全唐诗/poet.song.56000.json','["維摩老子五十七，大聖天子初元年。", "傳聞有意用幽側，病著不能朝日邊。"]'),
('18d6c9e2-842a-4e2f-ba7e-fd304fb14e8d','病起荆江亭即事十首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','禁中夜半定天下，仁風義氣徹脩門。',32,'全唐诗/poet.song.56000.json','["禁中夜半定天下，仁風義氣徹脩門。", "十分整頓乾坤了，復辟歸來道更尊。"]'),
('86689274-d400-4895-b96f-7162821f661b','病起荆江亭即事十首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','成王小心似文武，周召何妨略不同。',32,'全唐诗/poet.song.56000.json','["成王小心似文武，周召何妨略不同。", "不須要出我門下，實用人材即至公。"]'),
('a98bd1d9-471b-4960-95b0-3f953c52c2e4','病起荆江亭即事十首  其五','黄庭堅','宋','宋诗','song-poetry','','[]','司馬丞相昔登庸，詔用元老超羣公。',32,'全唐诗/poet.song.56000.json','["司馬丞相昔登庸，詔用元老超羣公。", "楊綰當朝天下喜，斷碑零落卧秋風。"]'),
('17a12850-590d-4add-a9cb-ead44b7e3cfe','病起荆江亭即事十首  其六','黄庭堅','宋','宋诗','song-poetry','','[]','死者已死黄霧中，三事不數兩蘇公。',32,'全唐诗/poet.song.56000.json','["死者已死黄霧中，三事不數兩蘇公。", "豈謂高才難駕御，空歸萬里白頭翁。"]'),
('c5569368-e65f-4ce7-bb66-c882b6c586b0','病起荆江亭即事十首  其七','黄庭堅','宋','宋诗','song-poetry','','[]','文章韓杜無遺恨，草詔陸贄傾諸公。',32,'全唐诗/poet.song.56000.json','["文章韓杜無遺恨，草詔陸贄傾諸公。", "玉堂端要真學士，須得儋州禿鬢翁。"]'),
('91a4c00d-5897-4727-9615-fe5362c46415','病起荆江亭即事十首  其八','黄庭堅','宋','宋诗','song-poetry','','[]','閉門覓句陳無己，對客揮毫秦少游。',32,'全唐诗/poet.song.56000.json','["閉門覓句陳無己，對客揮毫秦少游。", "正字不知溫飽未，西風吹淚古藤州。"]'),
('f364a204-d9b4-429d-8770-278e5892eda9','病起荆江亭即事十首  其九','黄庭堅','宋','宋诗','song-poetry','','[]','張子耽酒語蹇吃，聞道潁州又陳州。',32,'全唐诗/poet.song.56000.json','["張子耽酒語蹇吃，聞道潁州又陳州。", "形模彌勒一布袋，文字江河萬古流。"]'),
('6c2b3c00-1feb-4195-bd04-c88a2f7dedd5','病起荆江亭即事十首  其一○','黄庭堅','宋','宋诗','song-poetry','','[]','魯中狂士邢尚書，本意扶日上天衢。',32,'全唐诗/poet.song.56000.json','["魯中狂士邢尚書，本意扶日上天衢。", "惇夫若在鑴此老，不令平地生崎嶇。"]'),
('c56497fb-2c3f-4882-b95e-ae6e30edecdf','鄒松滋寄苦竹泉橙麴蓮子湯三首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','松滋縣西竹林寺，苦竹林中甘井泉。',32,'全唐诗/poet.song.56000.json','["松滋縣西竹林寺，苦竹林中甘井泉。", "巴人漫說蝦蟆培，試裹春芽來就煎。"]'),
('dcdc406b-055d-41c0-a6de-35d7c678163d','鄒松滋寄苦竹泉橙麴蓮子湯三首  其二','黄庭堅','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','天將金闕真黄色，借與洞庭霜後橙。',32,'全唐诗/poet.song.56000.json','["天將金闕真黄色，借與洞庭霜後橙。", "松滋解作逡巡麴，壓倒江南好事僧。"]'),
('7cd93443-2e77-4202-bf92-49eec6f85199','鄒松滋寄苦竹泉橙麴蓮子湯三首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','新收千百秋蓮菂，剝盡紅衣搗玉霜。',32,'全唐诗/poet.song.56000.json','["新收千百秋蓮菂，剝盡紅衣搗玉霜。", "不假參同成氣味，跳珠椀裏綠荷香。"]'),
('309beed7-6699-4bd1-a496-34ef02ec50a9','次韵答黄與迪','黄庭堅','宋','宋诗','song-poetry','','[]','和氏有尺璧，楚國無人知。',240,'全唐诗/poet.song.56000.json','["和氏有尺璧，楚國無人知。", "青山抱國器，歲月忽如遺。", "但使玉非石，果有遭逢時。", "吾宗固神秀，天乃晚成之。", "蘭芳深九畹，露味挹三危。", "流俗不顧省，古人可前追。", "胸中凌雲賦，自貴知音希。", "淵源學未淺，孝友家正肥。", "與世殊軌轍，三黜理亦宜。", "吳溪浣紗女，不用朱粉施。", "豈伊風塵子，市門自夸毗。", "我作僰道囚，三年始放歸。", "邂逅終日語，貽我五字詩。", "句如秋雨晴，遠峰抹脩眉。", "老馬甘伏櫪，坐看天驥馳。", "灑掃清樾下，當爲果茗期。", "光陰去易失，日月轉兩儀。", "仲氏有東園，花竹深可依。", "寸步不往來，千里常夢思。", "幾時開後戶，扶策方自茲。"]'),
('03cd6cb1-b2c8-401d-9a41-1321e7340031','次前韵謝與迪惠所作竹五幅','黄庭堅','宋','宋诗','song-poetry','','[]','吾宗墨脩竹，心手不自知。',240,'全唐诗/poet.song.56000.json','["吾宗墨脩竹，心手不自知。", "天公造化爐，攬取如拾遺。", "風雪煙霧雨，榮悴各一時。", "此物抱晚節，君又潤色之。", "抽萌或發石，懸箠有阽危。", "林梢一片雨，造次以筆追。", "猛吹萬籟作，微凉大音希。", "霜兔束毫健，松煙泛硯肥。", "盤桓未落筆，落筆必中宜。", "今代捧心學，取笑如東施。", "或可遺巾幗，選耎如辛毗。", "生枝不應節，亂葉無所歸。", "非君一起予，衰病豈能詩。", "憶君初解鞍，新月挂彎眉。", "夜來上金鏡，坐歎光景馳。", "我有好東絹，晴明要會期。", "猗猗淇園姿，此君有威儀。", "願作數百竿，水石相因依。", "他年風動璧，洗我別後思。", "開圖慰滿眼，何時遂臻茲。"]'),
('a3f2cb69-369b-4028-bc8a-2d4af2771eec','戲簡朱公武劉邦直田子平五首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','不趨吏部曹中版，且鱠高沙湖裏魚。',32,'全唐诗/poet.song.56000.json','["不趨吏部曹中版，且鱠高沙湖裏魚。", "雖無季子六國印，要讀田郎萬卷書。"]'),
('cf24ec30-050a-4988-9400-bc9aa88a441c','戲簡朱公武劉邦直田子平五首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','歡伯可解藜藿嘲，孔方定非金石交。',32,'全唐诗/poet.song.56000.json','["歡伯可解藜藿嘲，孔方定非金石交。", "君看劉郎最多智，昨者火事幾焚巢。"]'),
('0475d352-4002-407b-8f0b-110ad6398550','戲簡朱公武劉邦直田子平五首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','劉郎好詩又能文，方我奔竄義甚敦。',32,'全唐诗/poet.song.56000.json','["劉郎好詩又能文，方我奔竄義甚敦。", "爲親未葬走人門，閉門却掃不足論。"]'),
('d30b2c9c-34ee-4ac4-84de-5279f6fe0789','戲簡朱公武劉邦直田子平五首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','朱家塤篪好兄弟，陋巷六經葵莧秋。',32,'全唐诗/poet.song.56000.json','["朱家塤篪好兄弟，陋巷六經葵莧秋。", "我卜荆州三畝宅，讀田家書從之游。"]'),
('034e3f26-67c9-4c27-8492-9a62bbaea71f','戲簡朱公武劉邦直田子平五首  其五','黄庭堅','宋','宋诗','song-poetry','','[]','朱公趨朝瘦至骨，歸來豪健踞胡牀。',32,'全唐诗/poet.song.56000.json','["朱公趨朝瘦至骨，歸來豪健踞胡牀。", "日看省曹閽者面，何如田家侍兒妝。"]'),
('1ceaf9ff-cf53-4807-ae69-b2f871220bc2','次韵益修四弟','黄庭堅','宋','宋诗','song-poetry','','[]','霜晚菊未花，節物亦可嘉。',60,'全唐诗/poet.song.56000.json','["霜晚菊未花，節物亦可嘉。", "欣欣登高侶，畏雨占暮霞。", "楚人醖菉豆，輕碧自相誇。", "老夫不舉酒，嚥嗽鳴兩車。", "良辰與美景，客至但成嗟。"]'),
('6c173d01-7aef-47ad-ac7d-81fc6992d217','以峽州酒遺益修復繼前韵','黄庭堅','宋','宋诗','song-poetry','','[]','令節不把酒，新詩徒拜嘉。',60,'全唐诗/poet.song.56000.json','["令節不把酒，新詩徒拜嘉。", "頗憶宋玉賦，登高氣成霞。", "渚宮但衰柳，朝雲爲誰誇。", "吾宗懷古恨，流涎過麴車。", "一壺澆往事，聊送解愁嗟。"]'),
('07b4d1b7-57e8-4f7e-9488-9a51746d1544','謝益修四弟送石屏','黄庭堅','宋','宋诗','song-poetry','','[]','石似江滄落日明，鸕鷀烏鵲滿沙汀。',32,'全唐诗/poet.song.56000.json','["石似江滄落日明，鸕鷀烏鵲滿沙汀。", "小兒骨相能文字，乞與班班作硯屏。"]'),
('372b6e9e-62bf-4f05-b836-d535c22fe077','戲答王觀復酴醾菊二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','誰將陶令黄金菊，幻作酴醾白玉花。',32,'全唐诗/poet.song.56000.json','["誰將陶令黄金菊，幻作酴醾白玉花。", "小草真成有風味，東園添我老生涯。"]'),
('64902f60-8b10-43a8-9884-ad3baa37b02b','戲答王觀復酴醾菊二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','呂園未肯輕沽我，且寄田家砌下栽。',32,'全唐诗/poet.song.56000.json','["呂園未肯輕沽我，且寄田家砌下栽。", "他日秋花媚重九，清香知自故人來。"]'),
('612068e2-0135-452a-81cc-5f7f93ad5676','戲答王子予送凌風菊二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','病來孤負鸕鷀杓，禪板蒲團入眼中。',32,'全唐诗/poet.song.56000.json','["病來孤負鸕鷀杓，禪板蒲團入眼中。", "浪說閒居愛重九，黄花應笑白頭翁。"]'),
('b8e5086f-3528-4798-9754-bbe1957aab24','戲答王子予送凌風菊二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','王郎頗病金瓢酒，不耐寒花晚更芳。',32,'全唐诗/poet.song.56000.json','["王郎頗病金瓢酒，不耐寒花晚更芳。", "瘦盡腰圍怯風景，故來歸我一枝香。"]'),
('d80fa3b3-fd30-4073-ad1c-8ecffb589c09','謝王子予送橄欖','黄庭堅','宋','宋诗','song-poetry','','[]','方懷味諫軒中果，忽見金盤橄欖來。',32,'全唐诗/poet.song.56000.json','["方懷味諫軒中果，忽見金盤橄欖來。", "想共餘甘有瓜葛，苦中真味晚方回。"]'),
('ce6a5a5a-d494-45cc-a6e5-a7afa5ee1e89','以椰子小冠送子予','黄庭堅','宋','宋诗','song-poetry','','[]','漿成乳酒醺人醉，肉截鵝肪上客盤。',32,'全唐诗/poet.song.56000.json','["漿成乳酒醺人醉，肉截鵝肪上客盤。", "有核如匏可彫琢，道裝宜作玉人冠。"]'),
('057e0e54-1e45-4c50-aca8-197668929816','呈楊康國','黄庭堅','宋','宋诗','song-poetry','','[]','君家秋實羅浮種，已作纍纍半拂牆。',32,'全唐诗/poet.song.56000.json','["君家秋實羅浮種，已作纍纍半拂牆。", "莫遣兒童酸打盡，要看霜後十分黄。"]'),
('707c93b0-b4cc-49de-b994-3b69e18e6269','又戲呈康國','黄庭堅','宋','宋诗','song-poetry','','[]','整冠行客莫先嘗，楊子家無數仞牆。',32,'全唐诗/poet.song.56000.json','["整冠行客莫先嘗，楊子家無數仞牆。", "假借肅霜令弄色，勾添寒日與爭黄。"]'),
('7b52e123-9eb7-4644-8e04-6ed27a1c8009','次韵馬荆州','黄庭堅','宋','宋诗','song-poetry','','[]','六年絕域夢刀頭，判得南還萬事休。',64,'全唐诗/poet.song.56000.json','["六年絕域夢刀頭，判得南還萬事休。", "誰謂石渠劉校尉，來依絳帳馬荆州。", "霜髭雪鬢共看鏡，茱糝菊英同送秋。", "他日江梅臘前破，還從天際望歸舟。"]'),
('626f824a-aa29-4957-ad41-aff44c2c8076','和中玉使君晚秋開天寧節道場','黄庭堅','宋','宋诗','song-poetry','','[]','江南江北盡雲沙，車騎東來風旆斜。',64,'全唐诗/poet.song.56000.json','["江南江北盡雲沙，車騎東來風旆斜。", "倒影樓臺開紫府，得霜籬落賸黄花。", "釣溪築野收多士，航海梯山共一家。", "想見星壇祝堯壽，步虛聲裏靜無譁。"]'),
('afa8e61d-5b73-48d7-87e2-db8a561a83da','入窮巷謁李材叟翹叟戲贈兼簡田子平三首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','紫冠黄鈿網絲窠，蝶繞蜂圍奈晚何。',32,'全唐诗/poet.song.56000.json','["紫冠黄鈿網絲窠，蝶繞蜂圍奈晚何。", "二叟家居如避世，開門自少俗人過。"]'),
('beeddcba-0ead-4406-ad19-e16c967d999b','入窮巷謁李材叟翹叟戲贈兼簡田子平三首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','只可闋中安止止，誰能鐵裏鬭錚錚。',32,'全唐诗/poet.song.56000.json','["只可闋中安止止，誰能鐵裏鬭錚錚。", "田多穀少無人會，譬似無田過一生。"]'),
('03054b84-4533-4acc-8d02-58becce7a732','入窮巷謁李材叟翹叟戲贈兼簡田子平三首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','田郎杞菊荒三徑，文字時追二叟游。',32,'全唐诗/poet.song.56000.json','["田郎杞菊荒三徑，文字時追二叟游。", "萬卷藏書多未見，老夫端擬乞荆州。"]'),
('32ea444d-f53b-4114-9677-4ea186e96aef','次韵答馬中玉三首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','雨入紗窗風簸船，菊花過後早梅前。',32,'全唐诗/poet.song.56000.json','["雨入紗窗風簸船，菊花過後早梅前。", "錦江春色熏人醉，也到壺中小隠天。"]'),
('0b9ee957-cae7-4c18-a7b7-ec7c5f881b0f','次韵答馬中玉三首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','卷沙成浪北風顛，銜尾千艘不敢前。',32,'全唐诗/poet.song.56000.json','["卷沙成浪北風顛，銜尾千艘不敢前。", "匝岸水居皆有酒，行人得意買江天。"]'),
('59d90176-b03d-4b97-b93b-9c2d6d2193d7','次韵答馬中玉三首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','仁氣已蒸全楚盡，同雲欲合暮江前。',32,'全唐诗/poet.song.56000.json','["仁氣已蒸全楚盡，同雲欲合暮江前。", "爭春梅柳無三月，對雪樽罍屬二天。"]'),
('8f742d4a-28c8-4ce4-8588-e573e0d11cd7','次韵中玉早梅二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','梅蘂爭先公不嗔，知公家有似梅人。',32,'全唐诗/poet.song.56000.json','["梅蘂爭先公不嗔，知公家有似梅人。", "何時各得自由去，相逐揚州作好春。"]'),
('ea4482dc-f109-47a2-a2d0-82f6429abe17','次韵中玉早梅二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','折得寒香不露機，小窗斜日兩三枝。',32,'全唐诗/poet.song.56000.json','["折得寒香不露機，小窗斜日兩三枝。", "羅帷翠幕深調護，已被遊蜂聖得知。"]'),
('3e5ee255-68a6-42a1-91ef-9a0894fab48f','次韵中玉水仙花二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','借水開花自一奇，水沈爲骨玉爲肌。',32,'全唐诗/poet.song.56000.json','["借水開花自一奇，水沈爲骨玉爲肌。", "暗香已壓酴醾倒，只比寒梅無好枝。"]'),
('6cd47342-cde1-4ce0-80bc-fa5bf0615772','次韵中玉水仙花二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','淤泥解作白蓮藕，糞壤能開黄玉花。',32,'全唐诗/poet.song.56000.json','["淤泥解作白蓮藕，糞壤能開黄玉花。", "可惜國香天不管，隨緣流落小民家。"]'),
('5d7612fa-4144-46f8-8ca4-627b344e08c9','王充道送水仙花五十枝欣然會心爲之作詠','黄庭堅','宋','宋诗','song-poetry','','["\u548f\u7269\u8bd7", "\u82b1", "\u548f\u7269", "\u5199\u82b1"]','凌波仙子生塵襪，水上輕盈步微月。',64,'全唐诗/poet.song.56000.json','["凌波仙子生塵襪，水上輕盈步微月。", "是誰招此斷腸魂，種作寒花寄愁絕。", "含香體素欲傾城，山礬是弟梅是兄。", "坐對真成被花惱，出門一笑大江橫。"]'),
('ce9d48f0-e3b2-48c6-bc0c-e037c68358ba','吳君送水仙花并二大本','黄庭堅','宋','宋诗','song-poetry','','[]','折送南園栗玉花，并移香本到寒家。',32,'全唐诗/poet.song.56000.json','["折送南園栗玉花，并移香本到寒家。", "何時持上玉宸殿，乞與宮梅定等差。"]'),
('cf62017c-ec71-4a03-bfed-0d7507bd1766','劉邦直送早梅水仙花四首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','簸船綪纜北風嗔，霜落千林憔悴人。',32,'全唐诗/poet.song.56000.json','["簸船綪纜北風嗔，霜落千林憔悴人。", "欲問江南近消息，喜君貽我一枝春。"]'),
('98cc6575-8e26-4473-b878-dd82e3c86493','劉邦直送早梅水仙花四首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','探請東皇第一機，水邊風日笑橫枝。',32,'全唐诗/poet.song.56000.json','["探請東皇第一機，水邊風日笑橫枝。", "鴛鴦浮弄嬋娟影，白鷺窺魚凝不知。"]'),
('06a7e263-5f9e-4ec6-8868-f3a3b283be2d','劉邦直送早梅水仙花四首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','得水能仙天與奇，寒香寂寞動冰肌。',32,'全唐诗/poet.song.56000.json','["得水能仙天與奇，寒香寂寞動冰肌。", "仙風道骨今誰有，淡掃蛾眉簪一枝。"]'),
('4f105124-990b-41ed-85e2-0871ccdb44d1','劉邦直送早梅水仙花四首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','錢塘昔聞水仙廟，荆州今見水仙花。',32,'全唐诗/poet.song.56000.json','["錢塘昔聞水仙廟，荆州今見水仙花。", "暗香靜色撩詩句，宜在林逋處士家。"]'),
('768bbae7-4521-4ada-84d1-af234ee1db38','謝檀敦信送柑子','黄庭堅','宋','宋诗','song-poetry','','[]','色深林表風霜下，香著尊前指爪間。',32,'全唐诗/poet.song.56000.json','["色深林表風霜下，香著尊前指爪間。", "書後合題三百顆，頻隨驛使未應慳。"]'),
('261a23a0-0e46-4d55-8a29-1c81738809d5','贈李輔聖','黄庭堅','宋','宋诗','song-poetry','','[]','交蓋相逢水急流，八年今復會荆州。',64,'全唐诗/poet.song.56000.json','["交蓋相逢水急流，八年今復會荆州。", "已回青眼追鴻翼，肯使黄塵沒馬頭。", "舊管新收幾妝鏡，流行坎止一虛舟。", "相看絕歎女博士，筆研管絃成古丘。"]'),
('229f7efe-527d-4e1f-94ee-e72ee6a75420','和高仲本喜相見','黄庭堅','宋','宋诗','song-poetry','','[]','雨昏南浦曾相對，雪滿荆州喜再逢。',64,'全唐诗/poet.song.56000.json','["雨昏南浦曾相對，雪滿荆州喜再逢。", "有子才如不羈馬，知君心是後凋松。", "閒尋書冊應多味，老傍人門似更慵。", "何日晴軒觀筆硯，一樽相屬要從容。"]'),
('921b53c5-c5f7-4098-bbec-31a31ed1b5dc','戲詠煖足瓶二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','小姬煖足卧，或能起心兵。',24,'全唐诗/poet.song.56000.json','["小姬煖足卧，或能起心兵。", "千金買脚婆，夜夜睡天明。"]'),
('ee6c55d3-bb57-459d-b136-e268b6c7c6cd','戲詠煖足瓶二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','脚婆原不食，纏裹一衲足。',24,'全唐诗/poet.song.56000.json','["脚婆原不食，纏裹一衲足。", "天明更傾瀉，頮面有餘燠。"]'),
('987250d5-145f-4a18-ad05-8e5384df092e','戲呈聞善二兄','黄庭堅','宋','宋诗','song-poetry','','[]','匏懸籬落鴉窺井，草上階除雪衮風。',32,'全唐诗/poet.song.56000.json','["匏懸籬落鴉窺井，草上階除雪衮風。", "想得尊前欹醉帽，渾家兒女笑山公。"]'),
('06833e91-67be-496f-aea1-8eacf7f64841','次韵聞善','黄庭堅','宋','宋诗','song-poetry','','[]','扶醉三竿日，題詩一研埃。',48,'全唐诗/poet.song.56000.json','["扶醉三竿日，題詩一研埃。", "張羅門带雪，投轄井生苔。", "待得成丘隴，誰能把酒盃。", "常應黄菊畔，悵望白衣來。"]'),
('32edaa79-9818-47f8-acdd-23bea202b1b0','謝答聞善二兄九絕句  其一','黄庭堅','宋','宋诗','song-poetry','','[]','身入醉鄉無畔岸，心與歡伯爲友朋。',32,'全唐诗/poet.song.56000.json','["身入醉鄉無畔岸，心與歡伯爲友朋。", "更闌駡坐客星散，午過未蘇髮鬅鬙。"]'),
('886658d7-f52f-4393-8973-fa1e19a39d06','謝答聞善二兄九絕句  其二','黄庭堅','宋','宋诗','song-poetry','','[]','未嘗頃刻可去酒，無有一日不吟詩。',32,'全唐诗/poet.song.56000.json','["未嘗頃刻可去酒，無有一日不吟詩。", "詩狂克念作酒聖，意態忽如少年時。"]'),
('9dfd8cf5-c903-4857-853e-c4ce3cf77bbc','謝答聞善二兄九絕句  其三','黄庭堅','宋','宋诗','song-poetry','','[]','羣豬過飲尚可醉，疥手轑甕庸何傷。',32,'全唐诗/poet.song.56000.json','["羣豬過飲尚可醉，疥手轑甕庸何傷。", "柳家兄弟太迫窄，狂藥不容人發狂。"]'),
('56aa310a-b3ac-4a26-bfcc-4dfc4055a773','謝答聞善二兄九絕句  其四','黄庭堅','宋','宋诗','song-poetry','','[]','莫作叫號驚四鄰，甕中有地可藏真。',32,'全唐诗/poet.song.56000.json','["莫作叫號驚四鄰，甕中有地可藏真。", "淵明醉握遠公手，大笑絕倒人不嗔。"]'),
('1af1ebbb-5571-4a00-bc1b-0e1f028065e3','謝答聞善二兄九絕句  其五','黄庭堅','宋','宋诗','song-poetry','','[]','阮籍醉睡不論昏，劉伶雞肋避尊拳。',32,'全唐诗/poet.song.56000.json','["阮籍醉睡不論昏，劉伶雞肋避尊拳。", "至今凜凜有生氣，飲酒真成不愧天。"]'),
('fa16508c-8650-4951-b4ec-f4a0bb5f9cc8','謝答聞善二兄九絕句  其六','黄庭堅','宋','宋诗','song-poetry','','[]','公擇醉面桃花紅，人百忤之無慍容。',32,'全唐诗/poet.song.56000.json','["公擇醉面桃花紅，人百忤之無慍容。", "莘老夜闌傾數斗，焚香默坐日生東。"]'),
('f2edc533-92ac-47a1-9b93-9a2c45c9e3ed','謝答聞善二兄九絕句  其七','黄庭堅','宋','宋诗','song-poetry','','[]','椎牀破面棖觸人，作無義語怒四鄰。',32,'全唐诗/poet.song.56000.json','["椎牀破面棖觸人，作無義語怒四鄰。", "尊中歡伯笑爾輩，我本和氣如三春。"]'),
('8c050469-7977-40ed-ac0e-8e5367c61a7a','謝答聞善二兄九絕句  其八','黄庭堅','宋','宋诗','song-poetry','','[]','陶令舍中有名酒，無日不爲父老傾。',32,'全唐诗/poet.song.56000.json','["陶令舍中有名酒，無日不爲父老傾。", "四座歡欣觀酒德，一燈明暗又詩成。"]'),
('b3e9b77c-381f-4070-857e-12f932f55398','謝答聞善二兄九絕句  其九','黄庭堅','宋','宋诗','song-poetry','','[]','阮籍劉伶智如海，人間有道作糟丘。',32,'全唐诗/poet.song.56000.json','["阮籍劉伶智如海，人間有道作糟丘。", "酒中無諍真三昧，便覺嵇康輸一籌。"]'),
('8299f128-547c-47a0-9c29-e80b0cebad04','戲呈聞善','黄庭堅','宋','宋诗','song-poetry','','[]','堆豗病鶴怯雞羣，見酒特地生精神。',32,'全唐诗/poet.song.56000.json','["堆豗病鶴怯雞羣，見酒特地生精神。", "坐中索起時被肘，亦任旁人嫌我真。"]'),
('b2734020-a1ae-4388-96ab-4b1d1dd4e413','題子瞻畫竹石','黄庭堅','宋','宋诗','song-poetry','','[]','風枝雨葉瘠土竹，龍蹲虎踞蒼蘚石。',32,'全唐诗/poet.song.56000.json','["風枝雨葉瘠土竹，龍蹲虎踞蒼蘚石。", "東坡老人翰林公，醉時吐出胸中墨。"]'),
('85140f77-21f9-4fb8-83cf-82dbf3004766','戲贈米元章二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','萬里風帆水著天，麝煤鼠尾過年年。',32,'全唐诗/poet.song.56000.json','["萬里風帆水著天，麝煤鼠尾過年年。", "滄江靜夜虹貫月，定是米家書畫船。"]'),
('3f43acc6-7ae1-49cc-812c-b765674c86ca','戲贈米元章二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','我有玄暉古印章，印刓不忍與諸郎。',32,'全唐诗/poet.song.56000.json','["我有玄暉古印章，印刓不忍與諸郎。", "虎兒筆力能扛鼎，教字玄暉繼阿章。"]'),
('d3643a4b-befc-4edc-bb4d-59323f6b7c69','次韵高子勉十首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','雪盡虛簷滴，春從細草迴。',48,'全唐诗/poet.song.56000.json','["雪盡虛簷滴，春從細草迴。", "德人泉下夢，俗物眼中埃。", "久立我有待，長吟君不來。", "重玄鎖關籥，要待玉匙開。"]'),
('314c1082-f385-4b79-8bb9-86b842e404ed','次韵高子勉十首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','掃雪我三日，御風君過旬。',48,'全唐诗/poet.song.56000.json','["掃雪我三日，御風君過旬。", "言詩今有數，下筆不無神。", "行布佺期近，飛揚子建親。", "可憐金石友，去不待斯人。"]'),
('1554bc55-a8e5-42b1-8cc0-5cac855fc7d2','次韵高子勉十首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','峴南羈旅井，灞上獵歸亭。',48,'全唐诗/poet.song.56000.json','["峴南羈旅井，灞上獵歸亭。", "日繞分魚市，風回落雁汀。", "筆由詩客把，笛爲故人聽。", "但恐蘇耽鶴，歸時或姓丁。"]'),
('5b3ef236-9988-4be3-8709-5554287cd7af','次韵高子勉十首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','君不居郎省，還應上諫坡。',48,'全唐诗/poet.song.56000.json','["君不居郎省，還應上諫坡。", "才高殊未識，歲晚喜無它。", "櫪馬羸難出，鄰雞凍不歌。", "寒爐餘幾火，灰裏撥陰何。"]'),
('3ea83dc4-a9f7-4744-9ac6-3255eeffd563','次韵高子勉十首  其五','黄庭堅','宋','宋诗','song-poetry','','[]','荆渚樓中賦，南陽壠底吟。',48,'全唐诗/poet.song.56000.json','["荆渚樓中賦，南陽壠底吟。", "誰言小隠處，頻屈故人臨。", "經笥難窺底，詞源幸汲深。", "思君眠竹屋，雪月冰寒衾。"]'),
('dab11eb2-95f5-4951-ac3b-1f5ef5be4678','次韵高子勉十首  其六','黄庭堅','宋','宋诗','song-poetry','','[]','驚人得佳句，或以傲王公。',48,'全唐诗/poet.song.56000.json','["驚人得佳句，或以傲王公。", "處世要清節，滑稽安足雄。", "深沈似康樂，簡遠到安豐。", "一點無俗氣，相期林下同。"]'),
('77c5c89f-d9c5-4655-b243-e9068f48ecc6','次韵高子勉十首  其七','黄庭堅','宋','宋诗','song-poetry','','[]','志士難推轂，將如高子何。',48,'全唐诗/poet.song.56000.json','["志士難推轂，將如高子何。", "心期誠不淺，餘論或相多。", "欲向滄洲去，還能小艇麽。", "鸕鷀西照處，相並曬漁蓑。"]'),
('7f2dd210-0941-4fc4-883a-8c7f046d8078','次韵高子勉十首  其八','黄庭堅','宋','宋诗','song-poetry','','[]','鑿開混沌竅，窺見伏羲心。',48,'全唐诗/poet.song.56000.json','["鑿開混沌竅，窺見伏羲心。", "有物先天地，含生盡陸沈。", "伐山成大厦，鼓橐鑄祥金。", "三尺無絃木，期君發至音。"]'),
('1042f005-9a63-4587-9586-7e4ec7e1a8ae','次韵高子勉十首  其九','黄庭堅','宋','宋诗','song-poetry','','[]','少年基一簣，長歲足三餘。',48,'全唐诗/poet.song.56000.json','["少年基一簣，長歲足三餘。", "忽作飛黄去，頓超同隊魚。", "尊前八采句，窗下十年書。", "定作牛腰束，傳抄聽小胥。"]'),
('c8a9fae0-1bfe-4f9b-9726-6cf2e1623152','次韵高子勉十首  其一○','黄庭堅','宋','宋诗','song-poetry','','[]','沙上步微暖，思君剩欲招。',48,'全唐诗/poet.song.56000.json','["沙上步微暖，思君剩欲招。", "蔞蒿穿雪動，楊柳索春饒。", "枉駕時逢出，新詩若見撩。", "樽前遠湖樹，來飲莫辭遙。"]'),
('d67bff7d-3094-4697-b619-f3315dbeaf43','贈高子勉四首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','文章瑞世驚人，學行刳心潤身。',28,'全唐诗/poet.song.56000.json','["文章瑞世驚人，學行刳心潤身。", "沅江求九肋鼈，荆州見一角麟。"]'),
('c0ec9b86-be56-4043-8679-7c47e33fb6bb','贈高子勉四首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','張侯海內長句，晁子廟中雅歌。',28,'全唐诗/poet.song.56000.json','["張侯海內長句，晁子廟中雅歌。", "高郎少加筆力，我知三傑同科。"]'),
('fe709235-2675-4def-99c8-4607fe331e63','贈高子勉四首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','妙在和光同塵，事須鈎深入神。',28,'全唐诗/poet.song.56000.json','["妙在和光同塵，事須鈎深入神。", "聽他下虎口著，我不爲牛後人。"]'),
('efb622c0-9a4b-47b4-9d12-486084ad450a','贈高子勉四首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','拾遺句中有眼，彭澤意在無絃。',28,'全唐诗/poet.song.56000.json','["拾遺句中有眼，彭澤意在無絃。", "顧我今六十老，付公以二百年。"]'),
('1c4efc17-2122-405f-a69d-525198f9c201','再用前韵贈子勉四首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','胸中有度擇人，事上無心活身。',28,'全唐诗/poet.song.56000.json','["胸中有度擇人，事上無心活身。", "只麽情親魚鳥，儻然圖畫麒麟。"]'),
('12ce096a-2045-46ca-a167-e353c0b44212','再用前韵贈子勉四首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','行要爭光日月，詩須皆可絃歌。',28,'全唐诗/poet.song.56000.json','["行要爭光日月，詩須皆可絃歌。", "著鞭莫落人後，百年風轉蓬科。"]'),
('0723c57a-2822-4d6a-a45c-a7c315cef442','再用前韵贈子勉四首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','句法俊逸清新，詞源廣大精神。',28,'全唐诗/poet.song.56000.json','["句法俊逸清新，詞源廣大精神。", "建安才六七子，開元數兩三人。"]'),
('75cad54c-5e9e-4402-bb6e-7a891d0f12dc','再用前韵贈子勉四首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','醉鄉閒處日月，鳥語花中管絃。',28,'全唐诗/poet.song.56000.json','["醉鄉閒處日月，鳥語花中管絃。", "有興勤來把酒，與君端欲忘年。"]'),
('04cae364-f455-4780-952c-8af34fdffa99','荆南簽判向和卿用予六言見惠次韵奉酬四首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','仕宦初不因人，富貴方來逼身。',28,'全唐诗/poet.song.56000.json','["仕宦初不因人，富貴方來逼身。", "要是出羣拔萃，乃成威鳳祥麟。"]'),
('c6511317-153d-4f0d-85bc-1ef89cde789e','荆南簽判向和卿用予六言見惠次韵奉酬四首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','向侯賦我菁莪，何敢當不類歌。',28,'全唐诗/poet.song.56000.json','["向侯賦我菁莪，何敢當不類歌。", "顧我乃山林士，看君取將相科。"]'),
('ae241822-5011-4469-9d68-a65066351c6d','荆南簽判向和卿用予六言見惠次韵奉酬四首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','覆却萬方無準，安排一字有神。',28,'全唐诗/poet.song.56000.json','["覆却萬方無準，安排一字有神。", "更能識詩家病，方是我眼中人。"]'),
('9adb2e5b-796e-47d4-8b7a-48222f355bb5','荆南簽判向和卿用予六言見惠次韵奉酬四首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','覓句真成小技，知音定須絕絃。',28,'全唐诗/poet.song.56000.json','["覓句真成小技，知音定須絕絃。", "景公有馬千駟，伯夷垂名萬年。"]'),
('6de8b3c9-255b-41ea-ad0d-e606cb2c846b','蟻蝶圖','黄庭堅','宋','宋诗','song-poetry','','[]','胡蝶雙飛得意，偶然畢命網羅。',28,'全唐诗/poet.song.56000.json','["胡蝶雙飛得意，偶然畢命網羅。", "羣蟻爭收墜翼，策勳歸去南柯。"]'),
('0cfb0798-d8cb-4114-92af-1502f54653f8','謝胡藏之送栗鼠尾畫維摩二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','貂尾珍材可筆，虎頭墨妙疑神。',28,'全唐诗/poet.song.56000.json','["貂尾珍材可筆，虎頭墨妙疑神。", "頗知君塵外物，真是我眼中人。"]'),
('8265632b-89a8-45f4-bb33-b75e97278099','謝胡藏之送栗鼠尾畫維摩二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','丹青貌金粟影，毛物宜管城公。',28,'全唐诗/poet.song.56000.json','["丹青貌金粟影，毛物宜管城公。", "只今爲君落筆，他日聽我談空。"]'),
('1c683912-03e2-43b7-a575-7481e434461d','次韵向和卿行松滋縣與鄒天錫夜語南極亭二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','雪泥滑滑到山郭，提壺勸沽亦不惡。',32,'全唐诗/poet.song.56000.json','["雪泥滑滑到山郭，提壺勸沽亦不惡。", "林中解道不如歸，家人應念思歸樂。"]'),
('d39a5b68-99dd-4345-8355-204943e67c01','次韵向和卿行松滋縣與鄒天錫夜語南極亭二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','衝風衝雨走七縣，唯有白鷗盟未寒。',32,'全唐诗/poet.song.56000.json','["衝風衝雨走七縣，唯有白鷗盟未寒。", "坐中更得江南客，開盡南窗借月看。"]'),
('f8cc52f4-a413-4e27-9f24-9a65cb3fba1e','戲答荆州王充道烹茶四首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','三徑雖鋤客自稀，醉鄉安穩更何之。',32,'全唐诗/poet.song.56000.json','["三徑雖鋤客自稀，醉鄉安穩更何之。", "老翁更把春風椀，靈府清寒要作詩。"]'),
('fe3bbdac-054a-4098-8a40-ca1e66474e22','戲答荆州王充道烹茶四首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','茗椀難加酒椀醇，暫時扶起藉糟人。',32,'全唐诗/poet.song.56000.json','["茗椀難加酒椀醇，暫時扶起藉糟人。", "何須忍垢不濯足，苦學梁州陰子春。"]'),
('5fdf1410-8e63-437f-b908-c8b7a68e9a0d','戲答荆州王充道烹茶四首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','香從靈堅壟上發，味自白石源中生。',32,'全唐诗/poet.song.56000.json','["香從靈堅壟上發，味自白石源中生。", "爲公喚覺荆州夢，可待南柯一夢成。"]'),
('65c0ce6f-484b-49e5-9590-0cb92df70c08','戲答荆州王充道烹茶四首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','龍焙東風魚眼湯，箇中即是白雲鄉。',32,'全唐诗/poet.song.56000.json','["龍焙東風魚眼湯，箇中即是白雲鄉。", "更煎雙井蒼鷹爪，始耐落花春日長。"]'),
('7e3718ac-105c-4d07-84b8-fb69f6daddf3','雨中登岳陽樓望君山二首  其一','黄庭堅','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','投荒萬死鬢毛斑，生出瞿塘灧澦關。',32,'全唐诗/poet.song.56000.json','["投荒萬死鬢毛斑，生出瞿塘灧澦關。", "未到江南先一笑，岳陽樓上對君山。"]'),
('7894b1a9-d173-41c1-bdf9-0930705867ef','雨中登岳陽樓望君山二首  其二','黄庭堅','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','滿川風雨獨憑欄，綰結湘娥十二鬟。',32,'全唐诗/poet.song.56000.json','["滿川風雨獨憑欄，綰結湘娥十二鬟。", "可惜不當湖水面，銀山堆裏看青山。"]'),
('053f58ce-e739-47d1-86e7-0acea170f7a0','自巴陵略平江臨湘入通城無日不雨至黄龍奉謁清禪師繼而晚晴邂逅禪客戴道純款語作長句呈道純','黄庭堅','宋','宋诗','song-poetry','','[]','山行十日雨霑衣，幕阜峰前對落暉。',64,'全唐诗/poet.song.56000.json','["山行十日雨霑衣，幕阜峰前對落暉。", "野水自添田水滿，晴鳩却喚雨鳩歸。", "靈源大士人天眼，雙塔老師諸佛機。", "白髮蒼顔重到此，問君還是昔人非。"]'),
('ea170ec4-b503-4b8a-b9dd-9b788ce3555a','題徐氏書院','黄庭堅','宋','宋诗','song-poetry','','[]','學書但學溪老鵝，讀書可觀樵父歌。',32,'全唐诗/poet.song.56000.json','["學書但學溪老鵝，讀書可觀樵父歌。", "紫髯將軍不復見，空餘巖桂綠婆娑。"]'),
('dd7cb58c-0a76-4da4-aebb-ce284bcc873a','贈石敏若','黄庭堅','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','才似謫仙惟欠酒，情如宋玉更逢秋。',32,'全唐诗/poet.song.56000.json','["才似謫仙惟欠酒，情如宋玉更逢秋。", "相看領會一談勝，注目長江天際流。"]'),
('0a040c21-0cc8-47b0-ab96-296bdfa652a8','題胡逸老致虛庵','黄庭堅','宋','宋诗','song-poetry','','["\u65f7\u8fbe", "\u5199\u4eba", "\u6292\u6000", "\u5199\u4eba\u8bd7"]','藏書萬卷可教子，遺金滿籯常作災。',64,'全唐诗/poet.song.56000.json','["藏書萬卷可教子，遺金滿籯常作災。", "能與貧人共年穀，必有明月生蚌胎。", "山隨宴坐圖畫出，水作夜窗風雨來。", "觀水觀山皆得妙，更將何物污靈臺。"]'),
('8e1c8813-57ff-4c5a-92aa-262f64c0a4bd','題蓮華寺','黄庭堅','宋','宋诗','song-poetry','','[]','狂卒猝起金坑西，脅從數百馬百蹄。',64,'全唐诗/poet.song.56000.json','["狂卒猝起金坑西，脅從數百馬百蹄。", "所過州縣不敢誰，肩輿擄載三十妻。", "伍生有膽無智略，謂河可馮虎可搏。", "身膏白刃浮屠前，此鄉父老至今憐。"]'),
('ce638bff-5085-46c0-8f82-abc7e0ee6688','衝雨向萬載道中得逍遙觀託宿遂戲題','黄庭堅','宋','宋诗','song-poetry','','[]','逍遙近道邊，憩息慰憊懣。',48,'全唐诗/poet.song.56000.json','["逍遙近道邊，憩息慰憊懣。", "晴暉時晦明，謔語諧讜論。", "草萊荒蒙蘢，室屋壅塵坌。", "僕僮偪側泌，涇渭清濁混。"]'),
('b3dea2a8-8648-43bc-abb1-a5bac6da6db9','題竹尊者軒','黄庭堅','宋','宋诗','song-poetry','','[]','平生脊骨硬如鐵，聽風聽雨隨宜說。',32,'全唐诗/poet.song.56000.json','["平生脊骨硬如鐵，聽風聽雨隨宜說。", "百尺竿頭放步行，更向脚跟參一節。"]'),
('820c3156-4ced-485f-ad87-afdabe9726e7','送密老住五峰','黄庭堅','宋','宋诗','song-poetry','','[]','我穿高安過萍鄉，七十二渡遶羊腸。',96,'全唐诗/poet.song.56000.json','["我穿高安過萍鄉，七十二渡遶羊腸。", "水邊林下逢衲子，南北東西古道場。", "五峰秀出雲雨上，中有寶坊如側掌。", "去與青山作主人，不負法昌老禪將。", "栽松種竹是家風，莫嫌斗絕無來往。", "但得螺螄吞大象，從來美酒無深巷。"]'),
('4b45a0db-ab7e-4cd3-8b32-b78725e170ea','新喻道中寄元明用觴字韵','黄庭堅','宋','宋诗','song-poetry','','[]','中年畏病不舉酒，孤負東來數百觴。',64,'全唐诗/poet.song.56000.json','["中年畏病不舉酒，孤負東來數百觴。", "喚客煎茶山店遠，看人秧稻午風凉。", "但知家裏俱無恙，不用書來細作行。", "一百八盤携手上，至今猶夢遶羊腸。"]'),
('d5267df9-871d-47e4-b947-8365ba8dbe59','拜劉凝之畫像','黄庭堅','宋','宋诗','song-poetry','','[]','弃官清潁尾，買田落星灣。',48,'全唐诗/poet.song.56000.json','["弃官清潁尾，買田落星灣。", "身在菰蒲中，名滿天地間。", "誰能四十年，保此清靜退。", "往來澗谷中，神光射牛背。"]'),
('baf10ecc-eb0e-41ec-8143-88518e67a7ce','追和東坡壺中九華','黄庭堅','宋','宋诗','song-poetry','','[]','有人夜半持山去，頓覺浮嵐暖翠空。',64,'全唐诗/poet.song.56000.json','["有人夜半持山去，頓覺浮嵐暖翠空。", "試問安排華屋處，何如零落亂雲中。", "能回趙璧人安在，已入南柯夢不通。", "頼有霜鐘難席卷，袖椎來聽響玲瓏。"]'),
('894ada87-985d-4ea7-8341-551a9bc1f925','罷姑熟寄元明用觴字韵','黄庭堅','宋','宋诗','song-poetry','','[]','追隨富貴勞牽尾，準擬田園略濫觴。',64,'全唐诗/poet.song.56000.json','["追隨富貴勞牽尾，準擬田園略濫觴。", "本與江鷗成保社，聊隨海燕度炎凉。", "未栽姑熟桃李徑，却入江西鴻雁行。", "別後常同千里月，書來莫寄九回腸。"]'),
('a624ad19-d84c-45bb-b1d3-6c374c4e3038','次蘇子瞻和李太白潯陽紫極宮感秋詩韵追懷太白子瞻','黄庭堅','宋','宋诗','song-poetry','','[]','不見兩謫仙，長懷倚脩竹。',96,'全唐诗/poet.song.56000.json','["不見兩謫仙，長懷倚脩竹。", "行遶紫極宮，明珠得盈掬。", "平生人欲殺，耿介受命獨。", "往者如可作，抱被求同宿。", "砥柱閱頹波，不疑更何卜。", "但觀草木秋，葉落根自復。", "我病二十年，大斗久不覆。", "因之酌蘇李，蟹肥社醅熟。"]'),
('7497c6b8-b731-4211-a79e-cc1c70ebff68','瓊芝軒','黄庭堅','宋','宋诗','song-poetry','','[]','卓僊在時養瓊芝，深根固蒂活人命。',32,'全唐诗/poet.song.56000.json','["卓僊在時養瓊芝，深根固蒂活人命。", "憧憧來問此何草，但告渠是唐婆鏡。"]'),
('c8ab47b3-9aab-478f-9f95-bbe95f78d964','龜殻軒','黄庭堅','宋','宋诗','song-poetry','','[]','紫極宮中三百楹，道人獨藏一神屋。',32,'全唐诗/poet.song.56000.json','["紫極宮中三百楹，道人獨藏一神屋。", "開軒納息星月明，時有白雲來伴宿。"]'),
('ce3f42c2-232f-40fd-8d63-1f948f57c359','秋聲軒','黄庭堅','宋','宋诗','song-poetry','','[]','誰居空閒扇橐籥，情與無情並時作。',32,'全唐诗/poet.song.56000.json','["誰居空閒扇橐籥，情與無情並時作。", "是聲皆自根極來，更莫辛勤問南郭。"]'),
('cb292f08-8165-4f1b-b13e-56ef1c77e9ea','戲效禪月作遠公詠','黄庭堅','宋','宋诗','song-poetry','','[]','邀陶淵明把酒椀，過陸脩靜送虎溪。',32,'全唐诗/poet.song.56000.json','["邀陶淵明把酒椀，過陸脩靜送虎溪。", "胸次九流清似鏡，人間萬事醉如泥。"]'),
('c5dd69e2-d07a-4276-a964-b8a014ff72dc','跋子瞻和陶詩','黄庭堅','宋','宋诗','song-poetry','','["\u6292\u60c5", "\u5199\u4eba", "\u8d5e\u7f8e", "\u82e6\u95f7"]','子瞻謫嶺南，時宰欲殺之。',48,'全唐诗/poet.song.56000.json','["子瞻謫嶺南，時宰欲殺之。", "飽喫惠州飯，細和淵明詩。", "彭澤千載人，東坡百世士。", "出處雖不同，風味乃相似。"]'),
('041e4858-2f84-45b4-ab3b-96c76c0d0873','題李亮功戴嵩牛圖','黄庭堅','宋','宋诗','song-poetry','','[]','韓生畫肥馬，立仗有輝光。',48,'全唐诗/poet.song.56000.json','["韓生畫肥馬，立仗有輝光。", "戴老作瘦牛，平生千頃荒。", "觳觫告主人，實已盡筋力。", "乞我一牧童，林間聽橫笛。"]'),
('e1455da6-1e36-4960-b3d7-67ff8f95da57','追和東坡題李亮功歸來圖','黄庭堅','宋','宋诗','song-poetry','','[]','今人常恨古人少，今得見之誰謂無。',64,'全唐诗/poet.song.56000.json','["今人常恨古人少，今得見之誰謂無。", "欲學淵明歸作賦，先煩摩詰畫成圖。", "小池已築魚千里，隙地仍栽芋百區。", "朝市山林俱有累，不居京洛不江湖。"]'),
('10fc6162-24ee-4bae-9ff1-9123e6b4cd9d','次韵徐仲車喜董元達訪之作南郭篇四韵','黄庭堅','宋','宋诗','song-poetry','','[]','董侯從軍來，意望名不朽。',48,'全唐诗/poet.song.56000.json','["董侯從軍來，意望名不朽。", "款門拜徐公，在德不在酒。", "徐公雖避俗，對客輒粲然。", "耳不聞世事，時誦陶令篇。"]'),
('bb57ffd7-ccdd-45d3-b02f-0eed875f68f8','次韵仲車爲元達置酒四韵','黄庭堅','宋','宋诗','song-poetry','','[]','射陽三萬家，莫貴徐公門。',48,'全唐诗/poet.song.56000.json','["射陽三萬家，莫貴徐公門。", "誰能拜牀前，況乃共酒尊。", "惟此酒中趣，難爲醒者論。", "盜卧月皎皎，雞鳴雨昏昏。"]'),
('25a26c42-bb28-4a34-81d0-f203166a7e6f','次韵仲車因婁行父見寄之什','黄庭堅','宋','宋诗','song-poetry','','[]','前朝老諸生，大半正邱首。',48,'全唐诗/poet.song.56000.json','["前朝老諸生，大半正邱首。", "投荒萬里歸，煩公問健否。", "往時望江宰，今爲夏津吏。", "他日可教之，玉音尚無棄。"]'),
('43645b7b-566f-4747-8a04-68951a97adb2','武昌松風閣','黄庭堅','宋','宋诗','song-poetry','','[]','依山築閣見平川，夜闌箕斗插屋椽。',168,'全唐诗/poet.song.56000.json','["依山築閣見平川，夜闌箕斗插屋椽。", "我來名之意適然。", "老松魁梧數百年，斧斤所赦今參天。", "風鳴媧皇五十絃，洗耳不須菩薩泉。", "嘉二三子甚好賢，力貧買酒醉此筵。", "夜雨鳴廊到曉懸，相看不歸卧僧氈。", "泉枯石燥復潺湲，山川光輝爲我妍。", "野僧早饑不能饘，曉見寒谿有炊煙。", "東坡道人已沈泉，張侯何時到眼前。", "釣臺驚濤可晝眠，怡亭看篆蛟龍纏。", "安得此身脫拘攣，舟載諸友長周旋。"]'),
('203116bd-30c8-408a-9416-fc4d2f845ba1','次韵文潛','黄庭堅','宋','宋诗','song-poetry','','[]','武昌赤壁弔周郎，寒溪西山尋漫浪。',160,'全唐诗/poet.song.56000.json','["武昌赤壁弔周郎，寒溪西山尋漫浪。", "忽聞天上故人來，呼船凌江不待餉。", "我瞻高明少吐氣，君亦歡喜失微恙。", "年來鬼祟覆三豪，詞林根柢頗摇蕩。", "天生大材竟何用，只與千古拜圖像。", "張侯文章殊不病，歷險心膽原自壯。", "汀洲鴻雁未安集，風雪牖戶當塞向。", "有人出手辦茲事，正可隠几窮諸妄。", "經行東坡眠食地，拂拭寶墨生楚愴。", "水清石見君所知，此是吾家秘密藏。"]'),
('f100769c-beee-4733-8466-6904ccfc2f91','和文潛舟中所題','黄庭堅','宋','宋诗','song-poetry','','[]','雲橫疑有路，天遠欲無門。',48,'全唐诗/poet.song.56000.json','["雲橫疑有路，天遠欲無門。", "信矣江山美，懷哉譴逐魂。", "長波空𣶂記，佳句洗眵昏。", "誰奈離愁得，村醪或可尊。"]'),
('6adf4eca-2370-484e-aa50-dbdff93ab269','題君子泉','黄庭堅','宋','宋诗','song-poetry','','[]','雲夢澤南君子泉，水無名字託人賢。',32,'全唐诗/poet.song.56000.json','["雲夢澤南君子泉，水無名字託人賢。", "兩蘇翰墨相爲重，未刻他山世已傳。"]'),
('b33ba322-d6e3-4007-9bc9-806cb4aebef2','宿黄州觀音院鐘樓上','黄庭堅','宋','宋诗','song-poetry','','[]','鐘鳴山川曉，露下星斗濕。',24,'全唐诗/poet.song.56000.json','["鐘鳴山川曉，露下星斗濕。", "老夫梳白頭，潘何塤篪集。"]'),
('099781a7-4b30-46c3-948f-a78d6ca6c1fd','謝何十三送蟹','黄庭堅','宋','宋诗','song-poetry','','[]','形模雖入婦女笑，風味可解壯士顔。',32,'全唐诗/poet.song.56000.json','["形模雖入婦女笑，風味可解壯士顔。", "寒蒲束縛十六輩，已覺酒興生江山。"]'),
('14a652fc-21cf-4cc7-a701-41544ad756b8','又借答送蟹韵并戲小何','黄庭堅','宋','宋诗','song-poetry','','[]','草泥本自行郭索，玉人爲開桃李顔。',32,'全唐诗/poet.song.56000.json','["草泥本自行郭索，玉人爲開桃李顔。", "恐似曹瞞說雞肋，不比東阿舉肉山。"]'),
('8c6a4112-e79c-4df4-a03d-d17bee777ab7','代二螯解嘲','黄庭堅','宋','宋诗','song-poetry','','[]','仙儒昔日卷龜殻，蛤蜊自可洗愁顔。',32,'全唐诗/poet.song.56000.json','["仙儒昔日卷龜殻，蛤蜊自可洗愁顔。", "不比二螯風味好，那堪把酒對西山。"]'),
('8ae56bf8-346d-440a-98c3-344649788c45','又借前韵見意','黄庭堅','宋','宋诗','song-poetry','','[]','招潮瘦惡無永味，海鏡纖毫只强顔。',32,'全唐诗/poet.song.56000.json','["招潮瘦惡無永味，海鏡纖毫只强顔。", "想見霜臍當大嚼，夢回雪壓摩圍山。"]'),
('45a2f906-b911-410a-bdd7-8abd4c4f54e7','次韵文潛立春日三絕句  其一','黄庭堅','宋','宋诗','song-poetry','','[]','眇然今日望歐梅，已發黄州首更回。',32,'全唐诗/poet.song.56000.json','["眇然今日望歐梅，已發黄州首更回。", "試問淮南風月主，新年桃李爲誰開。"]'),
('7ee1d3d2-2416-4247-a158-4568243e5aa1','次韵文潛立春日三絕句  其二','黄庭堅','宋','宋诗','song-poetry','','[]','誰憐舊日青錢選，不立春風玉筍班。',32,'全唐诗/poet.song.56000.json','["誰憐舊日青錢選，不立春風玉筍班。", "傳得黄州新句法，老夫端欲把降幡。"]'),
('30d12994-0612-485c-a21e-961001e6dfaf','次韵文潛立春日三絕句  其三','黄庭堅','宋','宋诗','song-poetry','','[]','江山也似隨春動，花柳真成觸眼新。',32,'全唐诗/poet.song.56000.json','["江山也似隨春動，花柳真成觸眼新。", "清濁盡須歸甕蟻，吉凶更莫問波臣。"]'),
('f7a65bca-382d-43e3-8a02-ef85016095a1','再次前韵  其一','黄庭堅','宋','宋诗','song-poetry','','[]','春工調物似鹽梅，一一根中生意回。',32,'全唐诗/poet.song.56000.json','["春工調物似鹽梅，一一根中生意回。", "風日安排催歲換，丹青次第與花開。"]'),
('5c3444a4-7e73-43e6-af26-36cb5be76480','再次前韵  其二','黄庭堅','宋','宋诗','song-poetry','','[]','久狎漁樵作往還，曉風宮殿夢催班。',32,'全唐诗/poet.song.56000.json','["久狎漁樵作往還，曉風宮殿夢催班。", "鄰娃似與春爭道，酥滴花枝綵剪幡。"]'),
('dff69478-be68-4cbf-bfb3-9d5ec5a08630','再次前韵  其三','黄庭堅','宋','宋诗','song-poetry','','[]','酒有全功筆有神，可將心付白頭新。',32,'全唐诗/poet.song.56000.json','["酒有全功筆有神，可將心付白頭新。", "春盤一任人爭席，莫道前銜是近臣。"]'),
('62fb8c32-618b-48d1-9b9c-c14a940726be','夢中和觴字韵','黄庭堅','宋','宋诗','song-poetry','','[]','天教兄弟各異方，不使新年對舉觴。',64,'全唐诗/poet.song.56000.json','["天教兄弟各異方，不使新年對舉觴。", "作雲作雨手翻覆，得馬失馬心清凉。", "何處胡椒八百斛，誰家金釵十二行。", "一邱一壑可曳尾，三沐三舋取刳腸。"]'),
('912e95e3-04f6-4179-81db-2c797eb50791','次韵吳可權題餘干縣白雲亭','黄庭堅','宋','宋诗','song-poetry','','[]','曩誰築孤亭，勝日有感遇。',156,'全唐诗/poet.song.56000.json','["曩誰築孤亭，勝日有感遇。", "永懷劉隨州，因榜白雲句。", "遺老不能談，歲月忽成屢。", "綠陰斤斧盡，華屋風雨仆。", "吳侯七閩英，宰縣有真趣。", "絃歌解民慍，根節去吏蠹。", "材收佛宮餘，工有子來助。", "厦成燕雀賀，水滿鳬雁翥。", "四海名士來，一笑佳客聚。", "雲興碧山留，雲散清江去。", "斯須成蒼狗，皆道不如故。", "至人觀萬物，誰有安立處。", "寄語吳令君，但遣糟牀注。"]'),
('2b122046-b2fc-4c97-b842-5673d8c34308','次韵廖明略同吳明府白雲亭宴集','黄庭堅','宋','宋诗','song-poetry','','[]','江靜明花竹，山空響管絃。',120,'全唐诗/poet.song.56000.json','["江靜明花竹，山空響管絃。", "風生學士麈，雲繞令君筵。", "百越餘生聚，三吳遠接連。", "庖霜刀落鱠，執玉酒明船。", "葉縣飛來舄，壺公謫處天。", "酌時多暴謔，舞短更成妍。", "唯我孤登覽，觀詩未究宣。", "空餘五字賞，文似兩京然。", "醫是肱三折，官當歲九遷。", "老夫看鏡罷，衰白敢爭先。"]'),
('22993819-4bbf-4d68-b6b6-37c07db76ea3','病來十日不舉酒二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','病來十日不舉酒，回施青春與後生。',32,'全唐诗/poet.song.56000.json','["病來十日不舉酒，回施青春與後生。", "滿袖東風愜人意，見君詩與字俱清。"]'),
('453a67fb-28ff-4a08-a570-4485b17a1ba2','病來十日不舉酒二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','病來十日不舉酒，獨卧南牀春草生。',32,'全唐诗/poet.song.56000.json','["病來十日不舉酒，獨卧南牀春草生。", "承君折送袁家紫，令我興發郎官清。"]'),
('bc89be58-ac71-4a94-a4e3-852250f8074e','題小景扇','黄庭堅','宋','宋诗','song-poetry','','["\u6625\u5929", "\u5199\u666f", "\u6292\u60c5", "\u6101\u6068"]','草色青青柳色黄，桃花零落杏花香。',32,'全唐诗/poet.song.56000.json','["草色青青柳色黄，桃花零落杏花香。", "春風不解吹愁却，春日偏能惹恨長。"]'),
('992cd895-ace2-4ae2-a8f1-c483ccdc776b','鄂州南樓書事四首  其一','黄庭堅','宋','宋诗','song-poetry','','["\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7", "\u5199\u666f"]','四顧山光接水光，凭欄十里芰荷香。',32,'全唐诗/poet.song.56000.json','["四顧山光接水光，凭欄十里芰荷香。", "清風明月無人管，併作南樓一味凉。"]'),
('bcc62380-bdec-4e85-8265-00775f73bb85','鄂州南樓書事四首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','畫閣傳觴容十客，透風透月兩明軒。',32,'全唐诗/poet.song.56000.json','["畫閣傳觴容十客，透風透月兩明軒。", "南樓槃礴三百尺，天上雲居不足言。"]'),
('5f96dc91-457b-4f9b-a1cb-78080385a123','鄂州南樓書事四首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','勢壓湖南可長雄，胸吞雲夢略從容。',32,'全唐诗/poet.song.56000.json','["勢壓湖南可長雄，胸吞雲夢略從容。", "北船未嘗睹巨麗，複閣重樓天際逢。"]'),
('ccdaa256-7a0a-4379-9408-e46ae3f45bb3','鄂州南樓書事四首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','武昌參佐幕中畫，我亦來追六月凉。',32,'全唐诗/poet.song.56000.json','["武昌參佐幕中畫，我亦來追六月凉。", "老子平生殊不淺，諸君少住對胡牀。"]'),
('7a612fae-6eb1-4fcd-bb0f-9dfa3a875d8e','南樓畫閣觀方公悅二小詩戲次韵  其一','黄庭堅','宋','宋诗','song-poetry','','[]','十年華屋網蛛塵，大旆重來一日新。',32,'全唐诗/poet.song.56000.json','["十年華屋網蛛塵，大旆重來一日新。", "五鳳樓前脩造手，箇中餘刃亦精神。"]'),
('2ccffb8f-c9cd-488b-89ba-98c03a31420a','南樓畫閣觀方公悅二小詩戲次韵  其二','黄庭堅','宋','宋诗','song-poetry','','[]','重山複水繞深幽，不見高賢獨倚樓。',32,'全唐诗/poet.song.56000.json','["重山複水繞深幽，不見高賢獨倚樓。", "手拂壁間留恨句，凌波微步有人愁。"]'),
('289dde76-b7e9-410f-8961-44584f656fdc','庭堅以去歲九月至鄂登南樓歎其制作之美成長句久欲寄遠因循至今書呈公悅','黄庭堅','宋','宋诗','song-poetry','','[]','江東湖北行畫圖，鄂州南樓天下無。',64,'全唐诗/poet.song.56000.json','["江東湖北行畫圖，鄂州南樓天下無。", "高明廣深勢抱合，表裏江山來畫閣。", "雪筵披襟夏簟寒，胸吞雲夢何足言。", "庾公風流冷似鐵，誰其繼之方公悅。"]'),
('04eeb73e-8902-4bcb-b696-f5069b3f0cec','養鬭雞','黄庭堅','宋','宋诗','song-poetry','','[]','崢嶸已介季氏甲，更以黄金飾兩戈。',32,'全唐诗/poet.song.56000.json','["崢嶸已介季氏甲，更以黄金飾兩戈。", "雖有英心甘鬭死，其如紀渻木雞何。"]'),
('e624fe29-87ed-4367-bd64-e47176a9d366','顔徒貧樂齋二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','衡門低首過，環堵容膝坐。',48,'全唐诗/poet.song.56000.json','["衡門低首過，環堵容膝坐。", "四旁無給侍，百衲自纏裹。", "論事直如絃，觀書曲肱卧。", "饑來或乞食，有道無不可。"]'),
('2bf7c95d-9f29-4427-8909-f878a785da5f','顔徒貧樂齋二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','小山作友朋，義重子輿桑。',48,'全唐诗/poet.song.56000.json','["小山作友朋，義重子輿桑。", "香草當姬妾，不須珠翠妝。", "鳥烏窺凍硯，星月入幽房。", "兒報無炊米，浩歌繞屋梁。"]'),
('d2743c98-64e0-449b-9b41-2ef025890762','和凉軒二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','打荷看急雨，吞月任行雲。',24,'全唐诗/poet.song.56000.json','["打荷看急雨，吞月任行雲。", "夜半蚊雷起，西風爲解紛。"]'),
('e0e5b2b4-ff8d-47e0-a234-cf1e5b730905','和凉軒二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','茗椀夢中覺，荷花鏡裏香。',24,'全唐诗/poet.song.56000.json','["茗椀夢中覺，荷花鏡裏香。", "凉生只當處，暑退亦無方。"]'),
('e7b92920-8ddd-4093-8543-9aea8741c900','題默軒和遵老','黄庭堅','宋','宋诗','song-poetry','','[]','平生三業浄，在俗亦超然。',48,'全唐诗/poet.song.56000.json','["平生三業浄，在俗亦超然。", "佛事一盂飯，橫眠不學禪。", "松風佳客共，茶夢小僧圓。", "漫續山家頌，非詩莫浪傳。"]'),
('86f46aa0-fba2-420c-9644-4b5c552e8e90','次韵文安國紀夢','黄庭堅','宋','宋诗','song-poetry','','[]','道人偶許俗人知，法喜非妻解養兒。',64,'全唐诗/poet.song.56000.json','["道人偶許俗人知，法喜非妻解養兒。", "夜久金莖添沆瀣，室虛璧月映琉璃。", "遠來醉俠匆匆去，近出詩仙句句奇。", "獨怪區區踐繩墨，相逢未省角巾敧。"]'),
('b0bc33d9-654b-4d83-a912-2b9a3c7f45d8','寄賀方回','黄庭堅','宋','宋诗','song-poetry','','[]','少游醉卧古藤下，誰與愁眉唱一盃。',32,'全唐诗/poet.song.56000.json','["少游醉卧古藤下，誰與愁眉唱一盃。", "解作江南斷腸句，只今唯有賀方回。"]'),
('d3ab22d2-f0e7-401a-a749-322cdb689c07','文安國挽詞二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','七閩家舉子，百粵海還珠。',48,'全唐诗/poet.song.56000.json','["七閩家舉子，百粵海還珠。", "往日推忠厚，窮年領轉輸。", "一牀遺杖屨，萬事委錙銖。", "豈有蒼茫恨，歸巢未拮据。"]'),
('23cbfbfa-39e7-4275-b7f9-ba9de01eb59b','文安國挽詞二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','平生翰墨學，空走使臣車。',48,'全唐诗/poet.song.56000.json','["平生翰墨學，空走使臣車。", "瞿令能蒼史，歸公好古書。", "秦山刊日月，周鼓頌畋漁。", "不見龍蛇筆，新乾研滴蜍。"]'),
('270f1ca3-43c5-4ee2-8ad3-cc67a73edfcf','鄂州節推陳榮緒惠示沿檄崇陽道中六詩老懶不能追韵輒自取韵奉和 頭陀寺','黄庭堅','宋','宋诗','song-poetry','','[]','頭陀全盛時，宮殿梯空級。',48,'全唐诗/poet.song.56000.json','["頭陀全盛時，宮殿梯空級。", "城中望金碧，雲外僧𧥄𧥄。", "人亡經禪盡，屋破龍象泣。", "惟有簡栖碑，文字巋然立。"]'),
('a998c613-b558-4b4f-be5a-67bbfc882d4a','鄂州節推陳榮緒惠示沿檄崇陽道中六詩老懶不能追韵輒自取韵奉和 道中聞松聲','黄庭堅','宋','宋诗','song-poetry','','[]','蟠空作風雨，發地鳴鼓吹。',48,'全唐诗/poet.song.56000.json','["蟠空作風雨，發地鳴鼓吹。", "日晴四無人，聲在高林際。", "伊優兒女語，蹇淺市井議。", "我欲抱七絃，寫此以卒歲。"]'),
('51f3cb57-fce0-4a53-8475-34e997a4fb38','鄂州節推陳榮緒惠示沿檄崇陽道中六詩老懶不能追韵輒自取韵奉和 中秋山行懷子興節判','黄庭堅','宋','宋诗','song-poetry','','[]','俗物常偪塞，令人眼生白。',48,'全唐诗/poet.song.56000.json','["俗物常偪塞，令人眼生白。", "永懷洛陽人，談詩論畫壁。", "青山吐秋月，阻作南樓客。", "但歌靡盬詩，賞此無瑕璧。"]'),
('48d0c823-885e-462d-ad8f-4d706af4a140','鄂州節推陳榮緒惠示沿檄崇陽道中六詩老懶不能追韵輒自取韵奉和 再登蓮落嶺懷君澤知錄','黄庭堅','宋','宋诗','song-poetry','','[]','邑下羹不和，幕中往調護。',48,'全唐诗/poet.song.56000.json','["邑下羹不和，幕中往調護。", "紛爭非士則，各使捐細故。", "頗憶郗參軍，能令公喜怒。", "應知鞅掌車，歷盡崔嵬路。"]'),
('c5e8e697-f196-486f-aeb6-427d9fc4fe5d','鄂州節推陳榮緒惠示沿檄崇陽道中六詩老懶不能追韵輒自取韵奉和 崇陽道中','黄庭堅','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','張公少爲令，愍俗有遺書。',48,'全唐诗/poet.song.56000.json','["張公少爲令，愍俗有遺書。", "左販洞庭橘，右擔彭蠡魚。", "歌奔中夜女，歸抱十年雛。", "近歲多儒學，仁風似有初。"]'),
('7f7ac3fc-c858-45c6-92c9-e1513b79508e','鄂州節推陳榮緒惠示沿檄崇陽道中六詩老懶不能追韵輒自取韵奉和 晚發咸寧行松徑至蘆子','黄庭堅','宋','宋诗','song-poetry','','[]','咸寧走蘆子，終日喬木陰。',48,'全唐诗/poet.song.56000.json','["咸寧走蘆子，終日喬木陰。", "太丘心灑落，古松韵清深。", "聊持不俗耳，靜聽無絃琴。", "非今胡部律，而獨可人心。"]'),
('be406a0d-ca24-4c67-bbcd-b6e7587c8902','陳榮緒惠示之字韵詩推奬過實非所敢當輒次高韵三首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','紛紛不可耐，君子有憂之。',48,'全唐诗/poet.song.56000.json','["紛紛不可耐，君子有憂之。", "鞅掌誠莊語，賢勞似怨詩。", "頹波閱砥柱，濁水得摩尼。", "知我無枝葉，刳心只有皮。"]'),
('bac4b02d-5536-4a5e-9f95-5ef19350181a','陳榮緒惠示之字韵詩推奬過實非所敢當輒次高韵三首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','太丘胸量闊，一葦莫杭之。',48,'全唐诗/poet.song.56000.json','["太丘胸量闊，一葦莫杭之。", "萬事不掛眼，四愁猶有詩。", "狀閒聊闒茸，心潔似毗尼。", "早晚同舟去，煙波學子皮。"]'),
('31a78d46-3c15-47ce-87d4-7a09a8782611','陳榮緒惠示之字韵詩推奬過實非所敢當輒次高韵三首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','十家有忠信，江夏可無之。',48,'全唐诗/poet.song.56000.json','["十家有忠信，江夏可無之。", "政苦寄賣友，忽聞衡說詩。", "饑蒙青䭀飯，寒贈紫陀尼。", "酬報矜難巧，深慙陸與皮。"]'),
('35fb5288-a8af-40fa-bb81-db7c6f202f25','德孺五丈和之字詩韵難而愈工輒復和成可發一笑','黄庭堅','宋','宋诗','song-poetry','','[]','且然聊爾耳，得也自知之。',48,'全唐诗/poet.song.56000.json','["且然聊爾耳，得也自知之。", "獨笑真成夢，狂歌或似詩。", "照灘禽郭索，燒野得伊尼。", "早晚來同醉，僧窗卧虎皮。"]'),
('d6285c1e-e607-49b0-8728-178502e8b5e9','次韵德孺新居病起','黄庭堅','宋','宋诗','song-poetry','','[]','潭潭經略府，寂寂閉門居。',48,'全唐诗/poet.song.56000.json','["潭潭經略府，寂寂閉門居。", "京洛聖賢宅，江湖魚鼈潴。", "官如一夢覺，話勝十年書。", "稍喜過從近，扶筇不駕車。"]'),
('0ef7f1ed-9670-44c8-b358-8ccebfc18d60','次韵德孺感興二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','于此吾忘我，從誰尺直尋。',48,'全唐诗/poet.song.56000.json','["于此吾忘我，從誰尺直尋。", "事來千萬種，人有兩三心。", "自守藩籬小，猶能井臼任。", "過時雖不采，吾與菊花斟。"]'),
('fd5db175-443e-4b92-aa24-f824a46b07f5','次韵德孺感興二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','眼前嘗廢忘，事往更追尋。',48,'全唐诗/poet.song.56000.json','["眼前嘗廢忘，事往更追尋。", "愛酒陶元亮，著書王仲任。", "寒蒲雖有節，枯木已無心。", "客至還須飲，逢歡起自斟。"]'),
('883ffc07-ac6c-427d-90a1-04752d69de85','次韵德孺惠貺秋字之句','黄庭堅','宋','宋诗','song-poetry','','[]','少日才華接貴游，老來忠義氣橫秋。',64,'全唐诗/poet.song.56000.json','["少日才華接貴游，老來忠義氣橫秋。", "未應白髮如霜草，不見丹砂似箭頭。", "顧我今成喪家狗，期君早作濟川舟。", "漢家宗廟英靈在，定是寒儒浪自愁。"]'),
('8c43a82e-0fd0-4706-aac5-2772d0426f68','求范子默染鴉青紙二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','學似貧家老破除，古今迷忘失三餘。',32,'全唐诗/poet.song.56000.json','["學似貧家老破除，古今迷忘失三餘。", "極知鵠白非新得，謾染鴉青襲舊書。"]'),
('418bf4b5-4c62-4ae2-b8a8-eb12cd616d85','求范子默染鴉青紙二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','深如女髮蘭膏罷，明似山光夜月餘。',32,'全唐诗/poet.song.56000.json','["深如女髮蘭膏罷，明似山光夜月餘。", "爲染溪藤三百箇，待渠湔拂一牀書。"]'),
('105cfacd-53bd-40af-8f14-28e98425e89f','謝榮緒惠貺鮮鯽','黄庭堅','宋','宋诗','song-poetry','','[]','偶思暖老庖玄鯽，公遣霜鱗貫柳來。',32,'全唐诗/poet.song.56000.json','["偶思暖老庖玄鯽，公遣霜鱗貫柳來。", "虀臼方看金作屑，鱠盤已見雪成堆。"]'),
('cdc729dc-d721-4e7f-9182-206f84ae9b85','謝榮緒割麞見貽二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','何處驚麏觸禍機，煩君遣騎割鮮肥。',32,'全唐诗/poet.song.56000.json','["何處驚麏觸禍機，煩君遣騎割鮮肥。", "秋來多病新開肉，糲飯寒葅得解圍。"]'),
('e77a26e1-4927-4d9c-9432-b3c6e481415c','謝榮緒割麞見貽二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','二十餘年枯淡過，病來筯下劇甘肥。',32,'全唐诗/poet.song.56000.json','["二十餘年枯淡過，病來筯下劇甘肥。", "果然口腹爲災怪，夢去呼鷹雪打圍。"]'),
('9b041cf5-2440-4b44-bcaf-a41602f42145','吳執中有兩鵝爲余烹之戲贈','黄庭堅','宋','宋诗','song-poetry','','[]','學書池上一雙鵝，宛頸相追筆意多。',32,'全唐诗/poet.song.56000.json','["學書池上一雙鵝，宛頸相追筆意多。", "皆爲涪翁赴湯鼎，主人言汝不能歌。"]'),
('259b67ad-e2a6-46d1-be59-33f5f96244b6','秋冬之間鄂渚絕市無蟹今日偶得數枚吐沫相濡乃可憫笑戲成小詩三首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','怒目橫行與虎爭，寒沙奔火禍胎成。',32,'全唐诗/poet.song.56000.json','["怒目橫行與虎爭，寒沙奔火禍胎成。", "雖爲天上三辰次，未免人間五鼎烹。"]'),
('875827d3-7b9a-4006-84b2-ea3ba02b12a5','秋冬之間鄂渚絕市無蟹今日偶得數枚吐沫相濡乃可憫笑戲成小詩三首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','勃窣媻跚烝涉波，草泥出沒尚橫戈。',32,'全唐诗/poet.song.56000.json','["勃窣媻跚烝涉波，草泥出沒尚橫戈。", "也知觳觫元無罪，奈此尊前風味何。"]'),
('f763ad7d-61a6-4e2b-a7e0-1f06af48b396','秋冬之間鄂渚絕市無蟹今日偶得數枚吐沫相濡乃可憫笑戲成小詩三首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','解縛華堂一座傾，忍堪支解見薑橙。',32,'全唐诗/poet.song.56000.json','["解縛華堂一座傾，忍堪支解見薑橙。", "東歸却爲鱸魚鱠，未敢知言許季鷹。"]'),
('d3ed1ff6-2881-4b67-badc-1e5523838947','甯子與追和予岳陽樓詩復次韵二首  其一','黄庭堅','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','去年新霽獨憑欄，山似樊姬擁髻鬟。',32,'全唐诗/poet.song.56000.json','["去年新霽獨憑欄，山似樊姬擁髻鬟。", "箇裏宛然多事在，世間遙望但雲山。"]'),
('c39783f2-addd-45f7-a66b-cf6e8796956e','甯子與追和予岳陽樓詩復次韵二首  其二','黄庭堅','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','軒皇樂罷拱朝班，天地爲家不閉關。',32,'全唐诗/poet.song.56000.json','["軒皇樂罷拱朝班，天地爲家不閉關。", "惟有金爐紫煙起，至今留作御前山。"]'),
('bab00e72-fb57-486c-9a4d-e6515354b9c4','和甯子與白鹿寺','黄庭堅','宋','宋诗','song-poetry','','[]','谷朗巖開見佛燈，雲遮霧掩碧層層。',32,'全唐诗/poet.song.56000.json','["谷朗巖開見佛燈，雲遮霧掩碧層層。", "青山得意看流水，白鹿歸來失舊僧。"]'),
('456d2350-f834-48ca-8c43-92b69befd663','謝人惠貓頭笋','黄庭堅','宋','宋诗','song-poetry','','[]','長沙一月煨鞭笋，鸚鵡洲前人未知。',32,'全唐诗/poet.song.56000.json','["長沙一月煨鞭笋，鸚鵡洲前人未知。", "走送煩公助湯餠，貓頭突兀想穿籬。"]'),
('a4531115-f555-4d39-8840-eec02975cedf','短韵奉乞臘梅','黄庭堅','宋','宋诗','song-poetry','','[]','卧雲莊上殘花笑，香似早梅開不遲。',32,'全唐诗/poet.song.56000.json','["卧雲莊上殘花笑，香似早梅開不遲。", "淺色春衫弄風日，遣來當爲作新詩。"]'),
('395f1eb9-74e7-457f-a202-e04b7582c26d','以酒渴愛江清作五小詩寄廖明略學士兼簡初和父主簿  其一','黄庭堅','宋','宋诗','song-poetry','','[]','將發沔鄂間，盡醉竹林酒。',48,'全唐诗/poet.song.56000.json','["將發沔鄂間，盡醉竹林酒。", "二三石友輩，未肯棄老朽。", "借問坐客誰，盧溪紫髯叟。", "此翁今惜醉，舊不論升斗。"]'),
('d7d3589a-699d-4cec-8b71-29ce52f713e9','以酒渴愛江清作五小詩寄廖明略學士兼簡初和父主簿  其二','黄庭堅','宋','宋诗','song-poetry','','[]','平生思故人，江漢不解渴。',48,'全唐诗/poet.song.56000.json','["平生思故人，江漢不解渴。", "誰言放逐地，燒燭飲至跋。", "憂予先狗馬，勸以愛膚髮。", "有罪當竄流，但懼不得活。"]'),
('ab237fcf-5d4d-4b85-974b-74fe2b1b323d','以酒渴愛江清作五小詩寄廖明略學士兼簡初和父主簿  其三','黄庭堅','宋','宋诗','song-poetry','','[]','廖侯勸我酒，此亦雅所愛。',48,'全唐诗/poet.song.56000.json','["廖侯勸我酒，此亦雅所愛。", "中年剛制之，常懼作災怪。", "連臺盤拗倒，故人不相貸。", "誰能知許事，痛飲且一快。"]'),
('c36e2dfc-fea0-4cb8-9ac1-490f59adff6d','以酒渴愛江清作五小詩寄廖明略學士兼簡初和父主簿  其四','黄庭堅','宋','宋诗','song-poetry','','[]','竹林文章伯，國士無與雙。',48,'全唐诗/poet.song.56000.json','["竹林文章伯，國士無與雙。", "比來少制作，非以弱故降。", "景陽機中錦，猶衣被丘江。", "時時能度曲，秀句入新腔。"]'),
('0aeb0e3b-88a7-46eb-b657-7f304af0ba48','以酒渴愛江清作五小詩寄廖明略學士兼簡初和父主簿  其五','黄庭堅','宋','宋诗','song-poetry','','[]','斯人絕少可，白眼視公卿。',48,'全唐诗/poet.song.56000.json','["斯人絕少可，白眼視公卿。", "每與俗物逢，三沐取潔清。", "我亦漫浪者，君何許同盟。", "試問盧溪叟，猶得多可名。"]'),
('8c90f7b6-5cc7-420f-abd6-bbf2d343c7f8','四休居士詩三首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','富貴何時潤髑髏，守錢奴與拘官囚。',32,'全唐诗/poet.song.56000.json','["富貴何時潤髑髏，守錢奴與拘官囚。", "太醫診得人間病，安樂延年萬事休。"]'),
('5c584da9-2994-4d43-9fd8-a6952d7785c7','四休居士詩三首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','無求不着看人面，有酒可以留人嬉。',32,'全唐诗/poet.song.56000.json','["無求不着看人面，有酒可以留人嬉。", "欲知四休安樂法，聽取山谷老人詩。"]'),
('fc4cbd69-e0cc-4025-8e57-de31a28d59b6','四休居士詩三首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','一病能惱安樂性，四病長作一生愁。',32,'全唐诗/poet.song.56000.json','["一病能惱安樂性，四病長作一生愁。", "借問四休何所好，不令一點上眉頭。"]'),
('105d0498-d023-4f89-b23b-39b31a1ed417','十二月十九日夜中發鄂渚曉泊漢陽親舊携酒追送聊爲短句','黄庭堅','宋','宋诗','song-poetry','','["\u9001\u522b", "\u8d2c\u8c2a", "\u53cb\u60c5"]','接淅報官府，敢違王事程。',48,'全唐诗/poet.song.56000.json','["接淅報官府，敢違王事程。", "宵征江夏縣，睡起漢陽城。", "鄰里煩追送，杯盤瀉濁清。", "秪應瘴鄉老，難答故人情。"]'),
('10473cf3-d78e-4baf-908f-bec96acd6dca','次韵陳榮緒同倚鐘樓晚望別後明日見寄之作','黄庭堅','宋','宋诗','song-poetry','','[]','天外僧伽塔，斜輝極照臨。',48,'全唐诗/poet.song.56000.json','["天外僧伽塔，斜輝極照臨。", "凭欄隨處好，殘雪向來深。", "青草無風浪，枯松半死心。", "衡陽有回雁，他日更傳音。"]'),
('05f0344c-baf8-42fc-b3fa-549dabac158c','過洞庭青草湖','黄庭堅','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','乙丑越洞庭，丙寅渡青草。',60,'全唐诗/poet.song.56000.json','["乙丑越洞庭，丙寅渡青草。", "似爲神所憐，雪上日杲杲。", "我雖貧至骨，猶勝杜陵老。", "憶昔上岳陽，一飯從人討。", "行矣勿遲留，蕉林追獦獠。"]'),
('28dfd797-56fd-43ac-a608-9595ac1e0138','過土山寨','黄庭堅','宋','宋诗','song-poetry','','[]','南風日日縱篙撐，時喜北風將我行。',32,'全唐诗/poet.song.56000.json','["南風日日縱篙撐，時喜北風將我行。", "湯餠一杯銀線亂，蔞蒿數筯玉簪橫。"]'),
('5b86fee5-aec3-421c-875a-596524f6b6cd','晚泊長沙示秦處度范元實用寄明略和父韵五首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','昔在秦少游，許我同門友。',48,'全唐诗/poet.song.56000.json','["昔在秦少游，許我同門友。", "掘獄無張雷，劍氣在牛斗。", "今來見令子，文似前哲有。", "何用相澆潑，清江綠如酒。"]'),
('3ddc29a8-eadb-4207-bc7a-bacca0c9dc81','晚泊長沙示秦處度范元實用寄明略和父韵五首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','范公太史僚，山立乃先達。',48,'全唐诗/poet.song.56000.json','["范公太史僚，山立乃先達。", "發揮百代史，管以六經轄。", "投身轉嶺海，就木乃京洛。", "仲子見長沙，且用慰饑渴。"]'),
('6c334c99-e87b-4f0a-a25e-00cddd929b0d','晚泊長沙示秦處度范元實用寄明略和父韵五首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','秦郎水江漢，范郎器鼎鼐。',48,'全唐诗/poet.song.56000.json','["秦郎水江漢，范郎器鼎鼐。", "逝者不可尋，猶喜二子在。", "相逢唾珠玉，貧病問薪菜。", "豫愁帆風船，目極別所愛。"]'),
('b486ed69-da41-453a-9ab3-e86396806b2b','晚泊長沙示秦處度范元實用寄明略和父韵五首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','往時高交友，宰木已樅樅。',48,'全唐诗/poet.song.56000.json','["往時高交友，宰木已樅樅。", "今我二三子，事業在燈窗。", "秦范波瀾闊，笑陸海潘江。", "願茲秉經術，出仕榮家邦。"]'),
('05840071-484a-4752-9fa7-440bb0d7a533','晚泊長沙示秦處度范元實用寄明略和父韵五首  其五','黄庭堅','宋','宋诗','song-poetry','','[]','少游五十策，其言明且清。',48,'全唐诗/poet.song.56000.json','["少游五十策，其言明且清。", "筆墨深關鍵，開闔見日星。", "陳友評斯文，如鐘磬鼓笙。", "誰能續鳳鳴，洗耳聽兩甥。"]'),
('e5c43494-563f-4d4a-ae66-71395710a97c','次韵元實病目','黄庭堅','宋','宋诗','song-poetry','','[]','道人嘗恨未灰心，儒士苦愛讀書眼。',131,'全唐诗/poet.song.56000.json','["道人嘗恨未灰心，儒士苦愛讀書眼。", "要須玄覽照鏡空，莫作白魚鑽蠹簡。", "閱人朦朧似有味，看字昏澀尤宜懶。", "范侯年少百夫雄，言行一一無可柬。", "看君眸子當瞭然，乃稱胸次常坦坦。", "如何有物食明月，淚睫隕珠衣袖滿。", "金篦刮膜會有時，湯熨取快術誠短。", "君不見岳頭懶瓚一生禪，鼻涕垂頤渠不管。"]'),
('ff6a31af-0ecb-4756-8cf3-d913d439702c','勝業寺悅亭','黄庭堅','宋','宋诗','song-poetry','','[]','苦雨已解嚴，諸峰來獻狀。',24,'全唐诗/poet.song.56000.json','["苦雨已解嚴，諸峰來獻狀。", "不見白頭禪，空倚紫藤杖。"]'),
('9004fb39-b0e8-4bb3-91f1-94076aee673f','離福嚴','黄庭堅','宋','宋诗','song-poetry','','[]','山下三日晴，山上三日雨。',24,'全唐诗/poet.song.56000.json','["山下三日晴，山上三日雨。", "不見祝融峰，還泝瀟湘去。"]'),
('0d8bf454-6196-46a6-b04b-411c6dd43279','花光仲仁出秦蘇詩卷思二國士不可復見開卷絕歎因花光爲我作梅數枝及畫煙外遠山追少游韵記卷末','黄庭堅','宋','宋诗','song-poetry','','[]','夢蝶真人貌黄槁，籬落逢花須醉倒。',128,'全唐诗/poet.song.56000.json','["夢蝶真人貌黄槁，籬落逢花須醉倒。", "雅聞花光能畫梅，更乞一枝洗煩惱。", "扶持愛梅說道理，自許牛頭參已早。", "長眠橘洲風雨寒，今日梅開向誰好。", "何況東坡成古丘，不復龍蛇看揮掃。", "我向湖南更嶺南，繫船來近花光老。", "歎息斯人不可見，喜我未學霜前草。", "寫盡南枝與北枝，更作千峰倚晴昊。"]'),
('6dc1c65f-2424-4601-a58a-4fc82def8bfd','題花光畫','黄庭堅','宋','宋诗','song-poetry','','[]','湖北山無地，湖南水徹天。',24,'全唐诗/poet.song.56000.json','["湖北山無地，湖南水徹天。", "雲沙真富貴，翰墨小神仙。"]'),
('3ab847b5-11e9-4504-9e8f-7e4d57909576','題花光畫山水','黄庭堅','宋','宋诗','song-poetry','','[]','花光寺下對雲沙，欲把輕舟小釣車。',32,'全唐诗/poet.song.56000.json','["花光寺下對雲沙，欲把輕舟小釣車。", "更看道人煙雨筆，亂峰深處是吾家。"]'),
('420ea836-b676-4a03-9ccf-647e00791325','所住堂','黄庭堅','宋','宋诗','song-poetry','','[]','此山花光佛所住，今日花光還放光。',32,'全唐诗/poet.song.56000.json','["此山花光佛所住，今日花光還放光。", "天女來修散花供，道人自有本來香。"]'),
('f2094c9e-6543-4111-80eb-ab47c49362da','戲詠高節亭邊山礬花二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','北嶺山礬取意開，輕風正用此時來。',32,'全唐诗/poet.song.56000.json','["北嶺山礬取意開，輕風正用此時來。", "平生習氣難料理，愛著幽香未擬迴。"]'),
('b1fa0ff4-f346-46c5-b920-bee55554ad0a','戲詠高節亭邊山礬花二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','高節亭邊竹已空，山礬獨自倚春風。',32,'全唐诗/poet.song.56000.json','["高節亭邊竹已空，山礬獨自倚春風。", "二三名士開顔笑，把斷花光水不通。"]'),
('d603e110-c69a-4091-b12b-afa2f5c6c4cc','贈惠洪','黄庭堅','宋','宋诗','song-poetry','','[]','數面欣羊胛，論詩喜雉膏。',48,'全唐诗/poet.song.56000.json','["數面欣羊胛，論詩喜雉膏。", "眼橫湘水暮，雲獻楚天高。", "墮我玉麈尾，乞君宮錦袍。", "月清放舟舫，萬里渺雲濤。"]'),
('fa22f97b-c75f-4375-9df8-2cc288cd0609','戲詠零陵李宗古居士家馴鷓鴣二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','山雌之弟竹雞兄，乍入雕籠便不驚。',32,'全唐诗/poet.song.56000.json','["山雌之弟竹雞兄，乍入雕籠便不驚。", "此鳥爲公行不得，報晴報雨總同聲。"]'),
('5a0131af-971e-456f-8193-2f9feffac768','戲詠零陵李宗古居士家馴鷓鴣二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','真人夢出大槐宮，萬里蒼梧一洗空。',32,'全唐诗/poet.song.56000.json','["真人夢出大槐宮，萬里蒼梧一洗空。", "終日憂兄行不得，鷓鴣應是鼻亭公。"]'),
('68d6897f-152d-4884-a062-f89bab9618cf','李宗古出示謝李道人苕帚杖從蔣彥回乞葬地二頌作二詩奉呈  其一','黄庭堅','宋','宋诗','song-poetry','','[]','提携禪客扶衰杖，斷當姻家葬骨山。',32,'全唐诗/poet.song.56000.json','["提携禪客扶衰杖，斷當姻家葬骨山。", "因病廢棋仍廢酒，鷓鴣鸚鵡伴清閒。"]'),
('2104ccb9-f272-4968-9b6d-dfae7a6a2606','李宗古出示謝李道人苕帚杖從蔣彥回乞葬地二頌作二詩奉呈  其二','黄庭堅','宋','宋诗','song-poetry','','[]','詩書傳女似中郎，杞菊同盤有孟光。',32,'全唐诗/poet.song.56000.json','["詩書傳女似中郎，杞菊同盤有孟光。", "今日鷓鴣鳴蹇蹇，他年鸚鵡恨堂堂。"]'),
('85f3bd8d-7b09-4d13-b3b0-e330f7d6e076','書磨崖碑後','黄庭堅','宋','宋诗','song-poetry','','["\u6292\u60c5", "\u8bae\u8bba", "\u548f\u53f2\u6000\u53e4", "\u5b8b\u30fb\u8fbd\u30fb\u91d1\u30fb\u5143"]','春風吹船著浯溪，扶藜上讀中興碑。',192,'全唐诗/poet.song.56000.json','["春風吹船著浯溪，扶藜上讀中興碑。", "平生半世看墨本，摩挲石刻鬢成絲。", "明皇不作苞桑計，顛倒四海由祿兒。", "九廟不守乘輿西，萬官已作烏擇栖。", "撫軍監國太子事，何乃趣取大物爲。", "事有至難天幸爾，上皇跼蹐還京師。", "內間張后色可否，外閒李父頤指揮。", "南內淒涼幾苟活，高將軍去事尤危。", "臣結舂陵二三策，臣甫杜鵑再拜詩。", "安知忠臣痛至骨，世上但賞瓊琚詞。", "同來野僧六七輩，亦有文士相追隨。", "斷崖蒼蘚對立久，涷雨爲洗前朝悲。"]'),
('11dcbbb3-11d8-4342-b9d4-cbd7daff8b8f','浯溪圖','黄庭堅','宋','宋诗','song-poetry','','[]','成子寫浯溪，下筆便造極。',48,'全唐诗/poet.song.56000.json','["成子寫浯溪，下筆便造極。", "空濛得真趣，膚寸已千尺。", "只今中宮寺，在昔漫郎宅。", "更作老夫船，檣竿插蒼石。"]'),
('39fa76c8-e0a6-488c-9167-f5ef0854950f','太平寺慈氏閣','黄庭堅','宋','宋诗','song-poetry','','[]','青玻瓈盆插千岑，湘江水清無古今。',64,'全唐诗/poet.song.56000.json','["青玻瓈盆插千岑，湘江水清無古今。", "何處拭目窮表裏，太平飛閣暫登臨。", "朝陽不聞皂蓋下，愚溪但見古木陰。", "誰與洗滌懷古恨，坐有佳客非孤斟。"]'),
('9088421d-9d68-42fd-b403-78b9fed900c8','題淡山巖二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','去城二十五里近，天與隔盡俗子塵。',64,'全唐诗/poet.song.56000.json','["去城二十五里近，天與隔盡俗子塵。", "春蛙秋蠅不到耳，夏凉冬暖總宜人。", "巖中清磬僧定起，洞口綠樹仙家春。", "惜哉次山世未顯，不得雄文鑱翠珉。"]'),
('8b9d8284-c478-4525-8f14-65719d31a2d2','題淡山巖二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','淡山淡姓人安在，徵君避秦亦不歸。',64,'全唐诗/poet.song.56000.json','["淡山淡姓人安在，徵君避秦亦不歸。", "石門竹徑幾時有，瓊臺瑶室至今疑。", "回中明潔坐十客，亦可呼樂醉舞衣。", "閬州城南果何似，永州淡巖天下稀。"]'),
('d9393dff-8e78-4ff4-a2d4-682fc42ad048','明遠庵','黄庭堅','宋','宋诗','song-poetry','','[]','遠公引得陶潛住，美酒沽來飲無數。',96,'全唐诗/poet.song.56000.json','["遠公引得陶潛住，美酒沽來飲無數。", "我醉欲眠卿且去，只有空瓶同此趣。", "誰知明遠似遠公，亦欲我行庵上路。", "多方挈取甕頭春，大白梨花十分注。", "與君深入逍遙遊，了無一物當情素。", "道卿道卿歸去來，明遠主人今進步。"]'),
('422ee90c-fb5a-426e-9d62-9d1db4491389','玉芝園','黄庭堅','宋','宋诗','song-poetry','','[]','春生瀟湘水，風鳴澗谷泉。',192,'全唐诗/poet.song.56000.json','["春生瀟湘水，風鳴澗谷泉。", "過雨花漠漠，弄晴絮翩翩。", "名園上朱閣，觀後復觀前。", "借問昔居人，岑絕無炊煙。", "人生須富貴，河水清且漣。", "百年共如此，安用涕潺湲。", "蔣侯真好事，杖屨喜接連。", "車載溪中骨，推排若差肩。", "厭看孔壬面，醜石反成妍。", "感君勸我醉，吾亦無間然。", "亂我朱碧眼，空花墜便翾。", "行動須人扶，那能金石堅。", "愛君雷氏琴，湯湯發朱絃。", "但恨賞音人，大半隨逝川。", "平生有詩罪，如痼不可痊。", "今當痛自改，三釁復三湔。"]'),
('a64ed9e3-a52a-4f68-9785-2cb805a188e1','遊愚溪','黄庭堅','宋','宋诗','song-poetry','','[]','意行到愚溪，竹輿鳴擔肩。',144,'全唐诗/poet.song.56000.json','["意行到愚溪，竹輿鳴擔肩。", "冉溪昔居人，埋沒不知年。", "偶託文字工，遂以愚溪傳。", "柳侯不可見，古木蔭濺濺。", "羅氏家瀟東，瀟西讀書園。", "笋茁不避道，檀欒摇春煙。", "下入朝陽巖，次山有銘鎸。", "蘚石破篆文，不辨瞿李袁。", "嵌竇響笙磬，洞中出寒泉。", "同遊三五客，拂石弄潺湲。", "俄頃生白雲，似欲駕我仙。", "吾將從此逝，挽牽遂回船。"]'),
('6ae06615-e4d5-43bf-9c84-667d97a34eec','代書寄翠巖新禪師','黄庭堅','宋','宋诗','song-poetry','','[]','山谷青石牛，自負萬鈞重。',96,'全唐诗/poet.song.56000.json','["山谷青石牛，自負萬鈞重。", "八風吹得行，處處是日用。", "又將十六口，去作宜州夢。", "苦憶新老人，是我法梁棟。", "信手斫方圓，規矩一一中。", "遙思靈源叟，分坐法席共。", "聊持楚狂句，往作天女供。", "嶺上早梅春，參軍慙獨弄。"]'),
('21fbad73-3416-4a8c-8722-b975f900eff1','戲答歐陽誠發奉議謝余送茶歌','黄庭堅','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','歐陽子，出陽山。',146,'全唐诗/poet.song.56000.json','["歐陽子，出陽山。", "山奇水怪有異氣，生此突兀熊豹顔。", "飲如江入洞庭野，詩成十手不供寫。", "老來抱璞向涪翁，東坡原是知音者。", "蒼龍璧，官焙香。", "涪翁投贈非世味，自許詩情合得嘗。", "却思翰林來餽光祿酒，兩家水鑑共寒光。", "予乃安敢比東坡，有如玉盤金叵羅。", "直相千萬不啻過，愛公好詩又能多。", "老夫何有更橫戈，奈此于思百戰何。"]'),
('17c9befd-b988-49bf-892b-d6ce610fff64','到桂州','黄庭堅','宋','宋诗','song-poetry','','[]','桂嶺環城如雁蕩，平地蒼玉忽嶒峨。',32,'全唐诗/poet.song.56000.json','["桂嶺環城如雁蕩，平地蒼玉忽嶒峨。", "李成不在郭熙死，奈此百嶂千峰何。"]'),
('860f06c2-d000-4a2c-97b4-169d53ba92ff','答許覺之惠桂花椰子茶盂二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','萬事相尋榮與衰，故人別來鬢成絲。',32,'全唐诗/poet.song.56000.json','["萬事相尋榮與衰，故人別來鬢成絲。", "欲知歲晚在何許，唯說山中有桂枝。"]'),
('0f16df6a-f73a-4876-abc0-120a80106dc3','答許覺之惠桂花椰子茶盂二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','碩果不食寒林梢，剖而器之如懸匏。',32,'全唐诗/poet.song.56000.json','["碩果不食寒林梢，剖而器之如懸匏。", "故人相見各貧病，且可烹茶當酒肴。"]'),
('1c6c97bc-446e-48a4-a745-be9036660680','以椰子茶瓶寄德孺二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','碩果霣林梢，可以代懸匏。',48,'全唐诗/poet.song.56000.json','["碩果霣林梢，可以代懸匏。", "携持二十年，煮茗當酒肴。", "我今禦魑魅，學打衲僧包。", "聊持堅重器，遺我金石交。"]'),
('e0064d4b-6817-4961-81cb-1931a50063fd','以椰子茶瓶寄德孺二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','炎丘椰木實，入用隨茗椀。',48,'全唐诗/poet.song.56000.json','["炎丘椰木實，入用隨茗椀。", "譬如楛矢砮，但貴從來遠。", "往時萬里物，今在籬落間。", "知公一拂拭，想我瘴霧顔。"]'),
('e00cd8e1-7d6a-4924-9465-ebec839b710b','寄黄龍清老三首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','萬山不隔中秋月，一雁能傳寄遠書。',32,'全唐诗/poet.song.56000.json','["萬山不隔中秋月，一雁能傳寄遠書。", "深密伽陀枯戰筆，真成相見問何如。"]'),
('e910cc53-e4e7-4770-b352-61ba461b57af','寄黄龍清老三首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','風前橄欖星宿落，日下桄榔羽扇開。',32,'全唐诗/poet.song.56000.json','["風前橄欖星宿落，日下桄榔羽扇開。", "昭默堂中有相憶，清秋忽遣化人來。"]'),
('13d68e37-af9a-4bd0-bdb8-0c80b50c04a0','寄黄龍清老三首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','騎馿覓馿但可笑，非馬喻馬亦成癡。',32,'全唐诗/poet.song.56000.json','["騎馿覓馿但可笑，非馬喻馬亦成癡。", "一天月色爲誰好，二老風流只自知。"]'),
('a710e81f-decf-42a2-b377-1695a9579327','宜陽別元明用觴字韵','黄庭堅','宋','宋诗','song-poetry','','[]','霜鬚八十期同老，酌我仙人九醖觴。',64,'全唐诗/poet.song.56000.json','["霜鬚八十期同老，酌我仙人九醖觴。", "明月灣頭松老大，永思堂下草荒凉。", "千林風雨鶑求友，萬里雲天雁斷行。", "別夜不眠聽鼠齧，非關春茗攪枯腸。"]'),
('57a922d0-30d7-41ec-b1fb-643b02f0da39','和范信中寓居崇寧遇雨二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','范侯來尋八桂路，走避俗人如脫兔。',96,'全唐诗/poet.song.56000.json','["范侯來尋八桂路，走避俗人如脫兔。", "衣囊夜雨寄禪家，行潦升階漂兩屨。", "遣悶悶不離眼前，避愁愁已知人處。", "慶公憂民苗未立，旻公憂木水推去。", "兩禪有意開壽域，歲晚築室當百堵。", "他時無屋可藏身，且作五里公超霧。"]'),
('040a19ab-3cc9-4ff1-bebc-2b04a6e00f43','和范信中寓居崇寧遇雨二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','當年游俠成都路，黄犬蒼鷹伐狐兔。',96,'全唐诗/poet.song.56000.json','["當年游俠成都路，黄犬蒼鷹伐狐兔。", "二十始肯爲儒生，行尋丈人奉巾屨。", "千江渺然萬山阻，抱衣一囊遍處處。", "或持劍掛宰上回，亦有酒罷壺中去。", "昨來禪榻寄曲肱，上雨傍風破環堵。", "何時鯤化北溟波，好在豹隠南山霧。"]'),
('4a65b1ae-5687-4ac8-8ca3-94571ad87508','乞鍾乳于曾公衮','黄庭堅','宋','宋诗','song-poetry','','[]','寄語曾公子，金丹幾時熟。',48,'全唐诗/poet.song.56000.json','["寄語曾公子，金丹幾時熟。", "願持鍾乳粉，實此罄懸腹。", "遙憐蟹眼湯，已化鵝管玉。", "刀圭勿妄傳，此物非碌碌。"]'),
('7dc61f5b-f16f-4bc9-aeee-4c97c6ebde85','溪上吟','黄庭堅','宋','宋诗','song-poetry','','[]','短生無長期，聊暇日婆娑。',180,'全唐诗/poet.song.56000.json','["短生無長期，聊暇日婆娑。", "出門望高丘，拱木漫春蘿。", "試爲省鬼錄，不飲死者多。", "安能如南山，千歲保不磨。", "在世崇名節，飄如赴燭蛾。", "及汝知悔時，萬事蓬一窠。", "青青陵陂麥，妍暖亦已花。", "長煙淡平川，輕風不爲波。", "無人按律呂，好鳥自和歌。", "杖藜山中歸，牛羊在坡陀。", "本自無廊廟，正爾樂澗阿。", "念昔揚子雲，刻意師孟軻。", "狂夫移九鼎，深巷考四科。", "亦有好事人，時能載酒過。", "無疑舉爾酒，定知我爲何。"]'),
('e77953db-cc76-4987-8c1c-08b7ce78b629','清江引','黄庭堅','宋','宋诗','song-poetry','','[]','江鷗摇蕩荻花秋，八十漁翁百不憂。',64,'全唐诗/poet.song.56000.json','["江鷗摇蕩荻花秋，八十漁翁百不憂。", "清曉采蓮來盪槳，夕陽收網更橫舟。", "羣兒學漁亦不惡，老妻白頭從此樂。", "全家醉著篷底眠，舟在寒沙夜潮落。"]'),
('169d3b52-f1de-4734-8778-c452ad1f4094','次韵叔父聖謨詠鶑遷谷','黄庭堅','宋','宋诗','song-poetry','','[]','鴉舅頗强聒，僕姑常勃谿。',120,'全唐诗/poet.song.56000.json','["鴉舅頗强聒，僕姑常勃谿。", "黄鳥懷好音，秋菊染春衣。", "嚶嚶求朋友，憂患同一枝。", "提壺要酤我，杜宇賦式微。", "黄鳥在幽谷，韜光養羽儀。", "晴風曜桃李，言語自知時。", "先生丘中隠，喬木見雄雌。", "引子遷綠陰，相戒防禍機。", "李杜死刀鋸，陳張怨棄遺。", "不如聽黄鳥，永晝客爭棋。"]'),
('580ab629-6697-4e76-af61-60a18f03fe39','次韵十九叔父臺源','黄庭堅','宋','宋诗','song-poetry','','[]','聞道臺源境，鋤荒三徑通。',48,'全唐诗/poet.song.56000.json','["聞道臺源境，鋤荒三徑通。", "人曾夢蟻穴，鶴亦怕雞籠。", "萬壑秋聲別，千江月體同。", "須知有一路，不在白雲中。"]'),
('c340addb-ded8-49d6-bc63-12329f6103f1','叔父釣亭','黄庭堅','宋','宋诗','song-poetry','','[]','檻外溪風拂面凉，四圍春草自鋤荒。',64,'全唐诗/poet.song.56000.json','["檻外溪風拂面凉，四圍春草自鋤荒。", "陸沈霜髮爲鈎直，柳貫錦鱗緣餌香。", "影落華亭千尺月，夢通岐下六州王。", "麒麟卧笑功名骨，不道山林日月長。"]'),
('d27ceda4-b4ff-4b4e-9bd8-97156ec908ae','巖下放言五首 釣臺','黄庭堅','宋','宋诗','song-poetry','','[]','林居野處，而貫萬事。',60,'全唐诗/poet.song.56000.json','["林居野處，而貫萬事。", "花落鳥啼，而成四時。", "物有才德，水爲官師。", "空明湛羣木之影，搏擊下諸峰之巇。", "游魚靜而知機，君子樂而忘歸。"]'),
('c3a066ec-77f2-4f30-90e3-27acb9dc4630','巖下放言五首 池亭','黄庭堅','宋','宋诗','song-poetry','','[]','水嬉者游魚，林樂者啼鳥。',41,'全唐诗/poet.song.56000.json','["水嬉者游魚，林樂者啼鳥。", "志士仁人觀其大，薪翁笱婦利其小。", "有美一人，獨燕居萬物之表。"]'),
('7b5cc0ca-694a-4dfb-90a0-ac147ec35aaa','巖下放言五首 冠鼇臺','黄庭堅','宋','宋诗','song-poetry','','[]','石生涯于寒藤，藤耈造于崖樹。',56,'全唐诗/poet.song.56000.json','["石生涯于寒藤，藤耈造于崖樹。", "鼇插翼而成鵬，隘六合而未翥。", "我來兮自東，攀桂枝兮容與。", "倚嵌巖兮顧同來，謂公等其皆去。"]'),
('fa4f069e-fefe-4e45-8c35-29d255a8d097','巖下放言五首 博山臺','黄庭堅','宋','宋诗','song-poetry','','[]','石藴璵璠，山得其來之澤。',72,'全唐诗/poet.song.56000.json','["石藴璵璠，山得其來之澤。", "木無犧象，天開不材之祥。", "屹金爐之突兀，其山海之來翔。", "然以明哲之火，熏以忠信之香。", "俯仰一時，非智所及。", "付與萬世，其存者長。"]'),
('85c74093-92d7-43b9-b52c-20215be4d6f2','巖下放言五首 靈椿臺','黄庭堅','宋','宋诗','song-poetry','','[]','蒼苔古木，相依澗壑之濱。',58,'全唐诗/poet.song.56000.json','["蒼苔古木，相依澗壑之濱。", "黄葛女蘿，自致風雲之上。", "人就陰而息迹，鳥投暮而來歸。", "水影林光，常相助發。", "溪聲斧響，直下稱提。"]'),
('dd40a1db-b180-45ca-afd8-6d31033d2e76','寄傅君倚同年','黄庭堅','宋','宋诗','song-poetry','','[]','有情清江水，東下投豫章。',156,'全唐诗/poet.song.56000.json','["有情清江水，東下投豫章。", "故人江上居，不寄書一行。", "相思對明月，談笑如清光。", "向風長歎息，孤雁起寒塘。", "傾寫鬰結懷，因之東南翔。", "姑氏有淑質，幽林蘭靜芳。", "願因奉箕帚，蘋藻羞烝嘗。", "念君方策名，要津邁騰驤。", "引車入里門，觀者塞路旁。", "雝雝求匹好，羔雁委潘楊。", "顧惟蓬茅陋，豈能屈東牀。", "眷言南鳴雁，七子伊在桑。", "幸緣一日雅，結好永不忘。"]'),
('a850c3be-45a6-4dfc-82e6-41a547ad8945','答德甫弟','黄庭堅','宋','宋诗','song-poetry','','[]','鳥啼花發獨愁思，憐子三章怨慕詩。',64,'全唐诗/poet.song.56000.json','["鳥啼花發獨愁思，憐子三章怨慕詩。", "鴻雁雙飛彈射下，脊令同病急難時。", "功名所在猶爭死，意氣相須尚不移。", "何況極天無以報，林回投璧負嬰兒。"]'),
('0f906cc3-e2b8-419a-9870-0e710b550fff','贈元發弟放言','黄庭堅','宋','宋诗','song-poetry','','[]','虧功一簣，未成丘山。',56,'全唐诗/poet.song.56000.json','["虧功一簣，未成丘山。", "鑿井九階，不次水澤。", "行百里者半九十，小狐汔濟濡其尾。", "故曰時乎，時不再來。", "終終始始，是謂君子。"]'),
('f15d6330-9c3a-4b0e-b3e1-75315db50464','清明','黄庭堅','宋','宋诗','song-poetry','','["\u6e05\u660e\u8282", "\u4eba\u751f", "\u5199\u666f", "\u611f\u53f9"]','佳節清明桃李笑，野田荒壠只生愁。',64,'全唐诗/poet.song.56000.json','["佳節清明桃李笑，野田荒壠只生愁。", "雷驚天地龍蛇蟄，雨足郊原草木柔。", "人乞祭餘驕妾婦，士甘焚死不公侯。", "賢愚千載知誰是，滿眼蓬蒿共一丘。"]'),
('7820248d-e644-4696-9765-b5873c51bcad','何造誠作浩然堂陳義甚高然頗喜度世飛昇之說築屋飯方士願乘六氣遊天地間故作浩然詞二章贈之  其一','黄庭堅','宋','宋诗','song-poetry','','[]','公欲輕身上紫霞，瓊爢玉饌厭豪奢。',64,'全唐诗/poet.song.56000.json','["公欲輕身上紫霞，瓊爢玉饌厭豪奢。", "百年世路同朝菌，九鑰天關守夜叉。", "霜檜左紐空白鹿，金爐同契漫丹砂。", "要令心地閒如水，萬物浮沈共我家。"]'),
('d7951c56-eb27-4a9c-b69b-057f8c97ccb3','何造誠作浩然堂陳義甚高然頗喜度世飛昇之說築屋飯方士願乘六氣遊天地間故作浩然詞二章贈之  其二','黄庭堅','宋','宋诗','song-poetry','','[]','萬物浮沈共我家，清明心水徧河沙。',64,'全唐诗/poet.song.56000.json','["萬物浮沈共我家，清明心水徧河沙。", "無鉤狂象聽人語，露地白牛看月斜。", "小雨呼兒蓺桃李，疏簾幃客轉琵琶。", "塵塵三昧開門戶，不用丹田養素霞。"]'),
('9366d919-de67-42cb-a17a-da1089a2b23e','徐孺子祠堂','黄庭堅','宋','宋诗','song-poetry','','["\u51ed\u540a", "\u6292\u6000", "\u5b8b\u30fb\u8fbd\u30fb\u91d1\u30fb\u5143", "\u8bbd\u523a"]','喬木幽人三畝宅，生芻一束向誰論。',64,'全唐诗/poet.song.56000.json','["喬木幽人三畝宅，生芻一束向誰論。", "藤蘿得意干雲日，簫鼓何心進酒樽。", "白屋可能無孺子，黄堂不是欠陳蕃。", "古人冷淡今人笑，湖水年年到舊痕。"]'),
('55997e31-75de-411c-a5ab-3b23ab00b8a4','思親汝州作','黄庭堅','宋','宋诗','song-poetry','','[]','歲晚寒侵遊子衣，拘留幕府報官移。',64,'全唐诗/poet.song.56000.json','["歲晚寒侵遊子衣，拘留幕府報官移。", "五更歸夢三百里，一日思親十二時。", "車上吐茵元不逐，市中有虎竟成疑。", "秋毫得失關何事，總爲平安書到遲。"]'),
('6fdc89bf-f6f7-48f1-942d-2f8c5a60a8d5','次韵戲答彥和','黄庭堅','宋','宋诗','song-poetry','','[]','本不因循老鏡春，江湖歸去作閒人。',64,'全唐诗/poet.song.56000.json','["本不因循老鏡春，江湖歸去作閒人。", "天于萬物定貧我，智效一官全爲親。", "布袋形骸增碨磊，錦囊詩句媿清新。", "杜門絕俗無行迹，相憶猶當遣化身。"]'),
('a657614d-4c61-44de-9413-6e161cd34e78','次韵裴仲謀同年','黄庭堅','宋','宋诗','song-poetry','','[]','交蓋春風汝水邊，客牀相對卧僧氈。',64,'全唐诗/poet.song.56000.json','["交蓋春風汝水邊，客牀相對卧僧氈。", "舞陽去葉纔百里，賤子與公皆少年。", "白髮齊生如有種，青山好去坐無錢。", "煙沙篁竹江南岸，輸與鸕鷀取次眠。"]'),
('de9f5ab7-1df5-4940-ab69-3f1e760f5f50','流民歎','黄庭堅','宋','宋诗','song-poetry','','[]','朔方頻年無好雨，五種不入虛春秋。',244,'全唐诗/poet.song.56000.json','["朔方頻年無好雨，五種不入虛春秋。", "邇來后土中夜震，有似巨鼇復戴三山遊。", "傾牆摧棟壓老弱，冤聲未定隨洪流。", "地文劃劙水觱沸，十戶八九生魚頭。", "稍聞澶淵渡河日數萬，河北不知虛幾州。", "纍纍襁負襄葉間，問舍無所耕無牛。", "初來猶自得曠土，嗟爾後至將何怙。", "刺史守令真分憂，明詔哀痛如父母。", "廟堂已用伊呂徒，何時眼前見安堵。", "疏遠之謀未易陳，市上三言或成虎。", "禍災流行固無時，堯湯水旱人不知。", "桓侯之疾初無證，扁鵲入秦始治病。", "投膠盈掬俟河清，一簞豈能續民命。", "雖然猶願及此春，略講周公十二政。", "風生羣口方出奇，老生常談幸聽之。"]'),
('7b5f9a8e-d48e-46e8-b8a6-e68e6cfd553a','次韵寄滑州舅氏','黄庭堅','宋','宋诗','song-poetry','','[]','舫齋聞有小溪山，便是壺公謫處天。',64,'全唐诗/poet.song.56000.json','["舫齋聞有小溪山，便是壺公謫處天。", "想聽瑣窗深夜雨，似看葉水上江船。", "瞻相白馬津亭路，寂寞雙鳬古縣前。", "舅氏知甥最疏嬾，折腰塵土解哀憐。"]'),
('ccaaa679-b894-4004-8159-119f37bc88e5','張仲謀家堂前酴醾委地','黄庭堅','宋','宋诗','song-poetry','','[]','沈水衣籠白玉苗，不蒙湔拂苦無聊。',32,'全唐诗/poet.song.56000.json','["沈水衣籠白玉苗，不蒙湔拂苦無聊。", "煩君斫取西莊柳，扶起春風十萬條。"]'),
('12eb1484-dcc2-478f-a653-dcbb1aab1e1f','和答登封王晦之登樓見寄','黄庭堅','宋','宋诗','song-poetry','','["\u6292\u60c5", "\u5199\u666f"]','縣樓三十六峰寒，王粲登臨獨倚闌。',64,'全唐诗/poet.song.56000.json','["縣樓三十六峰寒，王粲登臨獨倚闌。", "清坐一番春雨歇，相思千里夕陽殘。", "詩來嗟我不同醉，別後喜君能自寬。", "舉目盡妨人作樂，幾時歸得釣鯢桓。"]'),
('ebac1c1f-9fa0-4a64-91fd-01b578606119','和答孫不愚見贈','黄庭堅','宋','宋诗','song-poetry','','[]','詩比淮南似小山，酒名麴米出雲安。',64,'全唐诗/poet.song.56000.json','["詩比淮南似小山，酒名麴米出雲安。", "且憑詩酒勤春事，莫愛兒郎作好官。", "簿領侵尋台相筆，風埃蓬勃使星鞍。", "小臣才力堪爲掾，敢學前人便挂冠。"]'),
('fcd45b34-9ff5-45b2-8f13-5a600899b1a8','睡起','黄庭堅','宋','宋诗','song-poetry','','[]','彷彿江南一夢中，虛堂盡日轉溫風。',32,'全唐诗/poet.song.56000.json','["彷彿江南一夢中，虛堂盡日轉溫風。", "春深稍覺裌衣重，晝永不知樽酒空。"]'),
('6047342e-2e4a-44bb-bf5d-19f2eeace5a0','還家呈伯氏','黄庭堅','宋','宋诗','song-poetry','','[]','去日櫻桃初破花，歸來著子如紅豆。',274,'全唐诗/poet.song.56000.json','["去日櫻桃初破花，歸來著子如紅豆。", "四時驅迫少須臾，兩鬢飄零成老醜。", "永懷往在江南日，原上急難風雨後。", "私田苦薄王稅多，諸弟號寒諸妹瘦。", "扶將白髮渡江來，吾二人如左右手。", "苟從祿仕我邅回，且慰家貧兄孝友。", "强趨手板汝陽城，更責愆期被訶詬。", "法官毒螫草自摇，丞相霜威人避走。", "賤貧孤遠蓋如此，此事端于我何有。", "一囊粟麥七十錢，五人兄弟二十口。", "官如元亮且折腰，心似次山羞曲肘。", "北窗書冊久不開，筐篋黄塵生鎖鈕。", "何當略得共討論，況乃雍容把杯酒。", "意氣敷腴貴壯年，不早計之且衰朽。", "安得短船萬里隨江風，養魚去作陶朱公。", "斑衣奉親伯與儂，四方上下相依從。", "用舍由人不由己，乃是伏轅駒犢耳。"]'),
('17168239-5863-4967-9175-616f8b6b47eb','次韵時進叔二十六韵','黄庭堅','宋','宋诗','song-poetry','','[]','時子河上園，竹間開棟宇。',288,'全唐诗/poet.song.56000.json','["時子河上園，竹間開棟宇。", "大兒勝衣冠，小兒豐頰輔。", "嫁女與朱公，伏臘可稱舉。", "髮疏雖蒼浪，齒嚼未齟齬。", "雞棲牛羊下，各自有室處。", "四牆規摹小，易守若滕莒。", "舍前花木深，春物麗觀睹。", "舍後曲池蛙，齋堂風月苦。", "此豈不足歟，歎歲不我與。", "客宦孤雲耳，未知秦吳楚。", "向來千駟公，果媿一丘土。", "寧當損軒昂，聊欲效俯傴。", "時子听然笑，吾已悟倉鼠。", "少猶守章句，晚實愛農圃。", "鵲巢最知風，蟻穴識陰雨。", "世網事諳委，醉鄉俗淳古。", "坐忘兩家說，肉堅與腸腐。", "酒至即使傾，客來敢辭窶。", "時邀五柳陶，共過三徑詡。", "往在少年場，豪氣壓潁汝。", "借令今尚爾，真復難共語。", "稍知憐麴糵，漸解等灉濋。", "朋友半山阿，光陰共行旅。", "人故義當親，衣故義當補。"]'),
('9439d0f5-6566-481b-8b67-ef8c37de47ab','寄黄從善','黄庭堅','宋','宋诗','song-poetry','','[]','故人千里隔談經，想見牛刀刃發硎。',64,'全唐诗/poet.song.56000.json','["故人千里隔談經，想見牛刀刃發硎。", "渴雨芭蕉心不展，未春楊柳眼先青。", "鳬飛葉縣郎官宰，虹貫江南處士星。", "天子文思求逆耳，吾宗一爲試雷霆。"]'),
('c81aa685-4349-4736-b508-db9c289a2c14','薛樂道自南陽來入都留宿會飲作詩餞行','黄庭堅','宋','宋诗','song-poetry','','[]','薛侯本貴胄，射策一矢中。',288,'全唐诗/poet.song.56000.json','["薛侯本貴胄，射策一矢中。", "金蘭託平生，瓜葛比諸從。", "數面尚成親，況乃居連棟。", "交游及父子，講學連伯仲。", "奴人通使令，孩稚接戲弄。", "相憐負米勤，同力采蘭供。", "每持君家書，平安覷款縫。", "秦人與吾炙，憂樂一體共。", "釋之廷尉曹，微過成繫訟。", "從此張長公，不肯爲時用。", "丘阿無梧桐，曲直不在鳳。", "生涯谷口耕，世事邯鄲夢。", "自君抱憂端，酒椀未忍齅。", "高秋自南歸，意氣稍寬縱。", "黄花尚滿籬，白蟻方浮甕。", "私言助燕喜，且莫戒輜重。", "霜風獵帷幕，銀燭吐螮蝀。", "密坐幸頗歡，劇飲寧辭痛。", "疏鐘鳴曉撞，小雨作寒霿。", "廐馬蕭蕭鳴，征人稍稍動。", "九衢槐柳中，縱緩青絲鞚。", "朱樓豪士集，紅袖清歌送。", "河鯉獻鱠材，江橙解包貢。", "蟹擘鵝子黄，酒傾琥珀凍。"]'),
('0f01eaff-6716-4d69-878d-bf6209f41b25','戲詠江南土風','黄庭堅','宋','宋诗','song-poetry','','[]','十月江南未得霜，高林殘水下寒塘。',64,'全唐诗/poet.song.56000.json','["十月江南未得霜，高林殘水下寒塘。", "飯香獵戶分熊白，酒熟漁家擘蟹黄。", "橘摘金苞隨驛使，禾舂玉粒送官倉。", "踏歌夜結田神社，游女多隨陌上郎。"]'),
('1f7a21c5-3a3c-4406-ace1-6def47c2c50f','弈棋二首呈任公漸  其一','黄庭堅','宋','宋诗','song-poetry','','[]','偶無公事負朝暄，三百枯棋共一樽。',64,'全唐诗/poet.song.56000.json','["偶無公事負朝暄，三百枯棋共一樽。", "坐隠不知巖穴樂，手談勝與俗人言。", "簿書堆積塵生案，車馬淹留客在門。", "戰勝將驕疑必敗，果然終取敵兵翻。"]'),
('6c14e9b8-3acd-4766-bb07-13dea707a5de','弈棋二首呈任公漸  其二','黄庭堅','宋','宋诗','song-poetry','','[]','偶無公事客休時，席上談兵校兩棋。',64,'全唐诗/poet.song.56000.json','["偶無公事客休時，席上談兵校兩棋。", "心似蛛絲遊碧落，身如蜩甲化枯枝。", "湘東一目誠甘死，天下中分尚可持。", "誰謂吾徒猶愛日，參橫月落不曾知。"]'),
('980b5d6a-9553-4814-b8f7-13349353c641','謝曉純送衲襪','黄庭堅','宋','宋诗','song-poetry','','[]','剗草曾升馬祖堂，暖窗接膝話還鄉。',32,'全唐诗/poet.song.56000.json','["剗草曾升馬祖堂，暖窗接膝話還鄉。", "贈行百衲兜羅襪，處處相隨入道場。"]'),
('eabc7df5-41b8-4ae3-aaee-04453da88310','衝雪宿新寨忽忽不樂','黄庭堅','宋','宋诗','song-poetry','','[]','縣北縣南何日了，又來新寨解征鞍。',64,'全唐诗/poet.song.56000.json','["縣北縣南何日了，又來新寨解征鞍。", "山銜斗柄三星沒，雪共月明千里寒。", "小吏有時須束带，故人頗問不休官。", "江南長盡捎雲竹，歸及春風斬釣竿。"]'),
('d2b6acdb-75b3-47d4-909b-32b1021cf6d8','聽崇德君鼓琴','黄庭堅','宋','宋诗','song-poetry','','[]','月明江靜寂寥中，大家斂袂撫孤桐。',120,'全唐诗/poet.song.56000.json','["月明江靜寂寥中，大家斂袂撫孤桐。", "古人已矣古樂在，彷彿雅頌之遺風。", "妙手不易得，善聽良獨難。", "猶如優曇華，時一出世間。", "兩忘琴意與己意，迺似不著十指彈。", "禪心默默三淵靜，幽谷清風淡相應。", "絲聲誰道不如竹，我已忘言得真性。", "罷琴窗外月沈江，萬籟俱空七絃定。"]'),
('9fa464b6-7fea-47b8-872a-21f9daa54f18','郭明甫作西齋于潁尾請予賦詩二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','食貧自以官爲業，聞說西齋意凜然。',64,'全唐诗/poet.song.56000.json','["食貧自以官爲業，聞說西齋意凜然。", "萬卷藏書宜子弟，十年種木長風煙。", "未嘗終日不思潁，想見先生多好賢。", "安得雍容一樽酒，女郎臺下水如天。"]'),
('cc8d0f96-af63-4788-88e0-50ae3382a3c3','郭明甫作西齋于潁尾請予賦詩二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','東京望重兩并州，遂有汾陽整綴旒。',64,'全唐诗/poet.song.56000.json','["東京望重兩并州，遂有汾陽整綴旒。", "翁伯入關傾意氣，林宗異世想風流。", "君家舊事皆青史，今日高材未白頭。", "莫倚西齋好風月，長隨三徑古人遊。"]'),
('d51d979a-561f-4d7b-8162-2fc027a156dd','勸交代張和父酒','黄庭堅','宋','宋诗','song-poetry','','[]','風流五日張京兆，今日諸孫困小官。',64,'全唐诗/poet.song.56000.json','["風流五日張京兆，今日諸孫困小官。", "作尹大都如廣漢，畫眉仍復近長安。", "三人成虎事多有，衆口鑠金君自寬。", "酒興情親俱不淺，賤生何取罄交歡。"]'),
('798fea4f-ba20-4038-8646-92128171e3f4','過平輿懷李子先時在并州','黄庭堅','宋','宋诗','song-poetry','','["\u6292\u60c5", "\u5199\u666f", "\u529d\u8beb", "\u9690\u5c45"]','前日幽人佐吏曹，我行隄草認青袍。',64,'全唐诗/poet.song.56000.json','["前日幽人佐吏曹，我行隄草認青袍。", "心隨汝水春波動，興與并門夜月高。", "世上豈無千里馬，人中難得九方臯。", "酒船魚網歸來是，花落故溪深一篙。"]'),
('bbde8acb-b5e9-4e3a-b115-b2d76b1a56d5','以金沙酴醾送公壽','黄庭堅','宋','宋诗','song-poetry','','[]','天遣酴醾玉作花，紫綿揉色染金沙。',32,'全唐诗/poet.song.56000.json','["天遣酴醾玉作花，紫綿揉色染金沙。", "憑君著意樽前看，便與春工立等差。"]'),
('c1dac030-0640-4cf6-92d7-f4c5c2b52d49','寄懷公壽','黄庭堅','宋','宋诗','song-poetry','','[]','好賦梁王在日邊，重簾複幕鎖神仙。',64,'全唐诗/poet.song.56000.json','["好賦梁王在日邊，重簾複幕鎖神仙。", "莫因酒病疏桃李，且把春愁付管絃。", "愚智相懸三十里，榮枯同有百餘年。", "及身强健且行樂，一笑端須直萬錢。"]'),
('b19102f2-02f6-4c22-9ccb-7b368e4c9834','武陵','黄庭堅','宋','宋诗','song-poetry','','[]','武陵樵客出桃源，自許重遊不作難。',32,'全唐诗/poet.song.56000.json','["武陵樵客出桃源，自許重遊不作難。", "却覓洞門煙鎖斷，歸舟風月夜深寒。"]'),
('814feabb-4a50-4539-b95e-c874e004bcd2','呻吟齋睡起五首呈世弼  其一','黄庭堅','宋','宋诗','song-poetry','','[]','棐几坐清晝，博山凝妙香。',48,'全唐诗/poet.song.56000.json','["棐几坐清晝，博山凝妙香。", "蘭芽依客土，柳色過鄰牆。", "巷僻過從少，官閒氣味長。", "江南一枕夢，高卧聽鳴桹。"]'),
('cc163a51-613a-49c9-95d0-02953954c4dd','呻吟齋睡起五首呈世弼  其二','黄庭堅','宋','宋诗','song-poetry','','[]','學省非簿領，卧痾常閉關。',48,'全唐诗/poet.song.56000.json','["學省非簿領，卧痾常閉關。", "雨餘樓閣靜，風晚鳥烏還。", "賞逐四時改，心安一味閒。", "古人雖已往，不廢仰高山。"]'),
('444ac3e6-0f76-4f89-9625-b2cb1b6b4ac7','呻吟齋睡起五首呈世弼  其三','黄庭堅','宋','宋诗','song-poetry','','[]','疏食吾猶飽，曲肱哦古今。',48,'全唐诗/poet.song.56000.json','["疏食吾猶飽，曲肱哦古今。", "酒傾因好事，絃絕爲知音。", "妬蘗長春木，爭巢喧暮禽。", "長懷阮校尉，北望首陽岑。"]'),
('57dd6ae2-8776-4f26-859d-e79354dea28f','呻吟齋睡起五首呈世弼  其四','黄庭堅','宋','宋诗','song-poetry','','[]','已把社公酒，春寒那得嚴。',48,'全唐诗/poet.song.56000.json','["已把社公酒，春寒那得嚴。", "厭聽鴻啄雪，喜有燕穿簾。", "璞玉深藏器，囊錐立見尖。", "兒時愛談道，今日口如箝。"]'),
('f87945bc-1c15-4858-aea5-0929b7b98d05','呻吟齋睡起五首呈世弼  其五','黄庭堅','宋','宋诗','song-poetry','','[]','牆下蓬蒿地，兒童課翦除。',48,'全唐诗/poet.song.56000.json','["牆下蓬蒿地，兒童課翦除。", "蔓萵隨分種，杞菊未須遊。", "河水傳烽火，交州報捷書。", "無能落閒處，慙媿飽春蔬。"]'),
('80daae00-4662-45bd-aeb8-d4868296befb','奉答子高見贈十韵','黄庭堅','宋','宋诗','song-poetry','','[]','柳徑雨著綿，竹齋風隕籜。',120,'全唐诗/poet.song.56000.json','["柳徑雨著綿，竹齋風隕籜。", "屏處人事少，晴餘鳥聲樂。", "詩卷墮我前，謂從天上落。", "君有古人風，詩如古人作。", "簞瓢謝膏粱，翰墨化糟粕。", "誤蒙東海觀，吾淺迺可酌。", "真成聞道百，自謂莫己若。", "謝生石韞玉，志尚本丘壑。", "雖無首陽粟，飲水亦不惡。", "跫然何時來，爲我一發藥。"]'),
('3faa0395-9a9f-41d6-85e0-1ff7e8e8e588','招子高二十二韵兼簡常甫世弼','黄庭堅','宋','宋诗','song-poetry','','[]','我行向厭次，夏扇日在摇。',264,'全唐诗/poet.song.56000.json','["我行向厭次，夏扇日在摇。", "甘瓜未除壟，高柳尚鳴蜩。", "駕言聊攝歸，飛霜曉封條。", "負薪泣裘褐，公子御狐貂。", "歲月坐晼晚，鬢顔颯然凋。", "道德千古事，斯文非一朝。", "往者我不及，後生多見超。", "吾黨二三子，士林聳孤標。", "小謝抱周易，忘言獨參寥。", "崔郎楚左史，二典考舜堯。", "王生風雅學，談辯秋江潮。", "灑筆驚有司，小敵謂可驕。", "安知摴蒱局，臨關敗三梟。", "三生數步隔，屢赴茗碗邀。", "小謝殊未來，我覺百里遙。", "問之憂菽水，心慮極無聊。", "父憐母不訶，日以濁酒澆。", "此道如鼎實，念子羹未調。", "古來有親養，回也樂一瓢。", "不田鶉生宎，在物乃爲妖。", "吾言有師承，可信如斗杓。", "詩以解子憂，亦用當子招。"]'),
('5de77fa8-b3d0-4a91-ac4f-0a9b5511d731','次韵謝子高讀淵明傳','黄庭堅','宋','宋诗','song-poetry','','[]','枯木嵌空微暗淡，古器雖在無古絃。',64,'全唐诗/poet.song.56000.json','["枯木嵌空微暗淡，古器雖在無古絃。", "袖中正有南風手，誰爲聽之誰爲傳。", "風流豈落正始後，甲子不數義熙前。", "一軒黄菊平生事，無酒令人意缺然。"]'),
('32594c85-4f73-400f-9ebf-3f09c0c6508d','奉和王世弼寄上七兄先生用其韵','黄庭堅','宋','宋诗','song-poetry','','[]','宮槐弄黄黄，蓮葉綠婉婉。',288,'全唐诗/poet.song.56000.json','["宮槐弄黄黄，蓮葉綠婉婉。", "時同二三友，竹軒凉夏晚。", "駕言都城南，以望征車返。", "何知苦淹回，及此秋景短。", "愁思令人瘦，舉目道路遠。", "西風脫一葉，薦士聞鄉選。", "簡書催渡河，賓客不得展。", "親憂對萱叢，婦病廢巾盥。", "言趨厭次城，鞭馬倦長阪。", "棗林蔽天日，交陰不容繖。", "仰看實離離，憶見花纂纂。", "異鄉懷節物，不共斟酒盞。", "舉場下馬入，深鎖嚴籥管。", "諸生所程書，捃束若稭稈。", "蜜燈坐回環，丹硯精料柬。", "披榛拔芝蘭，斷石收琰琬。", "紛爭一日事，聲實溷端窾。", "天球或棄遺，斗筲尚何算。", "西歸到官舍，塵土昏案版。", "寒窗穿碧疏，潤礎鬧蒼蘚。", "詩書鵲巢翻，帷幔蛛絲罥。", "果知兄未來，光陰坐晼晚。", "昨蒙叔父報，亦歎音書簡。", "薄言使事重，激切被天遣。"]'),
('9351c852-8735-454f-b74a-b89804cc1f1b','送吳彥歸番陽','黄庭堅','宋','宋诗','song-poetry','','[]','學省困齏鹽，人材任尊奬。',288,'全唐诗/poet.song.56000.json','["學省困齏鹽，人材任尊奬。", "倥侗祝螟蛉，小大器罌瓬。", "諸生厭晚成，躐學要儈駔。", "摹書說偏旁，破義析名象。", "九鼎奏簫韶，爰居端不饗。", "青衿少到門，庭除晝閒敞。", "竹風交槐陰，三見秋氣爽。", "時頼解事人，載酒直心賞。", "吳郎楚國材，幽蘭秀榛莽。", "彥國吐嘉言，子將喜標榜。", "平生欽豪俊，久客慕鄉黨。", "虛齋延灑掃，薄飯薦腒鮝。", "詩句唾成珠，笑嘲愜爬痒。", "春夏頻謝除，曾未厭來往。", "歸雁多喜聲，寒蟬停哀響。", "黄花滿籬落，白蟻鬧甕盎。", "留君待佳節，忽忽戒徂兩。", "親戚傷離居，交游念疇曩。", "棋局無對曹，摴蒱失朋長。", "問君去爲何，雲物愁莽蒼。", "壽親髮斑斑，千里勞夢想。", "家雞藁頭肥，寒魚受罾網。", "甘旨蔌中厨，伊啞弄文襁。", "此行樂未央，安知川塗廣。"]'),
('8cbe2eaa-6c15-44d8-885f-61ff2bf88c0a','二月丁卯喜雨吳體爲北門留守文潞公作','黄庭堅','宋','宋诗','song-poetry','','[]','乘輿齋祭甘泉宮，遣使駿奔河岳中。',64,'全唐诗/poet.song.56000.json','["乘輿齋祭甘泉宮，遣使駿奔河岳中。", "誰與至尊分旰食，北門卧鎮司徒公。", "微風不動天如醉，潤物無聲春有功。", "三十餘年霖雨手，淹留河外作時豐。"]'),
('0044aba8-2580-4e44-adaf-8ed7de6a1532','李右司以詩送梅花至潞公予雖不接右司想見其人用老杜和元次山詩例次韵','黄庭堅','宋','宋诗','song-poetry','','[]','凡花俗草敗人意，晚見瓊蕤不恨遲。',32,'全唐诗/poet.song.56000.json','["凡花俗草敗人意，晚見瓊蕤不恨遲。", "江左風流尚如此，春功終到歲寒枝。"]'),
('f9372b8f-d8a6-402a-88ed-6cdfd5fa9ba3','次韵外舅喜王正仲三丈奉詔禱南岳回至襄陽舍驛馬就舟見過三首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','漢上思見龐德公，別來悲歎事無窮。',64,'全唐诗/poet.song.56000.json','["漢上思見龐德公，別來悲歎事無窮。", "聲名藉甚漫前日，鬚鬢索然成老翁。", "家釀已隨刻漏下，園花更開三四紅。", "相逢不飲未爲得，聽取百鳥啼匆匆。"]'),
('d72fc96a-6f5e-4770-9d62-1b9754b5a88a','次韵外舅喜王正仲三丈奉詔禱南岳回至襄陽舍驛馬就舟見過三首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','能來問疾好音傳，蹇步昏花當日痊。',64,'全唐诗/poet.song.56000.json','["能來問疾好音傳，蹇步昏花當日痊。", "烹鯉得書增目力，呼兒扶立候門前。", "游談取重慙犀首，居物多贏昧計然。", "惟有交親等金石，白頭忘義復忘年。"]'),
('6ff704cb-cad9-496d-a183-33aa5d7878ba','次韵外舅喜王正仲三丈奉詔禱南岳回至襄陽舍驛馬就舟見過三首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','語言少味無阿堵，冰雪相看有此君。',64,'全唐诗/poet.song.56000.json','["語言少味無阿堵，冰雪相看有此君。", "燈火詩書如夢寐，麒麟圖畫屬浮雲。", "平章息女能爲婦，歡喜兒曹解綴文。", "憂樂同科惟石友，別離空復數朝曛。"]'),
('dad638a9-85e3-47d9-af95-7fc208146558','次韵正仲三丈自衡山返命舍驛過外舅師厚贈答','黄庭堅','宋','宋诗','song-poetry','','["\u8861\u5c71"]','昏昏市井氣，呫呫兒女語。',84,'全唐诗/poet.song.56000.json','["昏昏市井氣，呫呫兒女語。", "禽喧聲百種，春作事萬緒。", "人間雞黍期，天上德星聚。", "乖離略十年，髮白齒齟齬。", "太史禱衡丘，佐王用貔虎。", "子雲免大夫，草玄空自苦。", "人生只爾是，付與甕頭醑。"]'),
('ab6d793c-374c-4ed2-a2a9-82819601f0b1','次韵子瞻春菜','黄庭堅','宋','宋诗','song-poetry','','[]','北方春蔬嚼冰雪，妍暖思采南山蕨。',128,'全唐诗/poet.song.56000.json','["北方春蔬嚼冰雪，妍暖思采南山蕨。", "韭苗水餠姑置之，苦菜黄雞羹糝滑。", "蓴絲色紫菰首白，蔞蒿芽甜蔊頭辣。", "生葅入湯翻手成，芼以薑橙誇縷抹。", "驚雷菌子出萬釘，白鵝截掌鼈解甲。", "琅玕森深未飄籜，軟炊香秔煨短茁。", "萬錢自是宰相事，一飯且從吾黨說。", "公如端爲苦筍歸，明日青衫誠可脫。"]'),
('c5ff7b43-2bdd-426e-8a07-5c6324029899','閏月訪同年李夷伯子真于河上子真以詩謝次韵','黄庭堅','宋','宋诗','song-poetry','','[]','十年不見猶如此，未覺斯人歎滯留。',64,'全唐诗/poet.song.56000.json','["十年不見猶如此，未覺斯人歎滯留。", "白璧明珠多按劍，濁涇清渭要同流。", "日晴花色自深淺，風軟鳥聲相應酬。", "談笑一樽非俗物，對公無地可言愁。"]'),
('c2fae3c2-9535-4f9d-aee9-bce25fc69ec5','戲答李子真河上見招來詩頗誇河上風物聊以當嘲云','黄庭堅','宋','宋诗','song-poetry','','[]','渾渾舊水無新意，漫漫黄塵涴白鷗。',32,'全唐诗/poet.song.56000.json','["渾渾舊水無新意，漫漫黄塵涴白鷗。", "安得江湖忽當眼，卧聽禽語信船流。"]'),
('de27cfd7-84cb-424b-bc4f-93347535a377','和答李子真讀陶庾詩','黄庭堅','宋','宋诗','song-poetry','','[]','樂易陶彭澤，憂思庾義城。',48,'全唐诗/poet.song.56000.json','["樂易陶彭澤，憂思庾義城。", "風流掃地盡，詩句識餘情。", "往者不再作，前賢畏後生。", "君言得意處，此意少人明。"]'),
('7313fc14-70f4-46cf-bc0d-967c67e7dbec','丙寅十四首效韋蘇州  其一','黄庭堅','宋','宋诗','song-poetry','','[]','雪霽草木動，春融煙景和。',36,'全唐诗/poet.song.56000.json','["雪霽草木動，春融煙景和。", "嘉晨掩關坐，如此節物何。", "同游得二子，晤對不在多。"]'),
('758b0987-8b5e-47b8-8cbc-8cb562fd2c9e','丙寅十四首效韋蘇州  其二','黄庭堅','宋','宋诗','song-poetry','','[]','不知鞍馬倦，想見洲渚春。',36,'全唐诗/poet.song.56000.json','["不知鞍馬倦，想見洲渚春。", "清晝鎖芳園，誰家停畫輪。", "高柳極有思，向風招遊人。"]'),
('f893b098-b3b5-4ded-b928-5539a46ad184','丙寅十四首效韋蘇州  其三','黄庭堅','宋','宋诗','song-poetry','','[]','漸嘉樓外花，嘉賞亭邊柳。',36,'全唐诗/poet.song.56000.json','["漸嘉樓外花，嘉賞亭邊柳。", "作者歸山丘，今春爲誰有。", "千秋萬歲後，還復來游否。"]'),
('98c30593-e476-4fc6-99be-6d0b2e52b639','丙寅十四首效韋蘇州  其四','黄庭堅','宋','宋诗','song-poetry','','[]','城南有佳園，風物迎馬首。',36,'全唐诗/poet.song.56000.json','["城南有佳園，風物迎馬首。", "但賞主人竹，不飲主人酒。", "紅日媚紫苔，輕風泛春柳。"]'),
('667ee82b-edcf-4804-b70b-50180a06a66c','丙寅十四首效韋蘇州  其五','黄庭堅','宋','宋诗','song-poetry','','[]','三公未白髮，十輩乘朱輪。',36,'全唐诗/poet.song.56000.json','["三公未白髮，十輩乘朱輪。", "只取人看好，何益百年身。", "但願長今日，清樽對故人。"]'),
('5e901451-20aa-4ede-b8be-f1f13eedf061','丙寅十四首效韋蘇州  其六','黄庭堅','宋','宋诗','song-poetry','','[]','江梅香冷淡，開徧未全疏。',36,'全唐诗/poet.song.56000.json','["江梅香冷淡，開徧未全疏。", "已有耐寒蜨，雙飛上花鬚。", "今夜嚴城角，肯留花在無。"]'),
('9b05c4db-9a8b-4beb-a404-15bdc6eec511','丙寅十四首效韋蘇州  其七','黄庭堅','宋','宋诗','song-poetry','','[]','我思五柳翁，解作一生事。',36,'全唐诗/poet.song.56000.json','["我思五柳翁，解作一生事。", "得錢送酒家，便靜尋山寺。", "念我還如此，翁應會人意。"]'),
('384f31fc-44c4-4919-8985-1a5114553cd0','丙寅十四首效韋蘇州  其八','黄庭堅','宋','宋诗','song-poetry','','[]','庭空日色靜，樓迥鐘聲遲。',36,'全唐诗/poet.song.56000.json','["庭空日色靜，樓迥鐘聲遲。", "褐叟已爭席，馴鴉更不疑。", "同來復同去，竟別我爲誰。"]'),
('54c5d648-b867-4401-a184-afec50d1b06b','丙寅十四首效韋蘇州  其九','黄庭堅','宋','宋诗','song-poetry','','[]','謝甥有逸興，李髯非不嘉。',36,'全唐诗/poet.song.56000.json','["謝甥有逸興，李髯非不嘉。", "苦思夢春草，醉狂眠酒家。", "斯遊無俗物，傲睨至昏鴉。"]'),
('265c3bc2-ed90-489c-aa2d-2ee0c506591b','丙寅十四首效韋蘇州  其一○','黄庭堅','宋','宋诗','song-poetry','','[]','寺古老僧靜，亭陰脩竹多。',36,'全唐诗/poet.song.56000.json','["寺古老僧靜，亭陰脩竹多。", "萊公作州日，部曲屢經過。", "衆推識公面，蒼石眠綠莎。"]'),
('5ed9d497-745a-4c88-a638-79d927cad005','丙寅十四首效韋蘇州  其一一','黄庭堅','宋','宋诗','song-poetry','','[]','盛時衆吹噓，謫去衆毀辱。',36,'全唐诗/poet.song.56000.json','["盛時衆吹噓，謫去衆毀辱。", "不爲公存亡，幽蘭春自綠。", "欲書名相傳，安得南山竹。"]'),
('33c65059-515b-4c58-81fe-cab8d9d8dcd2','丙寅十四首效韋蘇州  其一二','黄庭堅','宋','宋诗','song-poetry','','[]','昔公調鼎實，指顧九廟尊。',36,'全唐诗/poet.song.56000.json','["昔公調鼎實，指顧九廟尊。", "郡國富士馬，于今開塞垣。", "誰能起公死，爲國守北門。"]'),
('d52415d3-b2a4-457c-a18d-37083cba60f1','丙寅十四首效韋蘇州  其一三','黄庭堅','宋','宋诗','song-poetry','','[]','出身世喪道，解綬饑驅我。',36,'全唐诗/poet.song.56000.json','["出身世喪道，解綬饑驅我。", "杯中得醉鄉，去就不復果。", "豈爲俗人言，達人儻余可。"]'),
('1209435e-a60f-4a6e-aa2b-ef29aeb047c4','丙寅十四首效韋蘇州  其一四','黄庭堅','宋','宋诗','song-poetry','','[]','少小尚狷介，與人常不款。',36,'全唐诗/poet.song.56000.json','["少小尚狷介，與人常不款。", "置身稍雍容，遇酒輒引滿。", "自是鶴足長，難齊鳬脛短。"]'),
('24011b94-92f7-4a7d-8689-00e1ec65483d','催公靜碾茶','黄庭堅','宋','宋诗','song-poetry','','[]','雪裏過門多惡客，春陰只惱有情人。',32,'全唐诗/poet.song.56000.json','["雪裏過門多惡客，春陰只惱有情人。", "睡魔正仰茶料理，急遣溪童碾玉塵。"]'),
('5ff1ce26-f91c-4e55-961f-dae7f311da1a','用前韵戲公靜','黄庭堅','宋','宋诗','song-poetry','','[]','偶逢携酒便與飲，竟別我爲何等人。',32,'全唐诗/poet.song.56000.json','["偶逢携酒便與飲，竟別我爲何等人。", "兔月龍團不當惜，長卿消渴肺生塵。"]'),
('ff5e6852-ad4b-4b94-a599-e73bca228cb8','對酒歌答謝公靜','黄庭堅','宋','宋诗','song-poetry','','[]','我爲北海飲，君作東武吟。',269,'全唐诗/poet.song.56000.json','["我爲北海飲，君作東武吟。", "看君平生用意處，蕭灑定自知人心。", "南陽城邊雪三日，愁陰不能分皂白。", "摧輪踠蹄泥數尺，城門晝開眠賈客。", "移人僵尸在旦夕，誰能忍饑待食麥。", "身憂天下自有人，寒士何者愁填臆。", "民生正自不願材，可乘以車可鞭策。", "君不見海南水沈紫栴檀，碎身百鍊金博山。", "豈如不蒙斧斤賞，老大絕崖霜雪間。", "投身有用禍所集，何況四達之衢井先汲。", "昨日青童天上回，手捧玉帝除書來。", "一番通籍清都闕，百身書名赤城臺。", "飛昇度世無虛日，怪我短褐趨塵埃。", "顧謂彼童子，此何預人事。", "但對清樽即眼開，一杯引人著勝地。", "傳聞官酒亦自清，徑須沽取續吾瓶。", "南山朝來似有意，今夜儻放春月明。"]'),
('62f27c6f-1e8d-460a-a60b-04836538dd43','種决明','黄庭堅','宋','宋诗','song-poetry','','[]','后皇富嘉種，决明著方術。',72,'全唐诗/poet.song.56000.json','["后皇富嘉種，决明著方術。", "耘鋤一席地，時至觀茂密。", "縹葉資芼羹，緗花馬蹄實。", "霜叢風雨餘，簸簸場功畢。", "枕囊代曲肱，甘寢聽芬苾。", "老眼願力餘，讀書真成癖。"]'),
('041d01a6-3536-4791-a29b-c0cfc772ad98','同世弼韵作寄伯氏在濟南兼呈六舅祠部','黄庭堅','宋','宋诗','song-poetry','','[]','山光掃黛水挼藍，聞說樽前愜笑談。',64,'全唐诗/poet.song.56000.json','["山光掃黛水挼藍，聞說樽前愜笑談。", "伯氏清修如舅氏，濟南蕭灑似江南。", "屢陪風月乾吟筆，不解笙簧醉舞衫。", "只恐使君乘傳去，拾遺今日是前銜。"]'),
('079cdd8a-7e04-4804-8b70-09022df0747b','伯氏到濟南寄詩頗言太守居有湖山之勝同韵和','黄庭堅','宋','宋诗','song-poetry','','[]','西來黄犬傳佳句，知是陸機思陸雲。',64,'全唐诗/poet.song.56000.json','["西來黄犬傳佳句，知是陸機思陸雲。", "歷下樓臺追把酒，舅家賓客厭論文。", "山椒欲雨好雲氣，湖面逆風生水紋。", "想得爭棋飛鳥上，行人不見只聽聞。"]'),
('ea735002-1628-44e5-99fc-6c851c0d5f54','次韵寄李六弟濟南郡城橋亭之詩','黄庭堅','宋','宋诗','song-poetry','','[]','客心如頭垢，日欲撩千篦。',204,'全唐诗/poet.song.56000.json','["客心如頭垢，日欲撩千篦。", "聞人說江南，喜氣吐晴霓。", "伏枕夢歸路，子規吟翠微。", "濟南似江南，舊見今不疑。", "洗心欲成游，王事相奪移。", "駑馬戀棧豆，豈能辭縶縲。", "本無封侯骨，見事又重遲。", "徒能多著酒，大腹如鴟夷。", "惟思一漁舟，載網橫渺瀰。", "矯貢歷下亭，朱闌轉清溪。", "春風吹桃李，三月自成蹊。", "翠葉張日幄，紅英鋪地衣。", "此中有佳興，不醉定自非。", "況當郡政成，野繭麥兩岐。", "與民同觀游，永夜不闔扉。", "女牆上金樞，天如青琉璃。", "想子果下歸，馬飽生芻嘶。"]'),
('ab64120a-90e9-43e6-9ad3-985b2fd8f0c9','用明發不寐有懷二人爲韵寄李秉彝德叟  其一','黄庭堅','宋','宋诗','song-poetry','','[]','竹貫四時清，月通雲氣明。',48,'全唐诗/poet.song.56000.json','["竹貫四時清，月通雲氣明。", "外弟有佳質，妙年推老成。", "後凋對霜雪，不昧處陰晴。", "盛德當如此，古人畏後生。"]'),
('878cd773-0226-4bc0-94d6-cc8e7635b4ac','用明發不寐有懷二人爲韵寄李秉彝德叟  其二','黄庭堅','宋','宋诗','song-poetry','','[]','在昔授子書，髧彼垂兩髮。',48,'全唐诗/poet.song.56000.json','["在昔授子書，髧彼垂兩髮。", "乖離今十年，樹立映先達。", "青燈哦妙句，如酌春酒滑。", "把書念携手，惆悵至明發。"]'),
('1db43465-9558-45aa-9629-1219f9f8f85c','用明發不寐有懷二人爲韵寄李秉彝德叟  其三','黄庭堅','宋','宋诗','song-poetry','','[]','人生不如意，十事恒八九。',48,'全唐诗/poet.song.56000.json','["人生不如意，十事恒八九。", "未見歷下人，徒傾歷城酒。", "從來親骨肉，不免相可不。", "但願崇事實，虛名等箕斗。"]'),
('25fad7c5-3938-4c67-bd33-89f8f98f46d7','用明發不寐有懷二人爲韵寄李秉彝德叟  其四','黄庭堅','宋','宋诗','song-poetry','','[]','蚤知鵲山亭，李杜發佳思。',48,'全唐诗/poet.song.56000.json','["蚤知鵲山亭，李杜發佳思。", "彌年聽傳誇，登覽通夢寐。", "遙憐坐清曠，落筆富新製。", "尚因賓客集，瀝酒使我醉。"]'),
('9416a3ea-39de-47b8-a4eb-b1ae7acce45c','用明發不寐有懷二人爲韵寄李秉彝德叟  其五','黄庭堅','宋','宋诗','song-poetry','','[]','往在舅氏旁，獲拚堂上帚。',48,'全唐诗/poet.song.56000.json','["往在舅氏旁，獲拚堂上帚。", "六經觀聖人，明如夜占斗。", "索居廢舊聞，獨學無新有。", "羨子杞梓材，未曾離矯揉。"]'),
('824afe96-5112-4f5a-8f38-5c7df37ae4f4','用明發不寐有懷二人爲韵寄李秉彝德叟  其六','黄庭堅','宋','宋诗','song-poetry','','[]','安詩無恙時，學行超輩儕。',48,'全唐诗/poet.song.56000.json','["安詩無恙時，學行超輩儕。", "華屋落丘山，百憂滿人懷。", "此士如不亡，仲子抱奇材。", "不獨典刑在，神明還觀來。"]'),
('ed74ce12-35f2-4a96-99c5-b64f03dfe606','用明發不寐有懷二人爲韵寄李秉彝德叟  其七','黄庭堅','宋','宋诗','song-poetry','','[]','少時誦詩書，貫穿數萬字。',48,'全唐诗/poet.song.56000.json','["少時誦詩書，貫穿數萬字。", "邇來窺陳編，記一忘三二。", "光陰如可玩，老境翻手至。", "良醫曾折足，說病迺真意。"]'),
('2884bcba-ada7-4469-9809-c6cb35ba91ee','用明發不寐有懷二人爲韵寄李秉彝德叟  其八','黄庭堅','宋','宋诗','song-poetry','','[]','桃李春成徑，本自不期人。',48,'全唐诗/poet.song.56000.json','["桃李春成徑，本自不期人。", "歷下兩寒士，簞瓢能悅親。", "恥蒙伐國問，肯卧覆車塵。", "子既得此友，從之求日新。"]'),
('48fbcdf4-ea14-4961-85cd-b559278a1c97','陪師厚遊百花洲槃礴范文正祠下道羊曇哭謝安石事因讀生存華屋處零落歸山丘爲十詩  其一','黄庭堅','宋','宋诗','song-poetry','','[]','憶在昭陵日，傾心用老成。',24,'全唐诗/poet.song.56000.json','["憶在昭陵日，傾心用老成。", "功歸仁祖廟，正得一書生。"]'),
('07ddfc2b-2a6d-42ce-b838-3178e202db3a','陪師厚遊百花洲槃礴范文正祠下道羊曇哭謝安石事因讀生存華屋處零落歸山丘爲十詩  其二','黄庭堅','宋','宋诗','song-poetry','','[]','羊生但著鞭，勿哭西州門。',24,'全唐诗/poet.song.56000.json','["羊生但著鞭，勿哭西州門。", "故有不亡者，南山相與存。"]'),
('dbc91758-9df2-46f1-81a7-ec3419174aa6','陪師厚遊百花洲槃礴范文正祠下道羊曇哭謝安石事因讀生存華屋處零落歸山丘爲十詩  其三','黄庭堅','宋','宋诗','song-poetry','','[]','慶州自不惡，藉甚載聲華。',24,'全唐诗/poet.song.56000.json','["慶州自不惡，藉甚載聲華。", "忠義可無憾，公今有世家。"]'),
('feead6eb-5e7b-4adc-9de3-a3a5c14ad47f','陪師厚遊百花洲槃礴范文正祠下道羊曇哭謝安石事因讀生存華屋處零落歸山丘爲十詩  其四','黄庭堅','宋','宋诗','song-poetry','','[]','公歸未百年，鸛巢荒古屋。',24,'全唐诗/poet.song.56000.json','["公歸未百年，鸛巢荒古屋。", "我吟殄瘁詩，悲風韵喬木。"]'),
('da9ed751-8515-40d7-b51c-02edf46029d4','陪師厚遊百花洲槃礴范文正祠下道羊曇哭謝安石事因讀生存華屋處零落歸山丘爲十詩  其五','黄庭堅','宋','宋诗','song-poetry','','[]','傷心祠下亭，在時公燕處。',24,'全唐诗/poet.song.56000.json','["傷心祠下亭，在時公燕處。", "臨水不相猜，江鷗會人語。"]'),
('af74aaa7-6b52-4a34-8291-d2264e3b20ab','陪師厚遊百花洲槃礴范文正祠下道羊曇哭謝安石事因讀生存華屋處零落歸山丘爲十詩  其六','黄庭堅','宋','宋诗','song-poetry','','[]','公有一杯酒，與人同醉醒。',24,'全唐诗/poet.song.56000.json','["公有一杯酒，與人同醉醒。", "遺民能記憶，欲語涕飄零。"]'),
('b7e916d6-81fe-440d-8cbb-2cacd1153faa','陪師厚遊百花洲槃礴范文正祠下道羊曇哭謝安石事因讀生存華屋處零落歸山丘爲十詩  其七','黄庭堅','宋','宋诗','song-poetry','','[]','委徑問謠俗，高丘省佃作。',24,'全唐诗/poet.song.56000.json','["委徑問謠俗，高丘省佃作。", "昔遊非苟然，今花幾開落。"]'),
('d0c4a54f-dce5-4e5f-a8b0-69e7981f507a','陪師厚遊百花洲槃礴范文正祠下道羊曇哭謝安石事因讀生存華屋處零落歸山丘爲十詩  其八','黄庭堅','宋','宋诗','song-poetry','','[]','在昔實方枘，成功見圓機。',24,'全唐诗/poet.song.56000.json','["在昔實方枘，成功見圓機。", "九原尚友心，白首要同歸。"]'),
('2704034b-ad73-4fe6-8e87-9c223cce1dda','陪師厚遊百花洲槃礴范文正祠下道羊曇哭謝安石事因讀生存華屋處零落歸山丘爲十詩  其九','黄庭堅','宋','宋诗','song-poetry','','[]','人去洲渚在，春回花草斑。',24,'全唐诗/poet.song.56000.json','["人去洲渚在，春回花草斑。", "清談值淵對，發興如江山。"]'),
('547529a2-94ff-44eb-912d-54dfd9b88eed','陪師厚遊百花洲槃礴范文正祠下道羊曇哭謝安石事因讀生存華屋處零落歸山丘爲十詩  其一○','黄庭堅','宋','宋诗','song-poetry','','[]','落日銜城壁，祠東更一遊。',24,'全唐诗/poet.song.56000.json','["落日銜城壁，祠東更一遊。", "悲來惜酒少，安得董糟丘。"]'),
('ec3da726-b40e-484f-a70a-439da173fd91','百花洲雜題','黄庭堅','宋','宋诗','song-poetry','','[]','范公種竹水邊亭，漂泊來游一客星。',32,'全唐诗/poet.song.56000.json','["范公種竹水邊亭，漂泊來游一客星。", "神理不應從此盡，百年草樹至今青。"]'),
('eb91a4d6-8163-4884-a208-ecf19b436843','竹下把酒','黄庭堅','宋','宋诗','song-poetry','','[]','竹下傾春酒，愁陰爲我開。',24,'全唐诗/poet.song.56000.json','["竹下傾春酒，愁陰爲我開。", "不知臨水語，更得幾回來。"]'),
('b2d14c9d-f648-4ae4-b497-1e6f33ac5c0c','砌臺晚思','黄庭堅','宋','宋诗','song-poetry','','[]','日極江南千里春，誰今灑筆可招魂。',32,'全唐诗/poet.song.56000.json','["日極江南千里春，誰今灑筆可招魂。", "向人猶作故時面，翠竹蒼烟一萬根。"]'),
('7b580e19-c24d-4e6f-8a82-31a59c8dc73c','和師厚接花','黄庭堅','宋','宋诗','song-poetry','','[]','妙手從心得，接花如有神。',48,'全唐诗/poet.song.56000.json','["妙手從心得，接花如有神。", "根株穰下土，顔色洛陽春。", "雍也本犁子，仲由元鄙人。", "升堂與入室，只在一揮斤。"]'),
('82173075-ec88-4088-80ef-455b4279468b','和師厚栽竹','黄庭堅','宋','宋诗','song-poetry','','[]','大隠在城市，此君真友生。',48,'全唐诗/poet.song.56000.json','["大隠在城市，此君真友生。", "根須辰日斸，筍要上番成。", "龍化葛陂去，鳳吹阿閣鳴。", "草荒三徑斷，歲晚見交情。"]'),
('b25abd92-90bc-41d0-8b08-27e59bca54bb','次韵師厚雨中晝寢憶江南餠麴酒','黄庭堅','宋','宋诗','song-poetry','','[]','雨砌無車馬，風簾灑靜便。',48,'全唐诗/poet.song.56000.json','["雨砌無車馬，風簾灑靜便。", "忽思江外酒，準擬醉時眠。", "隠几惟觀化，開書屢絕編。", "遙知煙渚夢，遣騎喚漁船。"]'),
('64a00ea1-275c-4227-92a4-ce874d129e30','次韵師厚萱草','黄庭堅','宋','宋诗','song-poetry','','[]','從來占北堂，雨露借恩光。',48,'全唐诗/poet.song.56000.json','["從來占北堂，雨露借恩光。", "與菊亂佳色，共葵傾太陽。", "人生真苦相，物理忌孤芳。", "不及空庭草，榮衰可兩忘。"]'),
('6850cfb3-87f5-4c16-b9a4-c1f235156bc8','次韵謝外舅病不能拜復官夏雨眠起之什','黄庭堅','宋','宋诗','song-poetry','','[]','丈人養痾卧，此道取衆棄。',168,'全唐诗/poet.song.56000.json','["丈人養痾卧，此道取衆棄。", "强飯尚可飽，力田苦常匱。", "欲從羣兒嬉，出語不娬媚。", "軒窗坐風凉，編簡勘遺墜。", "自安井无禽，未歎旅焚次。", "夏暑極陽功，時霖作陰事。", "呼兒疏藥畦，植杖按瓜地。", "南山雲氣佳，北極冕旒邃。", "自欣鬚髮白，得見衣裳治。", "山林收枯槁，草木洗憔悴。", "舐痔以車來，探珠遭龍睡。", "腹便時蒙嘲，身退得自恣。", "伊優無下僚，骯髒謝高位。", "誰能領斯會，好在漆園吏。"]'),
('e39f6a6d-d977-41b7-8cb1-d6fe969ec105','次韵師厚病間十首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','貝錦不足歌，請陳江漢詩。',48,'全唐诗/poet.song.56000.json','["貝錦不足歌，請陳江漢詩。", "美人出江漢，窈窕世未窺。", "折蘭不肯佩，告我以蠶饑。", "獨歸豈憚遠，三危露如飴。"]'),
('f6fa6215-397e-4c46-a035-ca2a7d833c6c','次韵師厚病間十首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','德人更疢疾，術智益灑落。',48,'全唐诗/poet.song.56000.json','["德人更疢疾，術智益灑落。", "反身見萬古，道不在卜度。", "胸中有鏌鋣，老境要志弱。", "謝公賦達生，達生真可託。"]'),
('3741c225-2c05-4b29-ab5a-b9e74564feeb','次韵師厚病間十首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','引鏡照清骨，驚非曩時人。',48,'全唐诗/poet.song.56000.json','["引鏡照清骨，驚非曩時人。", "天地入喻指，芭蕉自觀身。", "陳力則已病，征財又室貧。", "古來支離疏，粟帛王所仁。"]'),
('0590e84e-8f63-4727-b4c3-343d66e1f241','次韵師厚病間十首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','葅寒知園秋，飯白問米賤。',48,'全唐诗/poet.song.56000.json','["葅寒知園秋，飯白問米賤。", "婦孫勸甘旨，霜兔頗宜麵。", "黄花不舉酒，佳句餘嫪戀。", "經行宴坐堂，鼠跡書几硯。"]'),
('7cfd15e4-d19e-4f4b-9f12-4207f272ec1f','次韵師厚病間十首  其五','黄庭堅','宋','宋诗','song-poetry','','[]','桃李一春期，松栢千歲永。',48,'全唐诗/poet.song.56000.json','["桃李一春期，松栢千歲永。", "經玄事寂寞，髮白官閒冷。", "草綠艾如張，波清蜮司影。", "東里與無趾，渠有幸不幸。"]'),
('9cece427-5565-4635-b016-6648f90eaa55','次韵師厚病間十首  其六','黄庭堅','宋','宋诗','song-poetry','','[]','病餘兒廢鋤，門巷草芊眠。',48,'全唐诗/poet.song.56000.json','["病餘兒廢鋤，門巷草芊眠。", "來者何所聞，披草足跫然。", "封侯謝骨相，使鬼無金錢。", "夢作白鷗去，江湖水黏天。"]'),
('139afc19-0d52-4299-ae0c-99f0e74207d2','次韵師厚病間十首  其七','黄庭堅','宋','宋诗','song-poetry','','[]','民生自煎熬，煮豆以萁爨。',48,'全唐诗/poet.song.56000.json','["民生自煎熬，煮豆以萁爨。", "居然忘本根，光陰不供翫。", "藏山夜半失，烏合歸星散。", "因病見不生，達人果大觀。"]'),
('cc368098-32bb-4bb4-8c31-2e9be94d27fb','次韵師厚病間十首  其八','黄庭堅','宋','宋诗','song-poetry','','[]','開田種白玉，飽牛事耕犁。',48,'全唐诗/poet.song.56000.json','["開田種白玉，飽牛事耕犁。", "雨露非無澤，得秋常苦遲。", "猛虎擅文章，斑斑被諸兒。", "長松抱勁節，惟有歲寒知。"]'),
('457721d1-b5c0-4789-a0a2-976af41f95e0','次韵師厚病間十首  其九','黄庭堅','宋','宋诗','song-poetry','','[]','謝公蒔蘭苕，真意付此物。',48,'全唐诗/poet.song.56000.json','["謝公蒔蘭苕，真意付此物。", "惠然風肯來，香爲一披拂。", "遙知醉吟姿，黽勉向朱紱。", "搘筇橘柚黄，僧屋對像佛。"]'),
('19c7fb4c-9f75-48c5-abaa-4458d0db489e','次韵師厚病間十首  其一○','黄庭堅','宋','宋诗','song-poetry','','[]','身病心輕安，道肥體癯瘦。',48,'全唐诗/poet.song.56000.json','["身病心輕安，道肥體癯瘦。", "好懷當告誰，四牆棗紅皺。", "負暄不可獻，捫蝨坐清晝。", "端有真富貴，千秋萬年後。"]'),
('09b039db-c309-4f8d-888c-d8d9a6846564','次韵奉送公定','黄庭堅','宋','宋诗','song-poetry','','[]','去年君渡河，棗下實離離。',288,'全唐诗/poet.song.56000.json','["去年君渡河，棗下實離離。", "今年君渡河，剝棗詠豳詩。", "直緣恩義重，不憚鞍馬疲。", "詩書半行李，道路費歲時。", "親交歎存亡，學問訪闕遺。", "我多後時悔，君亦見事遲。", "即此有真意，定非兒女知。", "虛名無用處，北斗與南箕。", "燕趙游俠子，長安輕薄兒。", "狂掉三寸舌，躐登九級墀。", "覆手雲雨翻，立談光陰移。", "歃血盟父子，指天出肝脾。", "從來國器重，見謂骨相奇。", "築巖發夢寐，獵渭非熊螭。", "百工改繩墨，一世擅文詞。", "全人脰肩肩，甕盎嫵且宜。", "大槐陰黄庭，女蘿綿絡之。", "昭陽兩兄弟，還自妬蛾眉。", "工顰又宜笑，百輩來茹咨。", "班姬輕鴻毛，更合衆口吹。", "引繩痛排拫，蒙蔽枉成帷。", "惟恐出己上，殺之如弈棋。", "塵埃百年琴，絕絃爲鍾期。", "落落虎豹文，義難管中窺。"]'),
('72dcf0a6-4e5f-4d83-8343-39e89f37197b','和謝公定河朔漫成八首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','急雨長風溢兩河，欣然河伯順風歌。',32,'全唐诗/poet.song.56000.json','["急雨長風溢兩河，欣然河伯順風歌。", "行觀東海方存少，不以黄流更自多。"]'),
('e1bee4f1-baa2-4c8a-8731-295d4f9de3f0','和謝公定河朔漫成八首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','直渠殺勢煩才吏，機器爬沙聚水兵。',32,'全唐诗/poet.song.56000.json','["直渠殺勢煩才吏，機器爬沙聚水兵。", "河面常從天上落，金隄千里護都城。"]'),
('ec02c347-42ca-45c5-bbcc-1ffec3643159','和謝公定河朔漫成八首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','直令南粵還歸帝，誰謂匈奴不敢王。',32,'全唐诗/poet.song.56000.json','["直令南粵還歸帝，誰謂匈奴不敢王。", "願見推財多卜式，未須算賦似桑羊。"]'),
('e03ecc3e-3578-49d4-9840-450a5c952ab9','和謝公定河朔漫成八首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','萊公廟略傳耆舊，韓令風流在井疆。',32,'全唐诗/poet.song.56000.json','["萊公廟略傳耆舊，韓令風流在井疆。", "安用鳴鼛增漢壘，不妨羅拜下諸羌。"]'),
('87c15c2f-fbb7-48ce-9062-11dcd0e1e41d','和謝公定河朔漫成八首  其五','黄庭堅','宋','宋诗','song-poetry','','[]','漢時水占十萬頃，官寺民居皆濁河。',32,'全唐诗/poet.song.56000.json','["漢時水占十萬頃，官寺民居皆濁河。", "豈必九渠亡故道，直緣穿鑿用功多。"]'),
('d6ce3b8d-12bb-4876-8e36-ac244049c2fc','和謝公定河朔漫成八首  其六','黄庭堅','宋','宋诗','song-poetry','','[]','漠庭數遣林牙使，羌種來窺雁塞耕。',32,'全唐诗/poet.song.56000.json','["漠庭數遣林牙使，羌種來窺雁塞耕。", "壯士看天思上策，月邊鳴笛爲誰橫。"]'),
('0498ef8a-ce24-4591-88af-eeb15a7d7c69','和謝公定河朔漫成八首  其七','黄庭堅','宋','宋诗','song-poetry','','[]','蛛蒙黄畫屏初暗，塵澀金門鎖不開。',32,'全唐诗/poet.song.56000.json','["蛛蒙黄畫屏初暗，塵澀金門鎖不開。", "六十餘年望琱輦，赭袍曾是映宮槐。"]'),
('d22e380e-f1f7-49c6-86fd-07c8960a70c0','和謝公定河朔漫成八首  其八','黄庭堅','宋','宋诗','song-poetry','','[]','百里棄疆王自直，萬金捐費物皆春。',32,'全唐诗/poet.song.56000.json','["百里棄疆王自直，萬金捐費物皆春。", "須令牧馬甘踰幕，更遣彎弓不射人。"]'),
('e931f081-9f27-4fee-92d6-d52212bb047a','次韵謝公定王世弼贈答二絕句  其一','黄庭堅','宋','宋诗','song-poetry','','[]','何用苦吟肝腎愁，但知把酒更無憂。',32,'全唐诗/poet.song.56000.json','["何用苦吟肝腎愁，但知把酒更無憂。", "聲名本不關人事，看取青門一故侯。"]'),
('4777cd75-78db-4d7d-8194-b29eacbb2881','次韵謝公定王世弼贈答二絕句  其二','黄庭堅','宋','宋诗','song-poetry','','[]','酒因咀嚼還知味，詩就呻吟不要工。',32,'全唐诗/poet.song.56000.json','["酒因咀嚼還知味，詩就呻吟不要工。", "王謝風流看二妙，病夫直欲卧牆東。"]'),
('862d67a9-c528-4761-b1ed-83ee50062471','次韵公定世弼登北都東樓四首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','日著闌干角，風吹濯澣衣。',48,'全唐诗/poet.song.56000.json','["日著闌干角，風吹濯澣衣。", "喜同王季哲，更得謝玄暉。", "清興俱不淺，長吟無用歸。", "月明南北道，猶見驛塵飛。"]'),
('9e7a2bf7-d4d5-4e2a-85f5-7aceb12d9c9b','次韵公定世弼登北都東樓四首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','真皇多廟勝，仁祖用功深。',48,'全唐诗/poet.song.56000.json','["真皇多廟勝，仁祖用功深。", "卜宅遷九鼎，破胡藏萬金。", "百年休戰士，當日縱前禽。", "欲斷匈奴臂，不如留此心。"]'),
('9ca8e596-f178-4624-9ae8-456b4797ab61','次韵公定世弼登北都東樓四首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','都城礙飛鳥，軍幕卧貔貅。',48,'全唐诗/poet.song.56000.json','["都城礙飛鳥，軍幕卧貔貅。", "紫葚知蠶老，黄雲見麥秋。", "接天雙闕起，伏地九河流。", "耆老深望幸，鑾輿不好遊。"]'),
('b0c80129-4d29-492e-9602-04ed52999319','次韵公定世弼登北都東樓四首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','漢皇勤遠略，晚節相千秋。',48,'全唐诗/poet.song.56000.json','["漢皇勤遠略，晚節相千秋。", "不足中原地，猶思一戰收。", "聖朝方北顧，斜日倚東樓。", "廟算知無敵，寒儒浪自愁。"]'),
('ead0f622-e90e-4e07-8239-515b1d3786d5','和謝公定征南謠','黄庭堅','宋','宋诗','song-poetry','','[]','傳聞交州初陸梁，東連五溪西氐羌。',387,'全唐诗/poet.song.56000.json','["傳聞交州初陸梁，東連五溪西氐羌。", "軍行不斷蠻標盾，謀主皆收漢畔亡。", "合浦譙門腥血沸，晉興城下白骨荒。", "謀臣異時坐致寇，守臣今日愧苞桑。", "已遣戈船下灕水，更分樓船浮豫章。", "頗聞師出三鴉路，盡是中屯六郡良。", "漢南食麥如食玉，湖南驅人如驅羊。", "營平請穀三百萬，祁連引兵九千里。", "少府私錢不可知，大農計歲今餘幾。", "土兵番馬貔虎同，蝮蛇毒草篁竹中。", "未論芻粟捐金費，直愁瘴癘連營空。", "我思荆州李太守，欲募蠻夷令自攻。", "至今民歌尹殺我，州郡擇人誠見功。", "張喬祝良不難得，誰借前筯開天聰。", "詔書哀痛言語切，爲民一洗橫尸血。", "摧鋒陷堅賞萬戶，塹山堙谷窮三穴。", "南平舊時頗臣順，欲獻封疆請旄節。", "廟謨猶計病中原，豈知一朝更屠滅。", "天道從來不爭勝，功臣好爲可喜說。", "交州雞肋安足貪，漢開九郡勞臣監。", "呂嘉不肯佩銀印，徵側持戈敵百男。", "君不見往年瀕海未郡縣，趙佗閉關罷朝獻。", "老翁竊帝聊自娛，白頭抱孫思事漢。", "孝文親遺勞苦書，稽首請去黄屋車。"]'),
('e0d4c821-b788-4fb9-97b5-8eb6d60a6a86','和師厚秋半時復官分司西都','黄庭堅','宋','宋诗','song-poetry','','[]','遙知得謝分西洛，無復肯彈冠上塵。',64,'全唐诗/poet.song.56000.json','["遙知得謝分西洛，無復肯彈冠上塵。", "園地除瓜猶入市，水田收秫未全貧。", "杜陵白髮垂垂老，張翰黄花句句新。", "還與老農爭坐席，青林同社賽田神。"]'),
('c5794e57-6438-4f4f-87a9-19f0ec1783e0','和師厚郊居示里中諸君','黄庭堅','宋','宋诗','song-poetry','','[]','籬邊黄菊關心事，窗外青山不世情。',64,'全唐诗/poet.song.56000.json','["籬邊黄菊關心事，窗外青山不世情。", "江橘千頭供歲計，秋蛙一部洗朝酲。", "歸鴻往燕競時節，宿草新墳多友生。", "身後功名空自重，眼前樽酒未宜輕。"]'),
('395e599e-224e-4d9b-bfbb-fc5f06eca7a5','寄南陽謝外舅','黄庭堅','宋','宋诗','song-poetry','','[]','謝公遂偃蹇，南陽無舊廬。',288,'全唐诗/poet.song.56000.json','["謝公遂偃蹇，南陽無舊廬。", "天與解纓紱，元非傲當塗。", "庖丁釋牛刀，衆手斫大軱。", "白雲曲肱卧，青山滿牀書。", "妙質落川澤，果然天網疏。", "故知今人巧，未覺古人迂。", "築場歲功休，夜泉鳴竹渠。", "胸懷鬰壘塊，此物諒時須。", "兒能了翁事，安用府中趨。", "孫能誦翁詩，乃是千里駒。", "人生行樂耳，用舍要自如。", "我方神其拙，社櫟官道樗。", "公猶憂斧斤，睥睨斲樽壺。", "萬古身後前，芭蕉秋雨餘。", "少年喜狡獪，叱化粒成珠。", "謨功可歌舞，學古則暖姝。", "所好果不同，未可一理驅。", "眇思忘言對，安得南飛鳬。", "鄙心生蔓草，萌芽望耘鉏。", "離筵如昨日，春柳見霜枯。", "未辱錦繡段，時蒙雙鯉魚。", "憶昔參几杖，雍容覷規模。", "引接開藻鑒，高明通事樞。", "門生五七輩，寂寞半白鬚。"]'),
('b1ea4a91-bc0f-40ba-b5ef-93db977ad18a','和外舅夙興三首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','瓜蔓已除壟，苔痕猶上牆。',48,'全唐诗/poet.song.56000.json','["瓜蔓已除壟，苔痕猶上牆。", "蓬蒿貪雨露，松竹見冰霜。", "卷幔天垂斗，披衣日在房。", "無詩歎不遇，千古一潛郎。"]'),
('3f304b10-1123-4f80-979c-709470767320','和外舅夙興三首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','風烈僧魚響，霜嚴郡角悲。',48,'全唐诗/poet.song.56000.json','["風烈僧魚響，霜嚴郡角悲。", "短童疲洒掃，落葉故紛披。", "水凍食鮭少，甕寒浮蟻遲。", "朝陽烏鳥樂，安穩託禪枝。"]'),
('ae65b819-356d-4676-8f27-b46c88b8b10c','和外舅夙興三首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','暑逐池蓮盡，寒隨塞雁來。',48,'全唐诗/poet.song.56000.json','["暑逐池蓮盡，寒隨塞雁來。", "衣裘雖得暖，狐貉正相哀。", "僧汲轆轤曉，車鳴關鎖開。", "不因朝鼓起，來帙亂書堆。"]'),
('4702c0bb-6ff0-47d1-9966-9c42d932f3da','和答師厚黄連橋壞大木亦爲秋雹所碎','黄庭堅','宋','宋诗','song-poetry','','[]','溪橋喬木下，往歲記經過。',88,'全唐诗/poet.song.56000.json','["溪橋喬木下，往歲記經過。", "居人指神社，不敢尋斧柯。", "青陰百尺蔽白日，烏鵲取意占作窠。", "黄泉浸根雨長葉，造物著意固已多。", "風摧電打掃地盡，竟莫知爲何譴訶。", "獨山冷落城東路，不見指名終不磨。"]'),
('4786caa9-717b-4f8d-a5c2-fefab7c61178','世弼惠詩求舜泉輒欲以長安酥共泛一盃次韵戲答','黄庭堅','宋','宋诗','song-poetry','','[]','寒齏薄飯留佳客，蠹簡殘編作近鄰。',64,'全唐诗/poet.song.56000.json','["寒齏薄飯留佳客，蠹簡殘編作近鄰。", "避地梁鴻真好學，著書揚子未全貧。", "玉酥鍊得三危露，石火燒成一片春。", "沙鼎探湯供卯飲，不憂問字絕無人。"]'),
('a04360ef-4c5f-4262-9c90-1dd16fe3f887','送蛤蜊與李明叔諸公','黄庭堅','宋','宋诗','song-poetry','','[]','雪屋吹燈然豆萁，古來壯士亦長饑。',32,'全唐诗/poet.song.56000.json','["雪屋吹燈然豆萁，古來壯士亦長饑。", "廣文不得載酒去，且詠太玄庖蛤蜊。"]'),
('72c0ea20-8ed3-4d13-aa0c-da450089a3ef','戲贈世弼用前韵','黄庭堅','宋','宋诗','song-poetry','','[]','盜跖人肝常自飽，首陽薇蕨向來饑。',32,'全唐诗/poet.song.56000.json','["盜跖人肝常自飽，首陽薇蕨向來饑。", "誰能著意知許事，且爲元長食蛤蜊。"]'),
('731ddbbd-8cfa-494e-a391-9baf771b54d5','世弼病方家不善論蛤蜊之功戲答','黄庭堅','宋','宋诗','song-poetry','','[]','伯樂無傳驥空老，重華不見士長饑。',32,'全唐诗/poet.song.56000.json','["伯樂無傳驥空老，重華不見士長饑。", "從來萬事乖名實，豈但藥翁論蛤蜊。"]'),
('9cd06a82-155b-4386-941b-e2d6ad5dba76','次韵師厚食蟹','黄庭堅','宋','宋诗','song-poetry','','[]','海饌糖蟹肥，江醪白蟻醇。',120,'全唐诗/poet.song.56000.json','["海饌糖蟹肥，江醪白蟻醇。", "每恨腹未厭，誇說齒生津。", "三歲在河外，霜臍常食新。", "朝泥看郭索，暮鼎調酸辛。", "趨蹌雖入笑，風味極可人。", "憶觀淮南夜，火攻不及晨。", "橫行葭葦中，不自貴其身。", "誰憐一網盡，大去河伯民。", "鼎司費萬錢，玉食羅常珍。", "吾評揚州貢，此物真絕倫。"]'),
('6df27b66-996a-47e5-9d1c-bebf6fe3927c','次韵謝外舅食馿腸','黄庭堅','宋','宋诗','song-poetry','','[]','垂頭畏庖丁，趨死尚能鳴。',96,'全唐诗/poet.song.56000.json','["垂頭畏庖丁，趨死尚能鳴。", "說以雕俎樂，甘言果非誠。", "生無千金轡，死得五鼎烹。", "禍胎無腸胃，殺身和椒橙。", "春風都門道，貫魚百十并。", "騎奴吹一吷，駔駿不敢爭。", "物材苟當用，何必渥洼生。", "忽思麒麟楦，突兀使人驚。"]'),
('170a25e2-3207-4c0f-9eb2-6fe01f2275da','次韵師厚答馬著作屢贈詩','黄庭堅','宋','宋诗','song-poetry','','[]','嘗聞馬南郡，少有拔俗韵。',72,'全唐诗/poet.song.56000.json','["嘗聞馬南郡，少有拔俗韵。", "寒灰幾見溺，鎩翮常思奮。", "桐薪鳴竈間，劍氣吐吳分。", "多言世益嗤，當律心自隠。", "家雖四立壁，仕要三無慍。", "會將漁父意，往就莊生問。"]'),
('dd63bda4-8f40-46cb-964c-8aead8fe0880','次韵子瞻與舒堯文禱雪霧豬泉唱和','黄庭堅','宋','宋诗','song-poetry','','[]','老農年饑望人腹，想見四溟森雨足。',208,'全唐诗/poet.song.56000.json','["老農年饑望人腹，想見四溟森雨足。", "林回投璧負嬰兒，豈聞烹兒翁不哭。", "未論萬戶無炊煙，蛛絲蝸涎經杼軸。", "使君閔雪無肉味，煮餠青蒿下鹽菽。", "豈云剪爪宜侵肌，霜不殺草仍故綠。", "幽靈奰贔西山霧，牲肥酒香神未瀆。", "得微往從董父餐，寧當罪繫葛陂淵。", "卜擇祠官齊博士，暴露致告蒼崖顛。", "請天行澤不汲汲，爾亦枯魚過河泣。", "生鵝斬頸血未乾，風馬雲車坐相及。", "百里旌旗灑玉花，使君義動龍蛇蟄。", "老農歡喜有春事，呼兒飯牛理簑笠。", "博士勿嘆從公疲，明年麥飯滑流匙。"]'),
('872195da-23a9-4e44-87d7-ff900431ecda','薄薄酒二章  其一','黄庭堅','宋','宋诗','song-poetry','','[]','薄酒可與忘憂，醜婦可與白頭。',134,'全唐诗/poet.song.56000.json','["薄酒可與忘憂，醜婦可與白頭。", "徐行不必駟馬，稱身不必狐裘。", "無禍不必受福，甘餐不必食肉。", "富貴于我如浮雲，小者譴訶大戮辱。", "一身畏首復畏尾，門多賓客飽僮僕。", "美物必甚惡，厚味生五兵。", "匹夫懷璧死，百鬼瞰高明。", "醜婦千秋萬歲同室，萬金良藥不如無疾。", "薄酒一談一笑勝茶，萬里封侯不如還家。"]'),
('4a6b1032-f068-4722-a72c-c4d76341e88a','薄薄酒二章  其二','黄庭堅','宋','宋诗','song-poetry','','[]','薄酒終勝飲茶，醜婦不是無家。',156,'全唐诗/poet.song.56000.json','["薄酒終勝飲茶，醜婦不是無家。", "醇醪養牛等刀鋸，深山大澤生龍蛇。", "秦時東陵千戶食，何如青門五色瓜。", "傳呼鼓吹擁部曲，何如春雨一池蛙。", "性剛太傅促和藥，何如羊裘釣煙沙。", "綺席象牀琱玉枕，重門夜鼓不停撾。", "何如一身無四壁，滿船明月卧蘆花。", "吾聞食人之肉，可隨以鞭朴之戮。", "乘人之車，可加以鈇鉞之誅。", "不如薄酒醉眠牛背上，醜婦自能搔背痒。"]'),
('930a80fc-6f8e-4d0d-8608-356cc69fa738','戲贈彥深','黄庭堅','宋','宋诗','song-poetry','','[]','李髯家徒立四壁，未嘗一飯能留客。',323,'全唐诗/poet.song.56000.json','["李髯家徒立四壁，未嘗一飯能留客。", "春寒茅屋交相風，倚牆捫虱讀書策。", "老妻甘貧能養姑，寧剪髻鬟不典書。", "大兒得餐不索魚，小兒得褌不索襦。", "庾郎鮭菜二十七，太常齋日三百餘。", "上丁分膰一飽飯，藏神夢訴羊蹴蔬。", "世傳寒士有食籍，一生當飯百甕葅。", "冥冥主張審如此，附郭小圃宜勤鋤。", "葱秧青青葵甲綠，早韭晚菘羹糝熟。", "充虛解戰頼湯餠，芼以蓱虀與甘菊。", "幾日憐槐已著花，一心咒笋莫成竹。", "羣兒笑髯窮百巧，我謂勝人飯重肉。", "羣兒笑髯不若人，我獨愛髯無事貧。", "君不見猛虎即人厭麋鹿，人還寢皮食其肉。", "濡需終與豕俱焦，飫肥擇甘果非福。", "蟲蟻無知不足驚，橫目之民萬物靈。", "請食熊蹯楚千乘，立死山壁漢公卿。", "李髯作人有佳處，李髯作詩有佳句。", "雖無厚祿故人書，門外猶多長者車。", "我讀揚雄逐貧賦，斯人用意未全疏。"]'),
('242b8580-2ac9-4c66-9eca-1fc421c46bf0','竹軒詠雪呈外舅謝師厚并調李彥深','黄庭堅','宋','宋诗','song-poetry','','[]','破臘春未融，土膏寒不發。',120,'全唐诗/poet.song.56000.json','["破臘春未融，土膏寒不發。", "數聲鳴條風，一夜洒窗雪。", "開軒萬物曉，落勢良未歇。", "鏗鏗青琅玕，閱此歲凜冽。", "摧埋頭搶地，意氣終自潔。", "君子謂此君，全身斯明哲。", "屋頭維女貞，額色少澤悅。", "稍能窺藩籬，亦有固窮節。", "佳興冉冉生，門外無車轍。", "寫之朱絲絃，清坐待明月。"]'),
('4f1d79dc-e2e4-4984-9e12-09a83a2bb5b1','賦未見君子憂心靡樂八韵寄李師載  其一','黄庭堅','宋','宋诗','song-poetry','','[]','同陞吏部曹，往在紀丁未。',48,'全唐诗/poet.song.56000.json','["同陞吏部曹，往在紀丁未。", "別離感寒暑，歲星行十二。", "我慚雞藎穀，子歎天且劓。", "空餘山梁期，尚不昧初志。"]'),
('6afb47d1-bf43-4d34-8d4c-60d0c3066744','賦未見君子憂心靡樂八韵寄李師載  其二','黄庭堅','宋','宋诗','song-poetry','','[]','會合良艱期，繫匏各異縣。',48,'全唐诗/poet.song.56000.json','["會合良艱期，繫匏各異縣。", "千里共明月，如披故人面。", "浮雲蔽高秋，此豈心中願。", "霧重豹成文，水清魚自見。"]'),
('70622799-989c-49de-8376-d48e34faa3f3','賦未見君子憂心靡樂八韵寄李師載  其三','黄庭堅','宋','宋诗','song-poetry','','[]','齊地穀翔貴，排門無爨饙。',48,'全唐诗/poet.song.56000.json','["齊地穀翔貴，排門無爨饙。", "二仲有甘旨，奉親亦良勤。", "原田水洸洸，何時稼如雲。", "無民願歲豐，正自不忘君。"]'),
('5bcb39f4-8102-48b0-8eeb-8b46e800cda6','賦未見君子憂心靡樂八韵寄李師載  其四','黄庭堅','宋','宋诗','song-poetry','','[]','古人有成言，歲暮于吾子。',48,'全唐诗/poet.song.56000.json','["古人有成言，歲暮于吾子。", "斧揮郢人鼻，琴即鍾期耳。", "新詩凌建安，高論到正始。", "徒言參隔辰，未負石投水。"]'),
('fa2620a7-42b8-48af-845f-5fb8035e933e','賦未見君子憂心靡樂八韵寄李師載  其五','黄庭堅','宋','宋诗','song-poetry','','[]','白雪非衆聽，夜光忌暗投。',48,'全唐诗/poet.song.56000.json','["白雪非衆聽，夜光忌暗投。", "古來不識察，浪自生百憂。", "三月楚國淚，千年郢中樓。", "無因杭一葦，濁水拍天流。"]'),
('fde38d22-13a1-4b6c-91ca-1f96d7684d4b','賦未見君子憂心靡樂八韵寄李師載  其六','黄庭堅','宋','宋诗','song-poetry','','[]','河南李茂彥，內藴邁俗心。',48,'全唐诗/poet.song.56000.json','["河南李茂彥，內藴邁俗心。", "濬沖有涇渭，一顧重千金。", "事親知色難，勝己又勇沈。", "外物既難必，求之首陽岑。"]'),
('eceab64b-a697-4e15-8ae2-5a93acd5a2c5','賦未見君子憂心靡樂八韵寄李師載  其七','黄庭堅','宋','宋诗','song-poetry','','[]','飄風從東來，雨足盡西靡。',48,'全唐诗/poet.song.56000.json','["飄風從東來，雨足盡西靡。", "萬物逐波流，金石終自止。", "渭因涇使濁，菲以葑故毀。", "智所無奈何，誰能爲樗里。"]'),
('908bea3d-b1fc-4ea9-adec-2468a8303f54','賦未見君子憂心靡樂八韵寄李師載  其八','黄庭堅','宋','宋诗','song-poetry','','[]','紛紛車馬客，如集市人博。',48,'全唐诗/poet.song.56000.json','["紛紛車馬客，如集市人博。", "彼雖有求來，我但快一噱。", "忽逢媚學子，時亦撼關鑰。", "何當携手期，濠上得魚樂。"]'),
('0388ff43-ab3b-4df5-ae49-29b38f586f53','次韵張秘校喜雪三首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','落月煙沙靜渺然，好風吹雪下平田。',64,'全唐诗/poet.song.56000.json','["落月煙沙靜渺然，好風吹雪下平田。", "瓊瑶萬里酒增價，桂玉一炊人少錢。", "學子已占秋食麥，廣文何憾客無氈。", "睡餘强起還詩債，臘裏春初未隔年。"]'),
('573f782a-b563-428b-8ba2-c7466452fb4e','次韵張秘校喜雪三首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','巷深朋友稀來往，日晏兒童不掃除。',64,'全唐诗/poet.song.56000.json','["巷深朋友稀來往，日晏兒童不掃除。", "雪裏正當梅臘盡，民饑可待麥秋無。", "寒生短棹誰乘興，光入疏櫺我讀書。", "官冷無人供美酒，何時却得步兵厨。"]'),
('5b8a88a2-6e7b-4fd4-b5ed-c31ea112392f','次韵張秘校喜雪三首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','滿城樓觀玉闌干，小雪晴時不共寒。',64,'全唐诗/poet.song.56000.json','["滿城樓觀玉闌干，小雪晴時不共寒。", "潤到竹根肥臘筍，暖開蔬甲助春盤。", "眼前多事觀游少，胸次無憂酒量寬。", "聞說壓沙梨已動，會須鞭馬蹋泥看。"]'),
('12037d20-fdea-46c1-9832-b647157f09f1','次韵寅菴四首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','四時說盡菴前事，寄遠如開水墨圖。',64,'全唐诗/poet.song.56000.json','["四時說盡菴前事，寄遠如開水墨圖。", "略有生涯如谷口，非無卜肆在成都。", "旁籬榛栗供賓客，滿眼雲山奉燕居。", "閒與老農歌帝力，年豐村落罷追胥。"]'),
('2ecee3b3-c79b-4a8b-8f5e-14cb00fe8859','次韵寅菴四首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','兄作新菴接舊居，一原風物萃庭隅。',64,'全唐诗/poet.song.56000.json','["兄作新菴接舊居，一原風物萃庭隅。", "陸機招隠方傳洛，張翰思歸正在吳。", "五斗折腰慚僕妾，幾年合眼夢鄉閭。", "白雲行處應垂淚，黄犬歸時早寄書。"]'),
('f84ee612-e2ec-4f49-b40f-e4e11e9bf38d','次韵寅菴四首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','大若塘邊擉網魚，小桃源口带經鋤。',64,'全唐诗/poet.song.56000.json','["大若塘邊擉網魚，小桃源口带經鋤。", "詩催孺子成雞柵，茶約鄰翁掘芋區。", "苦楝狂風寒徹骨，黄梅細雨潤如酥。", "此時睡到日三丈，自起開關招酒徒。"]'),
('17f12b76-de47-4c44-b94e-d7ee9376e901','次韵寅菴四首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','未怪窮山寂寞居，此情常與世情疏。',64,'全唐诗/poet.song.56000.json','["未怪窮山寂寞居，此情常與世情疏。", "誰家生計無閒地，太半歸來已白鬚。", "不用看雲眠永日，會思臨水寄雙魚。", "公私逋負田園薄，未至妨人作樂無。"]'),
('b1ba956a-d45f-4be3-a1cc-05034f02b502','以同心之言其臭如蘭爲韵寄李子先  其一','黄庭堅','宋','宋诗','song-poetry','','[]','往日三語掾，解道將無同。',48,'全唐诗/poet.song.56000.json','["往日三語掾，解道將無同。", "我觀李校書，超邁有古風。", "談道屢入微，閉門長蒿蓬。", "誰能賞遠韵，太守似安豐。"]'),
('4da5a0e1-ebdd-4180-86cf-72fec94f1050','以同心之言其臭如蘭爲韵寄李子先  其二','黄庭堅','宋','宋诗','song-poetry','','[]','流水鳴無意，白雲出無心。',48,'全唐诗/poet.song.56000.json','["流水鳴無意，白雲出無心。", "水得平淡處，渺渺不厭深。", "雲行不能雨，還歸碧山岑。", "斯人似雲水，廊廟等山林。"]'),
('e83bd020-4ae0-4dd5-add1-fcd2426730db','以同心之言其臭如蘭爲韵寄李子先  其三','黄庭堅','宋','宋诗','song-poetry','','[]','俗士得失重，舍龜觀朵頤。',48,'全唐诗/poet.song.56000.json','["俗士得失重，舍龜觀朵頤。", "六經成市道，駔儈以爲師。", "吾學淡如水，載行欲安之。", "惟有無心子，白雲相與期。"]'),
('a13f1522-59f2-4d11-be6e-c443f1871c94','以同心之言其臭如蘭爲韵寄李子先  其四','黄庭堅','宋','宋诗','song-poetry','','[]','摧藏褫冠冕，寂寞歸丘園。',48,'全唐诗/poet.song.56000.json','["摧藏褫冠冕，寂寞歸丘園。", "一瓢俱好學，伯仲吹篪塤。", "正以此易彼，高車擇朱門。", "得失固有在，難爲欲人言。"]'),
('50552997-48bc-4234-9cb4-92ff46aed1b2','以同心之言其臭如蘭爲韵寄李子先  其五','黄庭堅','宋','宋诗','song-poetry','','[]','携手力不足，七年坐乖離。',48,'全唐诗/poet.song.56000.json','["携手力不足，七年坐乖離。", "愁思不能眠，起視夜何其。", "殘月掛破鏡，寒星滿天垂。", "明明故人心，維斗終不移。"]'),
('0a5e88ab-d2c8-44e7-abc6-94215498267d','以同心之言其臭如蘭爲韵寄李子先  其六','黄庭堅','宋','宋诗','song-poetry','','[]','窮閻蒿蔓羶，富屋酒肉臭。',48,'全唐诗/poet.song.56000.json','["窮閻蒿蔓羶，富屋酒肉臭。", "酒肉令人肥，蒿蔓令人瘦。", "欲從鐘鼎食，復恐憂患構。", "秦時千戶侯，寂寞種瓜後。"]'),
('5311cc18-af67-4621-8a4e-3aad81317e6a','以同心之言其臭如蘭爲韵寄李子先  其七','黄庭堅','宋','宋诗','song-poetry','','[]','客從濟南來，遺我故人書。',48,'全唐诗/poet.song.56000.json','["客從濟南來，遺我故人書。", "墨淡字疏行，故人情有餘。", "上言猶健否，次問意何如。", "只今意何有，思食故溪魚。"]'),
('98dfbcf4-c250-4ef6-a48f-a925d81b1ffb','以同心之言其臭如蘭爲韵寄李子先  其八','黄庭堅','宋','宋诗','song-poetry','','[]','吾子有嘉德，譬如含薰蘭。',48,'全唐诗/poet.song.56000.json','["吾子有嘉德，譬如含薰蘭。", "清風不來過，歲晚蒿艾間。", "古來百夫雄，白首在澗槃。", "非關自取重，直爲知人難。"]'),
('ec600b73-e5db-4d8f-b988-1a445129f0d4','見子瞻粲字韵詩和答三人四返不困而愈崛奇輒次韵寄彭門三首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','公才如洪河，灌注天下半。',192,'全唐诗/poet.song.56000.json','["公才如洪河，灌注天下半。", "風日未嘗攖，晝夜聖所歎。", "名世二十年，窮無歌舞玩。", "入宮又見妬，徒友飛鳥散。", "一飽事難諧，五車書作伴。", "風雨暗樓臺，雞鳴自昏旦。", "雖非錦繡贈，欲報青玉案。", "文似離騷經，詩窺關雎亂。", "賤生恨學晚，曾未奉巾盥。", "昨蒙雙鯉魚，遠託鄭人緩。", "風義薄秋天，神明還舊貫。", "更磨薦禰墨，推挽起疲懦。", "忽忽未嗣音，微陽歸候炭。", "仁風從東來，拭目望齋館。", "鳥聲日日春，柳色弄晴暖。", "漫有酒盈樽，何因見此粲。"]'),
('fdc575b2-7371-4ca7-af66-50acbebf60e0','見子瞻粲字韵詩和答三人四返不困而愈崛奇輒次韵寄彭門三首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','人生等尺捶，豈耐日取半。',192,'全唐诗/poet.song.56000.json','["人生等尺捶，豈耐日取半。", "誰能如秋蟲，長夜向壁歎。", "朝四與暮三，適爲狙公玩。", "臭腐暫神奇，喑噫即飄散。", "我觀萬世中，獨立無介伴。", "小黠而大癡，夜氣不及旦。", "低首甘豢養，尻脽登俎案。", "所以終日飲，醉眠朱碧亂。", "無人明此心，忍垢待濯盥。", "仰看東飛雲，只使衣带緩。", "先生古人學，百氏一以貫。", "見義勇必爲，少作衰俗懦。", "忠言願回天，不忍斆吞炭。", "還從股肱郡，待詔圖書館。", "投壺得賜金，侏儒餘飽暖。", "寧令東方公，但索長安粲。"]'),
('b07b22fe-6af8-46d0-b60d-1e706d12f3d4','見子瞻粲字韵詩和答三人四返不困而愈崛奇輒次韵寄彭門三首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','元龍湖海士，毀譽略相半。',192,'全唐诗/poet.song.56000.json','["元龍湖海士，毀譽略相半。", "下牀卧許君，上牀自永嘆。", "丈夫屬有念，人物非所玩。", "坐令結歡客，化爲煙霧散。", "武功有大略，亦復寡朋伴。", "詠歌思見之，長夜鳴曷旦。", "東南望彭門，官道平如案。", "簡書束縛人，一水不能亂。", "斯文媲秬鬯，可用圭瓚盥。", "誠求活國醫，何忍棄和緩。", "開疆日百里，都內錢朽貫。", "銘功甚俊偉，迺見儒生懦。", "且當置是事，勿使冰作炭。", "上帝羣玉府，道家蓬萊館。", "曲肱夏簟寒，炙背冬屋暖。", "只令文字垂，萬世星斗粲。"]'),
('142679c9-d370-42d5-bc3e-6896d69b505a','再和寄子瞻聞得湖州','黄庭堅','宋','宋诗','song-poetry','','[]','天下無相知，得一已當半。',192,'全唐诗/poet.song.56000.json','["天下無相知，得一已當半。", "桃僵李爲仆，芝焚蕙增歎。", "佳人在江湖，照影自娛玩。", "一朝入漢宮，掃除備冗散。", "何如終流落，長作朝雲伴。", "相思欲面論，坐起雞五旦。", "身慚尸廩祿，有罪未見案。", "公文雄萬夫，皦皦不自亂。", "臧穀皆亡羊，要以道湔盥。", "傳聲向東南，王事不可緩。", "春波下數州，快若七札貫。", "椎鼓張風帆，相見激衰懦。", "空文不傳心，千古付煨炭。", "安得垂天雲，飛就吳興館。", "魚饜柳絮肥，筍煮溪沙暖。", "解歌使君詞，樽前有三粲。"]'),
('26530e62-0e9e-4b9c-b0e7-b0689ae774c4','次韵答堯民','黄庭堅','宋','宋诗','song-poetry','','[]','君聞蘇公詩，疾讀思過半。',192,'全唐诗/poet.song.56000.json','["君聞蘇公詩，疾讀思過半。", "譬如聞韶耳，三月忘味歎。", "我詩豈其朋，組麗等俳玩。", "不聞南風絃，同調廣陵散。", "鶴鳴九天上，肯作家雞伴。", "晁子但愛我，品藻私月旦。", "官閒樂相從，梨栗供杯案。", "門靜鳥雀嬉，花深蜂蝶亂。", "忽蒙加禮貌，齋戒事搢盥。", "問大心更小，意督詞反緩。", "君材于用多，舞選弓矢貫。", "聰明回自照，勝己果非懦。", "我如相繪事，素質施朽炭。", "古來得道人，非獨大庭館。", "晁子已不疑，冬寒春自暖。", "繫表知藥言，擇友得荀粲。"]'),
('8ce7413e-f438-42f8-aa3a-ac47a2bebf95','春遊','黄庭堅','宋','宋诗','song-poetry','','[]','終日桃李蹊，春風不相識。',96,'全唐诗/poet.song.56000.json','["終日桃李蹊，春風不相識。", "同我二三子，承我作意力。", "把酒忘味著，看花了香寂。", "晴雲散長空，曠蕩無限隔。", "身爲胡蝶夢，本自不漁色。", "春蟲勸人歸，今我誠是客。", "歸來翻故紙，書尾見麟獲。", "文字非我名，聊取二三策。"]'),
('a401beb0-685c-49f8-b077-3e5eaac91075','次韵感春五首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','我與子桑友，既往雨彌旬。',96,'全唐诗/poet.song.56000.json','["我與子桑友，既往雨彌旬。", "交情未曾改，天地忽趨新。", "東風無行迹，佳氣滿城闉。", "麥苗生陂隴，歎息不食陳。", "誰能裹飯來，定是寂寞人。", "一曲古流水，試拂絃上塵。", "古木少生意，輪囷卧河濱。", "慚愧桃與李，相隨見陽春。"]'),
('9478fe14-aa5e-4a4d-a993-af9790389a70','次韵感春五首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','張侯脫朝衣，兒褐多純綠。',84,'全唐诗/poet.song.56000.json','["張侯脫朝衣，兒褐多純綠。", "聞道無米舂，煮朮學辟穀。", "官吏但索錢，詔書哀惸獨。", "東方九尺長，不得侏儒祿。", "屋中聲鵝雁，日暮攪心曲。", "窮巷無桃李，縕袍非春服。", "我吟白駒詩，知君在空谷。"]'),
('a456eaec-8d2a-406c-aa60-8079a7b36d49','次韵感春五首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','祁寒不可怨，天道自平分。',72,'全唐诗/poet.song.56000.json','["祁寒不可怨，天道自平分。", "及爾春風來，四肢有餘溫。", "丈夫力如虎，爲人行灌園。", "椒蘭工壅蔽，未可怨芳蓀。", "寒魚守窮轍，蒙呴一沫恩。", "一朝被湔祓，吹毛見瘢痕。"]'),
('a36a609e-272d-4a9d-8abe-a9b8db381f42','次韵感春五首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','鳥聲春漸長，煙雨春薄暮。',84,'全唐诗/poet.song.56000.json','["鳥聲春漸長，煙雨春薄暮。", "風光不長妍，如客暫時寓。", "芸芸物爭時，天地有常度。", "我行睹大河，黄流日東騖。", "喟然欲乘桴，莽不見洲渚。", "張侯但飲酒，無用恨羈旅。", "十年富貴子，今作一丘土。"]'),
('9dbe5519-421d-4fc8-a81e-ca0a1f170c85','次韵感春五首  其五','黄庭堅','宋','宋诗','song-poetry','','[]','茶如鷹爪拳，湯作蟹眼煎。',96,'全唐诗/poet.song.56000.json','["茶如鷹爪拳，湯作蟹眼煎。", "時邀草玄客，晴明坐南軒。", "笑談非世故，獨立萬物先。", "春風引車馬，隠隠何闐闐。", "高蓋相摩戛，騎奴爭道喧。", "吾人撫榮觀，燕處自超然。", "城中百年木，有鵲巢其顛。", "鳲鳩來相宅，日暮更謀遷。"]'),
('0d8d1f4c-6c1b-433c-b590-f0d54670bb7b','聖柬將寓于衛行乞食于齊有可憐之色再次韵感春五首贈之  其一','黄庭堅','宋','宋诗','song-poetry','','[]','溫氣冰底歸，忽忽六過旬。',96,'全唐诗/poet.song.56000.json','["溫氣冰底歸，忽忽六過旬。", "園林改柯葉，鳥聲日日新。", "耕稼百年外，四郊無短闉。", "高丘試顧望，俯仰迹已陳。", "信陵松鬰鬰，不見曩時人。", "空懷負暄賞，莫望屬車塵。", "腹中書萬卷，阽死溝壑濱。", "投壺與射覆，一笑物皆春。"]'),
('eab44903-e345-44d1-8403-9152c0dbf1f3','聖柬將寓于衛行乞食于齊有可憐之色再次韵感春五首贈之  其二','黄庭堅','宋','宋诗','song-poetry','','[]','種萱欲遣憂，叢薄空自綠。',84,'全唐诗/poet.song.56000.json','["種萱欲遣憂，叢薄空自綠。", "洗心日三省，人亦不我穀。", "誰能書窗下，草玄抱幽獨。", "白首官不遷，校書漢天祿。", "身當萬戶侯，鼓吹擁部曲。", "解佩著犀渠，張弓插彫服。", "何時李將軍，射獵出上谷。"]'),
('6c85e169-a1eb-4593-ada6-220dd6236024','聖柬將寓于衛行乞食于齊有可憐之色再次韵感春五首贈之  其三','黄庭堅','宋','宋诗','song-poetry','','[]','春風鳴布穀，天道似勸分。',72,'全唐诗/poet.song.56000.json','["春風鳴布穀，天道似勸分。", "持饑望路人，誰能顔色溫。", "笑憶枯魚說，詼諧老漆園。", "湘纍不得祿，哀怨寫荃蓀。", "千年澗谷松，慚愧雨露恩。", "思爲萬乘器，顧掩斧鑿痕。"]'),
('b28c5a29-b160-47a6-b079-33a7ffaa275e','聖柬將寓于衛行乞食于齊有可憐之色再次韵感春五首贈之  其四','黄庭堅','宋','宋诗','song-poetry','','[]','風雨桃李華，佳人來何暮。',84,'全唐诗/poet.song.56000.json','["風雨桃李華，佳人來何暮。", "安齊果未安，寓衛豈所寓。", "張侯室縣磬，得酒美無度。", "常憂腐腸死，須我嫁阿騖。", "雙魚傳尺素，何處迷春渚。", "啼鳥勸不歸，曉鞍逐行旅。", "遙知登樓興，信美非吾土。"]'),
('1b25d3bd-77b3-40b9-b92c-af2542c87150','聖柬將寓于衛行乞食于齊有可憐之色再次韵感春五首贈之  其五','黄庭堅','宋','宋诗','song-poetry','','[]','魯公但食粥，百口常憂煎。',96,'全唐诗/poet.song.56000.json','["魯公但食粥，百口常憂煎。", "金張席貴寵，奴隸乘朱軒。", "丈夫例寒餓，萬世無後先。", "風霾天作惡，雷亦怒闐闐。", "俄頃花柳靜，煙暖谷鳥喧。", "人事每如此，翻覆不常然。", "下流多謗議，高位又疾顛。", "空餘壯士志，不逐四時遷。"]'),
('3952c9f9-685d-4a1c-900a-5a7684ecf1eb','次韵蓋郎中率郭郎中休官二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','仕路風波雙白髮，閒曹笑傲兩詩流。',64,'全唐诗/poet.song.56000.json','["仕路風波雙白髮，閒曹笑傲兩詩流。", "故人相見自青眼，新貴即今多黑頭。", "桃葉柳花明曉市，荻芽蒲笋上春洲。", "定知聞健休官去，酒戶家園得自由。"]'),
('5b5baef1-d94d-42f9-a518-43396e5e34dc','次韵蓋郎中率郭郎中休官二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','世態已更千變盡，心源不受一塵侵。',64,'全唐诗/poet.song.56000.json','["世態已更千變盡，心源不受一塵侵。", "青春白日無公事，紫燕黄鸝俱好音。", "付與兒孫知伏臘，聽教魚鳥逐飛沈。", "黄公壚下曾知味，定是逃禪入少林。"]'),
('65bdf488-477e-4fb2-8ae0-66aa4b11a2bf','次韵郭右曹','黄庭堅','宋','宋诗','song-poetry','','[]','閱世行將老斲輪，那能不朽見仍雲。',64,'全唐诗/poet.song.56000.json','["閱世行將老斲輪，那能不朽見仍雲。", "歲中日月又除盡，聖處工夫無半分。", "秋水寒沙魚得計，南山濃霧豹成文。", "古心自有著鞭地，尺璧分陰未當勤。"]'),
('b1544ebe-e44d-445e-857f-00efa493491b','送楊瓘雁門省親二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','執戟老翁年七十，人看生理亦無聊。',96,'全唐诗/poet.song.56000.json','["執戟老翁年七十，人看生理亦無聊。", "草玄事業窺周易，作賦聲名動漢朝。", "今見遠孫勤翰墨，還持遺藁困簞瓢。", "三年鄉校趨晨鼓，一日邊城聽夜刁。", "野飯盈盤厭葱韭，春風半道解狐貂。", "歸時定倒迎門屣，問雁安能學度遼。"]'),
('eb05a6df-52a3-41e3-a78f-912c4e972159','送楊瓘雁門省親二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','蜀客出衰世，獨升鄒魯堂。',72,'全唐诗/poet.song.56000.json','["蜀客出衰世，獨升鄒魯堂。", "蚊虻觀得失，虎豹擅文章。", "吾子已强學，草玄宜不忘。", "江河須畎澮，松柏要冰霜。", "馬策路千里，雁門書數行。", "旨甘君有婦，尺璧愛分光。"]'),
('1a9b3b21-9dfa-4e3c-bc6b-5794497900dc','次韵答張沙河','黄庭堅','宋','宋诗','song-poetry','','[]','張侯堂堂身八尺，老大無機如漢陰。',384,'全唐诗/poet.song.56000.json','["張侯堂堂身八尺，老大無機如漢陰。", "猛摩虎牙取吞噬，自歎日月不照臨。", "策名日已汙軒冕，逃去未必焚山林。", "我評君才甚高妙，孤竹截管空桑琴。", "四十未曾成老翁，紫髯垂頤鬰森森。", "眉宇之間見風雅，藍田煙霧生球琳。", "胸中壘塊正須酒，東海可攬北斗斟。", "古人已悲銅雀上，不聞向時清吹音。", "百年毀譽付誰定，取醉自可結舌瘖。", "使公繫腰印如斗，駟馬高蓋驅駸駸。", "親朋改觀婢僕敬，成都男子寧異今。", "又言屋底甚懸磬，兒婚女嫁取千金。", "古來聖賢多不飽，誰能獨無父母心。", "衆雛墮地各有命，强爲百草憂春霖。", "艾封人子暗目睫，與王同牀悔沾襟。", "隴鳥入籠左右啄，終日思歸碧山岑。", "一生能幾開口笑，何忍更遣百慮侵。", "忽投雄篇寫逸興，仰占乾文動奎參。", "自陳使酒嘗駡坐，惜予不與朋盍簪。", "君材蜀錦三千丈，要在刀尺成衣衾。", "南朝例有風流癖，楚地俗多詞賦淫。", "屈原離騷豈不好，只今漂骨滄江潯。", "正令夷甫開三窟，獵以我道皆成禽。", "溫恭忠厚神所勞，于魚得計豈厭深。"]'),
('7fd3df01-fd47-4984-9caa-fa71f9833c2e','送張沙河遊齊魯諸邦','黄庭堅','宋','宋诗','song-poetry','','[]','張侯去沙河，三食鄴下麥。',204,'全唐诗/poet.song.56000.json','["張侯去沙河，三食鄴下麥。", "筆力望晁董，頗遺俗眼白。", "平生學經綸，胸中負奇畫。", "未論功活人，飽飯不常得。", "妻寒尚賓敬，兒餓猶筆墨。", "側聞共伯城，魚稻頗宜客。", "又持塵生甑，欲往立四壁。", "平生貸米家，十輩來簿責。", "囊無孔方兄，面有在陳色。", "守株伺投兔，歲晚將何獲。", "廣道無人行，春風轉沙石。", "栖栖馬如狗，去謁東侯伯。", "布衣未可量，蒼髯身八尺。", "魚乾要斗水，士困易爲德。", "譬之舉大木，人借一臂力。", "諸公感意氣，豈待故相識。", "吾窮乏祖餞，折柳當馬策。"]'),
('96087e73-d8b6-43d7-aa20-833314518909','和張沙河招飲','黄庭堅','宋','宋诗','song-poetry','','[]','張侯耕稼不逢年，過午未炊兒女煎。',64,'全唐诗/poet.song.56000.json','["張侯耕稼不逢年，過午未炊兒女煎。", "腹裏雖盈五車讀，囊中能有幾錢穿。", "況聞縕素尚黄葛，可怕雪花鋪白氈。", "誰料丹徒布衣得，今朝忽有酒如川。"]'),
('502a5f9b-dba4-4259-a093-49fb5791413e','同堯民游靈源廟廖獻臣置酒用馬陵二字賦詩二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','靈源廟前木，我昔見拱把。',192,'全唐诗/poet.song.56000.json','["靈源廟前木，我昔見拱把。", "七年身屢到，鬰鬰蔭簷瓦。", "春風響馬銜，竝轡客蕭灑。", "更願少尹賢，置酒意傾寫。", "齋堂有佳處，花柳輕婭姹。", "蓮塘想舊葉，稻畦識枯苴。", "開關撫洪河，黄流極天瀉。", "憶昔武皇來，繫璧沈白馬。", "從官親土石，襁負至鰥寡。", "空餘瓠子詩，哀怨逼騷雅。", "白圭自聖禹，今誰定真假。", "晁子發讜言，聖功諒難亞。", "排河著地中，勢必千里下。", "移民就寬閒，何地不耕稼。", "此論似太高，吾亦茫取舍。", "有器可深川，吾未之學也。"]'),
('281056b5-fbcb-4a54-b4d9-501e8ac0fe6e','同堯民游靈源廟廖獻臣置酒用馬陵二字賦詩二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','洪河壯觀遊，太府佳友朋。',252,'全唐诗/poet.song.56000.json','["洪河壯觀遊，太府佳友朋。", "春色挽我出，東風如引繩。", "昏昏版築氣，王事始繁興。", "大堤如連山，小堤如岡陵。", "增卑更培薄，萬杵何登登。", "憶昨河失道，平原魚可罾。", "田萊人未復，瘡大國方懲。", "忽念耒耜閒，爲民保丘塍。", "百縣伐鼛出，夜半廢曲肱。", "吾儕愧祿廩，游衍事鞍乘。", "晁子漢公孫，新去司馬丞。", "出幹大農部，才術見嗟稱。", "我坐廣文舍，七年讀書燈。", "結髮入場屋，肯謂河難憑。", "爾來觸事短，癡甚霜前蠅。", "世味極淡薄，不了人愛憎。", "惟得一巵酒，尚能別淄澠。", "所以對樽俎，未曾聞斗升。", "酌我良已多，狂言恐侵陵。", "暮雲吞落日，歸鳥求其朋。", "冷官僕馬瘦，及門鼓騰騰。"]'),
('e345c462-58fa-4850-ab45-9e05c596b3a2','八音歌贈晁堯民','黄庭堅','宋','宋诗','song-poetry','','[]','金生寒沙中，見別會有時。',96,'全唐诗/poet.song.56000.json','["金生寒沙中，見別會有時。", "石上千年柏，材高用苦遲。", "絲亂猶可理，心亂不可治。", "竹齋聞履聲，迺是故人來。", "匏苦只多葉，水深難爲涉。", "土牀不安席，象牀卧燁燁。", "革與井同功，守道非關怯。", "木直常先伐，樗櫟萬世葉。"]'),
('c7f0ae14-6356-4763-8cf6-c5304ce0d27b','八音歌贈晁堯民','黄庭堅','宋','宋诗','song-poetry','','[]','金荷酌美酒，夫子莫留殘。',84,'全唐诗/poet.song.56000.json','["金荷酌美酒，夫子莫留殘。", "石有補天材，虎豹守九關。", "絲窠將柳花，入戶撲衣冠。", "竹風摇永日，思與子盤桓。", "匏瓜豈無匹，自古同心難。", "革急而韋緩，只在揉化間。", "木桃終報汝，藥石理予顔。"]'),
('3a226d4c-d582-417d-a09d-09bb4ea18627','次韵師厚五月十六日視田悼李彥深','黄庭堅','宋','宋诗','song-poetry','','[]','南雁傳尺素，飛來卧龍城。',120,'全唐诗/poet.song.56000.json','["南雁傳尺素，飛來卧龍城。", "頗知高卧久，忽作田野行。", "湛湛陂水滿，欣欣原草榮。", "日華麗山川，秀色奪目精。", "對酒不滿懷，攬物有餘清。", "念昔讀書客，遠人遺世情。", "南畝道觀餉，西郊留勸耕。", "共遊如昨日，笑語絕平生。", "此士今已矣，賓筵無老成。", "猶倚謝安石，深心撫嫠惸。"]'),
('eeb511c5-5f67-4578-b798-a654a2433944','次韵晁補之廖正一贈答詩','黄庭堅','宋','宋诗','song-poetry','','[]','晁子抱材耕谷口，世有高賢踐台斗。',179,'全唐诗/poet.song.56000.json','["晁子抱材耕谷口，世有高賢踐台斗。", "頃隨計吏西入關，關夫數日傳車還。", "封侯半屬妄校尉，射虎猛將猶行間。", "無因自致青雲上，浪說諸公見嗟賞。", "驥伏鹽車不稱情，輕裘肥馬鳳凰城。", "歸來作詩謝同列，句與桃李爭春榮。", "十年山林廖居士，今隨詔書稱舉子。", "文章宏麗學西京，新有詩聲似侯喜。", "君不見古來良爲知音難，絕絃不爲時人彈。", "已喜瓊枝在我側，更恨桂樹無由攀。", "千里風期初不隔，獨憐形迹滯河山。"]'),
('b859e74e-63fa-43d5-9762-4fd0783f1abb','再次韵呈廖明略','黄庭堅','宋','宋诗','song-poetry','','[]','吾觀三江五湖口，湯湯誰能議升斗。',182,'全唐诗/poet.song.56000.json','["吾觀三江五湖口，湯湯誰能議升斗。", "物誠有之士則然，晚得廖子喜往還。", "學如雲夢吞八九，文如壯士開黄間。", "十年呻吟江湖上，青楓白鷗付心賞。", "未減北郭漢先生，五府交書不到城。", "相者舉肥驥空老，山中無人桂自榮。", "君既不能如鍾世美，匭函上書動天子。", "且向華陰郡下作參軍，要令公怒令公喜。", "君不見晁家樂府可管絃，惜無傾城爲一彈。", "從軍補掾百僚底，九關虎豹何由攀。", "男兒身健事未定，且莫著書藏名山。"]'),
('bc4387eb-bfe8-4cf5-b492-41e7ea0670d7','走答明略適堯民來相約奉謁故篇末及之','黄庭堅','宋','宋诗','song-poetry','','[]','君不見生不願爲牛後，寧爲雞口。',191,'全唐诗/poet.song.56000.json','["君不見生不願爲牛後，寧爲雞口。", "吾聞向來得道人，終古不忒如維斗。", "希價咸陽諸少年，可推令往挽令還。", "俗學風波能自拔，我識廖侯眉宇間。", "省庭無人與爭長，主司得之如受賞。", "東家一笑市盡傾，略無下蔡與陽城。", "生珠之水砂礫潤，生玉之山草木榮。", "觀君詞章亦如此，諒知躬行有君子。", "更約探囊閱舊文，蛛絲燈花助我喜。", "賢樂堂前竹影斑，好鳥自語莫令彈。", "北鄰著作相勞苦，整駕謁子邀同攀。", "應煩下榻煮茶藥，坐待月輪銜屋山。"]'),
('a76ac7a5-d5c7-43cb-a46d-8c80a2bfdd12','答明略并寄无咎','黄庭堅','宋','宋诗','song-poetry','','[]','可以忘憂惟有酒，清聖濁賢皆可口。',198,'全唐诗/poet.song.56000.json','["可以忘憂惟有酒，清聖濁賢皆可口。", "前日過君飲不多，明日解酲無五斗。", "古木清陰丹井欄，夜來凉月屋頭還。", "論文撥置形骸外，得意相忘樽俎間。", "冰壺不可與夏蟲饗，秋月不可與俗士賞。", "已得樽前兩友生，更思一士濟陽城。", "雖無四至九卿之規畫，猶有千秋萬歲之真榮。", "空名未食太倉米，今作斑衣老萊子。", "卿家嗣宗望爾來，不獨我聞足音喜。", "西風索寞葉初乾，長鋏歸來亦罷彈。", "窮巷蓬蒿深一尺，朱門廉陛高難攀。", "吾儕相逢置是事，百世之下仰高山。"]'),
('4e7414fc-0bbf-4956-b683-7e746ab9d177','再次韵呈明略并寄无咎','黄庭堅','宋','宋诗','song-poetry','','[]','夏雲凉生土囊口，周鼎湯盤見科斗。',176,'全唐诗/poet.song.56000.json','["夏雲凉生土囊口，周鼎湯盤見科斗。", "清風古氣滿眼前，乃是戶曹報章還。", "只今書生無此語，已在貞元元和間。", "一夫鄂鄂獨無望，千夫唯唯皆論賞。", "野人泣血漫相明，和氏之璧無連城。", "參軍拄笏看雲氣，此中安知枯與榮。", "我夢浮天波萬里，扁舟去作鴟夷子。", "兩士風流對酒樽，四無人聲鳥語喜。", "夢回擾擾仍世間，心如傷弓怯虛彈。", "不堪市井逐乾沒，且願朋舊相追攀。", "寄聲小掾篤行李，落日東面空雲山。"]'),
('e39bd45c-3de6-483d-bd9e-43d780f12a46','再答明略二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','挾策讀書計糊口，故人南箕與北斗。',178,'全唐诗/poet.song.56000.json','["挾策讀書計糊口，故人南箕與北斗。", "江南江北萬重山，千里寄書聲不還。", "當時朱弦寫心曲，果在高山深水間。", "枯桐滿腹生蛛網，忍向時人覓清賞。", "廖侯文字得我驚，五嶽縱橫守嚴城。", "萬夫之下不稱屈，定知名滿四海非真榮。", "富於春秋已如此，他日卜鄰長兒子。", "一丘各自有林泉，扶將白頭親燕喜。", "秋風日暮衣裳單，深巷落葉已如彈。", "數來會面復能幾，六龍去人不可攀。", "短歌溷公更一和，聊乞淮南作小山。"]'),
('e25b6c0b-b046-4764-aedc-1597c90a9fa6','再答明略二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','廖侯言如不出口，銓量古今膽如斗。',181,'全唐诗/poet.song.56000.json','["廖侯言如不出口，銓量古今膽如斗。", "度越崔張與二班，古風蕭蕭筆追還。", "前日辭家來射策，聲名藉甚諸公間。", "華陰白雲鎖千嶂，勝日一談誰能賞。", "君不見曩時子産識然明，知音鬰鬰閉佳城。", "勿以匣中之明月，計較糞上之朝榮。", "我去丘園十年矣，種桑可蠶犢生子。", "使年七十今中半，安能朝四暮三浪憂喜。", "據席談經只强顔，不安時論取譏彈。", "愛君草木同臭味，頗似瓜葛相依攀。", "我有仙方煮白石，何時期君藍田山。"]'),
('e87b6fff-4d0b-4396-a118-add5c15245dc','次韵无咎閻子常携琴八村','黄庭堅','宋','宋诗','song-poetry','','[]','士寒餓，古猶今，向來亦有子桑琴。',186,'全唐诗/poet.song.56000.json','["士寒餓，古猶今，向來亦有子桑琴。", "倚楹嘯歌非寓淫，伯牙山高水深深，萬世丘壟一知音。", "閻君七絃抱幽獨，晁子爲之梁父吟。", "天寒絡緯悲向壁，秋高風露聲入林。", "冷絲枯木拂珠網，十指乃能寫人心。", "村村擊鼓如鳴鼉，豆田見角穀成螺。", "歲豐寒士亦把酒，滿眼飣餖梨棗多。", "晁家公子屢經過，笑談與世殊臼科。", "文章落落映晁董，詩句往往妙陰何。", "閻夫子，勿謂知人難，使琴抑怨久不和。", "明光晝開九門肅，不令高才牛下歌。"]'),
('eb23e2eb-6f80-404f-9ef6-8fd37879eefb','定交詩二首效鮑明遠體呈晁无咎  其一','黄庭堅','宋','宋诗','song-poetry','','[]','建酉金爲政，摇落草木衰。',144,'全唐诗/poet.song.56000.json','["建酉金爲政，摇落草木衰。", "除瓜隴畝凈，邵平無米炊。", "滿家色藜藿，詩書不賙饑。", "平生晁公子，正用此時來。", "定交無一物，秋月以爲期。", "執持荆山璧，要我雕琢之。", "破斧不能柯，況乃玉無疵。", "危冠論百揆，備樂奏四時。", "成功彼有命，用舍君自知。", "收身渺江湖，歲晚白鳥嬉。", "開徑蒲葦中，倚鋤望君歸。", "閉塞乃非道，不才當爾爲。"]'),
('eb1d8c03-dfae-405c-aa38-8bc825f341ee','定交詩二首效鮑明遠體呈晁无咎  其二','黄庭堅','宋','宋诗','song-poetry','','[]','建鼓求亡子，原非入耳歌。',144,'全唐诗/poet.song.56000.json','["建鼓求亡子，原非入耳歌。", "除去綠綺塵，水深山峨峨。", "滿堂悅秦聲，君獨用此何。", "平分感秋節，空闊湛金波。", "定夜百蟲息，高論聽懸河。", "執攬北斗柄，斟酌四時和。", "破屋仰見星，得子喜且多。", "危柱無安絃，野水自盈科。", "成道在禮樂，成山在丘阿。", "收此桑榆景，相從寄琢磨。", "開懷溟海闊，百怪出蛟鼉。", "閉藏願自愛，驚人取譴訶。"]'),
('f26790dd-b019-43c3-8b91-8f93a8ecc042','贈无咎八音歌','黄庭堅','宋','宋诗','song-poetry','','[]','金馬避世客，談諧玩漢朝。',96,'全唐诗/poet.song.56000.json','["金馬避世客，談諧玩漢朝。", "石門抱關人，長往閉寂寥。", "絲蟲日夜織，勞苦則以食。", "竹生罹斧斤，高林乃其賊。", "匏樽酌吾子，雖陋意不淺。", "土德貴重遲，水德貴深遠。", "革能談鯤鵬，晚乃得莊周。", "木雁兩不居，相期無待遊。"]'),
('7b9467ac-221b-4033-b187-30af954901f4','二十八宿歌贈別无咎','黄庭堅','宋','宋诗','song-poetry','','[]','虎剝文章犀解角，食未下亢奇禍作。',224,'全唐诗/poet.song.56000.json','["虎剝文章犀解角，食未下亢奇禍作。", "藥材根氐罹斸掘，蜜蟲奪房抱饑渴。", "有心無心材慧死，人言不如龜曳尾。", "衛平哆口無南箕，斗柄指日江使噫。", "狐腋牛衣同一燠，高丘無女甘獨宿。", "虛名挽人受實禍，累棋既危安處我。", "室中凝塵散髮坐，四壁矗矗見天下。", "奎蹄曲隈取脂澤，婁豬艾豭彼何擇。", "傾腸倒胃得相知，貫日食昴終不疑。", "古來畢命黄金臺，佩君一言等觜觿。", "月沒參橫惜相違，秋風金井梧桐落。", "故人過半在鬼錄，柳枝贈君當馬策。", "歲晏星回觀盛德，張弓射雉武且力。", "白鷗之翼沒江波，抽絃去軫君謂何。"]'),
('bddb17be-e064-44cb-8643-c792560dd826','林爲之送筆戲贈','黄庭堅','宋','宋诗','song-poetry','','[]','閻生作三副，規摹宣城葛。',240,'全唐诗/poet.song.56000.json','["閻生作三副，規摹宣城葛。", "外貌雖銑澤，毫心或麤糲。", "功將希栗尾，拙乃成棗核。", "李慶縛散卓，含墨能不洩。", "病在惜白毫，往往半巧拙。", "小字亦周旋，大字難曲折。", "時時一毛亂，乃似逆梳髮。", "張鼎徒有表，徐偃元無骨。", "橅畫記姓名，亦可應倉卒。", "爲之街南居，時通鈴下謁。", "晴軒坐風凉，怪我把枯筆。", "開囊撲蠹魚，遣奴送一束。", "洗硯磨松煤，揮灑至日沒。", "蚤年學屠龍，適用固疏闊。", "廣文困虀鹽，烹茶對秋月。", "略無人問字，況有客投轄。", "文章寄呻吟，講授費頰舌。", "閒無用心處，雌黄到筆墨。", "時不與人遊，孔子尚愛日。", "作詩當鳴鼓，聊自攻短闕。"]'),
('9ef565ea-496f-4fc6-8f4a-5ba2b5ca6c4d','再和答爲之','黄庭堅','宋','宋诗','song-poetry','','[]','君勿嘲廣文，沍寒被絺葛。',240,'全唐诗/poet.song.56000.json','["君勿嘲廣文，沍寒被絺葛。", "君勿嘲廣文，窮年飯粢糲。", "常恐俎豆予，與世充肴核。", "凡木不願材，大折小枝洩。", "櫟依曲轅社，聊用神其拙。", "吾家本江南，一丘藏曲折。", "瀕溪蔭蒼筤，萧洒可散髮。", "既無使鬼錢，又無封侯骨。", "薄祿庇閒曹，且免受逼卒。", "爲此懶出門，徒弊懷中謁。", "直齋賓客退，風物供落筆。", "詩成著牀頭，不知今幾束。", "君何向予勤，見詩歎埋沒。", "嗣宗須酒澆，未信胸懷闊。", "自狀一片心，碧潭浸寒月。", "令德感來教，爲君賦車轄。", "君思揚雄吒，何似張儀舌。", "此意恐太狂，願爲引繩墨。", "正使此道非，改過從今日。", "報章望瓊琚，勿使音塵闕。"]'),
('3076a3f3-f89a-421c-8295-75de1cb5dde1','再和答爲之','黄庭堅','宋','宋诗','song-poetry','','[]','林君維閩英，數面成瓜葛。',240,'全唐诗/poet.song.56000.json','["林君維閩英，數面成瓜葛。", "鄰居接杖藜，過飯厭疏糲。", "讀書飽工夫，論事極精核。", "奮身君子場，勇若怒未洩。", "窮年棲旅巢，由命非由拙。", "王良驅八駿，方駕度九折。", "學堂疏雨餘，石砌長苔髮。", "弟子肥如瓠，先生瘦惟骨。", "北門一都會，塵埃人卒卒。", "高蓋如秋荷，勢利相奔謁。", "惟君尚寂寞，來觀草玄筆。", "斯文未易陳，正當高閣束。", "金馬事陸沈，市門逐乾沒。", "未須相賢愚，聊自嘲迂闊。", "憶昨戲贈詩，羣辱報明月。", "極知推挽意，我車君欲轄。", "屠龍真强言，奔馬不及舌。", "賜書盈五車，直舍方二墨。", "意會便欣然，餘事過窗日。", "尚恐素餐錢，諸生在城闕。"]'),
('b06e3214-536f-4a47-b3cc-54d4f2b73309','贈趙言','黄庭堅','宋','宋诗','song-poetry','','[]','饒陽趙方士，眼如九秋鷹。',332,'全唐诗/poet.song.56000.json','["饒陽趙方士，眼如九秋鷹。", "學書不成不學劍，心術妙解通神明。", "醫如俯身拾地芥，相如仰面觀天星。", "自言方術雜鬼怪，萬種一貫皆天成。", "大梁卜肆傾賓客，二十餘年聲籍籍。", "得錢滿屋不經營，散與世人還寄食。", "北門塵土滿衣襟，廣文直舍官槐陰。", "白雲勸酒終日醉，紅燭圍棋清夜深。", "大車駟馬不回首，强項老翁來見尋。", "向人忠信去表襮，可喜正在無機心。", "輕談禍福邀重糈，所在多于竹葦林。", "翁言此輩無足聽，見葉知根論才性。", "飛騰九天沈九淵，自種自收皆在行。", "先期出語駭傳聞，事至十九中時病。", "輪囷離奇惜老大，成器本可千萬乘。", "自歎輕霜白髮新，又去驚動都城人。", "都城達官老于事，嫌翁出言不娬媚。", "有手莫炙權門火，有口莫辯荆山玉。", "吳宮火起燕焚巢，當時卞和斮兩足。", "千里辭家却入門，三春榮木會歸根。", "我有江南黄篾舫，與翁長入白鷗羣。"]'),
('4f2950cc-875e-43de-b1ab-fbc42d130331','次韵題粹老客亭詩後','黄庭堅','宋','宋诗','song-poetry','','[]','客亭長短路南北，衮衮行人那得知。',32,'全唐诗/poet.song.56000.json','["客亭長短路南北，衮衮行人那得知。", "惟有相逢即相別，一杯成喜只成悲。"]'),
('58b59a6e-4796-48e7-be5a-475dc2f648c9','贈張仲謀','黄庭堅','宋','宋诗','song-poetry','','[]','車如雞栖馬如狗，閉門常多出門少。',240,'全唐诗/poet.song.56000.json','["車如雞栖馬如狗，閉門常多出門少。", "去天尺五張公子，官居城南池館好。", "健兒快馬紫游韁，迎我不知沙路長。", "高榆老柳媚寒日，枯荷小鴨凍野航。", "津人刺船起應客，遙知故人一水隔。", "下馬索酒呼三遲，騎奴笑言客竟癡。", "向來情義比瓜葛，萬事略不置町畦。", "追數存亡異憂樂，燭如白虹貫酒巵。", "開軒臨水弄長笛，吹落殘月風凄凄。", "城頭漏下四十刻，破魔驚睡聽新詩。", "君詩清壯悲節物，正與秋蟲同一律。", "邇來更覺苦語工，思婦霜碪擣寒月。", "朱顔綠髮深誤人，不似草木長青春。", "潔身好賢君自有，今日相看進于舊。", "以茲敢傾一盃酒，爲太夫人千萬壽。"]'),
('f5a6907c-86aa-4710-a5a2-a7a67533a4e6','乞貓','黄庭堅','宋','宋诗','song-poetry','','[]','秋來鼠輩欺貓死，窺甕翻盤攪夜眠。',32,'全唐诗/poet.song.56000.json','["秋來鼠輩欺貓死，窺甕翻盤攪夜眠。", "聞道貍奴將數子，買魚穿柳聘銜蟬。"]'),
('2af9f3fd-1a03-42c1-b7dc-2d9c05f399c5','謝周文之送貓兒','黄庭堅','宋','宋诗','song-poetry','','[]','養得狸奴立戰功，將軍細柳有家風。',32,'全唐诗/poet.song.56000.json','["養得狸奴立戰功，將軍細柳有家風。", "一簞未厭魚餐薄，四壁當令鼠穴空。"]'),
('226ddd7c-365f-41d3-928c-036b12eb4da9','謝張泰伯惠黄雀鮓','黄庭堅','宋','宋诗','song-poetry','','[]','去家十二年，黄雀慳下筯。',180,'全唐诗/poet.song.56000.json','["去家十二年，黄雀慳下筯。", "笑開張侯盤，湯餠始有助。", "蜀王煎藙法，醢以羊彘兔。", "麥餠薄于紙，含漿和鹹酢。", "秋霜落場穀，一一挾繭絮。", "飛飛蒿艾間，入網輒萬數。", "烹煎宜老稚，罌缶煩愛護。", "南包解京師，至尊所珍御。", "玉盤登百十，睥睨輕桂蠹。", "五侯噦豢豹，見謂美無度。", "瀕河飯食漿，瓜葅已佳茹。", "誰言風沙中，鄉味入供具。", "坐令親饌甘，更使客得與。", "蒲陰雖窮僻，勉作三年住。", "願公且安樂，分寄尚能屢。"]'),
('db0ff4a5-7ab3-4241-b712-1513bd1233a7','贈答晁次膺','黄庭堅','宋','宋诗','song-poetry','','[]','次膺豪健如霜鶻，空拳誤掛田犬牙。',64,'全唐诗/poet.song.56000.json','["次膺豪健如霜鶻，空拳誤掛田犬牙。", "果輸司空城旦作，付與步兵厨人家。", "野馬橫郊作凝水，牽牛引竹上寒花。", "無酒醉公不甚惜，誦公五字使人嗟。"]'),
('3c18f577-a19f-4322-9ab0-a48cc73a2c45','楊朴墓','黄庭堅','宋','宋诗','song-poetry','','[]','三尺孤墳一布衣，人言無復似當時。',32,'全唐诗/poet.song.56000.json','["三尺孤墳一布衣，人言無復似當時。", "千秋萬歲還來此，月笛煙莎世不知。"]'),
('e76ffa52-0a1d-4dbe-9c0e-b2f41b75e2ba','次韵孔四著作早行','黄庭堅','宋','宋诗','song-poetry','','[]','棄置鋤犁就車馬，從來計出古人下。',176,'全唐诗/poet.song.56000.json','["棄置鋤犁就車馬，從來計出古人下。", "塵埃好在三尺桐，不疑萬世期子野。", "明經使者著書郎，風雨乘馹忘夙夜。", "回車過門問無恙，何意深巷勤長者。", "聖師之後蓋多賢，領略世故有餘暇。", "白面長身雖不見，好古發憤尚類也。", "自然身如警露鶴，每先鳴雞整初駕。", "北行河决所至郡，肅肅王命哀鰥寡。", "力排滹沱避城郭，深澤疲民且田舍。", "賈生三策藏胸中，羿矢百中不虛捨。", "行歸定拜關內侯，但賜黄金恐非價。"]'),
('b3221233-3ec7-4adb-8920-f6b55a371eab','次韵孔四著作北行滹沱','黄庭堅','宋','宋诗','song-poetry','','[]','駝褐蒙風霜，雞聲眇墟里。',48,'全唐诗/poet.song.56000.json','["駝褐蒙風霜，雞聲眇墟里。", "青燈進豆粥，落月踏冰水。", "平生不龜藥，纔可衛十指。", "持比千戶封，誰能優劣此。"]'),
('fe1f7a7e-d566-4a8f-b292-690171f2e427','和陳君儀讀太真外傳五首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','朝廷無事君臣樂，花柳多情殿閣春。',32,'全唐诗/poet.song.56000.json','["朝廷無事君臣樂，花柳多情殿閣春。", "不覺胡雛心暗動，綺羅翻作墜樓人。"]'),
('3691f1fb-2052-4171-bda4-5f92ef57fa2e','和陳君儀讀太真外傳五首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','扶風喬木夏陰合，斜谷鈴聲秋夜深。',32,'全唐诗/poet.song.56000.json','["扶風喬木夏陰合，斜谷鈴聲秋夜深。", "人到愁來無處會，不關情處總傷心。"]'),
('370fece4-9991-47a1-8ac2-8d0c97f97429','和陳君儀讀太真外傳五首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','梁州一曲當時事，記得曾拈玉笛吹。',32,'全唐诗/poet.song.56000.json','["梁州一曲當時事，記得曾拈玉笛吹。", "端正樓空春晝永，小桃猶學淡燕支。"]'),
('b9212373-9a44-4c4d-b4d8-1833a132dadf','和陳君儀讀太真外傳五首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','高麗條脫琱紅玉，邏逤琵琶撚綠絲。',32,'全唐诗/poet.song.56000.json','["高麗條脫琱紅玉，邏逤琵琶撚綠絲。", "蛛網屋煤昏故物，此生惟有夢來時。"]'),
('44fbce65-3c9c-4402-bdca-c9544608dd9b','和陳君儀讀太真外傳五首  其五','黄庭堅','宋','宋诗','song-poetry','','[]','上皇曾御昭儀傳，鏡裏觀形只眼前。',32,'全唐诗/poet.song.56000.json','["上皇曾御昭儀傳，鏡裏觀形只眼前。", "養得祿兒傾四海，千秋更有一伶玄。"]'),
('3531e6ae-63a9-4c5d-8532-11dffbbe6a8c','讀曹公傳','黄庭堅','宋','宋诗','song-poetry','','[]','南征北伐報功頻，劉氏親爲魏國賓。',64,'全唐诗/poet.song.56000.json','["南征北伐報功頻，劉氏親爲魏國賓。", "畢竟以丕成霸業，豈能于漢作純臣。", "兩都秋色皆喬木，二祖恩波在細民。", "駕馭英雄雖有術，力扶宗社可無人。"]'),
('52fb815c-b381-4e4c-87da-f0914f89d9ec','雜詩','黄庭堅','宋','宋诗','song-poetry','','[]','古風蕭索不言歸，貧賤交情富貴非。',32,'全唐诗/poet.song.56000.json','["古風蕭索不言歸，貧賤交情富貴非。", "世祖本無天下量，子陵何慕釣魚磯。"]'),
('0e3015a0-3c57-45cb-bb2a-a85e1c954379','衛南','黄庭堅','宋','宋诗','song-poetry','','[]','今年畚鍤棄春耕，折葦枯荷繞壞城。',64,'全唐诗/poet.song.56000.json','["今年畚鍤棄春耕，折葦枯荷繞壞城。", "白鳥自多人自少，污泥終濁水終清。", "沙場旗鼓千人集，漁戶風煙一笛橫。", "惟有鳴鴟古祠柏，對人猶是向時情。"]'),
('4f2cdb1e-4b95-4f5d-9981-18d92e9cd7b3','酒','黄庭堅','宋','宋诗','song-poetry','','[]','江形圜似阮家盆，山勢岑如北海樽。',32,'全唐诗/poet.song.56000.json','["江形圜似阮家盆，山勢岑如北海樽。", "戶有浮蛆春盎盎，雙松一路醉鄉門。"]'),
('15ea2816-464c-4fa9-b93e-1f7298ee1b5c','次韵答柳通叟問舍求田之詩','黄庭堅','宋','宋诗','song-poetry','','[]','少日心期轉謬悠，蛾眉見妒且障羞。',64,'全唐诗/poet.song.56000.json','["少日心期轉謬悠，蛾眉見妒且障羞。", "但令有婦如康子，安用生兒似仲謀。", "橫笛牛羊歸晚徑，卷簾瓜芋熟西疇。", "功名可致猶回首，何況功名不可求。"]'),
('997315e2-582d-4d2c-b3af-fe79cd951ba0','書扇','黄庭堅','宋','宋诗','song-poetry','','[]','魯公筆法屋漏雨，未減右軍錐畫沙。',32,'全唐诗/poet.song.56000.json','["魯公筆法屋漏雨，未減右軍錐畫沙。", "可惜團團新月面，故教零亂黑雲遮。"]'),
('4f323fd6-61a5-4022-971f-664369ef540c','次韵答叔原會寂照房呈稚川','黄庭堅','宋','宋诗','song-poetry','','[]','客愁非一種，歷亂如蜜房。',192,'全唐诗/poet.song.56000.json','["客愁非一種，歷亂如蜜房。", "食甘念慈母，衣綻懷孟光。", "我家猶北門，王子渺湖湘。", "寄書無雁來，衰草漫寒塘。", "故人哀王孫，交味耐久長。", "置酒相暖熱，愜于冬飲湯。", "吾儕癡絕處，不減顧長康。", "得閒枯木坐，冷日下牛羊。", "坐有稻田衲，頗薰知見香。", "勝談初亹亹，脩綆汲銀牀。", "聲名九鼎重，冠蓋萬夫望。", "老禪不掛眼，看蝸書屋梁。", "韵與境俱勝，意將言兩忘。", "出門事衮衮，斗柄莫昂昂。", "月色麗雙闕，雪雲浮建章。", "苦寒無處避，惟欲酒中藏。"]'),
('f5453493-7b81-48e5-952c-1aef17d10bac','同王稚川晏叔原飯寂照房','黄庭堅','宋','宋诗','song-poetry','','[]','高人住寶坊，重客款齋房。',192,'全唐诗/poet.song.56000.json','["高人住寶坊，重客款齋房。", "市聲猶在耳，靜虛生白光。", "幽子遺淡墨，窗間見瀟湘。", "蒹葭落鳬雁，秋色媚橫塘。", "博山沈水煙，淡與人意長。", "自携鷹爪芽，來試魚眼湯。", "寒浴得溫湢，體浄意凱康。", "盤餐取近市，厭飫謝羶羊。", "裂餠羞豚膾，包魚芰荷香。", "平生所懷人，忽言共榻牀。", "常恐風雨散，千里鬰相望。", "斯游豈易得，淵對妙濠梁。", "雅雅王稚川，易親復難忘。", "晏子與人交，風義盛激昂。", "兩公盛才力，宮錦麗文章。", "鄙夫得秀句，成誦更懷藏。"]'),
('9caf754a-7bbd-4ced-a2c6-2c9c1fdccb8e','次韵叔原會寂照房','黄庭堅','宋','宋诗','song-poetry','','[]','風雨思齊詩，草木怨楚調。',96,'全唐诗/poet.song.56000.json','["風雨思齊詩，草木怨楚調。", "本無心擊排，勝日用歌嘯。", "僧窗茶煙底，清絕對二妙。", "俱含萬里情，雪梅開嶺徼。", "我慙風味淺，砌莎慕松蔦。", "中朝盛人物，誰與開顔笑。", "二公老諳事，似解寂寞釣。", "對之空歎嗟，樓閣重晚照。"]'),
('fd6129ca-099a-42f2-ace8-23266ce65705','次韵稚川','黄庭堅','宋','宋诗','song-poetry','','[]','平生萬里興，斂退著寸尺。',120,'全唐诗/poet.song.56000.json','["平生萬里興，斂退著寸尺。", "向來類竊鈇，少日已爭席。", "曩過招提飯，愜當易爲適。", "食鮭如舉士，名下無遺索。", "談餘天雨花，茶罷風生腋。", "誰言塵土中，有此坐上客。", "言前傾許可，胸次開堛塞。", "同是蠹魚癡，還歸理編冊。", "長安千門雪，蟹黄熊有白。", "更約載酒行，無爲守岑寂。"]'),
('804269dc-6146-4463-8a6d-e55c93ecc8ac','都下喜見八叔父','黄庭堅','宋','宋诗','song-poetry','','[]','一別七冬夏，幾書通置郵。',288,'全唐诗/poet.song.56000.json','["一別七冬夏，幾書通置郵。", "冥鴻難借問，江鯉多沈浮。", "心因夢想去，迹爲山川留。", "叔趨丹鳳闕，身向卧龍洲。", "邂逅入關馬，同時解轡鞦。", "別後事萬端，向來身百憂。", "咨嗟舊田園，慟哭新松楸。", "稍詢耆舊間，太半歸山丘。", "小兒携婦子，襁褓皆裹頭。", "青燈照逆旅，呼酒濯亂愁。", "破啼爲笑語，霜夜盡更籌。", "歲寒叔舊節，況又高春秋。", "老松心更槩，綠竹氣和柔。", "言如不出口，體若不勝裘。", "德音潤九里，政事無全牛。", "詩成戲筆墨，清甚韋蘇州。", "篆籀有志氣，當於古人求。", "自悲聞道晚，涉世如虛舟。", "雖無觸物意，儻亦遭駡咻。", "稍窺性命學，未窮言行尤。", "息心待自信，渺如大河流。", "隄防小不密，一决敗數州。", "安得心服禮，不見爲瘡疣。", "荆雞變化材，鵠卵滯陰幽。"]'),
('4e474d22-ebd4-46f1-b33e-8388d539859b','次韵叔父夷仲送夏君玉赴零陵主簿','黄庭堅','宋','宋诗','song-poetry','','[]','田竇堂上酒，未醉已變態。',132,'全唐诗/poet.song.56000.json','["田竇堂上酒，未醉已變態。", "何如東陵瓜，子母相鈎带。", "富貴席未煖，珠玉作災怪。", "茅茨雖長貧，終有懿親在。", "丈人困州縣，短髮餘會撮。", "居然枳棘棲，坐閱歲月代。", "青雲已迷津，濁酒未割愛。", "簿領能無休，飣餖喚魚菜。", "羈旅苦地偏，江湖見天大。", "萬里一帆檣，長風可倚頼。", "因行訪幽禪，頭陀煙雨外。"]'),
('277a1942-a084-4641-aa52-3b438010416d','病起次韵和稚川進叔倡酬之什','黄庭堅','宋','宋诗','song-poetry','','[]','池塘夜雨聽鳴蛙，老境侵尋每憶家。',64,'全唐诗/poet.song.56000.json','["池塘夜雨聽鳴蛙，老境侵尋每憶家。", "白髮生來驚客鬢，黄粱炊熟又春華。", "百年不負膠投漆，萬事相依葛與瓜。", "勝日主人如有酒，猶堪扶病見鶑花。"]'),
('fcb1a35e-26af-4488-bfd6-e281b0442f9d','稚川約晚過進叔次前韵贈稚川并呈進叔','黄庭堅','宋','宋诗','song-poetry','','[]','人騎一馬鈍如蛙，行向城東小隠家。',64,'全唐诗/poet.song.56000.json','["人騎一馬鈍如蛙，行向城東小隠家。", "道上風埃迷皂白，堂前水竹湛清華。", "春歸河曲定寒食，公到江南應削瓜。", "樽酒光陰俱可惜，端須連夜發園花。"]'),
('1181bfd7-966d-4a51-a434-23d4d6f4bc98','汴岸置酒贈黄十七','黄庭堅','宋','宋诗','song-poetry','','[]','吾宗端居叢百憂，長歌勸之肯出遊。',64,'全唐诗/poet.song.56000.json','["吾宗端居叢百憂，長歌勸之肯出遊。", "黄流不解涴明月，碧樹爲我生凉秋。", "初平羣羊置莫問，叔度千頃醉即休。", "誰倚柁樓吹玉笛，斗杓寒挂屋山頭。"]'),
('f12c202c-965c-4736-9885-b92c2f055f99','曉放汴舟','黄庭堅','宋','宋诗','song-poetry','','[]','秋聲滿山河，行李在梁宋。',48,'全唐诗/poet.song.56000.json','["秋聲滿山河，行李在梁宋。", "川塗事雞鳴，身亦逐羣動。", "霜清魚下流，橘柚入包貢。", "又持三十口，去作江南夢。"]'),
('2302cee7-e71f-41d2-8880-337a6d8abd5f','次盱眙同前韵','黄庭堅','宋','宋诗','song-poetry','','[]','去此二十年，持家西過宋。',48,'全唐诗/poet.song.56000.json','["去此二十年，持家西過宋。", "起予者白鷗，歸興岌飛動。", "宮殿明寶坊，山川開禹貢。", "破浪一帆風，更占夢中夢。"]'),
('f0a49170-c4e4-47dc-b8ed-2587bea18e26','外舅孫莘老守蘇州留詩斗野亭庚申十月庭堅和','黄庭堅','宋','宋诗','song-poetry','','[]','謝公所築埭，未歎曲池平。',120,'全唐诗/poet.song.56000.json','["謝公所築埭，未歎曲池平。", "蘇州來賦詩，句與秋氣清。", "僧構擅空闊，浮光飛棟甍。", "維斗天司南，其下百瀆傾。", "貝宮産明月，含澤遍諸生。", "槃礴淮海間，風煙侵十城。", "籟簫吹木末，浪波沸庖烹。", "我來杪摇落，霜清見魚行。", "白鷗遠飛來，得我若眼明。", "佳人歸何時，解衣繞廂榮。"]'),
('4e9af6a1-a732-4d85-ae4a-551f70e1d3e2','十月十三日泊舟白沙江口','黄庭堅','宋','宋诗','song-poetry','','[]','岸江倚帆檣，已專北風權。',96,'全唐诗/poet.song.56000.json','["岸江倚帆檣，已專北風權。", "飛霜挾月下，百笮直如弦。", "綠水去清夜，黄蘆摇白煙。", "篙人持更柝，相語聞並船。", "平生濯纓心，鷗鳥共忘年。", "風吹落塵網，歲星奔回旋。", "險艱自得力，細故可棄捐。", "至今夢洶洶，呼禹濟廣川。"]'),
('c1232da7-6c18-4366-8316-f1d086b1be94','發白沙口次長蘆','黄庭堅','宋','宋诗','song-poetry','','[]','篙師救首尾，我爲制中權。',96,'全唐诗/poet.song.56000.json','["篙師救首尾，我爲制中權。", "挂席滿風力，如椎强弩絃。", "曉放白沙口，長蘆見炊烟。", "一葉託秋雨，滄江百尺船。", "反觀世風波，誰能保長年。", "念昔聲利區，與世闕周旋。", "大道甚閒暇，百物不廢捐。", "誰知目力浄，改觀舊山川。"]'),
('9db0b909-c964-45fb-906b-129c15b66bd7','阻風入長蘆寺','黄庭堅','宋','宋诗','song-poetry','','[]','福公開百室，不借鄰國權。',96,'全唐诗/poet.song.56000.json','["福公開百室，不借鄰國權。", "法筵森龍象，天樂下管絃。", "我來雨花地，依舊薰爐烟。", "金碧動江水，鐘魚到客船。", "茗椀洗昏著，經行數徂年。", "歲寒風落山，故鄉喜言旋。", "林回負赤子，白璧乃可捐。", "侍親如履冰，風雨淼暗川。"]'),
('231cd309-1ef9-4679-ad76-34075b5beedf','次韵伯氏長蘆寺下','黄庭堅','宋','宋诗','song-poetry','','["\u6292\u60c5", "\u7eaa\u6e38", "\u5199\u666f"]','風從落帆休，天與大江平。',120,'全唐诗/poet.song.56000.json','["風從落帆休，天與大江平。", "僧坊晝亦靜，鐘磬寒逾清。", "淹留屬暇日，植杖數連甍。", "頗與幽子逢，煮茗當酒傾。", "携手霜木末，朱欄見潮生。", "檣移永正縣，鳥度建康城。", "薪者得樹雞，羹盂味南烹。", "香秔炊白玉，飽飯愧閒行。", "叢祠思歸樂，吟弄夕陽明。", "思歸誠獨樂，薇蕨漸春榮。"]'),
('7e7ae3ea-0f6d-4ac6-8d6c-47acb1bc280b','金陵','黄庭堅','宋','宋诗','song-poetry','','[]','豪士阻江海，瓜分域中權。',96,'全唐诗/poet.song.56000.json','["豪士阻江海，瓜分域中權。", "真人開關梁，曾不費一弦。", "六朝妙人物，蔓草縈寒烟。", "至今哀江南，詠歌在漁船。", "窮山虎豹穴，磨衲擁高年。", "青天行日月，坐看磨蟻旋。", "身將時共晚，道與世相捐。", "猶能攬壯觀，巨浸朝百川。"]'),
('ddef564d-559e-4360-bc7d-adee80606304','贈別李端叔','黄庭堅','宋','宋诗','song-poetry','','[]','我觀江南山，如目不受垢。',192,'全唐诗/poet.song.56000.json','["我觀江南山，如目不受垢。", "憶食江南薇，子獨于我厚。", "在北思江山，如懷冰雪顔。", "千峰上雲雨，岑絕何由攀。", "當時喜文章，各有兒子氣。", "爾來頷鬚白，有兒能拜起。", "讀書浩湖海，解意開春冰。", "成山更崇崛，顧我醜丘陵。", "白玉著石中，與物本落落。", "涇渭相將流，世不名清濁。", "乞言既不易，贈言良獨難。", "古來得道人，掛舌屋壁間。", "牧羊金華道，載酒太玄宅。", "支頤聽晤語，願君喙三尺。", "我行風雨夜，船窗聞遠雞。", "故人不可見，故人心可知。"]'),
('f046c604-fe51-445d-8bde-77ab685217a9','阻風銅陵','黄庭堅','宋','宋诗','song-poetry','','[]','頓舟古銅官，晝夜風雨黑。',144,'全唐诗/poet.song.56000.json','["頓舟古銅官，晝夜風雨黑。", "洪波崩奔去，天地無限隔。", "船人謹維笮，何暇思挂席。", "憑江裂嵌空，中有暗水滴。", "洞視不敢前，潭潭蛟龍宅。", "網師登長鱣，賈我腥釜鬲。", "斑斑被文章，突兀喙三尺。", "言語竟不通，噞喁亦何益。", "魁梧類長者，卒以筌餌得。", "浮沉江湖中，波友永相失。", "有生甚苦相，細大更噉食。", "安得無垢稱，對榻忘語默。"]'),
('183ae166-8668-4b84-9dfa-ee8e9b1283dc','阻水泊舟竹山下','黄庭堅','宋','宋诗','song-poetry','','[]','竹山蟲鳥朋友語，討論陰晴怕風雨。',64,'全唐诗/poet.song.56000.json','["竹山蟲鳥朋友語，討論陰晴怕風雨。", "丁寧相教防禍機，草動塵驚忽飛去。", "提壺歸去意甚真，柳暗花濃亦半春。", "北風幾日銅官縣，欲過五松無主人。"]'),
('1ff2c90a-6c77-437e-ba8b-6500ce6d569e','池口風雨留三日','黄庭堅','宋','宋诗','song-poetry','','["\u6292\u60c5", "\u6000\u624d\u4e0d\u9047", "\u5199\u666f"]','孤城三日風吹雨，小市人家只菜蔬。',64,'全唐诗/poet.song.56000.json','["孤城三日風吹雨，小市人家只菜蔬。", "水遠山長雙屬玉，身閒心苦一舂鋤。", "翁從旁舍來收網，我適臨淵不羨魚。", "俛仰之間已陳迹，暮窗歸了讀殘書。"]'),
('def035c8-2279-4fab-8ef4-6a6e14e8d668','貴池','黄庭堅','宋','宋诗','song-poetry','','[]','橫雲初抹漆，爛漫南紀黑。',144,'全唐诗/poet.song.56000.json','["橫雲初抹漆，爛漫南紀黑。", "不見九華峰，如與親友隔。", "憶當秋景明，九老對几席。", "何曾閉篷窗，卧聽寒雨滴。", "不食貴池魚，喜尋昭明宅。", "筆硯鼠行塵，芝菌生銅鬲。", "思成佳句夢，貽我錦數尺。", "屬者浪吞舟，風雹更附益。", "老翁哭婦兒，相將難再得。", "存亡如日月，薄蝕行道失。", "流俗暗本源，謂神吐其食。", "神理儻有私，丘禱久以默。"]'),
('990eece6-8a63-4f74-add6-c5e7f0ae83ca','大雷口阻風','黄庭堅','宋','宋诗','song-poetry','','[]','號艣下滄江，避風大雷口。',156,'全唐诗/poet.song.56000.json','["號艣下滄江，避風大雷口。", "天與水糢糊，不復知地厚。", "誰家上江船，狂追雪山走。", "孤村無十室，旅飯困三韭。", "黄蘆麋鹿場，此地廣千肘。", "得禽多文章，肯顧魚貫柳。", "莽蒼天物悲，彫弓故在手。", "鹿鳴猶念羣，雉媒竟賣友。", "商人萬斛船，掛席上牛斗。", "橫笛倚柁樓，波深蒼龍吼。", "失水不能神，伐葭作城守。", "欲寄大雷書，往問長干婦。", "何當楫迎汝，秦淮綠如酒。"]'),
('34784c55-902c-495e-9a56-7afef5b9948d','庚寅乙未猶泊大雷口','黄庭堅','宋','宋诗','song-poetry','','[]','廣原嘷終風，發怒土囊口。',156,'全唐诗/poet.song.56000.json','["廣原嘷終風，發怒土囊口。", "萬艘萍無根，乃知積水厚。", "龍鱗火熒熒，鞭笞雷霆走。", "公私連檣休，森如束春韭。", "倚筇蒹葭灣，垂楊欲生肘。", "雄文酬江山，惜無韓與柳。", "五言呻吟內，慚愧陶謝手。", "送菜煩鄰船，買魚熟溪友。", "兒童報晦冥，正晝見箕斗。", "吾方廢書眠，鼻鼾鞲囊吼。", "猶防盜窺家，嚴鼓申夜守。", "冶城謝公墩，牛渚蕩子婦。", "何時快登臨，篙師分牛酒。"]'),
('3d30d49d-9cde-4dc1-9e5c-cab5716c8bee','乙未移舟出口','黄庭堅','宋','宋诗','song-poetry','','[]','江湖吞天胸，蛟龍垂涎口。',156,'全唐诗/poet.song.56000.json','["江湖吞天胸，蛟龍垂涎口。", "養軀無千金，特爲親故厚。", "本心非華軒，而與馬爭走。", "聘婦緝落毛，教兒耨葱韭。", "衣食端須幾，將老猶掣肘。", "安能詭隨人，曲折作杞柳。", "桓公甕盎癭，楚國不龜手。", "生涯但如此，那問託婚友。", "久陰快夜晴，天文若科斗。", "村南鬼火寒，村北風虎吼。", "野人驅雞豚，縛落堅纏守。", "劉郎弓石八，猛氣厭馮婦。", "一試金僕姑，歸飲軟臂酒。"]'),
('e048c87e-1452-4f27-9641-467e293e8f05','丙申泊東流縣','黄庭堅','宋','宋诗','song-poetry','','[]','前日發大雷，真成料虎頭。',84,'全唐诗/poet.song.56000.json','["前日發大雷，真成料虎頭。", "今日伐鼓出，棹歌傲陽侯。", "滄江百折來，及此始東流。", "東流會賓客，建德椎羊牛。", "野語尚信然，小市黄蘆洲。", "惟有采薪翁，經營往來舟。", "櫧櫪盡斤斧，山童煙雨愁。"]'),
('d10bd125-3c20-4edf-9718-963578227168','書石牛溪旁大石上','黄庭堅','宋','宋诗','song-poetry','','[]','鬰鬰窈窈天官宅，諸峰排霄帝不隔。',64,'全唐诗/poet.song.56000.json','["鬰鬰窈窈天官宅，諸峰排霄帝不隔。", "六時謁天開關鑰，我身金華牧羊客。", "羊眠野草我世閒，高真衆靈思我還。", "石盆之中有甘露，青牛駕我山谷路。"]'),
('201db872-d821-406e-b62f-08adabb0b4d9','題山谷大石','黄庭堅','宋','宋诗','song-poetry','','[]','畏畏佳佳石谷水，鼕鼕隆隆山木風。',32,'全唐诗/poet.song.56000.json','["畏畏佳佳石谷水，鼕鼕隆隆山木風。", "爐香四百六十載，開山者誰梁寶公。"]'),
('9e5e6a07-82ed-4fff-8b9f-5471b5a62b31','同蘇子平李德叟登擢秀閣','黄庭堅','宋','宋诗','song-poetry','','[]','築屋皖公城，木末置曲欄。',72,'全唐诗/poet.song.56000.json','["築屋皖公城，木末置曲欄。", "歲晚對烟景，人家橘柚間。", "獨秀司命峰，衆口讓高寒。", "松竹二喬宅，雪雲三祖山。", "衰懷造勝境，轉覺落筆難。", "蘇李工五字，屬聯不當慳。"]'),
('ed0aa5a0-ed0f-48aa-9411-04310d9bbca0','靈龜泉上','黄庭堅','宋','宋诗','song-poetry','','[]','大靈壽日月，化石皖公陂。',120,'全唐诗/poet.song.56000.json','["大靈壽日月，化石皖公陂。", "偶無斧斤尋，不作宰上碑。", "傾首若有謂，指泉來自西。", "泉甘崖木老，坐嘯欲忘歸。", "風流裴通直，商略從我嬉。", "蒔梅盈百科，洗石出崛奇。", "更約聘石工，鑱我靈龜詩。", "舅弟妙學古，亦復古鬚眉。", "卿家北海公，筆法可等夷。", "爲我書斯文，要與斗牛垂。"]'),
('664eefc3-cdde-4247-b8bf-bffc6aba65c8','從丘十四借韓文二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','吏部文章萬世，吾求善本編窺。',28,'全唐诗/poet.song.56000.json','["吏部文章萬世，吾求善本編窺。", "散帙雲窗棐几，同安得見丘遲。"]'),
('0b943fea-78d6-4140-9c74-840609708953','從丘十四借韓文二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','中有先君手澤，丹鉛點勘書詩。',28,'全唐诗/poet.song.56000.json','["中有先君手澤，丹鉛點勘書詩。", "莫惜借行千里，他日還君一鴟。"]'),
('8dc5519d-576c-419b-ac06-1742f37f3d8b','發舒州向皖口道中作寄李德叟','黄庭堅','宋','宋诗','song-poetry','','[]','黑雲平屋簷，晨夜隔星月。',132,'全唐诗/poet.song.56000.json','["黑雲平屋簷，晨夜隔星月。", "曉裝商旅前，冰底泥活活。", "野人攘畔耕，蹇馬不能滑。", "駝裘惜蒙茸，俱落水塘缺。", "孤材小蝸舍，乞火乾履襪。", "前登極崢嶸，他日飛鳥沒。", "寒花委亂草，耐凍鳴風葉。", "江形篆平沙，分派回勁筆。", "髯弟不俱來，得句漫剞劂。", "却望同安城，惟有松鬰鬰。", "遙知浦口晴，諸峰見明雪。"]'),
('440da535-ef39-4abb-b5dd-f9c264730f02','庭堅得邑太和六舅按節出同安邂逅于皖公溪口風雨阻留十日對榻夜語因詠誰知風雨夜復此對牀眠別後覺斯言可念列置十字字爲八句寄呈十首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','鵠白不以烏，蘭香端爲誰。',48,'全唐诗/poet.song.56000.json','["鵠白不以烏，蘭香端爲誰。", "外家秉明德，晚與世參差。", "乖離歲十二，會面卒卒期。", "何言灊丘底，玉稻同一炊。"]'),
('04a5cd79-3c5f-4bc2-b9b3-e763f950c819','庭堅得邑太和六舅按節出同安邂逅于皖公溪口風雨阻留十日對榻夜語因詠誰知風雨夜復此對牀眠別後覺斯言可念列置十字字爲八句寄呈十首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','滄江渺無津，同濟共安危。',48,'全唐诗/poet.song.56000.json','["滄江渺無津，同濟共安危。", "四海非不廣，舅甥自相知。", "孔鸞在榛梅，鷦鷯亦一枝。", "千里同明月，相期不磷緇。"]'),
('544c37a4-a8d9-4622-8251-7af9ffe40479','庭堅得邑太和六舅按節出同安邂逅于皖公溪口風雨阻留十日對榻夜語因詠誰知風雨夜復此對牀眠別後覺斯言可念列置十字字爲八句寄呈十首  其三','黄庭堅','宋','宋诗','song-poetry','','[]','少小長母家，拊憐輩諸童。',48,'全唐诗/poet.song.56000.json','["少小長母家，拊憐輩諸童。", "食貧走八方，略已一老翁。", "不能成宅相，頗似舅固窮。", "何以報嘉德，取琴作南風。"]'),
('05c5ca3e-f092-408f-92c7-9619284d81fb','庭堅得邑太和六舅按節出同安邂逅于皖公溪口風雨阻留十日對榻夜語因詠誰知風雨夜復此對牀眠別後覺斯言可念列置十字字爲八句寄呈十首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','德人心寂寥，立朝實莊語。',48,'全唐诗/poet.song.56000.json','["德人心寂寥，立朝實莊語。", "虎節坐山城，孤雲猶能雨。", "文章被甥姪，孝友諧婦女。", "偃息一畝宮，植梅當歌舞。"]'),
('709106dc-1eab-4806-acc6-dd522c619ede','庭堅得邑太和六舅按節出同安邂逅于皖公溪口風雨阻留十日對榻夜語因詠誰知風雨夜復此對牀眠別後覺斯言可念列置十字字爲八句寄呈十首  其五','黄庭堅','宋','宋诗','song-poetry','','[]','江都克家才，萬卷書插架。',48,'全唐诗/poet.song.56000.json','["江都克家才，萬卷書插架。", "願言渠出仕，從舅問耕稼。", "誰云瀕老境，此子即長夜。", "歸歟淼前期，蒔橘鋤甘蔗。"]'),
('5b1f98a0-d3cd-4baa-b422-ac3601490efa','庭堅得邑太和六舅按節出同安邂逅于皖公溪口風雨阻留十日對榻夜語因詠誰知風雨夜復此對牀眠別後覺斯言可念列置十字字爲八句寄呈十首  其六','黄庭堅','宋','宋诗','song-poetry','','[]','曩窺涉世方，白駒且場穀。',48,'全唐诗/poet.song.56000.json','["曩窺涉世方，白駒且場穀。", "平生漫歲晚，志尚向山木。", "返身觀小醜，真成覆車犢。", "否臧太磊磊，從此更三復。"]'),
('635e85eb-5e7b-498c-8157-46b2ce140417','庭堅得邑太和六舅按節出同安邂逅于皖公溪口風雨阻留十日對榻夜語因詠誰知風雨夜復此對牀眠別後覺斯言可念列置十字字爲八句寄呈十首  其七','黄庭堅','宋','宋诗','song-poetry','','[]','負薪反羊裘，愛表只傷裏。',48,'全唐诗/poet.song.56000.json','["負薪反羊裘，愛表只傷裏。", "補紉雖云工，歲晏安可恃。", "洗心如秋天，六合無塵滓。", "浮雲風去來，在彼不在此。"]'),
('22efbb3a-8062-4d35-b17e-c8fc2cfbcd6e','庭堅得邑太和六舅按節出同安邂逅于皖公溪口風雨阻留十日對榻夜語因詠誰知風雨夜復此對牀眠別後覺斯言可念列置十字字爲八句寄呈十首  其八','黄庭堅','宋','宋诗','song-poetry','','[]','阿髯學升堂，幹母思靡悔。',48,'全唐诗/poet.song.56000.json','["阿髯學升堂，幹母思靡悔。", "文成藝桃李，不言行道兌。", "阿蘇妙言語，機警欲無對。", "子姓何預人，蘭玉要可佩。"]'),
('00985aa6-f34e-48ae-8ab4-7cce6127e335','庭堅得邑太和六舅按節出同安邂逅于皖公溪口風雨阻留十日對榻夜語因詠誰知風雨夜復此對牀眠別後覺斯言可念列置十字字爲八句寄呈十首  其九','黄庭堅','宋','宋诗','song-poetry','','[]','解衣卧相語，濤波夜掀牀。',48,'全唐诗/poet.song.56000.json','["解衣卧相語，濤波夜掀牀。", "十年身百憂，險阻心已降。", "涉旬風更雨，宿昔燭生光。", "衾幬無端冷，明月一船霜。"]'),
('9ce981a1-4681-4c0d-9847-0a03c939dfde','庭堅得邑太和六舅按節出同安邂逅于皖公溪口風雨阻留十日對榻夜語因詠誰知風雨夜復此對牀眠別後覺斯言可念列置十字字爲八句寄呈十首  其一○','黄庭堅','宋','宋诗','song-poetry','','[]','親依爲日淺，愛不舍我眠。',48,'全唐诗/poet.song.56000.json','["親依爲日淺，愛不舍我眠。", "教我如牧羊，更著後者鞭。", "得邑邇梅嶺，開花向春妍。", "碌碌幸苟免，稱觴大人前。"]'),
('7879213b-b1f6-4575-a1dc-50043c313256','題馬當山魯望亭四首 元亮','黄庭堅','宋','宋诗','song-poetry','','[]','馬當一曲孤烟，人物于今眇然。',28,'全唐诗/poet.song.56000.json','["馬當一曲孤烟，人物于今眇然。", "不見繞籬黄菊，誰收種秫圭田。"]'),
('6a4c9a03-5695-4a7a-9d34-3858833f96a9','題馬當山魯望亭四首 狄梁公','黄庭堅','宋','宋诗','song-poetry','','[]','鯨波橫流砥柱，虎口活國宗臣。',28,'全唐诗/poet.song.56000.json','["鯨波橫流砥柱，虎口活國宗臣。", "小屈絃歌百里，不誣天下歸仁。"]'),
('fc5a2da4-0ce3-4965-b5cc-90f5b141f102','題馬當山魯望亭四首 顔魯公','黄庭堅','宋','宋诗','song-poetry','','[]','不見魯公斷石，誰家爲礎爲杠。',28,'全唐诗/poet.song.56000.json','["不見魯公斷石，誰家爲礎爲杠。", "筆法錐沙屋漏，心期曉日秋霜。"]'),
('75313860-74ec-4eee-9c24-3618d9b56ebf','題馬當山魯望亭四首 陸魯望','黄庭堅','宋','宋诗','song-poetry','','[]','笠澤道人高古，文章白髮蕭條。',28,'全唐诗/poet.song.56000.json','["笠澤道人高古，文章白髮蕭條。", "欲問勒銘遺墨，應書水府鮫綃。"]'),
('cb3a32a2-12a7-4894-91a0-a04354e99b1d','泊大孤山作','黄庭堅','宋','宋诗','song-poetry','','[]','匯澤爲彭蠡，其容化鵾鵬。',120,'全唐诗/poet.song.56000.json','["匯澤爲彭蠡，其容化鵾鵬。", "中流擢寒山，正色且無朋。", "其下蛟龍卧，宮譙珠貝層。", "朝雲與暮雨，何處會高陵。", "不見凌波襪，靚妝照澄凝。", "空餘血食地，猿嘯枯楠藤。", "高帆駕天來，落葉聚秋蠅。", "幽明異禮樂，忠信豈其憑。", "風波浩平陸，何況非履冰。", "安得曠達士，霜晴嘗一登。"]'),
('a4b8bb8f-36d7-4807-8e80-c59c4461505d','題落星寺四首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','星官游空何時落，著地亦化爲寶坊。',64,'全唐诗/poet.song.56000.json','["星官游空何時落，著地亦化爲寶坊。", "詩人晝吟山入座，醉客夜愕江撼牀。", "蜜房各自開牖戶，蟻穴或夢封侯王。", "不知青雲梯幾級，更借瘦藤尋上方。"]'),
('225a92aa-c61f-4900-9dd9-bfa16b42c9a6','題落星寺四首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','巖巖匡俗先生廬，其下宮亭水所都。',64,'全唐诗/poet.song.56000.json','["巖巖匡俗先生廬，其下宮亭水所都。", "北辰九關隔雲雨，南極一星在江湖。", "相黏蠔山作居室，竅鑿混沌無完膚。", "萬鼓舂撞夜濤湧，驪龍莫睡失明珠。"]'),
('a293bc42-e051-4ce0-95bd-745fb20d51ee','題落星寺四首  其三','黄庭堅','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','落星開士深結屋，龍閣老翁來賦詩。',64,'全唐诗/poet.song.56000.json','["落星開士深結屋，龍閣老翁來賦詩。", "小雨藏山客坐久，長江接天帆到遲。", "燕寢清香與世隔，畫圖妙絕無人知。", "蜂房各自開戶牖，處處煮茶藤一枝。"]'),
('3649ae6c-8de8-44d9-97da-8d873c71db00','題落星寺四首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','北風吹倒落星寺，吾與伯倫俱醉眠。',32,'全唐诗/poet.song.56000.json','["北風吹倒落星寺，吾與伯倫俱醉眠。", "螟蛉蜾蠃但癡坐，夜寒南北斗垂天。"]'),
('cd7c851b-2dab-4093-8e57-0c47823c8c8d','玉京軒','黄庭堅','宋','宋诗','song-poetry','','[]','蒼山其下白玉京，五城十二樓，鬰儀結鄰常杲杲。',106,'全唐诗/poet.song.56000.json','["蒼山其下白玉京，五城十二樓，鬰儀結鄰常杲杲。", "紫雲黄霧鏁玄關，雷驅不祥電揮掃。", "上有千年來歸之白鶴，下有萬世不凋之瑶草。", "野僧雲卧對開軒，一鉢安巢若飛鳥。", "北風卷沙過夜窗，枕底鯨波撼蓬島。", "箇中即是地行仙，但使心閒自難老。"]'),
('97ed9079-1eee-4bb0-94d1-b3af9b8013a9','過致政屯田劉公隠廬','黄庭堅','宋','宋诗','song-poetry','','[]','兒時拜公牀，眼碧眉紫煙。',252,'全唐诗/poet.song.56000.json','["兒時拜公牀，眼碧眉紫煙。", "舍前架茅茨，爐香坐僧禪。", "女奴煮甖粟，石盆瀉機泉。", "今來掃門巷，竹間翁蛻蟬。", "堂堂列五老，勝氣失江山。", "石盆爛黄土，茅齋薪壞椽。", "女奴爲民妻，又瘞蒿里園。", "當年笑語地，華屋轉朱欄。", "課兒種松子，傘蓋上參天。", "投策數去日，木行天再環。", "先生古人風，鐵膽石肺肝。", "眼前不可意，壯日掛其冠。", "解衣廬君峰，洗耳瀑布源。", "霧豹藏文章，驚世時一斑。", "衆人初易之，久遠乃見難。", "憶昔子政在，爲翁數解顔。", "五兵森武庫，河漢落舌端。", "王陽已富貴，塵冠不肯彈。", "呻吟刊十史，凡例墨新乾。", "宰木忽拱把，相望風隧寒。", "百楹書萬卷，少子似翁賢。"]'),
('c97edddc-130c-4a07-9015-a35fbdd9589c','壽聖觀道士黄至明開小隠軒太守徐公爲題曰快軒庭堅集句詠之','黄庭堅','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','金華牧羊兒，一粒粟中藏世界。',121,'全唐诗/poet.song.56000.json','["金華牧羊兒，一粒粟中藏世界。", "使君從南來，清風明月不用一錢買。", "鸕鷀杓，鸚鵡杯，一杯一杯復一杯，玉山自倒非人推。", "廬山秀出南斗傍，登高送遠形神開。", "銀河倒挂三石梁，砅崖轉石萬壑雷。", "吟詩作賦北窗裏，安得青天化作一張紙。", "有長鯨白齒若雪山，我願因之寄千里。"]'),
('95c2a265-fa1c-4332-8d23-2e945a837cd3','駐輿遣人尋訪後山陳德方家','黄庭堅','宋','宋诗','song-poetry','','[]','江雨濛濛作小寒，雪飄五老髮毛斑。',32,'全唐诗/poet.song.56000.json','["江雨濛濛作小寒，雪飄五老髮毛斑。", "城中咫尺雲橫棧，獨立前山望後山。"]'),
('f1128401-c894-4895-ad5a-077c2c66ef12','題李夫人偃竹','黄庭堅','宋','宋诗','song-poetry','','[]','孤根偃蹇非傲世，勁節癯枝萬壑風。',32,'全唐诗/poet.song.56000.json','["孤根偃蹇非傲世，勁節癯枝萬壑風。", "閨中白髮翰墨手，落筆乃與天同功。"]'),
('7334f2e7-531a-4fea-b029-3244077705af','次韵章禹直開元寺觀畫壁兼簡李德素','黄庭堅','宋','宋诗','song-poetry','','[]','丹青古藏壁，風雨飽侵食。',240,'全唐诗/poet.song.56000.json','["丹青古藏壁，風雨飽侵食。", "拂塵開藻鑒，志士淚霑臆。", "靈山遠飛來，不可以智測。", "龍神湛回向，擁衛立劍戟。", "依稀吳生手，旌旆略可識。", "鴻濛插樓殿，毫髮數動植。", "廣林瞻二聖，有衆拱萬億。", "飛行湊六合，攬取著一席。", "人人開生面，絕妙推心得。", "李侯天機深，指點目所及。", "三生石上夢，天樂鳴我側。", "幽尋前日事，晦明忽復易。", "章生南溟鵬，籠檻鎖六翮。", "能同寂寞遊，濁酒聊放適。", "西風葉蕭蕭，蟋蟀依牆壁。", "家無萬金産，四鄰碪聲急。", "藜羹傲鼎食，藍縷亦山立。", "並船有歌姝，粉白眉黛黑。", "期公開顔笑，醉語雜翰墨。", "不須談俗事，秖令人氣塞。"]'),
('b8d916b8-2ca9-4b66-a39b-4b719ce4a7fa','豐城','黄庭堅','宋','宋诗','song-poetry','','[]','豐城邑巖巖，水種六萬戶。',120,'全唐诗/poet.song.56000.json','["豐城邑巖巖，水種六萬戶。", "石隄眠長虹，輟棹日沈霧。", "令君政有聲，新亭延客步。", "淚落世父碑，心傾文饒賦。", "憶昔兩神兵，埋玉思武庫。", "寒光射漢津，兩賢紆一顧。", "張公拆中台，木拱孔章墓。", "不能從兒嬉，歲晚龍蛇去。", "空餘寒泉泓，因雨長蛙鮒。", "鉛刀藏寶室，萬世同此度。"]'),
('9e30d92c-979c-44d7-9676-d8d2f614860b','上蕭家峽','黄庭堅','宋','宋诗','song-poetry','','[]','玉笥峰前幾百家，山明松雪水明沙。',32,'全唐诗/poet.song.56000.json','["玉笥峰前幾百家，山明松雪水明沙。", "趁虛人集春蔬好，桑菌竹萌煙蕨芽。"]'),
('969b8432-fae4-4e8e-9091-9d86c328b1db','何蕭二族','黄庭堅','宋','宋诗','song-poetry','','[]','西漢功名相國多，南朝人物數諸何。',32,'全唐诗/poet.song.56000.json','["西漢功名相國多，南朝人物數諸何。", "向來富貴喧天地，亦有文章在澗阿。"]'),
('9cb90870-28eb-4d78-9ceb-40e766c2a388','魏夫人壇','黄庭堅','宋','宋诗','song-poetry','','[]','獨掃蛾眉作遠山，春風瑶草照朱顔。',32,'全唐诗/poet.song.56000.json','["獨掃蛾眉作遠山，春風瑶草照朱顔。", "我來欲問許玉斧，二十四峰如髻鬟。"]'),
('5a4cdd36-d433-4d1f-81d9-8deb640e78df','隠梅福處','黄庭堅','宋','宋诗','song-poetry','','[]','吳門不作南昌尉，上疏歸來朝市空。',32,'全唐诗/poet.song.56000.json','["吳門不作南昌尉，上疏歸來朝市空。", "笑拂巖花問塵世，故人子是國師公。"]'),
('c88f36c3-d7e0-41d4-9219-c3e7f639c940','蕭子雲宅','黄庭堅','宋','宋诗','song-poetry','','[]','郁木坑頭春鳥呼，雲迷帝子在時居。',32,'全唐诗/poet.song.56000.json','["郁木坑頭春鳥呼，雲迷帝子在時居。", "風流掃地無尋處，只有寒藤學草書。"]'),
('19869f63-34e8-4b77-8dd7-aa67d174282b','避秦十人','黄庭堅','宋','宋诗','song-poetry','','[]','九真承詔上龍胡，盡是驪山所送徒。',32,'全唐诗/poet.song.56000.json','["九真承詔上龍胡，盡是驪山所送徒。", "惟有鄧公留不去，松根搘鼎煮菖蒲。"]'),
('a25ca971-07c4-4bb6-9e85-de2aee8f02a0','黄雀','黄庭堅','宋','宋诗','song-poetry','','[]','牛大垂天且割烹，細微黄雀莫貪生。',32,'全唐诗/poet.song.56000.json','["牛大垂天且割烹，細微黄雀莫貪生。", "頭顱雖復行萬里，猶和鹽梅傅說羹。"]'),
('bccdedc1-967f-41f3-af81-78bacf759c9b','到官歸志浩然二絕句  其一','黄庭堅','宋','宋诗','song-poetry','','[]','雨洗風吹桃李浄，松聲聒盡鳥驚春。',32,'全唐诗/poet.song.56000.json','["雨洗風吹桃李浄，松聲聒盡鳥驚春。", "滿船明月從此去，本是江湖寂寞人。"]'),
('edc1cc5f-d40a-4ea2-a356-766d0de14c39','到官歸志浩然二絕句  其二','黄庭堅','宋','宋诗','song-poetry','','[]','鳥烏未覺常先曉，筍蕨登盤始見春。',32,'全唐诗/poet.song.56000.json','["鳥烏未覺常先曉，筍蕨登盤始見春。", "斂手還他能者作，從來刀筆不如人。"]'),
('5fe8cb8f-491f-404d-a5e0-b0fc27e67fce','題吉州承天院清凉軒','黄庭堅','宋','宋诗','song-poetry','','[]','菩薩清凉月，遊於畢竟空。',48,'全唐诗/poet.song.56000.json','["菩薩清凉月，遊於畢竟空。", "我觀諸境盡，心與古人同。", "僧髮侵眉白，桃花映竹紅。", "儻來尋祖意，展手似家風。"]'),
('8d793510-20fb-41b0-a563-3af18149170f','次韵答楊子聞見贈','黄庭堅','宋','宋诗','song-poetry','','[]','金盤厭飫五侯鯖，玉壺澆潑郎官清。',160,'全唐诗/poet.song.56000.json','["金盤厭飫五侯鯖，玉壺澆潑郎官清。", "長安市上醉不起，左右明妝奪目精。", "結交賢豪多杜陵，桃李成蹊卧落英。", "黄綬今爲白下令，蒼顔只使故人驚。", "督郵小吏皆趨版，陽春白雪分吞聲。", "楊君青雲貴公子，歎嗟簿領困書生。", "贈我新詩甚高妙，淚斑枯笛月邊橫。", "文章不直一杯水，老矣忍與時人爭。", "江城歌舞聊得醉，但願數有美酒傾。", "莫要朱金纏縛我，陸沈世上貴無名。"]'),
('37dbda2e-d031-4a62-a547-48b59132e797','聞致政胡朝請多藏書以詩借書目','黄庭堅','宋','宋诗','song-poetry','','[]','萬事不理問伯始，藉甚聲名南郡胡。',64,'全唐诗/poet.song.56000.json','["萬事不理問伯始，藉甚聲名南郡胡。", "遠孫白頭坐郎省，乞身歸來猶好書。", "手抄萬卷未閣筆，心醉六經還荷鉏。", "願公借我藏書目，時送一鴟開鏁魚。"]'),
('7ce67bb2-245e-4117-92dd-f6e6032182eb','戲贈南安倅柳朝散','黄庭堅','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','柳侯風味晚相見，衣袂頗薰荀令香。',64,'全唐诗/poet.song.56000.json','["柳侯風味晚相見，衣袂頗薰荀令香。", "桃李能言妙歌舞，樽前一曲斷人腸。", "洞庭歸客有佳句，庾嶺梅花如小棠。", "乘興高帆少相待，淮湖秋月要傳觴。"]'),
('bfe29622-b773-4b5b-8ef6-872cd44c1ad2','題槐安閣','黄庭堅','宋','宋诗','song-poetry','','[]','曲閣深房古屋頭，病僧枯几過春秋。',64,'全唐诗/poet.song.56000.json','["曲閣深房古屋頭，病僧枯几過春秋。", "垣衣蛛網蒙窗牖，萬象縱橫不繫留。", "白蟻戰酣千里血，黄粱炊熟百年休。", "功成事遂人間世，欲夢槐安向此遊。"]'),
('79b0a251-b0f3-457d-bb0f-3bc101d857b6','洪範以不合俗人題廳壁二絕句次韵和之  其一','黄庭堅','宋','宋诗','song-poetry','','[]','寂寥吾道付萬世，忍向時人覓賞音。',32,'全唐诗/poet.song.56000.json','["寂寥吾道付萬世，忍向時人覓賞音。", "搔首金城西萬里，樽前從此嘆人琴。"]'),
('48c09e80-cc7d-4004-8ebe-fbc7ce4c13ef','洪範以不合俗人題廳壁二絕句次韵和之  其二','黄庭堅','宋','宋诗','song-poetry','','[]','埋沒高才築釣間，風雲未會要鯢桓。',32,'全唐诗/poet.song.56000.json','["埋沒高才築釣間，風雲未會要鯢桓。", "南康郡下參軍耳，付與紅塵白眼看。"]'),
('05f84602-9257-4d7e-ab5c-4b2e0906ba7d','發贛上寄余洪範','黄庭堅','宋','宋诗','song-poetry','','[]','二川來集南康郡，氣味相似相和流。',64,'全唐诗/poet.song.56000.json','["二川來集南康郡，氣味相似相和流。", "木落山明數歸雁，鬰孤欄楯繞深秋。", "胸中淳于吞一石，塵下庖丁解十牛。", "他日欲言人不解，西風散髮棹扁舟。"]'),
('ba59f50e-18e7-4719-a752-4109179626b8','次元明韵寄子由','黄庭堅','宋','宋诗','song-poetry','','["\u6625\u5929", "\u6292\u6000", "\u53cb\u60c5", "\u76f8\u601d"]','半世交親隨逝水，幾人圖畫入凌烟。',64,'全唐诗/poet.song.56000.json','["半世交親隨逝水，幾人圖畫入凌烟。", "春風春雨花經眼，江北江南水拍天。", "欲解銅章行問道，定知石友許忘年。", "脊令各有思歸恨，日月相催雪滿顛。"]'),
('b2109eca-72a5-4a13-b217-24df15b35354','再次韵奉答子由','黄庭堅','宋','宋诗','song-poetry','','[]','蠆尾銀鈎寫珠玉，剡藤蜀繭照松烟。',64,'全唐诗/poet.song.56000.json','["蠆尾銀鈎寫珠玉，剡藤蜀繭照松烟。", "似逢海若談秋水，始覺醯雞守甕天。", "何日清揚能覿面，只今黄落又凋年。", "萬錢買酒從公醉，一鉢行歌聽我顛。"]'),
('e2dc6ebd-1fb7-4194-b51f-beb91c093a6d','再次韵寄子由','黄庭堅','宋','宋诗','song-poetry','','[]','想見蘇耽携手僊，青山桑柘冒寒烟。',64,'全唐诗/poet.song.56000.json','["想見蘇耽携手僊，青山桑柘冒寒烟。", "騏驎墮地思千里，虎豹憎人上九天。", "風雨極知雞自曉，雪霜寧與菌爭年。", "何時確論傾樽酒，醫得儒生自聖顛。"]'),
('ee8c03b8-5461-45e7-85af-a10089e0d64e','次韵寄上七兄','黄庭堅','宋','宋诗','song-poetry','','[]','學得屠龍長縮手，鍊成五色化蒼烟。',64,'全唐诗/poet.song.56000.json','["學得屠龍長縮手，鍊成五色化蒼烟。", "誰言遊刃有餘地，自信無功可補天。", "啼鳥笑歌追暇日，飽牛耕鑿望豐年。", "荷鋤端欲相隨去，邂逅青雲恐疾顛。"]'),
('60a62b3d-d672-4ebb-8f39-5a39fdeeda1e','和七兄山蕷湯','黄庭堅','宋','宋诗','song-poetry','','[]','厨人清曉獻瓊糜，正是相如酒渴時。',64,'全唐诗/poet.song.56000.json','["厨人清曉獻瓊糜，正是相如酒渴時。", "能解饑寒勝湯餠，略無風味笑蹲鴟。", "打窗急雨知然鼎，亂眼晴雲看上匙。", "已覺塵生雙井椀，濁醪從此不須持。"]'),
('5240d09c-26dc-4bb1-b2e9-c27317b0124f','同韵和元明兄知命弟九日相憶二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','革囊南渡傳詩句，摹寫相思意象真。',64,'全唐诗/poet.song.56000.json','["革囊南渡傳詩句，摹寫相思意象真。", "九日黄花傾壽酒，幾回青眼望歸塵。", "蚤爲學問文章誤，晚作東西南北人。", "安得田園可溫飽，長拋簪紱裹頭巾。"]'),
('561f2caa-4816-4bb4-ac04-9556637c8521','同韵和元明兄知命弟九日相憶二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','萬水千山厭問津，芭蕉林裏自觀身。',64,'全唐诗/poet.song.56000.json','["萬水千山厭問津，芭蕉林裏自觀身。", "鄰田雞黍留熊也，風雨關河走阿秦。", "鴻雁池邊照雙影，脊令原上憶三人。", "年年獻壽須歡喜，白髮黄花映角巾。"]'),
('6dcd8ae6-d7c3-4f72-bb18-369ab395dc24','代書','黄庭堅','宋','宋诗','song-poetry','','[]','阿熊去我時，秋暑削甘瓜。',288,'全唐诗/poet.song.56000.json','["阿熊去我時，秋暑削甘瓜。", "離別日月除，蓮房倒箭靫。", "得書報平安，肥字如栖鴉。", "汝才躍鑪金，自必爲鏌鋣。", "窮年抱新書，挽條咀春葩。", "弄筆不能休，屈宋欲作衙。", "屈指推日星，許身上雲霞。", "安知九天關，虎豹守夜叉。", "祝田操豚蹄，持狹所欲奢。", "文章六經來，汗漫十牛車。", "譬如觀滄海，細大極龍蝦。", "古人以聖學，未肯廢百家。", "舊山木十圍，齋堂綠陰遮。", "紅稻香盂飯，黄雞厭食鮭。", "摩挲垂腴腹，頗復讀書耶。", "念汝齒壯矣，無婦助烹茶。", "父兄亦憐汝，須兒牧犬豭。", "且伐千章木，贈行當馬檛。", "贏糧果後時，定隨八月槎。", "覺民在林中，丁丁聞兔罝。", "奉身甚和友，幹父辦咄嗟。", "臺源吟松籟，先生岸巾紗。", "留客醉風月，盤筯供柔嘉。", "仍工朱絲絃，洗心拂奇邪。"]'),
('271bb5d6-db50-41df-9e63-f7122384227b','雙澗寺二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','二水奔奔鳴屋除，松林落日吼烏菟。',32,'全唐诗/poet.song.56000.json','["二水奔奔鳴屋除，松林落日吼烏菟。", "老僧更有百歲母，白髮身爲反哺烏。"]'),
('d4a3ec9d-96f0-41fd-a079-301b2345fd42','雙澗寺二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','山陿江深屋翠崖，夜鐘聲自甕中來。',32,'全唐诗/poet.song.56000.json','["山陿江深屋翠崖，夜鐘聲自甕中來。", "長松偃蹇蒼龍卧，六月澗泉轟怒雷。"]'),
('2229cf78-4178-4ced-bac4-f7a1092dba1a','睡起','黄庭堅','宋','宋诗','song-poetry','','[]','柿葉鋪庭紅顆秋，薰爐沈水度衣篝。',32,'全唐诗/poet.song.56000.json','["柿葉鋪庭紅顆秋，薰爐沈水度衣篝。", "松風夢與故人遇，同駕飛鴻跨九州。"]'),
('1057d48a-f708-4b75-8399-bd9a91e4c85a','奉送周元翁鎖吉州司法廳赴禮部試','黄庭堅','宋','宋诗','song-poetry','','[]','江南江北木葉黄，五湖歸雁天雨霜。',224,'全唐诗/poet.song.56000.json','["江南江北木葉黄，五湖歸雁天雨霜。", "繫船湓城秣高馬，客丁結束女縫裳。", "貢書登名徹未央，不比長卿薄游梁。", "南山霧豹出文章，去取公卿易驅羊。", "與君初無一日雅，傾蓋許子如班揚。", "囚拘官曹少相見，忽忽歲晚稼滌場。", "一盃僚友喜多在，謝守不見空澄江。", "澄江如練明橘柚，萬峰相倚摩青蒼。", "暮堂醺醺客被酒，艷歌聒醉燭生光。", "椎鼓發船星斗白，明日各在天一方。", "寒鴉滿枝二橋宅，樽前顧曲憶周郎。", "鱸魚斫膾蔗爲漿，恨君不留誰與嘗。", "殿前春風君射策，漢庭諸公必動色。", "故人若問黄初平，將作金華牧羊客。"]'),
('2bbced43-fa06-4677-8e06-f3d4e3d0fea5','飲潤父家','黄庭堅','宋','宋诗','song-poetry','','[]','齋閤寒麝薰，書帙映斜景。',60,'全唐诗/poet.song.56000.json','["齋閤寒麝薰，書帙映斜景。", "偶來樽俎同，延此笑言頃。", "宮線添尺餘，朝來日未永。", "一醉解語花，萬事畫地餠。", "要似虎頭癡，何須樗里癭。"]'),
('56b96f61-60bb-4f67-a727-97feae8fc40c','次前韵寄潤父','黄庭堅','宋','宋诗','song-poetry','','[]','昏昏迷簿領，勿勿貴晷景。',60,'全唐诗/poet.song.56000.json','["昏昏迷簿領，勿勿貴晷景。", "嘗盡身百憂，迄無田二頃。", "喜從吾宗遊，九里河潤永。", "呼兒跪酒樽，戒婦饌湯餠。", "老夫何取焉，君悅甕盎癭。"]'),
('f62f7365-1251-460f-b65e-afce7af7490a','送酒與周法曹用前韵','黄庭堅','宋','宋诗','song-poetry','','[]','遙知謝法曹，詩句多夏景。',60,'全唐诗/poet.song.56000.json','["遙知謝法曹，詩句多夏景。", "聞道學書勤，墨池方一頃。", "大字苦未遒，小字逼智永。", "我有何郎樽，清江醖玉餠。", "還書及斗數，與君酌楠癭。"]'),
('1f65ed4a-d379-4ab6-9b37-0d7cbc84f510','出迎使客質明放船自瓦窯歸','黄庭堅','宋','宋诗','song-poetry','','[]','鼓吹喧江雨不開，丹楓落葉放船回。',64,'全唐诗/poet.song.56000.json','["鼓吹喧江雨不開，丹楓落葉放船回。", "風行水上如雲過，地近嶺南無雁來。", "樓閣人家捲簾幕，菰蒲鷗鳥樂灣洄。", "惜無陶謝揮斤手，詩句縱橫付酒杯。"]'),
('b503de4a-bfad-44b1-b34a-7ee5279c499d','次韵和答孔毅甫','黄庭堅','宋','宋诗','song-poetry','','[]','鵬飛鯤化未即逍遙游，龍章鳳姿終作廣陵散。',164,'全唐诗/poet.song.56000.json','["鵬飛鯤化未即逍遙游，龍章鳳姿終作廣陵散。", "湓浦鑪邊督數錢，故人陸沉心可見。", "氣與神兵上斗牛，詩如晴雪濯江漢。", "把詠公詩闔且開，旁無知音面牆歎。", "我今廢書迷簿領，魚蠹筆鋒蛛網硯。", "六年國子無寸功，猶得江南萬家縣。", "客來欲語誰與同，令人熟寐觸屏風。", "竊食仰愧冥冥鴻，少年所期如夢中。", "江頭酒賤樽屢空，南山有田歲不逢。", "相思夜半涕無從，千金公亦費屠龍。"]'),
('56f93017-92e9-4dc1-a08d-54cb85dd59de','再用舊韵寄孔毅甫','黄庭堅','宋','宋诗','song-poetry','','[]','鑒中之髮蒲柳望秋衰，眼中之人風雨俱星散。',164,'全唐诗/poet.song.56000.json','["鑒中之髮蒲柳望秋衰，眼中之人風雨俱星散。", "往者託體同青山，健者漂零不相見。", "庾公樓上有詩人，平生落筆瀉河漢。", "置驛勤來索我詩，自說中郎識元歎。", "我方凍坐酒官曹，爲公然薪炙冰硯。", "不解窮愁著一書，豈有文章名九縣。", "奴星結柳送文窮，退倚北窗睡松風。", "太阿耿耿截歸鴻，夜思龍泉號匣中。", "斗柄垂天霜雨空，獨雁叫羣雲萬重。", "何時握手香爐峰，下看寒泉濯卧龍。"]'),
('d2410605-44cb-407d-821e-61f63d83c782','二月二日曉夢會于廬陵西齋作寄陳適用','黄庭堅','宋','宋诗','song-poetry','','[]','燕寢著爐香，愔愔閒窗闥。',228,'全唐诗/poet.song.56000.json','["燕寢著爐香，愔愔閒窗闥。", "夢到郡城東，笑談西齋月。", "行樂未渠央，苦遭晴鳩聒。", "江郡梅李白，士女嬉城闕。", "聞道潘河陽，滿城花秀發。", "頗留載酒車，共醉生塵襪。", "想見舞餘姿，風枝斜蠆髮。", "鄙夫不舉酒，春事亦可悅。", "雨足肥菌芝，沙暄饒筍蕨。", "海牛壓風簾，野飯薰僧鉢。", "飽食愧公家，曾無助毫末。", "勸鹽推新令，王欲惸獨活。", "此邦淡食傖，儉陋深次骨。", "公囷積丘山，賈豎但圭撮。", "縣官恩乳哺，下吏用鞭撻。", "正恐利一源，未塞兔三窟。", "寄聲賢令尹，何道補黥刖。", "從來無研桑，顧影愧簪笏。", "何顔課殿上，解綬行采葛。"]'),
('a87da612-578e-43fd-b0cf-71385997aacc','長句謝陳適用惠送吳南雄所贈紙','黄庭堅','宋','宋诗','song-poetry','','[]','廬陵政事無全牛，恐是漢時陳太丘。',224,'全唐诗/poet.song.56000.json','["廬陵政事無全牛，恐是漢時陳太丘。", "書記姓名不肯學，得紙無異夏得裘。", "琢詩包紙送贈我，自狀明月非暗投。", "詩句縱橫剪宮錦，惜無阿買書銀鉤。", "蠻溪切藤卷盈百，側理羞滑繭羞白。", "想當鳴杵砧面平，桄榔葉風溪水碧。", "千里鵝毛意不輕，瘴衣腥膩北歸客。", "君侯謙虛不自供，胡不贈世文章伯。", "一涔之水容牛蹄，識字有數我自知。", "小時雙鉤學楷法，至令兒子憎家雞。", "雖然嘉惠敢虛辱，煮泥續尾成大軸。", "寫心與君心莫傳，平生落魄不問天。", "樽前花底幸好戲，爲君絕筆謝風煙。", "已無商頌猗那手，請續南華內外篇。"]'),
('66c7c271-f8c9-437b-873f-7e869166e1e4','寄陳適用','黄庭堅','宋','宋诗','song-poetry','','[]','日月如驚鴻，歸燕不及社。',288,'全唐诗/poet.song.56000.json','["日月如驚鴻，歸燕不及社。", "清明氣妍暖，亹亹向朱夏。", "輕衣頗宜人，裘褐就椸架。", "已非紅紫時，春事歸桑柘。", "空餘車馬跡，顛倒桃李下。", "新晴百鳥語，各自有匹亞。", "林中僕姑歸，苦遭拙婦駡。", "氣候使之然，光陰促晨夜。", "解甲號清風，即有幽蟲化。", "朱墨本非工，王事少閒暇。", "幸蒙餘波及，治郡得黄霸。", "邑鄰陳太丘，威德可資借。", "决事不遲疑，敏手擘太華。", "頗復集紅衣，呼僚飲休暇。", "歌梁韵金石，舞地委蘭麝。", "寄我五字詩，句法窺鮑謝。", "亦嘆簿領勞，行欲問田舍。", "相期黄公壚，不異秦人炙。", "我初無廊廟，身願執耕稼。", "今將荷鋤歸，區芋畦甘蔗。", "觀君氣如虹，千輩可陵跨。", "自當出懷璧，往取連城價。", "賜地買歌僮，珠翠羅廣厦。", "富貴不相忘，寄聲相慰藉。"]'),
('b836c4f5-f0ee-4df8-a07b-4888e8dd321d','寄懷元翁','黄庭堅','宋','宋诗','song-poetry','','[]','歲年豐稻秔，井邑盛煙火。',120,'全唐诗/poet.song.56000.json','["歲年豐稻秔，井邑盛煙火。", "北園曾未窺，王事方勤我。", "花枝互低昂，鳥語相許可。", "觀物見歸根，撫時終宴坐。", "搔首望四鄰，諸賢皆最課。", "極工簿領書，甚辦米鹽顆。", "平生短朱墨，吏考仰丞佐。", "初無公侯心，骨相本寒餓。", "明窗懷玉友，清絕吟楚些。", "念君方坐曹，無因奉虛左。"]'),
('c78d37f5-8126-4d57-bb2c-65fa15428af4','對酒次前韵寄懷元翁','黄庭堅','宋','宋诗','song-poetry','','[]','花光漸寒食，木燧催國火。',120,'全唐诗/poet.song.56000.json','["花光漸寒食，木燧催國火。", "沽酒鳥勸人，懷賢吾忘我。", "事往墮甑休，心知求田可。", "可人不在眼，樽俎思促坐。", "有生常倥傯，無暇天所課。", "不解聞健飲，俄成一蓬顆。", "泥鈞埏萬物，寒暑勤五佐。", "豈其懷愛憎，私使我窮餓。", "醉招魂不來，浪下巫陽些。", "夢成少年嬉，走馬章臺左。"]'),
('4e6a8b4f-d178-4fa5-8f00-0f0bd37c35ac','侯尉之吉水覆按未歸三日泥雨戲成寄之','黄庭堅','宋','宋诗','song-poetry','','[]','嘆息侯嬴老，尉曹鞍馬疲。',48,'全唐诗/poet.song.56000.json','["嘆息侯嬴老，尉曹鞍馬疲。", "山花迷部曲，江雨壓旌旗。", "越鳥勸沽酒，竹雞憂蹋泥。", "不知何處醉，遙寄解酲詩。"]'),
('7414ba62-906d-47e1-b883-b8ed03e29eac','侯尉家聽琵琶','黄庭堅','宋','宋诗','song-poetry','','[]','舫齋蒼竹雨聲中，一曲琵琶酒一鍾。',32,'全唐诗/poet.song.56000.json','["舫齋蒼竹雨聲中，一曲琵琶酒一鍾。", "恰似潯陽江上聽，只無明月與丹楓。"]'),
('22271e95-5e56-45eb-bfa4-3d053bf06cad','寄袁守廖獻卿','黄庭堅','宋','宋诗','song-poetry','','[]','公移猥甚叢生筍，訟牒紛如蜜分窠。',64,'全唐诗/poet.song.56000.json','["公移猥甚叢生筍，訟牒紛如蜜分窠。", "少得曲肱成夢蝶，不堪衙吏報鳴鼉。", "已荒里社田園了，可奈春風桃李何。", "想見宜春賢太守，無書來問病維摩。"]'),
('b10d051a-e099-459c-aec6-f068271c5cba','廖袁州次韵見答并寄黄靖國再生傳次韵寄之','黄庭堅','宋','宋诗','song-poetry','','[]','春去懷賢感物多，飛花高下罥絲窠。',64,'全唐诗/poet.song.56000.json','["春去懷賢感物多，飛花高下罥絲窠。", "傳聞治境無戾虎，更道豐年鳴白鼉。", "史筆縱橫窺寶鉉，詩才清壯近陰何。", "寄聲千萬相勞苦，如倚胡牀得按摩。"]'),
('526b1c98-1f03-4a1b-8b9a-d4a717ede881','袁州劉司法亦和予摩字詩因次韵寄之','黄庭堅','宋','宋诗','song-poetry','','[]','袁州司法多兼局，日暮歸來印幾窠。',64,'全唐诗/poet.song.56000.json','["袁州司法多兼局，日暮歸來印幾窠。", "詩罷春風榮草木，書成快劍斬蛟鼉。", "遙知吏隠清如此，應問卿曹果是何。", "頗憶病餘居士否，在家無意飲蘿摩。"]'),
('dd2f2a23-836b-47e5-a83a-ab33ae0c9909','次韵奉答吉老并寄何君庸','黄庭堅','宋','宋诗','song-poetry','','[]','傾懷相見開城府，取意閒談沒臼窠。',64,'全唐诗/poet.song.56000.json','["傾懷相見開城府，取意閒談沒臼窠。", "但取吏曹無狡兔，任呼舞女伐靈鼉。", "屢中甕面酒幾聖，苦憶尊前人姓何。", "願得兩公俱投報，不唯朱墨要漸摩。"]'),
('292088f2-fa4d-4884-a754-ab390703ad0c','次韵奉答廖袁州懷舊隠之詩','黄庭堅','宋','宋诗','song-poetry','','[]','詩題怨鶴與驚猿，一幅溪藤照麝煙。',64,'全唐诗/poet.song.56000.json','["詩題怨鶴與驚猿，一幅溪藤照麝煙。", "聞道省郎方結綬，可容名士乞歸田。", "嚴安召見天嗟晚，賈誼歸來席更前。", "何况班家有超固，應封定遠勒燕然。"]'),
('b943ab29-fed1-4864-9d50-1cc79bdc9a26','上權郡孫承議','黄庭堅','宋','宋诗','song-poetry','','[]','公家簿領如雞棲，私家田園無置錐。',66,'全唐诗/poet.song.56000.json','["公家簿領如雞棲，私家田園無置錐。", "真成忍駡加餐飯，不如西江之水可樂饑。", "他人勤拙猶相補，身無功狀堪上府。", "公誠遣騎束縛歸，長隨白鷗卧煙雨。"]'),
('99bcda48-28f8-49b3-b6db-b3fef8be71ad','奉和孫奉議謝送菜','黄庭堅','宋','宋诗','song-poetry','','[]','春蔬照映庾郎貧，遣騎持籠佐茹葷。',32,'全唐诗/poet.song.56000.json','["春蔬照映庾郎貧，遣騎持籠佐茹葷。", "却得齋厨厭滋味，白鵝存掌鼈留裙。"]'),
('7d1d76b7-c353-4908-9e97-aabb4f4d0f66','和孫公善李仲同金櫻餌唱酬二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','人生欲長存，日月不肯遲。',132,'全唐诗/poet.song.56000.json','["人生欲長存，日月不肯遲。", "百年風吹過，忽成甘蔗滓。", "傳聞上世士，烹餌草木滋。", "千秋垂綠髮，每恨不同時。", "李侯好方術，肘後探神奇。", "金櫻出皇墳，刺橐覽霜枝。", "寒窗司火候，古鼎凍膠飴。", "初嘗不可口，醇酒和味宜。", "至今身七十，孺子色不衰。", "田中按耘鉏，孫息親抱持。", "却笑鄰舍公，未老須杖藜。"]'),
('dd59f2a4-4cac-4357-9c02-ef528be70804','和孫公善李仲同金櫻餌唱酬二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','假守富春公，秋毫聽民詞。',111,'全唐诗/poet.song.56000.json','["假守富春公，秋毫聽民詞。", "夙夜臨公廳，歸卧酸體肢。", "李侯來饋藥，期以十日知。", "深中護靈根，金鏁祕玉{氏}。", "不須許斧子，辛勤采玉芝。", "我方困健訟，撾翁爭一錐。", "不能鳴絃坐，頗似巫馬期。", "敢乞刀圭餘，歸和卯飲巵。", "儻令憂民病，從此得國醫。"]'),
('6a2e711d-b486-4d93-b517-bbf176a87cab','答余洪範二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','道在東西祖，詩如大小山。',48,'全唐诗/poet.song.56000.json','["道在東西祖，詩如大小山。", "一家同雪月，萬事廢機關。", "天上麒麟閣，山中虎豹閑。", "何時得丘壑，明鏡失朱顔。"]'),
('626ea356-39c0-4495-9851-992cd73497e5','答余洪範二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','懸磬齋厨數米炊，貧中氣味更相思。',32,'全唐诗/poet.song.56000.json','["懸磬齋厨數米炊，貧中氣味更相思。", "可無昨日黄花酒，又是春風柳絮時。"]'),
('622ddb12-a46e-4329-a6f9-db167f640740','三月乙巳來賦鹽萬歲鄉且蒐獮匿賦之家晏飯此舍遂留宿是日大風自采菊苗薦湯餠二首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','飛廉决雲開白日，頓撼天地萬竅號。',32,'全唐诗/poet.song.56000.json','["飛廉决雲開白日，頓撼天地萬竅號。", "挼挱桃李欲浄盡，乞與遊絲百尺高。"]'),
('4e4608cf-92ea-4056-a568-1f386a5d0186','三月乙巳來賦鹽萬歲鄉且蒐獮匿賦之家晏飯此舍遂留宿是日大風自采菊苗薦湯餠二首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','幽叢秀色可攬擷，煮餠菊苗深注湯。',32,'全唐诗/poet.song.56000.json','["幽叢秀色可攬擷，煮餠菊苗深注湯。", "飲冰食蘗浪自古，摩挲滿懷春草香。"]'),
('ca6b7b16-50a2-495a-ab6c-b94ac06912f2','題高君正適軒','黄庭堅','宋','宋诗','song-poetry','','[]','至靜在平氣，至神惟順心。',120,'全唐诗/poet.song.56000.json','["至靜在平氣，至神惟順心。", "道非貴與賤，達者古猶今。", "功名屬廊廟，閒暇歸山林。", "畜魚觀羣嬉，籠鳥聽好音。", "不如一邱壑，隨願得飛沉。", "開門納日月，呼客解纓簪。", "詩書撫塵迹，歌舞送光陰。", "妖嫺傾國笑，絲竹感人深。", "豁然開胸次，風至獨披襟。", "樊籠鎖形質，物外有幽尋。"]'),
('7298f56b-9d28-4416-9ddf-be106f268fbe','寄李次翁','黄庭堅','宋','宋诗','song-poetry','','[]','雨斷山川明，花深鳥烏樂。',132,'全唐诗/poet.song.56000.json','["雨斷山川明，花深鳥烏樂。", "枯骨不霑名，古今同一壑。", "惟有在世時，聊厚不爲薄。", "南箕與北斗，親友多離索。", "斯文如舊歡，李侯極磊落。", "頗似元魯山，用心撫疲弱。", "不以民爲梯，俯仰無所怍。", "胸中種妙覺，歲晚期必穫。", "然膏夜讀書，見聖宜有作。", "文字寄我來，官郵遠飛橐。", "世緣心已死，儻得萬金藥。"]'),
('7f49e80a-4d82-4033-9c27-32cd18f19e8c','四月戊申賦鹽萬歲山中仰懷外舅謝師厚','黄庭堅','宋','宋诗','song-poetry','','[]','只今漢龐公，白髮佐州郡。',168,'全唐诗/poet.song.56000.json','["只今漢龐公，白髮佐州郡。", "窮通視寒暑，仕已誰喜慍。", "長松卧澗底，桴霤多裂璺。", "未須論才難，世人無此韵。", "禪悅稱性深，語端入理近。", "渙若開春冰，超然聽年運。", "臨民秉三尺，朱墨不可紊。", "傳聞但言歸，心許手自隠。", "欲知南陂稻，得幾就收捃。", "胥疏江湖濱，不邇金玉訓。", "濡需且肉食，觳觫恐鐘釁。", "龍移山發洪，虎乳月生暈。", "竹聲寒夏簟，輟寢中夜聽。", "寄聲向鹿門，儻賜勞苦問。"]'),
('cf1055cf-22a3-45b3-b0a2-20266e3a055b','癸丑宿早禾渡僧舍','黄庭堅','宋','宋诗','song-poetry','','[]','城頭渡可涉，早禾渡可斟。',168,'全唐诗/poet.song.56000.json','["城頭渡可涉，早禾渡可斟。", "試問安用舟，春水三丈餘。", "是維一都會，駔儈權征輸。", "鬰鬰多大姓，儒冠頗詩書。", "以武斷鄉曲，舊俗小未除。", "厭囂謝近市，斬絕得僧區。", "此地美水竹，林明見浴鳬。", "相追啑菱藻，天樂非世娛。", "憶在田園日，放浪友禽魚。", "今來長山邑，忍饑撫惸孤。", "出入部曲隨，咳唾吏史趨。", "形骸束簪笏，可意一事無。", "謀生理未拙，仰愧擁腫樗。", "曲肱晴簷低，結網看蜘蛛。"]'),
('c96f6dbc-7da9-4e93-b42e-d126511c592a','宿觀山','黄庭堅','宋','宋诗','song-poetry','','[]','暮發白下地，暝投觀山宿。',96,'全唐诗/poet.song.56000.json','["暮發白下地，暝投觀山宿。", "橫溪赤欄橋，一徑入松竹。", "野僧如驚麏，避堂具燈燭。", "我眠興視夜，部曲始炊熟。", "筧水煙際鳴，萬籟入秋木。", "平生萧洒興，本願終澗谷。", "世累漸逼人，如垢不靧沐。", "已成老翁爲，作吏長碌碌。"]'),
('0dc37196-b977-4d0f-b437-c9ec4d6e29a7','上大蒙籠','黄庭堅','宋','宋诗','song-poetry','','[]','黄霧冥冥小石門，苔衣草路無人迹。',128,'全唐诗/poet.song.56000.json','["黄霧冥冥小石門，苔衣草路無人迹。", "苦竹參天大石門，虎迒兔蹊聊倚息。", "陰風搜林山鬼嘯，千丈寒藤繞崩石。", "清風源裏有人家，牛羊在山亦桑麻。", "向來陸梁嫚官府，試呼使前問其故。", "衣冠漢儀民父子，吏曹擾之至如此。", "窮鄉有米無食鹽，今日有田無米食。", "但願官清不愛錢，長養兒孫聽驅使。"]'),
('8aa074e3-3842-467d-b1c6-acaaf9612320','勞坑入前城','黄庭堅','宋','宋诗','song-poetry','','[]','刀坑石如刀，勞坑人馬勞。',96,'全唐诗/poet.song.56000.json','["刀坑石如刀，勞坑人馬勞。", "窈窕篁竹陰，是常主逋逃。", "白狐跳梁去，豪豬森怒嘷。", "雲黄覺日瘦，木落知風饕。", "輕軒息源口，飯羹煮溪毛。", "山農驚長吏，出拜家騷騷。", "借問淡食民，祖孫甘餔糟。", "頼官得鹽喫，正苦無錢刀。"]'),
('4c669f9c-dc0c-4f4c-93cb-47a073e98b55','乙卯宿清泉寺','黄庭堅','宋','宋诗','song-poetry','','[]','稅輿陟高岡，却立倚天壁。',96,'全唐诗/poet.song.56000.json','["稅輿陟高岡，却立倚天壁。", "就輿亂清溪，轉石飛霹靂。", "十步一沮洳，五步一枳棘。", "上方未言返，豁見平土宅。", "田家雞犬歸，佛廟檀欒碧。", "蓮蕩落紅衣，泉泓數白石。", "人如安巢鳥，稍就一枝息。", "鐘魚各知時，吾亦自得力。"]'),
('acf9797d-851d-4e7f-b1ae-95935b76289a','丙辰仍宿清泉寺','黄庭堅','宋','宋诗','song-poetry','','[]','山農居負山，呼集來苦遲。',144,'全唐诗/poet.song.56000.json','["山農居負山，呼集來苦遲。", "既來授政役，謠諑謂余欺。", "按省其家貲，可忍鞭抶之。", "恩言諭公家，疑阻久乃隨。", "滕口終自愧，吾敢乏王師。", "官寧憚淹留，職在拊惸嫠。", "所將部曲多，溷汝父老爲。", "西山失半壁，且復下囊輜。", "啼鴉散篇帙，休吏稅巾衣。", "石泉鼓坎坎，竹風吹參差。", "書冷行熠燿，壁蟲催杼機。", "昏釭夜未央，高枕夢登巘。"]'),
('96d2654f-8417-4941-82fd-a5e23ffa4567','丁巳宿寶石寺','黄庭堅','宋','宋诗','song-poetry','','[]','鐘磬秋山靜，爐香沉水寒。',108,'全唐诗/poet.song.56000.json','["鐘磬秋山靜，爐香沉水寒。", "晴風蕩濛雨，雲物尚盤桓。", "瀹茗赤銅椀，筧泉蒼煙竿。", "紅榴罅玉房，幺橘委金丸。", "枕簟已思燠，飯羹可加餐。", "觀己自得力，談玄舌本乾。", "理窟乃塊然，世故浪萬端。", "牛刀經肯綮，古人貴守官。", "摩挲發硎手，考此一丘槃。"]'),
('36b045ad-7a11-4c5f-9e98-856dda83a8a6','己未過太湖僧寺得宗汝爲書寄山蕷白酒長韵詩寄答','黄庭堅','宋','宋诗','song-poetry','','["\u592a\u6e56"]','從學晚聞道，謀官無見功。',288,'全唐诗/poet.song.56000.json','["從學晚聞道，謀官無見功。", "早衰觀水鑒，內熱愧鄰邦。", "比鄰有宗侯，治劇乃雍容。", "摩手撫鰥寡，藁碪磔强梁。", "桃李與荆棘，稱物施露霜。", "政經甚縝密，私不蚍蜉通。", "吏舍無請賕，家有侯在堂。", "府符下鹽策，縣官勸和羹。", "作民敏風雨，令先諸邑行。", "我居萬夫上，闒惰世無雙。", "此邑宅巖巖，里中頗秦風。", "翁媼無恙時，出分如峰房。", "一錢氣不直，白梃及父兄。", "簪筆懷三尺，揖我謂我臧。", "向來豪傑吏，治之以牛羊。", "我不忍敵民，教養如兒甥。", "荆雞伏鵠卵，久望羽翼成。", "訟端洶洶來，諭去稍聽從。", "尚餘租庸調，歲歲稽法程。", "按圖索家資，四壁達牖窗。", "揜目鞭扑之，桁楊相推掁。", "身欲免官去，駑馬戀豆糠。", "所以積廩鹽，未使戶得烹。", "八月釃社酒，公私樂年登。"]'),
('4c419703-429a-4d27-bace-857e2ddba123','庚申宿觀音院','黄庭堅','宋','宋诗','song-poetry','','[]','谷底一墟落，地形如盎盆。',132,'全唐诗/poet.song.56000.json','["谷底一墟落，地形如盎盆。", "榱題相照耀，其民頗家溫。", "土風甚于秦，不可借釜甗。", "僧屋無陶瓦，剪茅蒼竹樊。", "借問僧安在，乞飯走諸門。", "人鬨鳥烏語，簟凉風水文。", "旁有蜂蜜廬，頗聞衙集喧。", "將雨蟻爭丘，鏖兵復追奔。", "紅英委鳳翼，赤幘峨雞冠。", "汲烹寒泉窟，伐竹古松根。", "相戒莫浪出，月黑虎夔藩。"]'),
('7aa818b1-b384-4bd4-8a2f-b8306f9510f0','辛酉憩刀坑口','黄庭堅','宋','宋诗','song-poetry','','[]','羣山黛新染，蒙氣寒鬰鬰。',132,'全唐诗/poet.song.56000.json','["羣山黛新染，蒙氣寒鬰鬰。", "掃除迎將家，下簟脫巾襪。", "南北舍小棠，況可清煩暍。", "鳥聲廢書眠，聊以休吏卒。", "竹雞苦喚人，覺坐觀法窟。", "無外同一家，惟己非萬物。", "清波兩鴛鴦，善游且能沒。", "驚人相追飛，甚念失其匹。", "舂鉏貌閒暇，羨魚情至骨。", "廣道策堅良，熙熙集于菀。", "爛額始論功，儻能謀曲突。"]'),
('e638f064-c1ef-4118-ba5d-f53083f45abe','金刀坑迎將家待追漿坑十餘戶山農不至因題其壁','黄庭堅','宋','宋诗','song-poetry','','[]','窮鄉阻地險，篁竹嘯夔魖。',168,'全唐诗/poet.song.56000.json','["窮鄉阻地險，篁竹嘯夔魖。", "惡少擅三窟，不承吏追呼。", "老翁燕無凶，偃蹇坐里閭。", "後生習聞見，官不禁權輿。", "懷書斥長吏，持杖鏖公徒。", "遂令五百里，化爲豺豕墟。", "古來沈牛羊，檄水臣鰐魚。", "猛虎剝文章，矧而民髮膚。", "哀哉奉其身，曾不如鳥烏。", "破家縣令手，南面天子除。", "要能伐强梁，然後活惸孤。", "屬爲民父母，未教忍先誅。", "山川甚秀拔，人物亦詩書。", "十室有忠信，此鄉何獨無。"]'),
('57c8ee99-9909-4a3a-a750-644851f52c6e','次韵漢公招七兄','黄庭堅','宋','宋诗','song-poetry','','[]','白髮霏霏雪點斑，朱櫻忽忽鳥銜殘。',64,'全唐诗/poet.song.56000.json','["白髮霏霏雪點斑，朱櫻忽忽鳥銜殘。", "公庭休吏進湯餠，語燕無人窺井欄。", "詩句多傳知有暇，道人相見不應難。", "老郎親屈延處士，風味依稀如姓桓。"]'),
('1c7f0acb-1277-4fb4-8847-a9b53d9b2e11','寄題安福李令適軒','黄庭堅','宋','宋诗','song-poetry','','[]','琳宮接叢霄，淥水連翠微。',72,'全唐诗/poet.song.56000.json','["琳宮接叢霄，淥水連翠微。", "幽花露林薄，好鳥娛清輝。", "道人勤洒掃，令尹每忘歸。", "孝慈民父母，虎去蝗退飛。", "來思僚友同，歌舞醉紅衣。", "定知與民樂，吏瘦吾民肥。"]'),
('ac7f9a82-cd80-4486-b1b3-47ea6cceca98','寄題安福李令先春閣','黄庭堅','宋','宋诗','song-poetry','','[]','宮殿繞風煙，江山壯城郭。',84,'全唐诗/poet.song.56000.json','["宮殿繞風煙，江山壯城郭。", "令君蓺桃李，面春築飛閣。", "春至最先知，雨露徧花藥。", "是日勸農桑，冰銷土膏作。", "絃歌出縣齋，裴回問民瘼。", "雞犬聲相聞，嬰此簿領縛。", "安得携手嬉，烹茶煨鴨脚。"]'),
('3fa52d5a-b682-4f24-9b2e-d8352a84c6a0','寄題安福李令愛竹堂','黄庭堅','宋','宋诗','song-poetry','','[]','淵明喜種菊，子猷喜種竹。',132,'全唐诗/poet.song.56000.json','["淵明喜種菊，子猷喜種竹。", "託物雖自殊，心期俱不俗。", "千載得李侯，異世等風流。", "爲官恐是陶彭澤，愛竹最知王子猷。", "寒窗對酒聽雨雪，夏簟烹茶卧風月。", "小僧知令不凡材，自掃竹根培老節。", "富貴于我如浮雲，安可一日無此君。", "人言愛竹有何好，此中難爲俗人道。", "我于此物更不疏，一官窘束何由到。"]'),
('a6041f2f-ae1e-46b9-bae6-b260966dc191','題安福李令朝華亭','黄庭堅','宋','宋诗','song-poetry','','[]','丹楹刻桷上崢嶸，表裏江山路眼平。',64,'全唐诗/poet.song.56000.json','["丹楹刻桷上崢嶸，表裏江山路眼平。", "曉日成霞張錦綺，青林多露綴珠纓。", "人如旋磨觀羣蟻，田似圍棋據一枰。", "對案昏昏迷簿領，暫來登覽見高明。"]'),
('89c9bfb8-4fc9-42c6-b03e-0383e9ba9bae','登快閣','黄庭堅','宋','宋诗','song-poetry','','["\u5199\u666f", "\u4e00\u5e74\u7ea7\u4e0b\u518c", "\u6292\u60c5", "\u767b\u697c", "\u9ad8\u4e2d\u53e4\u8bd7", "\u5b8b\u8bd7"]','癡兒了却公家事，快閣東西倚晚晴。',64,'全唐诗/poet.song.56000.json','["癡兒了却公家事，快閣東西倚晚晴。", "落木千山天遠大，澄江一道月分明。", "朱絃已爲佳人絕，青眼聊因美酒橫。", "萬里歸船弄長笛，此心吾與白鷗盟。"]'),
('44d63d6d-1878-444e-a6a4-6adec3812e5f','和李才甫先輩快閣五首  其一','黄庭堅','宋','宋诗','song-poetry','','[]','山寒江冷丹楓落，爭渡行人簇晚沙。',32,'全唐诗/poet.song.56000.json','["山寒江冷丹楓落，爭渡行人簇晚沙。", "菰葉蘋花飛白鳥，一張紅錦夕陽斜。"]'),
('f1f04a0a-f671-4c67-af6a-8d23808f166a','和李才甫先輩快閣五首  其二','黄庭堅','宋','宋诗','song-poetry','','[]','赤欄終日倚西風，山色挼藍小雨中。',32,'全唐诗/poet.song.56000.json','["赤欄終日倚西風，山色挼藍小雨中。", "將老鬢毛秋著木，相思親舊水連空。"]'),
('dde62770-aabf-4c2d-839e-d19347e9f704','和李才甫先輩快閣五首  其三','黄庭堅','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江淡淡吞天去，甲子隨波日日流。',32,'全唐诗/poet.song.56000.json','["長江淡淡吞天去，甲子隨波日日流。", "萬事轉頭同墮甑，一身隨世作虛舟。"]'),
('5d604324-557d-4320-b813-fb9ef2e49bf9','和李才甫先輩快閣五首  其四','黄庭堅','宋','宋诗','song-poetry','','[]','雲橫章貢雨翻盆，寺下江深水到門。',32,'全唐诗/poet.song.56000.json','["雲橫章貢雨翻盆，寺下江深水到門。", "落日荷鋤人著本，西風滿地葉歸根。"]'),
('504c2b9d-4971-45ee-9335-1e8ea1b7ab9d','和李才甫先輩快閣五首  其五','黄庭堅','宋','宋诗','song-poetry','','[]','西南佳氣浮馬祖，東北祥風繞靜居。',32,'全唐诗/poet.song.56000.json','["西南佳氣浮馬祖，東北祥風繞靜居。", "山邑豐年人少訟，身來訪道得齋魚。"]'),
('bcc05f8a-94bb-4301-a84e-6302944f37a4','八月十四日夜刀坑口對月奉寄王子難子聞適用','黄庭堅','宋','宋诗','song-poetry','','[]','去年對月廬陵郡，醉留歌舞蹋金沙。',96,'全唐诗/poet.song.56000.json','["去年對月廬陵郡，醉留歌舞蹋金沙。", "今年今夕千峰下，新磨古鑒動菱花。", "寒藤老木被光景，深山大澤皆龍蛇。", "西風爲我奏萬籟，落葉起舞驚棲鴉。", "遙憐城中二三友，風流慣醉玉釵斜。", "今夕傳杯定何處，應無二十四琵琶。"]'),
('af096bbd-2bb5-4a24-ae31-fd69775a3e1e','彫陂','黄庭堅','宋','宋诗','song-poetry','','[]','彫陂之水清且泚，屈爲印文三百里。',128,'全唐诗/poet.song.56000.json','["彫陂之水清且泚，屈爲印文三百里。", "呼船載過七十餘，褰裳亂流初不記。", "竹輿嶇𡹄山徑凉，僕姑呼婦聲相倚。", "篁中猶道泥滑滑，僕夫慘慘耕夫喜。", "窮山爲吏如漫郎，安能爲人作嚆矢。", "老僧迎謁喜我來，吾以王事篤行李。", "知民虛實應縣官，我寧信目不信耳。", "僧言生長八十餘，縣令未曾身到此。"]'),
('8a74dd99-529d-4d3b-a475-074d07f782d4','幾復寄檳榔且答詩勸予同種復次韵寄之','黄庭堅','宋','宋诗','song-poetry','','[]','少來不食蟻丘漿，老去得意漆園方。',32,'全唐诗/poet.song.56000.json','["少來不食蟻丘漿，老去得意漆園方。", "鑑中已失兒時面，忍能乞與兵作郎。"]'),
('2d6d1e3a-ecd1-4976-b5d4-d8be9f640b83','黄幾復自海上寄惠金液三十兩且曰唯有德之士宜享將以排蕩陰邪守衛真火幸不以凡物畜之戲答','黄庭堅','宋','宋诗','song-poetry','','[]','皺面黄鬚已一翁，樽前猶發少年紅。',32,'全唐诗/poet.song.56000.json','["皺面黄鬚已一翁，樽前猶發少年紅。", "金丹乞與煩真友，只恐無名帝籍中。"]'),
('a3beb663-e2e4-4de8-a6b3-f90dd1ccd57b','幾道復覓檳榔','黄庭堅','宋','宋诗','song-poetry','','[]','蠻煙雨裏紅千樹，逐水排痰肘後方。',32,'全唐诗/poet.song.56000.json','["蠻煙雨裏紅千樹，逐水排痰肘後方。", "莫笑忍饑窮縣令，煩君一斛寄檳榔。"]'),
('81e70bea-173b-4c23-9c1f-63473aa81b9f','次韵幾復答予所贈三物三首 石燈檠','黄庭堅','宋','宋诗','song-poetry','','[]','誰憐湖海士，白髮夜窗檠。',48,'全唐诗/poet.song.56000.json','["誰憐湖海士，白髮夜窗檠。", "風雨雞不已，詩書眼尚明。", "禪枝安宿鳥，僧粥吼華鯨。", "但滿五車讀，行看一座傾。"]'),
('ff5f234d-0609-4b4a-935d-545d55f36803','次韵幾復答予所贈三物三首 石博山','黄庭堅','宋','宋诗','song-poetry','','[]','絕域薔薇露，他山菡萏爐。',48,'全唐诗/poet.song.56000.json','["絕域薔薇露，他山菡萏爐。", "薰衣作家想，伏枕夢閨姝。", "遊子官蟻穴，謫仙居瓠壺。", "當時有憂樂，回首亦成無。"]'),
('686f2781-aca1-4e4e-b34a-c5d202ae1d19','次韵幾復答予所贈三物三首 石刻','黄庭堅','宋','宋诗','song-poetry','','[]','九原誰復起，糟魄未傳心。',48,'全唐诗/poet.song.56000.json','["九原誰復起，糟魄未傳心。", "不取丁儀米，疑成校尉金。", "名從高位借，德有下僚沈。", "筆削多瑕點，猶希畏友箴。"]'),
('98d5367c-8529-43d2-99ae-70986b22ea49','送酒與畢大夫','黄庭堅','宋','宋诗','song-poetry','','[]','淺色官醅昨夜篘，一樽聊付卯時投。',32,'全唐诗/poet.song.56000.json','["淺色官醅昨夜篘，一樽聊付卯時投。", "甕邊吏部應歡喜，殊勝平原老督郵。"]'),
('b36e5498-6ef8-4980-87cc-2f7a47a1d1ed','喜太守畢朝散致政','黄庭堅','宋','宋诗','song-poetry','','[]','膏火煎熬無妄災，就陰息迹信明哉。',64,'全唐诗/poet.song.56000.json','["膏火煎熬無妄災，就陰息迹信明哉。", "功名富貴兩蝸角，險阻艱難一酒杯。", "百體觀來身是幻，萬夫爭處首先回。", "胸中元有不病者，記得陶潛歸去來。"]'),
('2fd1d60e-1213-4e85-9060-debcfafb5c45','次韵道輔雙嶺見寄三疊  其一','黄庭堅','宋','宋诗','song-poetry','','[]','明如九井璜，美如三危露。',48,'全唐诗/poet.song.56000.json','["明如九井璜，美如三危露。", "貞觀魏公孫，今來功名誤。", "兒時漢南柳，摇落傷歲暮。", "時不與我謀，羲和促天步。"]'),
('2fc40ff1-a5c3-46f7-8df0-46a7408bfdd5','次韵道輔雙嶺見寄三疊  其二','黄庭堅','宋','宋诗','song-poetry','','[]','生涯魚吹沫，文彩豹藏霧。',48,'全唐诗/poet.song.56000.json','["生涯魚吹沫，文彩豹藏霧。", "人言壺公老，渠但未得趣。", "飲酒入壺中，茫然失巾屨。", "時不與我謀，今君向何處。"]'),
('3a88bb60-4f79-4d31-82b2-754b748c1323','次韵道輔雙嶺見寄三疊  其三','黄庭堅','宋','宋诗','song-poetry','','[]','蓮塘倒箭靫，桂影凉霜兔。',48,'全唐诗/poet.song.56000.json','["蓮塘倒箭靫，桂影凉霜兔。", "平生知音地，地下無尺素。", "十夜九作夢，虜乘驚沙度。", "時不與我謀，征西枕戈去。"]'),
('b12885ec-6cc3-41e2-949a-995ea912740a','次韵章禹直魏道輔贈答之詩','黄庭堅','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','我老倦多故，心期馬少游。',240,'全唐诗/poet.song.56000.json','["我老倦多故，心期馬少游。", "願爲春眠蠶，吐絲自綢繆。", "翩翩魏公子，閱世無全牛。", "吹噓鼓萬物，領袖傾九流。", "昨來懷白璧，往撼西諸侯。", "中丞文武將，良非衛霍侔。", "誓開河源地，畫作禹貢州。", "壯士捐軀死，鯨鯢尚吞舟。", "客心無一寸，草食隨百憂。", "故人道舊語，末路非前籌。", "重來滕王閣，楓葉江上秋。", "章子飽徑術，賦詩如曹劉。", "太學得虛名，權勢殊未尤。", "禍機發無妄，對吏抵搶頭。", "遇逢椎鼓赦，帝澤萬邦休。", "章江三年拘，解裝買莫愁。", "麗姬泣又悔，生故難豫謀。", "邂逅識面晚，困窮理相收。", "夜語倒樽酒，參旌偃風旒。", "兩公但取醉，古今共高丘。"]'),
('0959a5c0-4bfe-4553-b220-f2be9eecab76','次韵道輔旅懷見寄','黄庭堅','宋','宋诗','song-poetry','','[]','歲華其將晚，霜葉不可風。',108,'全唐诗/poet.song.56000.json','["歲華其將晚，霜葉不可風。", "生理魚乞水，歸心鳥飛空。", "風塵化衣黑，旅宿夢裙紅。", "人言家無壁，自倚筆有鋒。", "轉蓬且半歲，交臂各衰翁。", "扁舟去日遠，明月與君同。", "露晞百年駛，麟獲萬事窮。", "裝懷酒澹淡，塞意霧空濛。", "諸公尚無恙，不見陳元龍。"]');
